    /** === نظام الصيانة / Maintenance system === */
    const MAINTENANCE_REGISTRY_KEY = 'bhd_maintenance_registry';
    const MAINTENANCE_STATUSES = ['pending_approval', 'pending', 'in_progress', 'completed', 'cancelled'];
    let _maintenanceUiState = { status: '', building: '', unit: '', tenant: '', search: '' };
    let _maintenanceFormLines = [];
    let _maintenanceFormState = { building: '', unit: '', notes: '', lineCategory: '', lineSubtype: '' };
    let _maintenanceAcctDraftAmounts = {};
    let _maintenanceStatusAction = { requestId: '', action: '' };

    function maintenanceLocalizedText(ar, en) {
        return appUiLanguage === 'en' ? (toStr(en) || toStr(ar) || '—') : (toStr(ar) || toStr(en) || '—');
    }

    function maintenanceLocalizedItem(ln) {
        if (!ln) return '—';
        return maintenanceLocalizedText(ln.labelAr, ln.labelEn);
    }

    function maintenanceLocalizedCategory(cat) {
        if (!cat) return '—';
        return maintenanceLocalizedText(cat.categoryAr, cat.categoryEn);
    }

    function getMaintenanceBuildingOptions() {
        const set = new Set(getActiveBuildingNames());
        getUnitsData().forEach((u) => {
            const b = toStr(u.building).trim();
            if (b) set.add(b);
        });
        return [...set].sort((a, b) => a.localeCompare(b, 'ar'));
    }

    function getMaintenanceUnitsForBuilding(building) {
        const b = toStr(building).trim();
        if (!b) return [];
        const seen = new Set();
        return getUnitsData()
            .filter((u) => toStr(u.building).trim() === b && toStr(u.unit).trim())
            .map((u) => toStr(u.unit).trim())
            .filter((unit) => {
                if (seen.has(unit)) return false;
                seen.add(unit);
                return true;
            })
            .sort((a, b) => a.localeCompare(b, 'ar', { numeric: true }));
    }

    function getMaintenanceStaffOptions() {
        try { reloadUsersRegistryFromStorageForAuth(); } catch (_eMntStaff) {}
        return (usersRegistry || [])
            .map((u) => normalizeUserRecord(u))
            .filter((u) => u && toStr(u.displayName || u.email))
            .sort((a, b) => toStr(a.displayName || a.email).localeCompare(toStr(b.displayName || b.email), 'ar'));
    }

    function maintenanceStaffSelectOptions(selectedId) {
        const sel = toStr(selectedId);
        const opts = `<option value="">${t('— اختر موظف —', '— Select staff —')}</option>`;
        return opts + getMaintenanceStaffOptions().map((u) => {
            const id = escHtml(u.id);
            const label = escHtml(u.displayName || u.email || u.id);
            return `<option value="${id}" ${sel === u.id ? 'selected' : ''}>${label}</option>`;
        }).join('');
    }

