                    { key: 'paint', labelAr: 'طلاء/معالجة جدار', labelEn: 'Paint touch-up', materialsCost: 10, laborCost: 15, hasQty: false, assigneeUserId: '', assigneeName: '' },
                    { key: 'other', labelAr: 'أخرى (سعر يدوي)', labelEn: 'Other (manual price)', materialsCost: 0, laborCost: 0, hasQty: false, customPrice: true, assigneeUserId: '', assigneeName: '' }
