    function emptyMaintenanceRegistry() {
        return {
            version: 1,
            seq: 1,
            settings: { completionAttachmentsRequired: false },
            priceCatalog: defaultMaintenancePriceCatalog(),
            requests: []
        };
    }

    function normalizeMaintenancePriceCatalog(catalog) {
        return (Array.isArray(catalog) ? catalog : []).map((cat, catIdx) => {
            const categoryKey = toStr(cat?.categoryKey) || `cat_${catIdx}`;
            const subtypes = (Array.isArray(cat?.subtypes) ? cat.subtypes : []).map((sub, subIdx) => {
                const key = toStr(sub?.key) || `legacy_${categoryKey}_${subIdx}`;
                return {
                    ...sub,
                    key,
                    labelAr: toStr(sub?.labelAr) || toStr(sub?.labelEn) || key,
                    labelEn: toStr(sub?.labelEn) || toStr(sub?.labelAr) || key,
                    materialsCost: parseFloat(sub?.materialsCost) || 0,
                    laborCost: parseFloat(sub?.laborCost) || 0,
                    assigneeUserId: toStr(sub?.assigneeUserId),
                    assigneeName: toStr(sub?.assigneeName)
                };
            });
            return {
                ...cat,
                categoryKey,
                categoryAr: toStr(cat?.categoryAr) || categoryKey,
                categoryEn: toStr(cat?.categoryEn) || categoryKey,
                subtypes
            };
        });
    }

    function loadMaintenanceRegistry() {
        try {
            const raw = localStorage.getItem(MAINTENANCE_REGISTRY_KEY);
            const o = raw ? JSON.parse(raw) : null;
            if (!o || typeof o !== 'object') return emptyMaintenanceRegistry();
            return {
                version: o.version || 1,
                seq: parseInt(o.seq, 10) || 1,
                settings: {
                    completionAttachmentsRequired: !!(o.settings && o.settings.completionAttachmentsRequired)
                },
                priceCatalog: normalizeMaintenancePriceCatalog(
                    Array.isArray(o.priceCatalog) && o.priceCatalog.length ? o.priceCatalog : defaultMaintenancePriceCatalog()
                ),
                requests: Array.isArray(o.requests) ? o.requests : []
            };
        } catch (_eMntLoad) {
            return emptyMaintenanceRegistry();
        }
    }

    function saveMaintenanceRegistry(reg) {
        try {
            localStorage.setItem(MAINTENANCE_REGISTRY_KEY, JSON.stringify(reg || emptyMaintenanceRegistry()));
            syncBhdKvToServer();
        } catch (_eMntSave) {}
    }

    function getMaintenanceSettings() {
        const reg = loadMaintenanceRegistry();
        return {
            completionAttachmentsRequired: !!(reg.settings && reg.settings.completionAttachmentsRequired)
        };
    }

    function setMaintenanceCompletionAttachmentsRequired(required) {
        const reg = loadMaintenanceRegistry();
        if (!reg.settings || typeof reg.settings !== 'object') reg.settings = {};
        reg.settings.completionAttachmentsRequired = !!required;
        saveMaintenanceRegistry(reg);
    }

    function maintenanceUnitKey(building, unit) {
        return `${toStr(building)}\t${toStr(unit)}`;
    }

    function newMaintenanceId() {
        return `mnt_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
    }

    function nextMaintenanceRequestNo(reg) {
        const y = new Date().getFullYear();
        const n = parseInt(reg.seq, 10) || 1;
        reg.seq = n + 1;
        return `MNT-${y}-${String(n).padStart(4, '0')}`;
    }

    function maintenanceStatusLabel(status) {
        const map = {
            pending_approval: t('مطلوب موافقة الإدارة', 'Management approval required'),
            pending: t('معلق', 'Pending'),
            in_progress: t('قيد التنفيذ', 'In progress'),
            completed: t('مكتمل', 'Completed'),
            cancelled: t('ملغي', 'Cancelled'),
            approved: t('تمت موافقة الإدارة', 'Management approved')
        };
        return map[toStr(status)] || toStr(status) || '—';
    }

    function maintenanceEventTypeLabel(type) {
        const map = {
            created: t('أنشأ طلب صيانة', 'Created maintenance request'),
            approved: t('وافق الإدارة على الطلب', 'Approved the request'),
            return_requested: t('طلب استرجاع البلاغ', 'Requested case return'),
            returned_to_assignee: t('أرجع الطلب للموظف', 'Returned request to staff'),
            follow_up_assigned: t('حوّل البلاغ للمتابعة', 'Assigned case for follow-up'),
            pending: t('علّق الطلب', 'Set request to pending'),
            pending_approval: t('أرسل الطلب لموافقة الإدارة', 'Sent request for management approval'),
            in_progress: t('بدأ التنفيذ', 'Started work'),
            completed: t('أكمل الطلب', 'Completed the request'),
            cancelled: t('ألغى الطلب', 'Cancelled the request'),
            amount_adjusted: t('عدّل المبلغ', 'Adjusted the amount'),
            linked_accounting: t('ربط الطلب بالمحاسبة', 'Linked request to accounting'),
            unlinked_accounting: t('فك ربط الطلب من المحاسبة', 'Unlinked request from accounting'),
            invoice_issued: t('أصدر فاتورة الصيانة', 'Issued maintenance invoice'),
            task_created: t('إنشاء مهمة متابعة', 'Follow-up task created'),
            task_note: t('ملاحظة على المهمة', 'Task note'),
            task_reply: t('رد على المهمة', 'Task reply'),
            task_completed: t('إكمال مهمة المتابعة', 'Follow-up task completed')
        };
        return map[toStr(type)] || maintenanceStatusLabel(type) || toStr(type) || '—';
    }

    function findTasksForMaintenanceRequest(requestId) {
        const rid = toStr(requestId);
        if (!rid) return [];
        const reg = loadTasksRegistry();
        return (reg.tasks || []).filter((task) =>
            toStr(task.sourceKey) === `maintenance_exec|${rid}` ||
            (toStr(task.relatedId) === rid && toStr(task.sourceKind) === 'maintenance_start')
        );
    }

    function taskMessageToMaintenanceLogEntry(msg, task) {
        const ty = toStr(msg.type);
        let eventType = 'task_note';
        if (ty === 'reply') eventType = 'task_reply';
        else if (ty === 'completed') eventType = 'task_completed';
        let noteText = toStr(msg.text);
        if (msg.followUpDate) noteText += ` · ${t('متابعة', 'Follow-up')}: ${msg.followUpDate}`;
        if (toStr(msg.parentMessageId)) {
            noteText = `↪ ${toStr(msg.replyToStaffName) || '—'}: ${noteText}`;
        }
        return {
            at: msg.at,
            type: eventType,
            staffName: msg.staffName,
            note: noteText,
            taskNo: task.taskNo,
            taskId: task.id,
            taskMessageId: msg.id
        };
    }

    function collectMaintenanceActivityEntries(req) {
        const entries = [];
        const seenMsgIds = new Set();
        (req.events || []).forEach((ev) => {
            entries.push({ ...ev });
            if (ev.taskMessageId) seenMsgIds.add(toStr(ev.taskMessageId));
        });
        findTasksForMaintenanceRequest(req.id).forEach((task) => {
            const hasCreated = entries.some((e) =>
                e.type === 'task_created' && toStr(e.taskId) === toStr(task.id)
            );
            if (!hasCreated && task.createdAt) {
                entries.push({
                    at: task.createdAt,
                    type: 'task_created',
                    staffName: task.createdBy,
                    note: `${task.taskNo} — ${task.title}`,
                    taskNo: task.taskNo,
                    taskId: task.id
                });
            }
            (task.messages || []).forEach((msg) => {
                const ty = toStr(msg.type);
                if (ty && !['note', 'reply', 'completed'].includes(ty)) return;
                if (seenMsgIds.has(msg.id)) return;
                entries.push(taskMessageToMaintenanceLogEntry(msg, task));
            });
        });
        return entries.sort((a, b) => toStr(b.at).localeCompare(toStr(a.at)));
    }

    function appendMaintenanceTaskEvent(requestId, event) {
        const mreg = loadMaintenanceRegistry();
        const req = mreg.requests.find((r) => r.id === requestId);
        if (!req) return;
        if (!Array.isArray(req.events)) req.events = [];
        req.events.push({
            ...(event || {}),
            at: (event && event.at) || new Date().toISOString()
        });
        saveMaintenanceRegistry(mreg);
    }

    function mirrorTaskMessageToMaintenanceRequest(task, msg) {
        const reqId = toStr(task?.relatedId);
        if (toStr(task?.sourceKind) !== 'maintenance_start' || !reqId || !msg) return;
        const ty = toStr(msg.type);
        if (ty && !['note', 'reply', 'completed'].includes(ty)) return;
        let eventType = 'task_note';
        if (ty === 'reply') eventType = 'task_reply';
        else if (ty === 'completed') eventType = 'task_completed';
        let noteText = toStr(msg.text);
        if (msg.followUpDate) noteText += ` · ${t('متابعة', 'Follow-up')}: ${msg.followUpDate}`;
        if (toStr(msg.parentMessageId)) {
            noteText = `↪ ${toStr(msg.replyToStaffName) || '—'}: ${noteText}`;
        }
        appendMaintenanceTaskEvent(reqId, {
            at: msg.at,
            type: eventType,
            staffName: msg.staffName,
            note: noteText,
            taskNo: task.taskNo,
            taskId: task.id,
            taskMessageId: msg.id
        });
    }

    function renderMaintenanceLinkedTaskBannerHtml(req) {
        const tasks = findTasksForMaintenanceRequest(req.id);
        if (!tasks.length) return '';
        const primary = tasks[0];
        const tid = escHtml(primary.id);
        const summary = tasks.map((tk) =>
            `${escHtml(tk.taskNo)} (${escHtml(taskStatusLabel(tk.status))})`
        ).join(' · ');
        return `<div style="margin-bottom:10px;padding:10px 12px;border-radius:8px;background:#e8f4fd;border:1px solid #90caf9;font-size:12px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
            <span><strong>${t('مهمة المتابعة / Follow-up task', 'Follow-up task / مهمة المتابعة')}:</strong> ${summary}</span>
            <button type="button" class="btn-outline mini-btn" onclick="openTaskDetailModal('${tid}')">${t('فتح المهمة / Open task', 'Open task / فتح')}</button>
        </div>`;
    }

    function renderMaintenanceActivityLogHtml(req) {
        const entries = collectMaintenanceActivityEntries(req);
        if (!entries.length) {
            return `<p style="margin:0;font-size:12px;color:#666">—</p>`;
        }
        return entries.map((ev) => renderMaintenanceEventLogEntry(ev)).join('');
    }
    function renderMaintenanceEventLogEntry(ev) {
        const when = escHtml(toStr(ev.at).slice(0, 16).replace('T', ' '));
        const who = escHtml(toStr(ev.staffName) || '—');
        const action = escHtml(maintenanceEventTypeLabel(ev.type));
        const taskBadge = ev.taskNo
            ? ` <span style="font-size:10px;background:#e3f2fd;color:#1565c0;padding:1px 6px;border-radius:4px">${escHtml(ev.taskNo)}</span>`
            : '';
        const note = toStr(ev.note).trim();
        const noteHtml = note
            ? `<div style="margin-top:3px;color:#444">${escHtml(note)}</div>`
            : '';
        const openTaskBtn = ev.taskId
            ? `<button type="button" class="btn-outline mini-btn" style="margin-top:6px;font-size:10px" onclick="openTaskDetailModal('${escHtml(ev.taskId)}')">${t('فتح المهمة / Open task', 'Open task / فتح')}</button>`
            : '';
        return `<div style="margin-bottom:8px;font-size:12px;line-height:1.45;padding:8px 10px;border-radius:6px;background:#fafafa;border:1px solid #eee">
            <div><strong>${who}</strong> — <strong style="color:#4a1525">${action}</strong>${taskBadge}</div>
            ${noteHtml}
            ${openTaskBtn}
            <small style="display:block;color:#888;margin-top:4px">${when}</small>
        </div>`;
    }

    function maintenanceVisibleToCurrentUser(req) {
        if (!req) return false;
        if (isMaintenanceSystemAdmin()) return true;
        const u = getLoggedInUser();
        if (u && isPortalScopedUser(u) && userHasPermission(u, 'request_maintenance')) {
            return unitPassesPortalScope(req.building, req.unit);
        }
        const actor = getCurrentActorLedgerRecord();
        const actorId = toStr(actor.staffUserId);
        if (actorId && toStr(req.createdByUserId) === actorId) return true;
        const isAssignee = actorId && toStr(req.assigneeUserId) === actorId;
        if (isAssignee && toStr(req.status) === 'pending_approval') return false;
        if (u && userHasPermission(u, 'manage_maintenance')) return true;
        if (u && userHasPermission(u, 'request_maintenance')) {
            return unitPassesPortalScope(req.building, req.unit);
        }
        return !usersRegistryHasRows();
    }

    function maintenanceStatusChip(status, linked) {
        const st = toStr(status) || 'pending';
        const cls = linked ? 'mnt-status-linked' : `mnt-status-${st}`;
        const label = linked ? t('مربوط بالمحاسبة', 'Linked to accounting') : maintenanceStatusLabel(st);
        return `<span class="mnt-status-chip ${cls}">${escHtml(label)}</span>`;
    }

    function maintenanceLineTotal(line) {
        const qty = Math.max(1, parseInt(line.qty, 10) || 1);
        const mat = parseFloat(line.materialsCost) || 0;
        const lab = parseFloat(line.laborCost) || 0;
        if (line.customPrice) return parseFloat(line.customTotal) || 0;
        return parseFloat(((mat + lab) * qty).toFixed(3));
    }

    function maintenanceRequestTotal(req) {
        if (!req) return 0;
        if (req.accountantAdjustedTotal != null && req.accountantAdjustedTotal !== '') {
            return parseFloat(req.accountantAdjustedTotal) || 0;
        }
        if (req.finalTotal != null && req.finalTotal !== '') return parseFloat(req.finalTotal) || 0;
        return maintenanceItemsSubtotal(req);
    }

    function maintenanceItemsSubtotal(req) {
        if (!req) return 0;
        const items = Array.isArray(req.items) ? req.items : [];
        return parseFloat(items.reduce((s, it) => s + maintenanceLineTotal(it), 0).toFixed(3));
    }

    function maintenanceAmountBreakdown(req, inv) {
        const originalTotal = maintenanceItemsSubtotal(req);
        let finalTotal = originalTotal;
        let hasAccountantAdjustment = false;
        if (req?.accountantAdjustedTotal != null && req.accountantAdjustedTotal !== '') {
            hasAccountantAdjustment = true;
            finalTotal = parseFloat(req.accountantAdjustedTotal) || 0;
        } else if (inv?.total != null && inv.total !== '') {
            const invTotal = parseFloat(inv.total) || 0;
            if (Math.abs(invTotal - originalTotal) > 0.001) {
                hasAccountantAdjustment = true;
                finalTotal = invTotal;
            }
        } else if (req?.finalTotal != null && req.finalTotal !== '') {
            finalTotal = parseFloat(req.finalTotal) || 0;
            if (Math.abs(finalTotal - originalTotal) > 0.001) {
                hasAccountantAdjustment = true;
            }
        }
        const adjustmentDelta = parseFloat((originalTotal - finalTotal).toFixed(3));
        return {
            originalTotal,
            finalTotal,
            hasAccountantAdjustment,
            hasDiscount: hasAccountantAdjustment && adjustmentDelta > 0.001,
            hasIncrease: hasAccountantAdjustment && adjustmentDelta < -0.001,
            discountAmount: adjustmentDelta > 0 ? adjustmentDelta : 0,
            increaseAmount: adjustmentDelta < 0 ? Math.abs(adjustmentDelta) : 0
        };
    }

    function renderMaintenanceInvoiceAmountSummaryHtml(req, inv) {
        const b = maintenanceAmountBreakdown(req, inv);
        if (!b.hasAccountantAdjustment) {
            return `
            <div class="section-header property-section-h">${t('ملخص الفاتورة / Invoice summary', 'Invoice summary / ملخص الفاتورة')}</div>
            <table class="info-table property-report-table print-zebra-cells" style="margin-bottom:14px">
                <tbody>
                    <tr>
                        <th style="width:55%">${t('الفاتورة الكاملة / Full invoice total', 'Full invoice total / الفاتورة الكاملة')}</th>
                        <td style="font-weight:700">${escHtml(summaryAmtOm(b.finalTotal))}</td>
                    </tr>
                </tbody>
            </table>`;
        }
        const discountRow = b.hasDiscount
            ? `<tr>
                <th>${t('قيمة الخصم / Discount amount', 'Discount amount / قيمة الخصم')}</th>
                <td style="color:#b71c1c;font-weight:700">${escHtml(summaryAmtOm(b.discountAmount))}</td>
            </tr>`
            : '';
        const increaseRow = b.hasIncrease
            ? `<tr>
                <th>${t('قيمة الزيادة / Increase amount', 'Increase amount / قيمة الزيادة')}</th>
                <td style="color:#e65100;font-weight:700">${escHtml(summaryAmtOm(b.increaseAmount))}</td>
            </tr>`
            : '';
        return `
            <div class="section-header property-section-h">${t('ملخص الفاتورة / Invoice summary', 'Invoice summary / ملخص الفاتورة')}</div>
            <table class="info-table property-report-table print-zebra-cells" style="margin-bottom:14px">
                <tbody>
                    <tr>
                        <th style="width:55%">${t('قيمة الفاتورة / Invoice amount', 'Invoice amount / قيمة الفاتورة')}</th>
                        <td>${escHtml(summaryAmtOm(b.originalTotal))}</td>
                    </tr>
                    <tr>
                        <th>${t('تم تعديل القيمة من قبل المحاسب إلى / Adjusted by accountant to', 'Adjusted by accountant to / تم التعديل إلى')}</th>
                        <td>${escHtml(summaryAmtOm(b.finalTotal))}</td>
                    </tr>
                    ${discountRow}
                    ${increaseRow}
                    <tr>
                        <th style="font-weight:800;background:#eef5ff">${t('الفاتورة الكاملة / Full invoice total', 'Full invoice total / الفاتورة الكاملة')}</th>
                        <td style="font-weight:800;font-size:13pt;background:#eef5ff">${escHtml(summaryAmtOm(b.finalTotal))}</td>
                    </tr>
                </tbody>
            </table>`;
    }

    function renderMaintenanceAmountAdjustmentPanel(req) {
        const b = maintenanceAmountBreakdown(req);
        if (!b.hasAccountantAdjustment) return '';
        const discountRow = b.hasDiscount
            ? `<div><small>${t('قيمة الخصم / Discount amount', 'Discount amount / قيمة الخصم')}</small><strong style="display:block;color:#b71c1c">${escHtml(summaryAmtOm(b.discountAmount))}</strong></div>`
            : '';
        const increaseRow = b.hasIncrease
            ? `<div><small>${t('قيمة الزيادة / Increase amount', 'Increase amount / قيمة الزيادة')}</small><strong style="display:block;color:#e65100">${escHtml(summaryAmtOm(b.increaseAmount))}</strong></div>`
            : '';
        return `<div style="margin:0 0 12px;padding:10px 12px;border-radius:8px;background:#f3f8ff;border:1px solid #c5d9f2;display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px;font-size:12px">
            <div><small>${t('قيمة الفاتورة / Invoice amount', 'Invoice amount / قيمة الفاتورة')}</small><strong style="display:block">${escHtml(summaryAmtOm(b.originalTotal))}</strong></div>
            <div><small>${t('تم تعديل القيمة من قبل المحاسب إلى / Adjusted by accountant to', 'Adjusted by accountant to / تم التعديل إلى')}</small><strong style="display:block">${escHtml(summaryAmtOm(b.finalTotal))}</strong></div>
            ${discountRow}${increaseRow}
            <div><small>${t('الفاتورة الكاملة / Full invoice total', 'Full invoice total / الفاتورة الكاملة')}</small><strong style="display:block;color:#1b5e20">${escHtml(summaryAmtOm(b.finalTotal))}</strong></div>
        </div>`;
    }

    function canPrintMaintenanceReceipt(req) {
        return !!(req && req.linkedToAccounting);
    }

    function printMaintenanceReceipt(requestId) {
        const req = loadMaintenanceRegistry().requests.find((r) => r.id === requestId);
        if (!req) return;
        if (!req.linkedToAccounting) {
            alert(t('الطلب غير مربوط بالمحاسبة. اربطه أولاً لطباعة الإيصال.', 'Request is not linked to accounting. Link it first to print the receipt.'));
            return;
        }
        if (!getMaintenanceAccountingInvoice(req)) {
            issueMaintenanceInvoiceForRequest(requestId);
            return;
        }
        printMaintenanceInvoiceByRequest(requestId);
    }

    let _maintenancePrintPendingId = '';

    function getMaintenancePrintSectionDefs(req) {
        const hasReceipt = !!(req && req.linkedToAccounting && getMaintenanceAccountingInvoice(req));
        const hasAtts = Array.isArray(req?.completionAttachments) && req.completionAttachments.length > 0;
        return [
            { key: 'details', label: t('تفاصيل الطلب / Request details', 'Request details / تفاصيل الطلب'), default: true },
            { key: 'items', label: t('بنود الصيانة / Maintenance items', 'Maintenance items / بنود الصيانة'), default: true },
            { key: 'events', label: t('سجل الإجراءات / Activity log', 'Activity log / سجل الإجراءات'), default: true },
            { key: 'receipt', label: t('الإيصال / الفاتورة / Receipt / Invoice', 'Receipt / Invoice / الإيصال'), default: hasReceipt, disabled: !hasReceipt },
            { key: 'attachments', label: t('مرفقات الحل / Solution attachments', 'Solution attachments / مرفقات الحل'), default: hasAtts, disabled: !hasAtts }
        ];
    }

    function openMaintenancePrintModal(requestId) {
        const req = loadMaintenanceRegistry().requests.find((r) => r.id === requestId);
        if (!req) return;
        _maintenancePrintPendingId = toStr(requestId);
        const modal = document.getElementById('maintenancePrintModal');
        const checks = document.getElementById('maintenancePrintSectionChecks');
        const title = document.getElementById('maintenancePrintModalTitle');
        if (!modal || !checks) return;
        if (title) title.textContent = `${t('طباعة طلب الصيانة', 'Print maintenance request')} — ${req.requestNo}`;
        const defs = getMaintenancePrintSectionDefs(req);
        checks.innerHTML = defs.map((sec) => {
            const dis = sec.disabled ? ' disabled' : '';
            const chk = sec.default && !sec.disabled ? ' checked' : '';
            return `<label class="cfv-check"${sec.disabled ? ' style="opacity:.55"' : ''}><input type="checkbox" class="mnt-print-sec-chk" data-mnt-print-key="${escAttr(sec.key)}"${chk}${dis}><span>${escHtml(sec.label)}</span></label>`;
        }).join('');
        modal.classList.add('open');
    }

    function closeMaintenancePrintModal() {
        document.getElementById('maintenancePrintModal')?.classList.remove('open');
        _maintenancePrintPendingId = '';
    }

    function maintenancePrintSelectAllSections(checked) {
        document.querySelectorAll('.mnt-print-sec-chk:not(:disabled)').forEach((el) => { el.checked = !!checked; });
    }

    function collectMaintenancePrintSelectedKeys() {
        return [...document.querySelectorAll('.mnt-print-sec-chk:checked')]
            .map((el) => toStr(el.getAttribute('data-mnt-print-key')))
            .filter(Boolean);
    }

    function buildMaintenanceDetailsPrintHtml(req) {
        const unitCtx = resolveMaintenanceUnitContext(req.building, req.unit);
        const tenantLabel = unitCtx.tenantDisplay;
        const unitStatusLabel = unitCtx.isRented ? t('مستأجرة', 'Rented') : t('شاغرة', 'Vacant');
        const total = maintenanceRequestTotal(req);
        const amountLabel = maintenanceAmountBreakdown(req).hasAccountantAdjustment
            ? t('المبلغ النهائي / Final amount', 'Final amount / المبلغ النهائي')
            : t('المبلغ / Amount', 'Amount / المبلغ');
        const extraRows = [];
        if (req.notes) extraRows.push(`<tr><th>${t('ملاحظات الطلب', 'Request notes')}</th><td colspan="3">${escHtml(req.notes)}</td></tr>`);
        if (req.completionNote) extraRows.push(`<tr><th>${t('ملاحظة الإكمال', 'Completion note')}</th><td colspan="3">${escHtml(req.completionNote)}</td></tr>`);
        if (req.statusNote) extraRows.push(`<tr><th>${t('ملاحظة الحالة', 'Status note')}</th><td colspan="3">${escHtml(req.statusNote)}</td></tr>`);
        if (req.returnRequested) {
            extraRows.push(`<tr><th>${t('طلب استرجاع', 'Return request')}</th><td colspan="3">${escHtml(req.returnRequestNote || '—')} — ${escHtml(toStr(req.returnRequestedBy || '—'))}</td></tr>`);
        }
        if (req.followUpActive) {
            extraRows.push(`<tr><th>${t('متابعة البلاغ', 'Follow-up')}</th><td colspan="3">${escHtml(req.followUpNote || req.statusNote || '—')}</td></tr>`);
        }
        if (req.linkedToAccounting) {
            extraRows.push(`<tr><th>${t('المحاسبة', 'Accounting')}</th><td colspan="3">${t('مربوط بالمحاسبة', 'Linked to accounting')}</td></tr>`);
        }
        return `
            <div class="section-header property-section-h">${t('تفاصيل الطلب / Request details', 'Request details / تفاصيل الطلب')}</div>
            <table class="info-table property-report-table print-zebra-cells" style="margin-bottom:14px">
                <tbody>
                    <tr>
                        <th style="width:22%">${t('رقم الطلب', 'Request no.')}</th>
                        <td style="width:28%">${escHtml(req.requestNo)}</td>
                        <th style="width:22%">${t('الحالة', 'Status')}</th>
                        <td style="width:28%">${escHtml(maintenanceStatusLabel(req.status))}</td>
                    </tr>
                    <tr>
                        <th>${t('العقار', 'Property')}</th>
                        <td>${escHtml(req.building)} — ${escHtml(req.unit)}</td>
                        <th>${t('حالة الوحدة', 'Unit status')}</th>
                        <td>${escHtml(unitStatusLabel)}</td>
                    </tr>
                    <tr>
                        <th>${t('المستأجر', 'Tenant')}</th>
                        <td>${escHtml(tenantLabel)}</td>
                        <th>${t('رقم العقد', 'Contract')}</th>
                        <td>${escHtml(unitCtx.isRented ? (unitCtx.agreementNo || req.agreementNo || '—') : '—')}</td>
                    </tr>
                    <tr>
                        <th>${t('المسؤول', 'Assignee')}</th>
                        <td>${escHtml(req.assigneeName || '—')}</td>
                        <th>${escHtml(amountLabel)}</th>
                        <td>${escHtml(summaryAmtOm(total))}</td>
                    </tr>
                    <tr>
                        <th>${t('أدخل الطلب', 'Created by')}</th>
                        <td>${escHtml(req.createdBy || '—')}</td>
                        <th>${t('تاريخ الإنشاء', 'Created at')}</th>
                        <td>${escHtml(toStr(req.createdAt).slice(0, 16).replace('T', ' '))}</td>
                    </tr>
                    ${req.completedAt ? `<tr><th>${t('تاريخ الإكمال', 'Completed at')}</th><td>${escHtml(toStr(req.completedAt).slice(0, 16).replace('T', ' '))}</td><th>${t('أكمله', 'Completed by')}</th><td>${escHtml(req.completedBy || '—')}</td></tr>` : ''}
                    ${extraRows.join('')}
                </tbody>
            </table>`;
    }

    function buildMaintenanceItemsPrintHtml(req) {
        const items = Array.isArray(req.items) ? req.items : [];
        const rows = items.length
            ? items.map((ln, i) => `<tr>
                <td class="print-num">${i + 1}</td>
                <td>${escHtml(maintenanceLocalizedText(ln.categoryAr || ln.categoryKey, ln.categoryEn || ln.categoryKey))}</td>
                <td>${escHtml(maintenanceLocalizedItem(ln))}</td>
                <td>${escHtml(ln.qty || 1)}</td>
                <td>${escHtml(summaryAmtOm(ln.materialsCost))}</td>
                <td>${escHtml(summaryAmtOm(ln.laborCost))}</td>
                <td>${escHtml(ln.assigneeName || '—')}</td>
                <td>${escHtml(summaryAmtOm(maintenanceLineTotal(ln)))}</td>
            </tr>`).join('')
            : `<tr><td colspan="8">${t('لا توجد بنود.', 'No items.')}</td></tr>`;
        return `
            <div class="section-header property-section-h">${t('بنود الصيانة / Maintenance items', 'Maintenance items / بنود الصيانة')}</div>
            <table class="info-table property-report-table print-zebra" style="margin-bottom:14px">
                <thead><tr>
                    <th class="print-num">#</th>
                    <th>${t('الفئة', 'Category')}</th>
                    <th>${t('البند', 'Item')}</th>
                    <th>${t('عدد', 'Qty')}</th>
                    <th>${t('مواد', 'Materials')}</th>
                    <th>${t('عامل', 'Labor')}</th>
                    <th>${t('المسؤول', 'Assignee')}</th>
                    <th>${t('إجمالي', 'Total')}</th>
                </tr></thead>
                <tbody>${rows}</tbody>
            </table>`;
    }

    function buildMaintenanceEventsPrintHtml(req) {
        const events = collectMaintenanceActivityEntries(req);
        if (!events.length) {
            return `<div class="section-header property-section-h">${t('سجل الإجراءات / Activity log', 'Activity log / سجل الإجراءات')}</div>
                <p class="property-report-meta">${t('لا توجد حركات مسجلة.', 'No activity recorded.')}</p>`;
        }
        const rows = events.map((ev, i) => `<tr>
            <td class="print-num">${i + 1}</td>
            <td>${escHtml(toStr(ev.at).slice(0, 16).replace('T', ' '))}</td>
            <td>${escHtml(toStr(ev.staffName) || '—')}</td>
            <td>${escHtml(maintenanceEventTypeLabel(ev.type))}</td>
            <td>${escHtml(toStr(ev.note) || '—')}</td>
        </tr>`).join('');
        return `
            <div class="section-header property-section-h">${t('سجل الإجراءات / Activity log', 'Activity log / سجل الإجراءات')}</div>
            <table class="info-table property-report-table print-zebra" style="margin-bottom:14px">
                <thead><tr>
                    <th class="print-num">#</th>
                    <th>${t('التاريخ', 'Date')}</th>
                    <th>${t('الموظف', 'Staff')}</th>
                    <th>${t('الإجراء', 'Action')}</th>
                    <th>${t('الملاحظة', 'Note')}</th>
                </tr></thead>
                <tbody>${rows}</tbody>
            </table>`;
    }

    async function printMaintenanceRequestFull() {
        const requestId = _maintenancePrintPendingId;
        const req = loadMaintenanceRegistry().requests.find((r) => r.id === requestId);
        if (!req) return;
        const keys = collectMaintenancePrintSelectedKeys();
        if (!keys.length) {
            alert(t('اختر قسماً واحداً على الأقل.', 'Select at least one section.'));
            return;
        }
        let bodyHtml = '';
        if (keys.includes('details')) bodyHtml += buildMaintenanceDetailsPrintHtml(req);
        if (keys.includes('items')) bodyHtml += buildMaintenanceItemsPrintHtml(req);
        if (keys.includes('events')) bodyHtml += buildMaintenanceEventsPrintHtml(req);
        if (keys.includes('receipt')) {
            const inv = getMaintenanceAccountingInvoice(req);
            if (inv) {
                bodyHtml += buildMaintenanceInvoicePrintHtml(req, inv);
            } else {
                bodyHtml += `<div class="section-header property-section-h">${t('الإيصال / الفاتورة', 'Receipt / Invoice')}</div>
                    <p class="property-report-meta">${t('لا يوجد إيصال مرتبط — اربط الطلب بالمحاسبة أولاً.', 'No linked receipt — link request to accounting first.')}</p>`;
            }
        }
        const contentKeys = keys.filter((k) => k !== 'attachments');
        if (keys.includes('attachments')) {
            const atts = Array.isArray(req.completionAttachments) ? req.completionAttachments : [];
            const items = await bhdHydrateAttachmentItemsForPrint(atts.map((att, i) => ({
                ...normalizeContractAttachmentRef(att),
                label: toStr(att.name) || `${t('مرفق', 'Attachment')} ${i + 1}`
            })).filter(Boolean));
            if (items.length) {
                bodyHtml += `<div class="section-header property-section-h">${t('مرفقات الحل / Solution attachments', 'Solution attachments / مرفقات الحل')}</div>
                    <p class="property-report-meta">${t(`${items.length} مرفق`, `${items.length} attachment(s)`)}</p>`;
                bodyHtml += buildContractAttachmentsPrintPagesHtml(items, req.requestNo, { breakBeforeFirst: contentKeys.length > 0 });
            } else {
                bodyHtml += `<div class="section-header property-section-h">${t('مرفقات الحل / Solution attachments', 'Solution attachments / مرفقات الحل')}</div>
                    <p class="property-report-meta">${t('لا توجد مرفقات قابلة للطباعة.', 'No printable attachments.')}</p>`;
            }
        }
        if (!toStr(bodyHtml).trim()) {
            alert(t('لا يوجد محتوى للطباعة.', 'Nothing to print.'));
            return;
        }
        const title = {
            ar: `طلب صيانة ${req.requestNo} — ${req.building} / ${req.unit}`,
            en: `Maintenance request ${req.requestNo} — ${req.building} / ${req.unit}`
        };
        closeMaintenancePrintModal();
        printWithSiteStandard(title, bodyHtml, { extraStyles: getContractAttachmentsPrintStylesCss() });
    }

    function getMaintenanceCatalogSubtype(catKey, subKey) {
        const reg = loadMaintenanceRegistry();
        const cat = reg.priceCatalog.find((c) => c.categoryKey === catKey);
        if (!cat) return null;
        const key = toStr(subKey);
        if (!key) return null;
        return (cat.subtypes || []).find((s) => toStr(s.key) === key) || null;
    }

    function resolveMaintenanceLineSelectionFromForm() {
        const host = document.getElementById('maintenanceRequestBody');
        const catEl = host?.querySelector('#mntLineCategory');
        const subEl = host?.querySelector('#mntLineSubtype');
        const catKey = toStr(catEl?.value || _maintenanceFormState.lineCategory).trim();
        let subKey = toStr(subEl?.value || _maintenanceFormState.lineSubtype).trim();
        const reg = loadMaintenanceRegistry();
        const cat = reg.priceCatalog.find((c) => c.categoryKey === catKey) || null;
        let sub = cat ? getMaintenanceCatalogSubtype(catKey, subKey) : null;
        if (!sub && cat && subEl && subEl.selectedIndex >= 0) {
            const byIndex = (cat.subtypes || [])[subEl.selectedIndex];
            if (byIndex) {
                sub = byIndex;
                subKey = toStr(byIndex.key);
            }
        }
        if (!sub && cat && subEl) {
            const label = toStr(subEl.options[subEl.selectedIndex]?.textContent).trim();
            if (label) {
                sub = (cat.subtypes || []).find((s) =>
                    maintenanceLocalizedItem(s) === label || toStr(s.labelAr) === label || toStr(s.labelEn) === label
                ) || null;
                if (sub) subKey = toStr(sub.key);
            }
        }
        return { catKey, subKey, cat, sub };
    }

    function getMaintenanceRequestsForUnit(building, unit) {
        const uk = maintenanceUnitKey(building, unit);
        return loadMaintenanceRegistry().requests.filter((r) => r.unitKey === uk);
    }

    function isMaintenanceSystemAdmin() {
        const u = getLoggedInUser();
        return !!(u && toStr(u.role) === 'system_admin');
    }

    function isMaintenanceAssignee(req) {
        if (!req) return false;
        const actor = getCurrentActorLedgerRecord();
        if (!toStr(actor.staffUserId)) return false;
        return toStr(req.assigneeUserId) === toStr(actor.staffUserId);
    }

    function resolveMaintenanceUnitContext(building, unit) {
        const unitRow = getUnitRecordByBuildingUnit(building, unit);
        const payload = getSavedContractPayloadForUnit({ building, unit });
        const tenantFromPayload = payload
            ? toStr(payload.tenantNameAr || payload.tenantNameEn || payload.tenantName || payload.tenant).trim()
            : '';
        const tenantFromUnit = toStr(unitRow?.tenant || unitRow?.tenantEn).trim();
        const agreementNo = payload ? toStr(payload.agreementNo) : toStr(unitRow?.agreementNo);
        const isRented = !!(unitRow && toStr(unitRow.status) === 'Rented') || !!(tenantFromPayload || tenantFromUnit || agreementNo);
        const tenantName = tenantFromPayload || tenantFromUnit || '';
        return {
            isRented,
            unitStatus: isRented ? 'rented' : 'vacant',
            tenant: tenantName,
            tenantDisplay: isRented ? (tenantName || t('مستأجر (بدون اسم)', 'Tenant (no name)')) : t('شاغر', 'Vacant'),
            agreementNo
        };
    }

    function getMaintenanceOverdueRentTotal(building, unit) {
        return parseFloat(getAccountingChequesForUnit(building, unit)
            .filter((c) => isAccountingChequeOverdue(c))
            .reduce((s, c) => s + Math.max(0, (parseFloat(c.amount) || 0) - (parseFloat(c.paidAmount) || 0)), 0)
            .toFixed(3));
    }

    function getMaintenanceClaimsTotal(building, unit) {
        return parseFloat(getAccountingChequesForUnit(building, unit)
            .filter((c) => {
                const st = toStr(c.status);
                return st === 'bounced' || st === 'returned';
            })
            .reduce((s, c) => s + (parseFloat(c.amount) || 0), 0)
            .toFixed(3));
    }

    function gatherMaintenancePreviousMaintenance(building, unit, excludeId) {
        return getMaintenanceRequestsForUnit(building, unit)
            .filter((r) => !excludeId || r.id !== excludeId)
            .map((r) => ({
                id: r.id,
                requestNo: r.requestNo,
                date: toStr(r.completedAt || r.createdAt).slice(0, 10),
                amount: maintenanceRequestTotal(r),
                status: r.status,
                linked: !!r.linkedToAccounting
            }))
            .sort((a, b) => toStr(b.date).localeCompare(toStr(a.date)));
    }

    function gatherMaintenanceTenantArrears(building, unit) {
        const ctx = resolveMaintenanceUnitContext(building, unit);
        if (!ctx.isRented) {
            return {
                hasArrears: false,
                hasMaintenanceHistory: false,
                lines: [],
                total: 0,
                maintenanceHistory: [],
                maintenanceHistoryTotal: 0,
                ctx
            };
        }
        const overdueRent = getMaintenanceOverdueRentTotal(building, unit);
        const claims = getMaintenanceClaimsTotal(building, unit);
        const lines = [];
        let total = 0;
        const pushLine = (label, amount) => {
            const amt = parseFloat(amount) || 0;
            if (amt <= 0) return;
            lines.push({ label, amount: amt });
            total += amt;
        };
        pushLine(t('شيكات إيجار متأخرة', 'Overdue rent cheques'), overdueRent);
        pushLine(t('شيكات مرتجعة', 'Bounced cheques'), claims);
        const maintenanceHistory = gatherMaintenancePreviousMaintenance(building, unit);
        const maintenanceHistoryTotal = parseFloat(maintenanceHistory.reduce((s, r) => s + r.amount, 0).toFixed(3));
        return {
            hasArrears: total > 0,
            hasMaintenanceHistory: maintenanceHistory.length > 0,
            lines,
            total: parseFloat(total.toFixed(3)),
            maintenanceHistory,
            maintenanceHistoryTotal,
            ctx
        };
    }

    function renderMaintenanceArrearsPanel(building, unit) {
        const arrears = gatherMaintenanceTenantArrears(building, unit);
        if (!building || !unit) return '';
        const bEsc = escHtml(building).replace(/'/g, "\\'");
        const uEsc = escHtml(unit).replace(/'/g, "\\'");
        if (!arrears.ctx.isRented) {
            return `<div style="margin:10px 0;padding:10px 12px;border-radius:8px;background:#f5f5f5;border:1px solid #e0e0e0;font-size:12px">
                <strong>${t('حالة الوحدة', 'Unit status')}:</strong> ${t('شاغر', 'Vacant')}
            </div>`;
        }
        const listPad = appUiLanguage === 'en' ? 'padding-left:18px' : 'padding-right:18px';
        let html = `<div style="margin:10px 0;padding:10px 12px;border-radius:8px;background:#f8fafc;border:1px solid #e0e6ed;font-size:12px">
            <strong>${t('حالة الوحدة', 'Unit status')}:</strong> ${escHtml(arrears.ctx.tenantDisplay)}`;
        if (arrears.hasArrears) {
            const linesHtml = arrears.lines.map((ln) =>
                `<li>${escHtml(ln.label)}: <strong>${escHtml(summaryAmtOm(ln.amount))}</strong></li>`
            ).join('');
            html += `
            <div style="margin-top:8px;padding:8px 10px;border-radius:6px;background:#fff8e1;border:1px solid #ffe082">
                <strong style="color:#6d4c00">${t('تنبيه: شيكات متأخرة على المستأجر', 'Alert: tenant has overdue cheques')}</strong>
                <ul style="margin:8px 0 4px;${listPad}">${linesHtml}</ul>
                <div><strong>${t('إجمالي المتأخرات', 'Overdue total')}:</strong> ${escHtml(summaryAmtOm(arrears.total))}</div>
                <div style="margin-top:8px;padding:8px 10px;border-radius:6px;background:#fce4ec;border:1px solid #f48fb1;color:#880e4f;font-weight:700">
                    ${t('طلب الصيانة يحتاج موافقة الإدارة بسبب الشيكات المتأخرة فقط (وليس الشيكات الآجلة).', 'Maintenance requires management approval due to overdue cheques only (not future-dated cheques).')}
                </div>
            </div>`;
        } else {
            html += ` — ${t('لا توجد شيكات إيجار متأخرة', 'No overdue rent cheques')}`;
        }
        if (arrears.hasMaintenanceHistory) {
            html += `
            <div style="margin-top:8px;padding:8px 10px;border-radius:6px;background:#eef5ff;border:1px solid #c5d9f2">
                <strong>${t('ملاحظة: طلبات صيانة سابقة', 'Note: previous maintenance requests')}</strong>
                <div style="margin-top:4px">${t('يوجد', 'There are')} <strong>${arrears.maintenanceHistory.length}</strong> ${t('طلب/طلبات بإجمالي', 'request(s) totaling')} <strong>${escHtml(summaryAmtOm(arrears.maintenanceHistoryTotal))}</strong></div>
                <button type="button" class="btn-outline mini-btn" style="margin-top:8px" onclick="openMaintenanceUnitHistoryModal('${bEsc}','${uEsc}')">${t('استعراض الطلبات السابقة', 'View previous requests')}</button>
            </div>`;
        }
        html += '</div>';
        return html;
    }

    function openMaintenanceUnitHistoryModal(building, unit) {
        const b = toStr(building).trim();
        const u = toStr(unit).trim();
        if (!b || !u) return;
        const modal = document.getElementById('maintenanceUnitHistoryModal');
        const body = document.getElementById('maintenanceUnitHistoryBody');
        const title = document.getElementById('maintenanceUnitHistoryTitle');
        if (!modal || !body) return;
        const rows = gatherMaintenancePreviousMaintenance(b, u);
        if (title) title.textContent = `${t('طلبات الصيانة السابقة', 'Previous maintenance requests')} — ${b} / ${u}`;
        body.innerHTML = rows.length
            ? `<table class="data-table" style="width:100%;font-size:12px">
                <thead><tr><th>${t('رقم الطلب', 'Request')}</th><th>${t('التاريخ', 'Date')}</th><th>${t('المبلغ', 'Amount')}</th><th>${t('الحالة', 'Status')}</th><th></th></tr></thead>
                <tbody>${rows.map((r) => `<tr>
                    <td>${escHtml(r.requestNo)}</td><td>${escHtml(r.date || '—')}</td>
                    <td>${escHtml(summaryAmtOm(r.amount))}</td>
                    <td>${maintenanceStatusChip(r.status, r.linked)}</td>
                    <td><button type="button" class="btn-outline mini-btn" onclick="openMaintenanceDetailModal('${escHtml(r.id)}')">${t('تفاصيل', 'Details')}</button></td>
                </tr>`).join('')}</tbody>
            </table>`
            : `<p style="color:#666;margin:0">${t('لا توجد طلبات صيانة سابقة.', 'No previous maintenance requests.')}</p>`;
        modal.classList.add('open');
    }

    function closeMaintenanceUnitHistoryModal() {
        document.getElementById('maintenanceUnitHistoryModal')?.classList.remove('open');
    }

    function resolveMaintenanceTenantContact(building, unit) {
        const payload = getSavedContractPayloadForUnit({ building, unit }) || {};
        const unitRow = getUnitRecordByBuildingUnit(building, unit) || {};
        return {
            mobile: toStr(payload.tenantMobile || unitRow.mobile || unitRow.contactNo).trim(),
            email: toStr(payload.tenantEmail || payload.email || '').trim()
        };
    }

    function normalizeWhatsAppPhone(mobile) {
        const d = toStr(mobile).replace(/\D/g, '');
        if (!d) return '';
        if (d.startsWith('968')) return d;
        if (d.length === 8) return `968${d}`;
        return d;
    }

    function getMaintenanceAccountingInvoice(req) {
        if (!req) return null;
        const areg = loadAccountingRegistry();
        if (req.accountingInvoiceId) {
            const byId = areg.invoices.find((i) => i.id === req.accountingInvoiceId);
            if (byId) return byId;
        }
        const entry = resolveMaintenanceAccountingEntry(req);
        if (!entry) return null;
        return findAccountingInvoiceForEntry(entry.id);
    }

    function findAccountingInvoiceForEntry(entryId) {
        if (!entryId) return null;
        const areg = loadAccountingRegistry();
        return areg.invoices.find((i) => Array.isArray(i.entryIds) && i.entryIds.includes(entryId)) || null;
    }

    function resolveMaintenanceAccountingEntry(req) {
        if (!req) return null;
        const areg = loadAccountingRegistry();
        if (req.accountingEntryId) {
            const byId = areg.entries.find((e) => e.id === req.accountingEntryId);
            if (byId) return byId;
        }
        const linkedKey = `maintenance|${req.id}`;
        return areg.entries.find((e) => e.linkedKey === linkedKey) || null;
    }

    function parseMaintenanceAmountInput(raw) {
        const s = toStr(raw).trim().replace(/,/g, '.');
        const amt = parseFloat(s);
        return Number.isNaN(amt) ? NaN : amt;
    }

    function onMaintenanceAcctAmountInput(requestId, value) {
        _maintenanceAcctDraftAmounts[toStr(requestId)] = toStr(value);
    }

    function createMaintenanceInvoiceForEntry(entry, req) {
        if (!entry) return null;
        const areg = loadAccountingRegistry();
        const existing = findAccountingInvoiceForEntry(entry.id);
        if (existing) return existing;
        const tenantCtx = req ? resolveMaintenanceUnitContext(req.building, req.unit) : null;
        const tenantName = req ? resolveMaintenanceInvoiceTenant(req) : toStr(entry.tenant);
        const agreementNo = req ? toStr(req.agreementNo || tenantCtx?.agreementNo) : toStr(entry.agreementNo);
        const total = parseFloat(entry.amount) || 0;
        const inv = {
            id: newAccountingId('inv'),
            entryIds: [entry.id],
            unitKey: entry.unitKey,
            building: entry.building,
            unit: entry.unit,
            agreementNo,
            tenant: tenantName !== '—' ? tenantName : '',
            maintenanceRequestId: req?.id || entry.maintenanceRequestId || '',
            maintenanceRequestNo: req?.requestNo || entry.sourceKey || '',
            total: parseFloat(total.toFixed(3)),
            status: 'draft',
            createdAt: new Date().toISOString(),
            sourceKind: 'maintenance'
        };
        areg.invoices.push(inv);
        saveAccountingRegistry(areg);
        return inv;
    }

    function resolveMaintenanceInvoiceTenant(req) {
        if (!req) return '—';
        const ctx = resolveMaintenanceUnitContext(req.building, req.unit);
        return toStr(req.tenantDisplay || req.tenant || ctx.tenantDisplay || ctx.tenant).trim() || '—';
    }

    function buildMaintenanceInvoicePrintHtml(req, inv) {
        const tenantName = resolveMaintenanceInvoiceTenant(req);
        const unitCtx = resolveMaintenanceUnitContext(req.building, req.unit);
        const agreementNo = toStr(req.agreementNo || unitCtx.agreementNo) || '—';
        const invoiceNo = inv?.invoiceNo || inv?.id || '—';
        const invoiceDate = inv?.approvedAt || inv?.createdAt || new Date().toISOString();
        const dateStr = toStr(invoiceDate).slice(0, 10);
        const items = Array.isArray(req.items) ? req.items : [];
        const itemsRows = items.length
            ? items.map((ln, i) => `<tr>
                <td class="print-num">${i + 1}</td>
                <td>${escHtml(maintenanceLocalizedText(ln.categoryAr || ln.categoryKey, ln.categoryEn || ln.categoryKey))}</td>
                <td>${escHtml(maintenanceLocalizedItem(ln))}</td>
                <td>${escHtml(ln.qty || 1)}</td>
                <td>${escHtml(summaryAmtOm(ln.materialsCost))}</td>
                <td>${escHtml(summaryAmtOm(ln.laborCost))}</td>
                <td>${escHtml(summaryAmtOm(maintenanceLineTotal(ln)))}</td>
            </tr>`).join('')
            : `<tr><td colspan="7">${t('لا توجد بنود صيانة مسجلة', 'No maintenance items recorded')}</td></tr>`;
        const notesBlock = req.notes
            ? `<p class="property-report-meta"><strong>${t('ملاحظات الطلب', 'Request notes')}:</strong> ${escHtml(req.notes)}</p>`
            : '';
        return `
            <div class="section-header property-section-h">${t('بيانات الفاتورة / Invoice details', 'Invoice details / بيانات الفاتورة')}</div>
            <table class="info-table property-report-table print-zebra-cells" style="margin-bottom:14px">
                <tbody>
                    <tr>
                        <th style="width:22%">${t('رقم الفاتورة / Invoice no.', 'Invoice no. / رقم الفاتورة')}</th>
                        <td style="width:28%">${escHtml(invoiceNo)}</td>
                        <th style="width:22%">${t('تاريخ الفاتورة / Invoice date', 'Invoice date / تاريخ الفاتورة')}</th>
                        <td style="width:28%">${escHtml(dateStr)}</td>
                    </tr>
                    <tr>
                        <th>${t('رقم طلب الصيانة / Maint. request', 'Maint. request / رقم طلب الصيانة')}</th>
                        <td>${escHtml(req.requestNo)}</td>
                        <th>${t('رقم العقد / Contract no.', 'Contract no. / رقم العقد')}</th>
                        <td>${escHtml(agreementNo)}</td>
                    </tr>
                    <tr>
                        <th>${t('العقار / Property', 'Property / العقار')}</th>
                        <td>${escHtml(req.building)} — ${escHtml(req.unit)}</td>
                        <th>${t('المستأجر / Tenant', 'Tenant / المستأجر')}</th>
                        <td>${escHtml(tenantName)}</td>
                    </tr>
                </tbody>
            </table>
            <div class="section-header property-section-h">${t('بنود الصيانة / Maintenance items', 'Maintenance items / بنود الصيانة')}</div>
            <table class="info-table property-report-table print-zebra">
                <thead>
                    <tr>
                        <th class="print-num">#</th>
                        <th>${t('الفئة / Category', 'Category / الفئة')}</th>
                        <th>${t('نوع الصيانة / Type', 'Maintenance type / نوع الصيانة')}</th>
                        <th>${t('العدد / Qty', 'Qty / العدد')}</th>
                        <th>${t('مواد / Materials', 'Materials / مواد')}</th>
                        <th>${t('عامل / Labor', 'Labor / عامل')}</th>
                        <th>${t('الإجمالي / Total', 'Total / الإجمالي')}</th>
                    </tr>
                </thead>
                <tbody>${itemsRows}</tbody>
            </table>
            ${renderMaintenanceInvoiceAmountSummaryHtml(req, inv)}
            ${notesBlock}
            ${inv?.approvedAt ? `<p class="property-report-meta" style="margin-top:12px">${t('معتمدة في / Approved at', 'Approved at / معتمدة في')}: ${escHtml(toStr(inv.approvedAt).slice(0, 16).replace('T', ' '))} — ${escHtml(inv.approvedBy || '')}</p>` : ''}`;
    }

    function printMaintenanceInvoiceDocument(req, inv) {
        if (!req || !inv) return;
        printWithSiteStandard(
            { ar: 'فاتورة صيانة', en: 'Maintenance Invoice' },
            buildMaintenanceInvoicePrintHtml(req, inv),
            {}
        );
        const reg = loadAccountingRegistry();
        const invRow = reg.invoices.find((i) => i.id === inv.id);
        if (invRow) {
            invRow.status = 'printed';
            invRow.printedAt = new Date().toISOString();
            saveAccountingRegistry(reg);
        }
        renderAccountingWorkspace();
    }

    function buildMaintenanceInvoiceShareText(req) {
        const inv = getMaintenanceAccountingInvoice(req);
        if (!inv) return '';
        const total = maintenanceRequestTotal(req);
        const tenantName = resolveMaintenanceInvoiceTenant(req);
        const b = maintenanceAmountBreakdown(req, inv);
        const itemsLines = (req.items || []).map((ln, i) =>
            `${i + 1}. ${maintenanceLocalizedText(ln.categoryAr || ln.categoryKey, ln.categoryEn || ln.categoryKey)} — ${maintenanceLocalizedItem(ln)}: ${summaryAmtOm(maintenanceLineTotal(ln))}`
        ).join('\n');
        const amountSummary = b.hasAccountantAdjustment
            ? `\n${t('قيمة الفاتورة', 'Invoice amount')}: ${summaryAmtOm(b.originalTotal)}\n${t('تم تعديل القيمة من قبل المحاسب إلى', 'Adjusted by accountant to')}: ${summaryAmtOm(b.finalTotal)}${b.hasDiscount ? `\n${t('قيمة الخصم', 'Discount amount')}: ${summaryAmtOm(b.discountAmount)}` : ''}${b.hasIncrease ? `\n${t('قيمة الزيادة', 'Increase amount')}: ${summaryAmtOm(b.increaseAmount)}` : ''}\n${t('الفاتورة الكاملة', 'Full invoice total')}: ${summaryAmtOm(b.finalTotal)}`
            : `\n${t('الفاتورة الكاملة', 'Full invoice total')}: ${summaryAmtOm(total)}`;
        return t(
            `فاتورة صيانة ${inv.invoiceNo || inv.id}\nالمستأجر: ${tenantName}\nالعقار: ${req.building} — ${req.unit}\nطلب الصيانة: ${req.requestNo}\n${itemsLines ? itemsLines + '\n' : ''}${amountSummary}`,
            `Maintenance invoice ${inv.invoiceNo || inv.id}\nTenant: ${tenantName}\nProperty: ${req.building} — ${req.unit}\nMaintenance request: ${req.requestNo}\n${itemsLines ? itemsLines + '\n' : ''}${amountSummary}`
        );
    }

    function printMaintenanceInvoiceByRequest(requestId) {
        const req = loadMaintenanceRegistry().requests.find((r) => r.id === requestId);
        if (!req) return;
        const inv = getMaintenanceAccountingInvoice(req);
        if (!inv) {
            alert(t('لا توجد فاتورة مرتبطة بهذا الطلب.', 'No invoice linked to this request.'));
            return;
        }
        printMaintenanceInvoiceDocument(req, inv);
    }

    function shareMaintenanceInvoiceWhatsApp(requestId) {
        const req = loadMaintenanceRegistry().requests.find((r) => r.id === requestId);
        if (!req) return;
        const contact = resolveMaintenanceTenantContact(req.building, req.unit);
        const phone = normalizeWhatsAppPhone(contact.mobile);
        if (!phone) {
            alert(t('لا يوجد رقم واتساب مسجل للمستأجر.', 'No WhatsApp number on file for tenant.'));
            return;
        }
        const text = buildMaintenanceInvoiceShareText(req);
        window.open(`https://wa.me/${phone}?text=${encodeURIComponent(text)}`, '_blank');
    }

    function shareMaintenanceInvoiceEmail(requestId) {
        const req = loadMaintenanceRegistry().requests.find((r) => r.id === requestId);
        if (!req) return;
        const contact = resolveMaintenanceTenantContact(req.building, req.unit);
        if (!contact.email) {
            alert(t('لا يوجد بريد إلكتروني مسجل للمستأجر.', 'No email on file for tenant.'));
            return;
        }
        const inv = getMaintenanceAccountingInvoice(req);
        const subject = t(`فاتورة صيانة ${inv?.invoiceNo || req.requestNo}`, `Maintenance invoice ${inv?.invoiceNo || req.requestNo}`);
        const body = buildMaintenanceInvoiceShareText(req);
        window.location.href = `mailto:${encodeURIComponent(contact.email)}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
    }

    function resolveMaintenanceTenantForUnit(building, unit) {
        const ctx = resolveMaintenanceUnitContext(building, unit);
        return {
            tenant: ctx.tenant,
            agreementNo: ctx.agreementNo,
            unitStatus: ctx.unitStatus,
            tenantDisplay: ctx.tenantDisplay,
            isRented: ctx.isRented
        };
    }

    function maintenanceMatchesFilter(req) {
        const st = _maintenanceUiState;
        if (toStr(st.building).trim() && toStr(req.building) !== toStr(st.building).trim()) return false;
        if (toStr(st.unit).trim() && toStr(req.unit) !== toStr(st.unit).trim()) return false;
        if (toStr(st.status).trim() && toStr(req.status) !== toStr(st.status).trim()) return false;
        if (toStr(st.tenant).trim() && !toStr(req.tenant).toLowerCase().includes(toStr(st.tenant).toLowerCase())) return false;
        const q = toStr(st.search).trim().toLowerCase();
        if (q) {
            const hay = [req.building, req.unit, req.tenant, req.requestNo, req.notes, req.agreementNo]
                .map((v) => toStr(v).toLowerCase())
                .join(' ');
            if (!hay.includes(q)) return false;
        }
        return true;
    }

    function saveMaintenanceRequestFromForm() {
        if (!assertPermissionOrAlert('manage_maintenance', 'لا تملك صلاحية الصيانة.', 'No maintenance permission.')) return;
        const building = toStr(document.getElementById('mntFormBuilding')?.value || _maintenanceFormState.building).trim();
        const unit = toStr(document.getElementById('mntFormUnit')?.value || _maintenanceFormState.unit).trim();
        const notes = toStr(document.getElementById('mntFormNotes')?.value).trim();
        if (!building || !unit) {
            alert(t('اختر المبنى والوحدة.', 'Select building and unit.'));
            return;
        }
        if (!_maintenanceFormLines.length) {
            alert(t('أضف بند صيانة واحداً على الأقل.', 'Add at least one maintenance item.'));
            return;
        }
        const reg = loadMaintenanceRegistry();
        const tenantInfo = resolveMaintenanceTenantForUnit(building, unit);
        const arrears = gatherMaintenanceTenantArrears(building, unit);
        const needsApproval = arrears.hasArrears;
        const actor = getCurrentActorLedgerRecord();
        const items = _maintenanceFormLines.map((ln) => ({ ...ln }));
        const estimatedTotal = parseFloat(items.reduce((s, it) => s + maintenanceLineTotal(it), 0).toFixed(3));
        const primaryAssignee = items.find((it) => toStr(it.assigneeUserId)) || null;
        const req = {
            id: newMaintenanceId(),
            requestNo: nextMaintenanceRequestNo(reg),
            unitKey: maintenanceUnitKey(building, unit),
            building,
            unit,
            tenant: tenantInfo.tenant,
            tenantDisplay: tenantInfo.tenantDisplay,
            unitStatus: tenantInfo.unitStatus,
            isRented: !!tenantInfo.isRented,
            agreementNo: tenantInfo.agreementNo,
            tenantKey: accountingTenantKey(tenantInfo.tenant, tenantInfo.agreementNo),
            status: needsApproval ? 'pending_approval' : 'pending',
            statusNote: needsApproval ? t('بانتظار موافقة الإدارة بسبب شيكات إيجار متأخرة', 'Awaiting management approval due to overdue rent cheques') : '',
            requiresManagementApproval: needsApproval,
            arrearsTotal: needsApproval ? arrears.total : 0,
            arrearsLines: needsApproval ? arrears.lines : [],
            approvedAt: null,
            approvedBy: '',
            items,
            estimatedTotal,
            finalTotal: null,
            accountantAdjustedTotal: null,
            notes,
            assigneeUserId: primaryAssignee ? toStr(primaryAssignee.assigneeUserId) : '',
            assigneeName: primaryAssignee ? toStr(primaryAssignee.assigneeName) : '',
            returnRequested: false,
            returnRequestNote: '',
            returnRequestedAt: null,
            returnRequestedBy: '',
            completionNote: '',
            completionAttachments: [],
            followUpActive: false,
            followUpAt: null,
            followUpBy: '',
            followUpNote: '',
            linkedToAccounting: false,
            accountingEntryId: null,
            accountingInvoiceId: null,
            createdAt: new Date().toISOString(),
            createdBy: actor.staffName,
            createdByUserId: actor.staffUserId,
            completedAt: null,
            completedBy: null,
            events: [{
                at: new Date().toISOString(),
                type: 'created',
                staffName: actor.staffName,
                note: needsApproval
                    ? t('إنشاء طلب صيانة — بانتظار موافقة الإدارة', 'Maintenance request created — awaiting management approval')
                    : t('إنشاء طلب صيانة', 'Maintenance request created')
            }]
        };
        reg.requests.push(req);
        saveMaintenanceRegistry(reg);
        recordSystemActivity({
            actionKey: 'maintenance_request_created',
            actionAr: needsApproval ? 'طلب صيانة بانتظار موافقة الإدارة' : 'طلب صيانة جديد',
            actionEn: needsApproval ? 'Maintenance request awaiting approval' : 'New maintenance request',
            building,
            unit,
            ref: req.requestNo,
            note: summaryAmtOm(estimatedTotal)
        });
        _maintenanceFormLines = [];
        closeMaintenanceRequestModal();
        renderMaintenanceWorkspace();
        if (needsApproval) {
            alert(t('تم حفظ الطلب. حالته: مطلوب موافقة الإدارة. لن يظهر للموظف المسؤول عن التنفيذ حتى تتم الموافقة.', 'Request saved. Status: management approval required. It will not appear for the assigned staff until approved.'));
        }
    }

    function setMaintenanceRequestStatus(requestId, status, note, options) {
        if (!assertPermissionOrAlert('manage_maintenance', 'لا تملك صلاحية الصيانة.', 'No maintenance permission.')) return;
        const reg = loadMaintenanceRegistry();
        const req = reg.requests.find((r) => r.id === requestId);
        if (!req) return;
        const opts = options || {};
        const noteText = toStr(note).trim();
        const actor = getCurrentActorLedgerRecord();

        if (opts.action === 'approve') {
            if (!isMaintenanceSystemAdmin()) {
                alert(t('موافقة الإدارة متاحة لمدير النظام فقط.', 'Management approval is for system admin only.'));
                return;
            }
            if (toStr(req.status) !== 'pending_approval') {
                alert(t('هذا الطلب ليس بانتظار موافقة الإدارة.', 'This request is not awaiting management approval.'));
                return;
            }
            req.status = 'pending';
            req.approvedAt = new Date().toISOString();
            req.approvedBy = actor.staffName;
            req.statusNote = noteText || t('تمت موافقة الإدارة على الطلب', 'Management approved the request');
            if (!Array.isArray(req.events)) req.events = [];
            req.events.push({
                at: new Date().toISOString(),
                type: 'approved',
                staffName: actor.staffName,
                note: req.statusNote
            });
            saveMaintenanceRegistry(reg);
            recordSystemActivity({
                actionKey: 'maintenance_approved',
                actionAr: 'موافقة إدارة على طلب صيانة',
                actionEn: 'Management approved maintenance request',
                building: req.building,
                unit: req.unit,
                ref: req.requestNo,
                note: req.statusNote
            });
            renderMaintenanceWorkspace();
            try { openMaintenanceDetailModal(requestId); } catch (_eAppr) {}
            return;
        }

        if (opts.action === 'request_return') {
            if (!isMaintenanceAssignee(req) && !isMaintenanceSystemAdmin()) {
                alert(t('هذا الإجراء للموظف المسؤول عن التنفيذ.', 'This action is for the assigned staff member.'));
                return;
            }
            if (!noteText) {
                alert(t('الملاحظة إلزامية لطلب الاسترجاع.', 'A note is required for return request.'));
                return;
            }
            req.returnRequested = true;
            req.returnRequestNote = noteText;
            req.returnRequestedAt = new Date().toISOString();
            req.returnRequestedBy = actor.staffName;
            if (!Array.isArray(req.events)) req.events = [];
            req.events.push({
                at: new Date().toISOString(),
                type: 'return_requested',
                staffName: actor.staffName,
                note: noteText
            });
            saveMaintenanceRegistry(reg);
            renderMaintenanceWorkspace();
            try { openMaintenanceDetailModal(requestId); } catch (_eRetReq) {}
            return;
        }

        if (opts.action === 'return_to_assignee') {
            if (!isMaintenanceSystemAdmin()) {
                alert(t('إرجاع الطلب للموظف متاح لمدير النظام فقط.', 'Return to staff is for system admin only.'));
                return;
            }
            if (req.linkedToAccounting) {
                alert(t('لا يمكن إرجاع الطلب للموظف بعد ربطه بالمحاسبة. استخدم «متابعة البلاغ» إذا كانت المشكلة ما زالت قائمة.', 'Cannot return to staff after linking to accounting. Use «Follow up case» if the issue persists.'));
                return;
            }
            if (!noteText) {
                alert(t('الملاحظة إلزامية عند إرجاع الطلب.', 'A note is required when returning the request.'));
                return;
            }
            if (req.status === 'completed') {
                req.status = 'in_progress';
            } else if (req.status === 'in_progress' || req.status === 'cancelled') {
                req.status = 'pending';
            } else {
                alert(t('لا يمكن إرجاع هذا الطلب في حالته الحالية.', 'Cannot return this request in its current state.'));
                return;
            }
            req.completedAt = null;
            req.completedBy = null;
            req.finalTotal = null;
            req.returnRequested = false;
            req.returnRequestNote = '';
            req.returnRequestedAt = null;
            req.returnRequestedBy = '';
            req.statusNote = noteText;
            if (!Array.isArray(req.events)) req.events = [];
            req.events.push({
                at: new Date().toISOString(),
                type: 'returned_to_assignee',
                staffName: actor.staffName,
                note: noteText
            });
            saveMaintenanceRegistry(reg);
            recordSystemActivity({
                actionKey: 'maintenance_returned_to_assignee',
                actionAr: 'إرجاع طلب صيانة للموظف',
                actionEn: 'Maintenance request returned to staff',
                building: req.building,
                unit: req.unit,
                ref: req.requestNo,
                note: noteText
            });
            renderMaintenanceWorkspace();
            try { openMaintenanceDetailModal(requestId); } catch (_eRet) {}
            return;
        }

        if (opts.action === 'follow_up') {
            if (!isMaintenanceSystemAdmin()) {
                alert(t('متابعة البلاغ متاحة لمدير النظام فقط.', 'Follow-up is for system admin only.'));
                return;
            }
            if (toStr(req.status) !== 'completed') {
                alert(t('متابعة البلاغ متاحة للطلبات المكتملة فقط.', 'Follow-up is only for completed requests.'));
                return;
            }
            if (!noteText) {
                alert(t('الملاحظة إلزامية عند تحويل البلاغ للمتابعة.', 'A note is required when assigning follow-up.'));
                return;
            }
            req.status = 'in_progress';
            req.statusNote = noteText;
            req.followUpActive = true;
            req.followUpAt = new Date().toISOString();
            req.followUpBy = actor.staffName;
            req.followUpNote = noteText;
            req.returnRequested = false;
            req.returnRequestNote = '';
            req.returnRequestedAt = null;
            req.returnRequestedBy = '';
            if (!Array.isArray(req.events)) req.events = [];
            req.events.push({
                at: new Date().toISOString(),
                type: 'follow_up_assigned',
                staffName: actor.staffName,
                note: noteText
            });
            saveMaintenanceRegistry(reg);
            recordSystemActivity({
                actionKey: 'maintenance_follow_up',
                actionAr: 'تحويل بلاغ صيانة للمتابعة',
                actionEn: 'Maintenance case assigned for follow-up',
                building: req.building,
                unit: req.unit,
                ref: req.requestNo,
                note: noteText
            });
            createMaintenanceExecutionTask(req, noteText);
            renderMaintenanceWorkspace();
            try { openMaintenanceDetailModal(requestId); } catch (_eFu) {}
            return;
        }

        if (!MAINTENANCE_STATUSES.includes(status)) return;
        if (['in_progress', 'completed'].includes(status) && !noteText) {
            alert(t('الملاحظة إلزامية قبل تغيير الحالة.', 'A note is required before changing status.'));
            return;
        }
        req.status = status;
        req.statusNote = noteText || maintenanceStatusLabel(status);
        if (status === 'completed') {
            req.completedAt = new Date().toISOString();
            req.completedBy = actor.staffName;
            req.finalTotal = maintenanceItemsSubtotal(req);
            req.completionNote = noteText;
            req.followUpActive = false;
            const newAttachments = Array.isArray(opts.completionAttachments) ? opts.completionAttachments.filter(Boolean) : [];
            if (newAttachments.length) {
                if (!Array.isArray(req.completionAttachments)) req.completionAttachments = [];
                req.completionAttachments.push(...newAttachments.map((att) => ({
                    ...att,
                    uploadedAt: new Date().toISOString(),
                    uploadedBy: actor.staffName
                })));
            }
        }
        if (status === 'in_progress') {
            req.returnRequested = false;
            req.returnRequestNote = '';
            req.returnRequestedAt = null;
            req.returnRequestedBy = '';
        }
        if (!Array.isArray(req.events)) req.events = [];
        req.events.push({
            at: new Date().toISOString(),
            type: status,
            staffName: actor.staffName,
            note: req.statusNote
        });
        saveMaintenanceRegistry(reg);
        recordSystemActivity({
            actionKey: 'maintenance_status_' + status,
            actionAr: 'تحديث صيانة',
            actionEn: 'Maintenance update',
            building: req.building,
            unit: req.unit,
            ref: req.requestNo,
            note: req.statusNote
        });
        if (status === 'in_progress') {
            createMaintenanceExecutionTask(req, noteText);
        }
        renderMaintenanceWorkspace();
        try { openMaintenanceDetailModal(requestId); } catch (_eD) {}
    }

    function openMaintenanceStatusActionModal(requestId, action) {
        if (!assertPermissionOrAlert('manage_maintenance', 'لا تملك صلاحية الصيانة.', 'No maintenance permission.')) return;
        const reg = loadMaintenanceRegistry();
        const req = reg.requests.find((r) => r.id === requestId);
        if (!req) return;
        if (action === 'return_to_assignee' && !isMaintenanceSystemAdmin()) {
            alert(t('إرجاع الطلب للموظف متاح لمدير النظام فقط.', 'Return to staff is for system admin only.'));
            return;
        }
        if (action === 'return_to_assignee' && req.linkedToAccounting) {
            alert(t('لا يمكن إرجاع الطلب للموظف بعد ربطه بالمحاسبة. استخدم «متابعة البلاغ» إذا كانت المشكلة ما زالت قائمة.', 'Cannot return to staff after linking to accounting. Use «Follow up case» if the issue persists.'));
            return;
        }
        if (action === 'follow_up' && !isMaintenanceSystemAdmin()) {
            alert(t('متابعة البلاغ متاحة لمدير النظام فقط.', 'Follow-up is for system admin only.'));
            return;
        }
        if (action === 'follow_up' && toStr(req.status) !== 'completed') {
            alert(t('متابعة البلاغ متاحة للطلبات المكتملة فقط.', 'Follow-up is only for completed requests.'));
            return;
        }
        if (action === 'approve' && !isMaintenanceSystemAdmin()) {
            alert(t('موافقة الإدارة متاحة لمدير النظام فقط.', 'Management approval is for system admin only.'));
            return;
        }
        if (action === 'request_return' && !isMaintenanceAssignee(req) && !isMaintenanceSystemAdmin()) {
            alert(t('هذا الإجراء للموظف المسؤول عن التنفيذ.', 'This action is for the assigned staff member.'));
            return;
        }
        const titleMap = {
            approve: t('موافقة الإدارة على الطلب', 'Approve maintenance request'),
            in_progress: t('بدء التنفيذ', 'Start work'),
            completed: t('إكمال الطلب', 'Complete request'),
            cancelled: t('إلغاء الطلب', 'Cancel request'),
            return_to_assignee: t('إرجاع الطلب للموظف', 'Return request to staff'),
            follow_up: t('متابعة البلاغ', 'Follow up case'),
            request_return: t('طلب استرجاع البلاغ', 'Request case return')
        };
        const hintMap = {
            approve: t('يمكنك إضافة ملاحظة عند الموافقة (اختياري). بعد الموافقة سيظهر الطلب للموظف المسؤول عن التنفيذ.', 'You may add an approval note (optional). After approval the request will appear for the assigned staff.'),
            in_progress: t('اكتب ملاحظة إلزامية توضح بدء التنفيذ وما سيتم عمله.', 'Write a required note explaining the work start.'),
            completed: t('اكتب ملاحظة إلزامية توضح العمل الذي تم إنجازه. يمكنك إرفاق صور أو فيديو للحل.', 'Write a required note explaining the work completed. You may attach photos or video of the solution.'),
            cancelled: t('اكتب سبب الإلغاء (اختياري).', 'Write cancellation reason (optional).'),
            return_to_assignee: t('اكتب سبب إرجاع الطلب للموظف (إلزامي).', 'Write why you are returning the request to staff (required).'),
            follow_up: t('اكتب سبب تحويل البلاغ للموظف للمتابعة والتحقق (إلزامي). يبقى الربط بالمحاسبة كما هو.', 'Write why you are assigning follow-up to staff (required). Accounting link remains unchanged.'),
            request_return: t('اكتب سبب طلب استرجاع البلاغ (إلزامي).', 'Write why you are requesting a case return (required).')
        };
        _maintenanceStatusAction = { requestId, action };
        const modal = document.getElementById('maintenanceStatusActionModal');
        const title = document.getElementById('maintenanceStatusActionTitle');
        const hint = document.getElementById('maintenanceStatusActionHint');
        const noteEl = document.getElementById('maintenanceStatusActionNote');
        const attBlock = document.getElementById('maintenanceStatusActionAttachmentsBlock');
        const attInput = document.getElementById('maintenanceStatusActionAttachments');
        const attHint = document.getElementById('maintenanceStatusActionAttachmentsHint');
        const settings = getMaintenanceSettings();
        if (title) title.textContent = titleMap[action] || t('ملاحظة إلزامية', 'Required note');
        if (hint) hint.textContent = hintMap[action] || '';
        if (noteEl) {
            noteEl.value = '';
            noteEl.placeholder = t('اكتب ملاحظة توضح سبب الإجراء...', 'Write a note explaining this action...');
            noteEl.disabled = false;
            noteEl.readOnly = false;
        }
        const noteLabel = document.getElementById('maintenanceStatusActionNoteLabel');
        if (noteLabel) noteLabel.textContent = appUiLanguage === 'en' ? (noteLabel.dataset.en || 'Note') : (noteLabel.dataset.ar || 'الملاحظة');
        if (attBlock) attBlock.style.display = action === 'completed' ? 'block' : 'none';
        if (attInput) attInput.value = '';
        if (attHint) {
            attHint.textContent = settings.completionAttachmentsRequired
                ? t('رفع مرفق الحل إلزامي حسب إعدادات مدير النظام.', 'Solution attachment upload is required per system admin settings.')
                : t('رفع مرفق الحل اختياري حالياً (يمكن لمدير النظام جعله إلزامياً).', 'Solution attachment is optional for now (system admin can make it required).');
        }
        if (modal) modal.classList.add('open');
        setTimeout(() => {
            try { document.getElementById('maintenanceStatusActionNote')?.focus(); } catch (_eMntNoteFocus) {}
        }, 50);
        try { localizeBilingualUi(); } catch (_eMntActLoc) {}
    }

    function closeMaintenanceStatusActionModal() {
        document.getElementById('maintenanceStatusActionModal')?.classList.remove('open');
        const attInput = document.getElementById('maintenanceStatusActionAttachments');
        if (attInput) attInput.value = '';
        _maintenanceStatusAction = { requestId: '', action: '' };
    }

    async function confirmMaintenanceStatusAction() {
        const { requestId, action } = _maintenanceStatusAction || {};
        const note = toStr(document.getElementById('maintenanceStatusActionNote')?.value).trim();
        if (!requestId || !action) return;
        if (action === 'request_return' || action === 'return_to_assignee' || action === 'follow_up' || action === 'in_progress' || action === 'completed') {
            if (!note) {
                alert(t('الملاحظة إلزامية.', 'Note is required.'));
                return;
            }
        }
        if (action === 'completed') {
            const settings = getMaintenanceSettings();
            const files = document.getElementById('maintenanceStatusActionAttachments')?.files;
            if (settings.completionAttachmentsRequired && (!files || !files.length)) {
                alert(t('مرفق الحل (صور/فيديو) إلزامي عند الإكمال.', 'Solution attachment (photo/video) is required when completing.'));
                return;
            }
            const req = loadMaintenanceRegistry().requests.find((r) => r.id === requestId);
            const attachments = [];
            if (files && files.length && req) {
                for (let i = 0; i < files.length; i++) {
                    try {
                        const ref = await bhdPersistUploadedFile(files[i], {
                            category: 'maintenance',
                            docType: 'completion',
                            buildingNo: req.building,
                            flatNo: req.unit,
                            agreementNo: req.agreementNo || req.requestNo
                        });
                        const saved = fileRefFromPersistResult(ref);
                        if (saved) attachments.push(saved);
                    } catch (_eMntAtt) {}
                }
            }
            closeMaintenanceStatusActionModal();
            setMaintenanceRequestStatus(requestId, action, note, { completionAttachments: attachments });
            return;
        }
        closeMaintenanceStatusActionModal();
        if (action === 'request_return' || action === 'return_to_assignee' || action === 'follow_up') {
            setMaintenanceRequestStatus(requestId, '', note, { action });
            return;
        }
        if (action === 'approve') {
            setMaintenanceRequestStatus(requestId, 'pending', note, { action: 'approve' });
            return;
        }
        setMaintenanceRequestStatus(requestId, action, note);
    }

    async function openMaintenanceCompletionAttachment(requestId, index) {
        const req = loadMaintenanceRegistry().requests.find((r) => r.id === requestId);
        const att = Array.isArray(req?.completionAttachments) ? req.completionAttachments[index] : null;
        if (!att) return;
        await openAttachmentPreviewModal(att, t('مرفق الحل / Solution attachment', 'Solution attachment / مرفق الحل'));
    }

    function adjustMaintenanceAmountByAccountant(requestId, newAmount) {
        if (!assertPermissionOrAlert('manage_accounting', 'لا تملك صلاحية المحاسبة.', 'No accounting permission.')) return;
        const reg = loadMaintenanceRegistry();
        const req = reg.requests.find((r) => r.id === requestId);
        if (!req) return;
        const amt = parseMaintenanceAmountInput(newAmount);
        if (Number.isNaN(amt) || amt < 0) {
            alert(t('مبلغ غير صالح.', 'Invalid amount.'));
            return;
        }
        const actor = getCurrentActorLedgerRecord();
        req.accountantAdjustedTotal = parseFloat(amt.toFixed(3));
        delete _maintenanceAcctDraftAmounts[toStr(requestId)];
        if (!Array.isArray(req.events)) req.events = [];
        req.events.push({
            at: new Date().toISOString(),
            type: 'amount_adjusted',
            staffName: actor.staffName,
            note: `${t('تعديل مبلغ المحاسب', 'Accountant amount adjustment')}: ${summaryAmtOm(amt)}`
        });
        saveMaintenanceRegistry(reg);
        if (req.linkedToAccounting && req.accountingEntryId) {
            const areg = loadAccountingRegistry();
            const ent = areg.entries.find((e) => e.id === req.accountingEntryId);
            if (ent) {
                ent.amount = req.accountantAdjustedTotal;
                ent.updatedAt = new Date().toISOString();
                recomputeAccountingAccountSummary(areg, req.unitKey);
            }
            if (req.accountingInvoiceId) {
                const inv = areg.invoices.find((i) => i.id === req.accountingInvoiceId);
                if (inv) {
                    inv.total = req.accountantAdjustedTotal;
                    inv.updatedAt = new Date().toISOString();
                }
            }
            saveAccountingRegistry(areg);
        }
        recordSystemActivity({
            actionKey: 'maintenance_amount_adjusted',
            actionAr: 'تعديل مبلغ صيانة / Adjust maintenance amount',
            actionEn: 'Adjust maintenance amount / تعديل مبلغ',
            building: req.building,
            unit: req.unit,
            ref: req.requestNo,
            note: summaryAmtOm(amt)
        });
        renderMaintenanceWorkspace();
        renderAccountingWorkspace();
    }

    function linkMaintenanceToAccounting(requestId) {
        if (!assertPermissionOrAlert('manage_accounting', 'لا تملك صلاحية المحاسبة.', 'No accounting permission.')) return;
        const mreg = loadMaintenanceRegistry();
        const req = mreg.requests.find((r) => r.id === requestId);
        if (!req) return;
        if (req.linkedToAccounting) {
            alert(t('الطلب مربوط بالمحاسبة مسبقاً.', 'Already linked to accounting.'));
            return;
        }
        const total = maintenanceRequestTotal(req);
        const areg = loadAccountingRegistry();
        const linkedKey = `maintenance|${req.id}`;
        const tenantCtx = resolveMaintenanceUnitContext(req.building, req.unit);
        const tenantName = resolveMaintenanceInvoiceTenant(req);
        const agreementNo = toStr(req.agreementNo || tenantCtx.agreementNo);
        let entry = areg.entries.find((e) => e.linkedKey === linkedKey);
        if (!entry) {
            const actor = getCurrentActorLedgerRecord();
            entry = {
                id: newAccountingId('ent'),
                unitKey: req.unitKey,
                building: req.building,
                unit: req.unit,
                linkedKey,
                sourceKey: req.requestNo,
                type: 'income',
                title: t(`صيانة ${req.requestNo}`, `Maintenance ${req.requestNo}`),
                amount: total,
                dueDate: toStr(req.completedAt || req.createdAt).slice(0, 10),
                status: 'confirmed',
                agreementNo,
                tenant: tenantName !== '—' ? tenantName : '',
                maintenanceRequestId: req.id,
                updatedAt: new Date().toISOString()
            };
            areg.entries.push(entry);
            recomputeAccountingAccountSummary(areg, req.unitKey);
            saveAccountingRegistry(areg);
            if (!Array.isArray(req.events)) req.events = [];
            req.events.push({
                at: new Date().toISOString(),
                type: 'linked_accounting',
                staffName: actor.staffName,
                note: t('ربط بالمحاسبة', 'Linked to accounting')
            });
        } else {
            entry.tenant = tenantName !== '—' ? tenantName : entry.tenant;
            entry.agreementNo = agreementNo || entry.agreementNo;
            entry.maintenanceRequestId = req.id;
            entry.amount = total;
            entry.updatedAt = new Date().toISOString();
            saveAccountingRegistry(areg);
        }
        req.linkedToAccounting = true;
        req.accountingEntryId = entry.id;
        if (!getMaintenanceAccountingInvoice(req)) {
            const inv = createMaintenanceInvoiceForEntry(entry, req);
            if (inv) {
                approveAccountingInvoice(inv.id);
                req.accountingInvoiceId = inv.id;
                if (!Array.isArray(req.events)) req.events = [];
                req.events.push({
                    at: new Date().toISOString(),
                    type: 'invoice_issued',
                    staffName: getCurrentActorLedgerRecord().staffName,
                    note: t('إصدار فاتورة صيانة', 'Maintenance invoice issued')
                });
            }
        }
        saveMaintenanceRegistry(mreg);
        recordSystemActivity({
            actionKey: 'maintenance_linked_accounting',
            actionAr: 'ربط صيانة بالمحاسبة / Link maintenance to accounting',
            actionEn: 'Link maintenance to accounting / ربط صيانة',
            building: req.building,
            unit: req.unit,
            ref: req.requestNo,
            note: summaryAmtOm(total)
        });
        renderAccountingWorkspace();
        renderMaintenanceWorkspace();
    }

    function unlinkMaintenanceFromAccounting(requestId) {
        if (!assertPermissionOrAlert('manage_accounting', 'لا تملك صلاحية المحاسبة.', 'No accounting permission.')) return;
        const mreg = loadMaintenanceRegistry();
        const req = mreg.requests.find((r) => r.id === requestId);
        if (!req || !req.linkedToAccounting) {
            alert(t('الطلب غير مربوط بالمحاسبة.', 'Request is not linked to accounting.'));
            return;
        }
        if (!confirm(t('فك ربط هذا الطلب من المحاسبة؟ سيتم حذف البند والفاتورة المرتبطة.', 'Unlink this request from accounting? The linked entry and invoice will be removed.'))) return;
        const areg = loadAccountingRegistry();
        const unitKey = req.unitKey;
        const entryId = req.accountingEntryId;
        const invoiceId = req.accountingInvoiceId;
        if (invoiceId) {
            areg.invoices = areg.invoices.filter((i) => i.id !== invoiceId);
        }
        if (entryId) {
            areg.entries = areg.entries.filter((e) => e.id !== entryId);
        } else {
            const linkedKey = `maintenance|${req.id}`;
            areg.entries = areg.entries.filter((e) => e.linkedKey !== linkedKey);
        }
        recomputeAccountingAccountSummary(areg, unitKey);
        saveAccountingRegistry(areg);
        const actor = getCurrentActorLedgerRecord();
        req.linkedToAccounting = false;
        req.accountingEntryId = null;
        req.accountingInvoiceId = null;
        if (!Array.isArray(req.events)) req.events = [];
        req.events.push({
            at: new Date().toISOString(),
            type: 'unlinked_accounting',
            staffName: actor.staffName,
            note: t('فك الربط من المحاسبة', 'Unlinked from accounting')
        });
        saveMaintenanceRegistry(mreg);
        recordSystemActivity({
            actionKey: 'maintenance_unlinked_accounting',
            actionAr: 'فك ربط صيانة من المحاسبة / Unlink maintenance from accounting',
            actionEn: 'Unlink maintenance from accounting / فك ربط صيانة',
            building: req.building,
            unit: req.unit,
            ref: req.requestNo,
            note: ''
        });
        renderAccountingWorkspace();
        renderMaintenanceWorkspace();
    }

    function issueMaintenanceInvoiceForRequest(requestId) {
        if (!assertPermissionOrAlert('manage_accounting', 'لا تملك صلاحية المحاسبة.', 'No accounting permission.')) return;
        const mreg = loadMaintenanceRegistry();
        const req = mreg.requests.find((r) => r.id === requestId);
        if (!req || !req.linkedToAccounting) {
            alert(t('الطلب غير مربوط بالمحاسبة.', 'Request is not linked to accounting.'));
            return;
        }
        const entry = resolveMaintenanceAccountingEntry(req);
        if (!entry) {
            alert(t('لا يوجد بند محاسبي مرتبط بهذا الطلب.', 'No accounting entry linked to this request.'));
            return;
        }
        req.accountingEntryId = entry.id;
        let inv = getMaintenanceAccountingInvoice(req);
        if (!inv) {
            const areg = loadAccountingRegistry();
            const entryStatus = toStr(entry.status);
            if (entryStatus === 'invoiced') {
                const ent = areg.entries.find((e) => e.id === entry.id);
                if (ent) {
                    ent.status = 'confirmed';
                    ent.updatedAt = new Date().toISOString();
                    saveAccountingRegistry(areg);
                }
            }
            inv = createMaintenanceInvoiceForEntry(entry, req);
            if (!inv) {
                alert(t('تعذر إصدار الفاتورة.', 'Could not issue invoice.'));
                return;
            }
            if (inv.status !== 'approved') {
                approveAccountingInvoice(inv.id);
            }
            if (!Array.isArray(req.events)) req.events = [];
            req.events.push({
                at: new Date().toISOString(),
                type: 'invoice_issued',
                staffName: getCurrentActorLedgerRecord().staffName,
                note: t('إصدار فاتورة صيانة', 'Maintenance invoice issued')
            });
        }
        req.accountingInvoiceId = inv.id;
        saveMaintenanceRegistry(mreg);
        renderAccountingWorkspace();
        printMaintenanceInvoiceByRequest(requestId);
    }

    function maintenanceAddFormLine() {
        const { catKey, subKey, cat, sub } = resolveMaintenanceLineSelectionFromForm();
        const qty = Math.max(1, parseInt(document.getElementById('mntLineQty')?.value, 10) || 1);
        if (!catKey || !sub) {
            alert(t('اختر نوع الصيانة.', 'Select maintenance type.'));
            return;
        }
        let materialsCost = parseFloat(sub.materialsCost) || 0;
        let laborCost = parseFloat(sub.laborCost) || 0;
        let customTotal = 0;
        if (sub.customPrice) {
            customTotal = parseFloat(document.getElementById('mntLineCustomTotal')?.value) || 0;
            if (customTotal <= 0) {
                alert(t('أدخل السعر اليدوي.', 'Enter manual price.'));
                return;
            }
        }
        _maintenanceFormLines.push({
            categoryKey: catKey,
            subtypeKey: subKey,
            labelAr: sub.labelAr,
            labelEn: sub.labelEn,
            categoryAr: cat?.categoryAr || catKey,
            categoryEn: cat?.categoryEn || catKey,
            qty: sub.hasQty ? qty : 1,
            materialsCost,
            laborCost,
            customPrice: !!sub.customPrice,
            customTotal: sub.customPrice ? customTotal : null,
            assigneeUserId: toStr(sub.assigneeUserId),
            assigneeName: toStr(sub.assigneeName)
        });
        renderMaintenanceRequestFormBody();
    }

    function maintenanceRemoveFormLine(idx) {
        _maintenanceFormLines.splice(idx, 1);
        renderMaintenanceRequestFormBody();
    }

    function onMaintenanceFormBuildingChange() {
        _maintenanceFormState.building = toStr(document.getElementById('mntFormBuilding')?.value);
        _maintenanceFormState.unit = '';
        renderMaintenanceRequestFormBody();
    }

    function onMaintenanceFormUnitChange() {
        _maintenanceFormState.unit = toStr(document.getElementById('mntFormUnit')?.value);
        renderMaintenanceRequestFormBody();
    }

    function onMaintenanceLineCategoryChange() {
        _maintenanceFormState.lineCategory = toStr(document.getElementById('mntLineCategory')?.value);
        _maintenanceFormState.lineSubtype = '';
        renderMaintenanceRequestFormBody();
    }

    function onMaintenanceLineSubtypeChange() {
        _maintenanceFormState.lineSubtype = toStr(document.getElementById('mntLineSubtype')?.value);
        renderMaintenanceRequestFormBody();
    }

    function captureMaintenanceRequestFormUiState() {
        const notesBefore = document.getElementById('mntFormNotes')?.value;
        if (notesBefore != null) _maintenanceFormState.notes = notesBefore;
        const catVal = document.getElementById('mntLineCategory')?.value;
        const subVal = document.getElementById('mntLineSubtype')?.value;
        if (catVal != null) _maintenanceFormState.lineCategory = toStr(catVal);
        if (subVal != null) _maintenanceFormState.lineSubtype = toStr(subVal);
        const bVal = document.getElementById('mntFormBuilding')?.value;
        const uVal = document.getElementById('mntFormUnit')?.value;
        if (bVal != null) _maintenanceFormState.building = toStr(bVal);
        if (uVal != null) _maintenanceFormState.unit = toStr(uVal);
    }

    function renderMaintenanceRequestFormBody() {
        const body = document.getElementById('maintenanceRequestBody');
        if (!body) return;
        captureMaintenanceRequestFormUiState();
        const reg = loadMaintenanceRegistry();
        const linesTotal = parseFloat(_maintenanceFormLines.reduce((s, ln) => s + maintenanceLineTotal(ln), 0).toFixed(3));
        const buildings = getMaintenanceBuildingOptions();
        const selectedBuilding = toStr(_maintenanceFormState.building);
        const units = getMaintenanceUnitsForBuilding(selectedBuilding);
        const selectedUnit = toStr(_maintenanceFormState.unit);
        if (selectedUnit && !units.includes(selectedUnit)) _maintenanceFormState.unit = '';
        const buildingOpts = `<option value="">${t('— اختر مبنى —', '— Select building —')}</option>` +
            buildings.map((b) => `<option value="${escAttr(b)}" ${b === selectedBuilding ? 'selected' : ''}>${escHtml(b)}</option>`).join('');
        const unitOpts = `<option value="">${selectedBuilding ? t('— اختر وحدة —', '— Select unit —') : t('اختر المبنى أولاً', 'Select building first')}</option>` +
            units.map((u) => `<option value="${escAttr(u)}" ${u === _maintenanceFormState.unit ? 'selected' : ''}>${escHtml(u)}</option>`).join('');
        const firstCat = reg.priceCatalog[0];
        const selectedCat = toStr(_maintenanceFormState.lineCategory || firstCat?.categoryKey);
        const cat = reg.priceCatalog.find((c) => c.categoryKey === selectedCat) || firstCat;
        const catOpts = reg.priceCatalog.map((c) =>
            `<option value="${escAttr(c.categoryKey)}" ${c.categoryKey === selectedCat ? 'selected' : ''}>${escHtml(maintenanceLocalizedCategory(c))}</option>`
        ).join('');
        const selectedSubKey = toStr(_maintenanceFormState.lineSubtype || cat?.subtypes?.[0]?.key);
        const subOpts = (cat?.subtypes || []).map((s) =>
            `<option value="${escAttr(s.key)}" ${toStr(s.key) === selectedSubKey ? 'selected' : ''}>${escHtml(maintenanceLocalizedItem(s))}</option>`
        ).join('');
        const selectedSub = getMaintenanceCatalogSubtype(cat?.categoryKey, selectedSubKey) || cat?.subtypes?.[0] || null;
        if (selectedSub) _maintenanceFormState.lineSubtype = toStr(selectedSub.key);
        const arrearsPanel = selectedBuilding && _maintenanceFormState.unit
            ? renderMaintenanceArrearsPanel(selectedBuilding, _maintenanceFormState.unit)
            : '';
        body.innerHTML = `
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:12px">
                <label style="font-size:12px">${t('المبنى', 'Building')}<select id="mntFormBuilding" onchange="onMaintenanceFormBuildingChange()" style="width:100%;margin-top:4px">${buildingOpts}</select></label>
                <label style="font-size:12px">${t('الوحدة', 'Unit')}<select id="mntFormUnit" onchange="onMaintenanceFormUnitChange()" style="width:100%;margin-top:4px" ${selectedBuilding ? '' : 'disabled'}>${unitOpts}</select></label>
            </div>
            ${arrearsPanel}
            <h5 style="margin:0 0 8px">${t('بنود الصيانة', 'Maintenance items')}</h5>
            <div style="display:flex;flex-wrap:wrap;gap:8px;align-items:flex-end;margin-bottom:10px">
                <label style="font-size:12px">${t('الفئة', 'Category')}<select id="mntLineCategory" onchange="onMaintenanceLineCategoryChange()" style="display:block;margin-top:4px">${catOpts}</select></label>
                <label style="font-size:12px">${t('نوع العمل', 'Work type')}<select id="mntLineSubtype" onchange="onMaintenanceLineSubtypeChange()" style="display:block;margin-top:4px;min-width:200px">${subOpts}</select></label>
                ${selectedSub?.hasQty ? `<label style="font-size:12px">${t('العدد', 'Qty')}<input id="mntLineQty" type="number" min="1" value="1" style="width:70px;margin-top:4px"></label>` : ''}
                ${selectedSub?.customPrice ? `<label style="font-size:12px">${t('السعر اليدوي', 'Manual price')}<input id="mntLineCustomTotal" type="number" step="0.001" style="width:100px;margin-top:4px"></label>` : ''}
                <button type="button" class="btn-outline mini-btn" onclick="maintenanceAddFormLine()">${t('إضافة بند', 'Add item')}</button>
            </div>
            ${selectedSub ? `<p style="font-size:11px;color:#666;margin:-4px 0 10px">${t('التكلفة التقديرية', 'Estimated cost')}: ${escHtml(summaryAmtOm((parseFloat(selectedSub.materialsCost) || 0) + (parseFloat(selectedSub.laborCost) || 0)))}${selectedSub.assigneeName ? ` · ${t('المسؤول', 'Assignee')}: ${escHtml(selectedSub.assigneeName)}` : ''}</p>` : ''}
            <table class="data-table" style="width:100%;font-size:12px">
                <thead><tr><th>${t('البند', 'Item')}</th><th>${t('العدد', 'Qty')}</th><th>${t('مواد', 'Materials')}</th><th>${t('عامل', 'Labor')}</th><th>${t('المسؤول', 'Assignee')}</th><th>${t('الإجمالي', 'Total')}</th><th></th></tr></thead>
                <tbody>${_maintenanceFormLines.length ? _maintenanceFormLines.map((ln, i) => `<tr>
                    <td>${escHtml(maintenanceLocalizedItem(ln))}</td><td>${escHtml(ln.qty)}</td>
                    <td>${escHtml(summaryAmtOm(ln.materialsCost))}</td><td>${escHtml(summaryAmtOm(ln.laborCost))}</td>
                    <td>${escHtml(ln.assigneeName || '—')}</td>
                    <td>${escHtml(summaryAmtOm(maintenanceLineTotal(ln)))}</td>
                    <td><button type="button" class="btn-outline mini-btn" onclick="maintenanceRemoveFormLine(${i})">✕</button></td>
                </tr>`).join('') : `<tr><td colspan="7" style="text-align:center;color:#666">${t('لا توجد بنود بعد', 'No items yet')}</td></tr>`}</tbody>
                <tfoot><tr><td colspan="5" style="text-align:left;font-weight:700">${t('الإجمالي التقديري', 'Estimated total')}</td><td colspan="2" style="font-weight:700">${escHtml(summaryAmtOm(linesTotal))}</td></tr></tfoot>
            </table>
            <label style="font-size:12px;display:block;margin-top:14px">${t('ملاحظات الطلب', 'Request notes')}
                <textarea id="mntFormNotes" rows="2" style="width:100%;margin-top:4px" placeholder="${t('تفاصيل إضافية من المستأجر...', 'Additional tenant details...')}"></textarea>
            </label>
            <button type="button" class="btn-primary" style="margin-top:12px" onclick="saveMaintenanceRequestFromForm()">${t('حفظ الطلب', 'Save request')}</button>`;
        const notesEl = document.getElementById('mntFormNotes');
        if (notesEl) notesEl.value = toStr(_maintenanceFormState.notes);
    }

    function openMaintenanceRequestModal(prefill) {
        if (!assertPermissionOrAlert('manage_maintenance', 'لا تملك صلاحية الصيانة.', 'No maintenance permission.')) return;
        _maintenanceFormLines = [];
        _maintenanceFormState = {
            building: toStr(prefill?.building),
            unit: toStr(prefill?.unit),
            notes: '',
            lineCategory: '',
            lineSubtype: ''
        };
        const modal = document.getElementById('maintenanceRequestModal');
        if (!modal) return;
        renderMaintenanceRequestFormBody();
        modal.classList.add('open');
        try { localizeBilingualUi(); } catch (_eMntLoc) {}
    }

    function closeMaintenanceRequestModal() {
        document.getElementById('maintenanceRequestModal')?.classList.remove('open');
    }

    function openMaintenanceCatalogModal() {
        if (!assertPermissionOrAlert('manage_maintenance', 'لا تملك صلاحية الصيانة.', 'No maintenance permission.')) return;
        const modal = document.getElementById('maintenanceCatalogModal');
        if (!modal) return;
        renderMaintenanceCatalogBody();
        modal.classList.add('open');
        try { localizeBilingualUi(); } catch (_eMntCatLoc) {}
    }

    function closeMaintenanceCatalogModal() {
        document.getElementById('maintenanceCatalogModal')?.classList.remove('open');
    }

    function updateMaintenanceCatalogSubtype(catKey, subKey, field, value) {
        const reg = loadMaintenanceRegistry();
        const cat = reg.priceCatalog.find((c) => c.categoryKey === catKey);
        const sub = (cat?.subtypes || []).find((s) => s.key === subKey);
        if (!sub) return;
        if (field === 'materialsCost' || field === 'laborCost') {
            sub[field] = parseFloat(value) || 0;
        } else if (field === 'assigneeUserId') {
            sub.assigneeUserId = toStr(value);
            const staff = getMaintenanceStaffOptions().find((u) => u.id === sub.assigneeUserId);
            sub.assigneeName = staff ? toStr(staff.displayName || staff.email) : '';
        }
        saveMaintenanceRegistry(reg);
    }

    function removeMaintenanceCatalogSubtype(catKey, subKey) {
        if (!assertPermissionOrAlert('manage_maintenance', 'لا تملك صلاحية الصيانة.', 'No maintenance permission.')) return;
        if (!confirm(t('حذف هذا البند من القائمة؟', 'Delete this item from the catalog?'))) return;
        const reg = loadMaintenanceRegistry();
        const cat = reg.priceCatalog.find((c) => c.categoryKey === catKey);
        if (!cat || !Array.isArray(cat.subtypes)) return;
        cat.subtypes = cat.subtypes.filter((s) => s.key !== subKey);
        saveMaintenanceRegistry(reg);
        renderMaintenanceCatalogBody();
    }

    function saveMaintenanceCatalogSubtype() {
        if (!assertPermissionOrAlert('manage_maintenance', 'لا تملك صلاحية الصيانة.', 'No maintenance permission.')) return;
        const catKey = toStr(document.getElementById('mntCatCategory')?.value);
        const labelAr = toStr(document.getElementById('mntCatLabelAr')?.value).trim();
        const labelEn = toStr(document.getElementById('mntCatLabelEn')?.value).trim();
        const materialsCost = parseFloat(document.getElementById('mntCatMaterials')?.value) || 0;
        const laborCost = parseFloat(document.getElementById('mntCatLabor')?.value) || 0;
        const assigneeUserId = toStr(document.getElementById('mntCatAssignee')?.value);
        const hasQty = !!document.getElementById('mntCatHasQty')?.checked;
        const customPrice = !!document.getElementById('mntCatCustomPrice')?.checked;
        if (!catKey || (!labelAr && !labelEn)) {
            alert(t('أدخل الفئة واسم البند.', 'Enter category and item name.'));
            return;
        }
        const reg = loadMaintenanceRegistry();
        const cat = reg.priceCatalog.find((c) => c.categoryKey === catKey);
        if (!cat) {
            alert(t('الفئة غير موجودة.', 'Category not found.'));
            return;
        }
        const staff = getMaintenanceStaffOptions().find((u) => u.id === assigneeUserId);
        if (!Array.isArray(cat.subtypes)) cat.subtypes = [];
        cat.subtypes.push({
            key: `custom_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
            labelAr: labelAr || labelEn,
            labelEn: labelEn || labelAr,
            materialsCost,
            laborCost,
            hasQty,
            customPrice,
            assigneeUserId,
            assigneeName: staff ? toStr(staff.displayName || staff.email) : ''
        });
        saveMaintenanceRegistry(reg);
        document.getElementById('mntCatLabelAr').value = '';
        document.getElementById('mntCatLabelEn').value = '';
        document.getElementById('mntCatMaterials').value = '';
        document.getElementById('mntCatLabor').value = '';
        renderMaintenanceCatalogBody();
    }

    function renderMaintenanceCatalogBody() {
        const body = document.getElementById('maintenanceCatalogBody');
        if (!body) return;
        const reg = loadMaintenanceRegistry();
        const catOpts = reg.priceCatalog.map((c) =>
            `<option value="${escHtml(c.categoryKey)}">${escHtml(maintenanceLocalizedCategory(c))}</option>`
        ).join('');
        const rows = [];
        reg.priceCatalog.forEach((cat) => {
            (cat.subtypes || []).forEach((sub) => {
                const ck = escHtml(cat.categoryKey).replace(/'/g, "\\'");
                const sk = escHtml(sub.key).replace(/'/g, "\\'");
                rows.push(`<tr>
                    <td>${escHtml(maintenanceLocalizedCategory(cat))}</td>
                    <td>${escHtml(maintenanceLocalizedItem(sub))}</td>
                    <td><input type="number" step="0.001" value="${escHtml(sub.materialsCost)}" style="width:80px" onchange="updateMaintenanceCatalogSubtype('${ck}','${sk}','materialsCost',this.value)"></td>
                    <td><input type="number" step="0.001" value="${escHtml(sub.laborCost)}" style="width:80px" onchange="updateMaintenanceCatalogSubtype('${ck}','${sk}','laborCost',this.value)"></td>
                    <td><select style="min-width:140px" onchange="updateMaintenanceCatalogSubtype('${ck}','${sk}','assigneeUserId',this.value)">${maintenanceStaffSelectOptions(sub.assigneeUserId)}</select></td>
                    <td>${escHtml(summaryAmtOm((parseFloat(sub.materialsCost) || 0) + (parseFloat(sub.laborCost) || 0)))}</td>
                    <td><button type="button" class="btn-outline mini-btn" onclick="removeMaintenanceCatalogSubtype('${ck}','${sk}')">✕</button></td>
                </tr>`);
            });
        });
        const settingsBlock = isMaintenanceSystemAdmin()
            ? `<div style="border:1px solid #d4e4f7;border-radius:10px;padding:12px;margin-bottom:14px;background:#f3f8ff">
                <h5 style="margin:0 0 8px">${t('إعدادات الصيانة / Maintenance settings', 'Maintenance settings / إعدادات الصيانة')}</h5>
                <label style="font-size:12px;display:flex;align-items:center;gap:8px;cursor:pointer">
                    <input type="checkbox" id="mntCompletionAttachmentsRequired" ${getMaintenanceSettings().completionAttachmentsRequired ? 'checked' : ''} onchange="setMaintenanceCompletionAttachmentsRequired(this.checked)">
                    ${t('إلزام رفع مرفق الحل (صور/فيديو) عند إكمال الطلب / Require solution attachment on completion', 'Require solution attachment on completion / إلزام مرفق الحل')}
                </label>
                <small style="display:block;margin-top:6px;color:#666;line-height:1.45">${t('حالياً يمكن تركه اختيارياً. عند التفعيل لن يتمكن الموظف من إكمال الطلب دون رفع مرفق.', 'Currently optional. When enabled, staff cannot complete without uploading an attachment.')}</small>
            </div>`
            : '';
        body.innerHTML = `
            ${settingsBlock}
            <p style="font-size:12px;color:#555;margin:0 0 12px;line-height:1.5">${t('حدّد تكلفة كل بند صيانة والموظف المسؤول عن التنفيذ. ستُستخدم هذه البيانات عند إنشاء الطلبات ولاحقاً في نظام المهام.', 'Set each maintenance item cost and the staff member responsible for execution. These values are used when creating requests and later in the task system.')}</p>
            <div style="border:1px solid #e8e0e0;border-radius:10px;padding:12px;margin-bottom:14px;background:#faf8f8">
                <h5 style="margin:0 0 10px">${t('إضافة بند صيانة جديد', 'Add new maintenance item')}</h5>
                <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:8px;align-items:end">
                    <label style="font-size:12px">${t('الفئة', 'Category')}<select id="mntCatCategory" style="display:block;width:100%;margin-top:4px">${catOpts}</select></label>
                    <label style="font-size:12px">${t('اسم البند (عربي)', 'Item name (Arabic)')}<input id="mntCatLabelAr" type="text" style="width:100%;margin-top:4px"></label>
                    <label style="font-size:12px">${t('اسم البند (إنجليزي)', 'Item name (English)')}<input id="mntCatLabelEn" type="text" style="width:100%;margin-top:4px"></label>
                    <label style="font-size:12px">${t('تكلفة المواد', 'Materials cost')}<input id="mntCatMaterials" type="number" step="0.001" min="0" style="width:100%;margin-top:4px"></label>
                    <label style="font-size:12px">${t('تكلفة العامل', 'Labor cost')}<input id="mntCatLabor" type="number" step="0.001" min="0" style="width:100%;margin-top:4px"></label>
                    <label style="font-size:12px">${t('المسؤول عن التنفيذ', 'Assignee')}<select id="mntCatAssignee" style="display:block;width:100%;margin-top:4px">${maintenanceStaffSelectOptions('')}</select></label>
                    <label style="font-size:12px;display:flex;align-items:center;gap:6px;margin-top:18px"><input id="mntCatHasQty" type="checkbox"> ${t('يدعم العدد', 'Supports quantity')}</label>
                    <label style="font-size:12px;display:flex;align-items:center;gap:6px;margin-top:18px"><input id="mntCatCustomPrice" type="checkbox"> ${t('سعر يدوي عند الطلب', 'Manual price on request')}</label>
                    <button type="button" class="btn-primary mini-btn" onclick="saveMaintenanceCatalogSubtype()">${t('إضافة البند', 'Add item')}</button>
                </div>
            </div>
            <div class="table-wrap"><table class="data-table" style="width:100%;font-size:12px">
                <thead><tr>
                    <th>${t('الفئة', 'Category')}</th><th>${t('البند', 'Item')}</th>
                    <th>${t('مواد', 'Materials')}</th><th>${t('عامل', 'Labor')}</th>
                    <th>${t('المسؤول', 'Assignee')}</th><th>${t('الإجمالي', 'Total')}</th><th></th>
                </tr></thead>
                <tbody>${rows.length ? rows.join('') : `<tr><td colspan="7" style="text-align:center;color:#666">${t('لا توجد بنود.', 'No items.')}</td></tr>`}</tbody>
            </table></div>`;
    }

    function openMaintenanceDetailModal(requestId) {
        const reg = loadMaintenanceRegistry();
        const req = reg.requests.find((r) => r.id === requestId);
        if (!req) return;
        const modal = document.getElementById('maintenanceDetailModal');
        const body = document.getElementById('maintenanceDetailBody');
        const title = document.getElementById('maintenanceDetailTitle');
        if (!modal || !body) return;
        const unitCtx = resolveMaintenanceUnitContext(req.building, req.unit);
        const tenantLabel = unitCtx.tenantDisplay;
        const unitStatusLabel = unitCtx.isRented ? t('مستأجرة', 'Rented') : t('شاغرة', 'Vacant');
        const rid = escHtml(req.id);
        if (title) title.textContent = `${t('طلب صيانة', 'Maintenance request')} ${req.requestNo} — ${req.building} / ${req.unit}`;
        const total = maintenanceRequestTotal(req);
        const amountLabel = maintenanceAmountBreakdown(req).hasAccountantAdjustment
            ? t('المبلغ النهائي / Final amount', 'Final amount / المبلغ النهائي')
            : t('المبلغ / Amount', 'Amount / المبلغ');
        const itemsHtml = (req.items || []).map((ln) => `<tr>
            <td>${escHtml(maintenanceLocalizedText(ln.categoryAr || ln.categoryKey, ln.categoryEn || ln.categoryKey))} — ${escHtml(maintenanceLocalizedItem(ln))}</td>
            <td>${escHtml(ln.qty || 1)}</td>
            <td>${escHtml(summaryAmtOm(ln.materialsCost))}</td>
            <td>${escHtml(summaryAmtOm(ln.laborCost))}</td>
            <td>${escHtml(ln.assigneeName || '—')}</td>
            <td>${escHtml(summaryAmtOm(maintenanceLineTotal(ln)))}</td>
        </tr>`).join('');
        const eventsHtml = renderMaintenanceActivityLogHtml(req);
        const returnReqBanner = req.returnRequested
            ? `<div style="margin-bottom:10px;padding:10px 12px;border-radius:8px;background:#fff3e0;border:1px solid #ffcc80;font-size:12px">
                <strong>${t('طلب استرجاع من الموظف', 'Staff return request')}</strong>
                <div style="margin-top:4px">${escHtml(req.returnRequestNote || '—')}</div>
                <small style="color:#666">${escHtml(toStr(req.returnRequestedBy || '—'))} · ${escHtml(toStr(req.returnRequestedAt).slice(0, 16).replace('T', ' '))}</small>
            </div>`
            : '';
        const arrearsLines = Array.isArray(req.arrearsLines) ? req.arrearsLines : [];
        const approvalListPad = appUiLanguage === 'en' ? 'padding-left:18px' : 'padding-right:18px';
        const approvalBanner = req.status === 'pending_approval'
            ? `<div style="margin-bottom:10px;padding:10px 12px;border-radius:8px;background:#fce4ec;border:1px solid #f48fb1;font-size:12px">
                <strong style="color:#880e4f">${t('مطلوب موافقة الإدارة', 'Management approval required')}</strong>
                <div style="margin-top:6px;line-height:1.5">${t('يوجد متأخرات على المستأجر. الطلب لن يظهر للموظف المسؤول عن التنفيذ حتى تتم الموافقة.', 'Tenant has arrears. The request will not appear for the assigned staff until approved.')}</div>
                ${arrearsLines.length ? `<ul style="margin:8px 0 0;${approvalListPad}">${arrearsLines.map((ln) => `<li>${escHtml(ln.label)}: ${escHtml(summaryAmtOm(ln.amount))}</li>`).join('')}</ul>` : ''}
                ${req.arrearsTotal ? `<div style="margin-top:6px"><strong>${t('إجمالي المتأخرات', 'Total arrears')}:</strong> ${escHtml(summaryAmtOm(req.arrearsTotal))}</div>` : ''}
            </div>`
            : '';
        const canApprove = isMaintenanceSystemAdmin() && req.status === 'pending_approval';
        const canReturnToAssignee = isMaintenanceSystemAdmin() && !req.linkedToAccounting &&
            (req.status === 'completed' || req.status === 'in_progress' || req.status === 'cancelled');
        const canFollowUp = isMaintenanceSystemAdmin() && req.status === 'completed';
        const canRequestReturn = (isMaintenanceAssignee(req) || isMaintenanceSystemAdmin()) &&
            (req.status === 'completed' || req.status === 'in_progress') && !req.returnRequested;
        const completionAtts = Array.isArray(req.completionAttachments) ? req.completionAttachments : [];
        const completionAttHtml = completionAtts.length
            ? `<h5 style="margin:12px 0 6px">${t('مرفقات الحل / Solution attachments', 'Solution attachments / مرفقات الحل')}</h5>
                <div style="display:flex;flex-wrap:wrap;gap:8px;margin-bottom:8px">${completionAtts.map((att, i) =>
                    `<button type="button" class="btn-outline mini-btn" onclick="openMaintenanceCompletionAttachment('${rid}',${i})">${escHtml(att.name || t('مرفق', 'Attachment') + ' ' + (i + 1))}</button>`
                ).join('')}</div>
                ${req.completionNote ? `<p style="font-size:12px;margin:0 0 8px"><strong>${t('ملاحظة الإكمال', 'Completion note')}:</strong> ${escHtml(req.completionNote)}</p>` : ''}`
            : '';
        const followUpBanner = req.followUpActive && req.status === 'in_progress'
            ? `<div style="margin-bottom:10px;padding:10px 12px;border-radius:8px;background:#e8f4fd;border:1px solid #90caf9;font-size:12px">
                <strong>${t('بلاغ قيد المتابعة', 'Case under follow-up')}</strong>
                <div style="margin-top:4px">${escHtml(req.followUpNote || req.statusNote || '—')}</div>
                <small style="color:#666">${escHtml(toStr(req.followUpBy || '—'))} · ${escHtml(toStr(req.followUpAt).slice(0, 16).replace('T', ' '))}</small>
            </div>`
            : '';
        const linkedAcctBanner = req.linkedToAccounting
            ? `<div style="margin-bottom:10px;padding:8px 10px;border-radius:6px;background:#eef5ff;border:1px solid #c5d9f2;font-size:11px;color:#1565c0">${t('الطلب مربوط بالمحاسبة — لا يمكن إرجاعه للموظف. استخدم «متابعة البلاغ» عند الحاجة.', 'Linked to accounting — cannot return to staff. Use «Follow up case» if needed.')}</div>`
            : '';
        const headActions = document.getElementById('maintenanceDetailHeadActions');
        if (headActions) {
            headActions.innerHTML = [
                canApprove ? `<button type="button" class="btn-primary mini-btn" onclick="openMaintenanceStatusActionModal('${rid}','approve')">${t('موافقة الإدارة', 'Management approval')}</button>` : '',
                req.status === 'pending' ? `<button type="button" class="btn-outline mini-btn" onclick="openMaintenanceStatusActionModal('${rid}','in_progress')">${t('بدء التنفيذ', 'Start work')}</button>` : '',
                req.status === 'in_progress' || req.status === 'pending' ? `<button type="button" class="btn-primary mini-btn" onclick="openMaintenanceStatusActionModal('${rid}','completed')">${t('إكمال الطلب', 'Complete')}</button>` : '',
                req.status !== 'completed' && req.status !== 'cancelled' && req.status !== 'pending_approval' ? `<button type="button" class="btn-outline mini-btn" onclick="openMaintenanceStatusActionModal('${rid}','cancelled')">${t('إلغاء', 'Cancel')}</button>` : '',
                req.status === 'pending_approval' && isMaintenanceSystemAdmin() ? `<button type="button" class="btn-outline mini-btn" onclick="openMaintenanceStatusActionModal('${rid}','cancelled')">${t('رفض / إلغاء', 'Reject / Cancel')}</button>` : '',
                canReturnToAssignee ? `<button type="button" class="btn-outline mini-btn" onclick="openMaintenanceStatusActionModal('${rid}','return_to_assignee')">${t('إرجاع للموظف', 'Return to staff')}</button>` : '',
                canFollowUp ? `<button type="button" class="btn-outline mini-btn" onclick="openMaintenanceStatusActionModal('${rid}','follow_up')">${t('متابعة البلاغ', 'Follow up case')}</button>` : '',
                canRequestReturn ? `<button type="button" class="btn-outline mini-btn" onclick="openMaintenanceStatusActionModal('${rid}','request_return')">${t('طلب استرجاع البلاغ', 'Request case return')}</button>` : '',
                `<button type="button" class="btn-outline mini-btn" onclick="openMaintenancePrintModal('${rid}')">${t('🖨️ طباعة التفاصيل / Print details', 'Print details / طباعة')}</button>`,
                canPrintMaintenanceReceipt(req) ? `<button type="button" class="btn-primary mini-btn" onclick="printMaintenanceReceipt('${rid}')">${t('طباعة الإيصال / Print receipt', 'Print receipt / طباعة الإيصال')}</button>` : ''
            ].filter(Boolean).join('');
        }
        body.innerHTML = `
            <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:10px;margin-bottom:12px">
                <div><small>${t('حالة الوحدة', 'Unit status')}</small><strong style="display:block">${escHtml(unitStatusLabel)}</strong></div>
                <div><small>${t('المستأجر', 'Tenant')}</small><strong style="display:block">${escHtml(tenantLabel)}</strong></div>
                <div><small>${t('رقم العقد', 'Contract')}</small><strong style="display:block">${escHtml(unitCtx.isRented ? (unitCtx.agreementNo || req.agreementNo || '—') : '—')}</strong></div>
                <div><small>${t('المسؤول عن التنفيذ', 'Assignee')}</small><strong style="display:block">${escHtml(req.assigneeName || '—')}</strong></div>
                <div><small>${t('الحالة', 'Status')}</small><strong style="display:block">${maintenanceStatusChip(req.status, req.linkedToAccounting)}</strong>${req.statusNote ? `<small style="display:block;color:#666;margin-top:4px">${escHtml(req.statusNote)}</small>` : ''}</div>
                <div><small>${escHtml(amountLabel)}</small><strong style="display:block">${escHtml(summaryAmtOm(total))}</strong></div>
                <div><small>${t('أدخل الطلب', 'Created by')}</small><strong style="display:block">${escHtml(req.createdBy || '—')}</strong></div>
                <div><small>${t('تاريخ الإنشاء', 'Created at')}</small><strong style="display:block">${escHtml(toStr(req.createdAt).slice(0, 16).replace('T', ' '))}</strong></div>
            </div>
            ${renderMaintenanceAmountAdjustmentPanel(req)}
            ${linkedAcctBanner}
            ${approvalBanner}
            ${followUpBanner}
            ${returnReqBanner}
            ${req.notes ? `<p style="font-size:12px"><strong>${t('ملاحظات الطلب', 'Request notes')}:</strong> ${escHtml(req.notes)}</p>` : ''}
            <h5 style="margin:12px 0 6px">${t('تفاصيل البنود', 'Item details')}</h5>
            <table class="data-table" style="width:100%;font-size:12px"><thead><tr><th>${t('البند', 'Item')}</th><th>${t('عدد', 'Qty')}</th><th>${t('مواد', 'Mat.')}</th><th>${t('عامل', 'Labor')}</th><th>${t('المسؤول', 'Assignee')}</th><th>${t('إجمالي', 'Total')}</th></tr></thead><tbody>${itemsHtml}</tbody></table>
            ${completionAttHtml}
            ${renderMaintenanceLinkedTaskBannerHtml(req)}
            <h5 style="margin:12px 0 6px">${t('سجل الحركات والمتابعة / Activity & follow-up log', 'Activity & follow-up log / سجل الحركات')}</h5>
            <div>${eventsHtml}</div>`;
        modal.classList.add('open');
    }

    function closeMaintenanceDetailModal() {
        document.getElementById('maintenanceDetailModal')?.classList.remove('open');
        const headActions = document.getElementById('maintenanceDetailHeadActions');
        if (headActions) headActions.innerHTML = '';
    }

    function renderMaintenanceWorkspace() {
        const host = document.getElementById('maintenancePanelHost');
        if (!host) return;
        if (!canAccessMaintenanceWorkspace()) {
            host.innerHTML = `<div class="insight-nested" style="padding:16px;border:1px solid #e8c4c4;background:#fff8f8;border-radius:10px">
                <p style="margin:0;font-weight:700">${t('صلاحية مطلوبة', 'Permission required')}</p>
            </div>`;
            return;
        }
        const portalOnly = effectivePermission('request_maintenance') && !effectivePermission('manage_maintenance');
        if (portalOnly) {
            const scope = getPortalScopedBuildingUnit();
            if (scope.building) _maintenanceUiState.building = scope.building;
            if (scope.unit) _maintenanceUiState.unit = scope.unit;
        }
        const reg = loadMaintenanceRegistry();
        const rows = reg.requests.filter(maintenanceMatchesFilter).filter(maintenanceVisibleToCurrentUser).sort((a, b) => toStr(b.createdAt).localeCompare(toStr(a.createdAt)));
        const pendingApproval = rows.filter((r) => r.status === 'pending_approval').length;
        const pending = rows.filter((r) => r.status === 'pending').length;
        const inProg = rows.filter((r) => r.status === 'in_progress').length;
        const completed = rows.filter((r) => r.status === 'completed').length;
        const canManage = effectivePermission('manage_maintenance');
        host.innerHTML = `
            <div class="accounting-summary" style="margin-bottom:14px">
                ${canManage ? `
                <div class="accounting-summary-card"><small>${t('موافقة الإدارة', 'Mgmt approval')}</small><strong>${pendingApproval}</strong></div>
                <div class="accounting-summary-card"><small>${t('معلق', 'Pending')}</small><strong>${pending}</strong></div>
                <div class="accounting-summary-card"><small>${t('قيد التنفيذ', 'In progress')}</small><strong>${inProg}</strong></div>
                <div class="accounting-summary-card"><small>${t('مكتمل', 'Completed')}</small><strong>${completed}</strong></div>
                ` : `<div class="accounting-summary-card" style="grid-column:1/-1"><small>${t('طلبات صيانتي', 'My maintenance requests')}</small><strong>${rows.length}</strong></div>`}
            </div>
            <div class="accounting-filter-panel">
                ${canManage ? `
                <input type="search" placeholder="${t('بحث', 'Search')}" value="${escHtml(_maintenanceUiState.search)}" oninput="_maintenanceUiState.search=this.value;renderMaintenanceWorkspace()" style="min-width:160px">
                <input type="text" placeholder="${t('مبنى', 'Building')}" value="${escHtml(_maintenanceUiState.building)}" oninput="_maintenanceUiState.building=this.value;renderMaintenanceWorkspace()" style="width:80px">
                <input type="text" placeholder="${t('وحدة', 'Unit')}" value="${escHtml(_maintenanceUiState.unit)}" oninput="_maintenanceUiState.unit=this.value;renderMaintenanceWorkspace()" style="width:70px">
                <input type="text" placeholder="${t('مستأجر', 'Tenant')}" value="${escHtml(_maintenanceUiState.tenant)}" oninput="_maintenanceUiState.tenant=this.value;renderMaintenanceWorkspace()" style="width:100px">
                <select onchange="_maintenanceUiState.status=this.value;renderMaintenanceWorkspace()">
                    <option value="">${t('كل الحالات', 'All statuses')}</option>
                    ${MAINTENANCE_STATUSES.map((s) => `<option value="${s}" ${_maintenanceUiState.status === s ? 'selected' : ''}>${escHtml(maintenanceStatusLabel(s))}</option>`).join('')}
                </select>
                ` : ''}
                <button type="button" class="btn-primary mini-btn" onclick="openMaintenanceRequestModal()">${t('طلب جديد', 'New request')}</button>
                ${canManage ? `<button type="button" class="btn-outline mini-btn" onclick="openMaintenanceCatalogModal()">${t('بنود الصيانة', 'Maintenance items')}</button>` : ''}
            </div>
            ${rows.length ? rows.map((r) => {
                const rid = escHtml(r.id);
                const bEsc = escHtml(r.building).replace(/'/g, "\\'");
                const uEsc = escHtml(r.unit).replace(/'/g, "\\'");
                const unitCtx = resolveMaintenanceUnitContext(r.building, r.unit);
                const tenantLine = unitCtx.isRented ? unitCtx.tenantDisplay : t('شاغر', 'Vacant');
                const returnBadge = r.returnRequested ? ` <span class="mnt-status-chip mnt-status-pending">${t('طلب استرجاع', 'Return req.')}</span>` : '';
                return `<div class="mnt-request-card" onclick="openMaintenanceDetailModal('${rid}')">
                    <div style="display:flex;justify-content:space-between;gap:8px;flex-wrap:wrap">
                        <strong>${escHtml(r.building)} — <span class="acct-unit-link" onclick="event.stopPropagation();openMaintenanceDetailModal('${rid}')">${escHtml(r.unit)}</span></strong>
                        <span>${maintenanceStatusChip(r.status, r.linkedToAccounting)}${returnBadge}</span>
                    </div>
                    <small style="display:block;color:#666;margin-top:4px">${escHtml(r.requestNo)} · ${escHtml(tenantLine)} · ${escHtml(summaryAmtOm(maintenanceRequestTotal(r)))}</small>
                    ${r.statusNote ? `<small style="display:block;color:#888;margin-top:2px">${escHtml(r.statusNote)}</small>` : ''}
                    <small style="display:block;color:#888;margin-top:2px">${escHtml(toStr(r.createdAt).slice(0, 16).replace('T', ' '))} — ${escHtml(r.createdBy || '—')}</small>
                </div>`;
            }).join('') : `<p style="color:#666;text-align:center;padding:24px">${t('لا توجد طلبات صيانة.', 'No maintenance requests.')}</p>`}`;
    }

    function openMaintenanceWorkspace() {
        if (!canAccessMaintenanceWorkspace()) {
            assertPermissionOrAlert('request_maintenance', 'لا تملك صلاحية الصيانة.', 'No maintenance permission.');
            return;
        }
        setWorkspaceMode('maintenance');
    }

    function openMaintenanceWorkspaceForUnit(building, unit) {
        _maintenanceUiState.building = toStr(building);
        _maintenanceUiState.unit = toStr(unit);
        openMaintenanceWorkspace();
    }

    function renderAccountingMaintenanceTab() {
        const reg = loadMaintenanceRegistry();
        const rows = reg.requests.slice().sort((a, b) => toStr(b.createdAt).localeCompare(toStr(a.createdAt)));
        return `<div class="table-wrap"><table class="data-table" style="width:100%;font-size:12px">
            <thead><tr>
                <th>${t('رقم الطلب', 'Request')}</th><th>${t('مبنى', 'Bld')}</th><th>${t('وحدة', 'Unit')}</th>
                <th>${t('مستأجر', 'Tenant')}</th><th>${t('المبلغ', 'Amount')}</th><th>${t('الحالة', 'Status')}</th>
                <th>${t('محاسبة', 'Accounting')}</th><th>${t('إجراء', 'Action')}</th>
            </tr></thead>
            <tbody>${rows.length ? rows.map((r) => {
                const rid = escHtml(r.id);
                const rawId = escAttr(r.id);
                const total = maintenanceRequestTotal(r);
                const inv = getMaintenanceAccountingInvoice(r);
                const invNo = inv ? escHtml(inv.invoiceNo || inv.id) : '';
                const hasInvoice = !!(inv || r.accountingInvoiceId);
                const draftAmt = _maintenanceAcctDraftAmounts[r.id];
                const displayAmt = draftAmt != null && toStr(draftAmt).trim() !== '' ? toStr(draftAmt) : String(total);
                return `<tr>
                    <td>${escHtml(r.requestNo)}</td>
                    <td>${escHtml(r.building)}</td>
                    <td>${escHtml(r.unit)}</td>
                    <td>${escHtml(r.tenant || '—')}</td>
                    <td>
                        <input type="text" inputmode="decimal" autocomplete="off" id="mntAcctAmt_${rid}" value="${escHtml(displayAmt)}" style="width:90px;font-size:11px" onclick="event.stopPropagation()" onkeydown="event.stopPropagation()" oninput="onMaintenanceAcctAmountInput('${rawId}', this.value); event.stopPropagation()">
                    </td>
                    <td>${maintenanceStatusChip(r.status, r.linkedToAccounting)}</td>
                    <td>${r.linkedToAccounting ? t('مربوط', 'Linked') : t('غير مربوط', 'Not linked')}${invNo ? `<div style="font-size:10px;color:#666;margin-top:2px">${t('فاتورة', 'Invoice')}: ${invNo}</div>` : ''}</td>
                    <td style="min-width:220px">
                        <button type="button" class="btn-outline mini-btn" onclick="adjustMaintenanceAmountByAccountant('${rid}', document.getElementById('mntAcctAmt_${rid}').value)">${t('تعديل المبلغ', 'Adjust')}</button>
                        ${!r.linkedToAccounting && r.status === 'completed' ? `<button type="button" class="btn-primary mini-btn" onclick="linkMaintenanceToAccounting('${rid}')">${t('ربط بالحسابات', 'Link')}</button>` : ''}
                        ${r.linkedToAccounting ? `<button type="button" class="btn-outline mini-btn" style="color:#b71c1c;border-color:#ef9a9a" onclick="unlinkMaintenanceFromAccounting('${rid}')">${t('فك الربط', 'Unlink')}</button>` : ''}
                        ${r.linkedToAccounting && hasInvoice ? `
                            <button type="button" class="btn-outline mini-btn" onclick="printMaintenanceInvoiceByRequest('${rid}')">${t('طباعة الفاتورة', 'Print invoice')}</button>
                            <button type="button" class="btn-outline mini-btn" onclick="shareMaintenanceInvoiceWhatsApp('${rid}')">${t('واتساب', 'WhatsApp')}</button>
                            <button type="button" class="btn-outline mini-btn" onclick="shareMaintenanceInvoiceEmail('${rid}')">${t('بريد', 'Email')}</button>` : ''}
                        ${r.linkedToAccounting && !hasInvoice ? `<button type="button" class="btn-primary mini-btn" onclick="issueMaintenanceInvoiceForRequest('${rid}')">${t('إصدار فاتورة', 'Issue invoice')}</button>` : ''}
                        <button type="button" class="btn-outline mini-btn" onclick="openMaintenanceDetailModal('${rid}')">${t('تفاصيل', 'Details')}</button>
                    </td>
                </tr>`;
            }).join('') : `<tr><td colspan="8" style="text-align:center;padding:16px;color:#666">${t('لا توجد طلبات صيانة', 'No maintenance requests')}</td></tr>`}</tbody>
        </table>
        <p style="margin:10px 0 0;font-size:11px;color:#666">${t('ملاحظة: مبالغ الصيانة لا تنعكس في المحاسبة إلا بعد الضغط على «ربط بالحسابات».', 'Note: maintenance amounts are not reflected in accounting until you click «Link to accounts».')}</p></div>`;
    }

    function renderUnitDetailsMaintenanceSection(unit) {
        if (!unit) return '';
        const reqs = getMaintenanceRequestsForUnit(unit.building, unit.unit).slice().sort((a, b) => toStr(b.createdAt).localeCompare(toStr(a.createdAt)));
        const bEsc = escHtml(unit.building).replace(/'/g, "\\'");
        const uEsc = escHtml(unit.unit).replace(/'/g, "\\'");
        const rows = reqs.length
            ? reqs.slice(0, 8).map((r) => {
                const rid = escHtml(r.id);
                const b = maintenanceAmountBreakdown(r);
                const amountCell = b.hasAccountantAdjustment
                    ? `<div>${escHtml(summaryAmtOm(b.finalTotal))}</div><small style="color:#888">${t('أصلي', 'Orig.')}: ${escHtml(summaryAmtOm(b.originalTotal))}${b.hasDiscount ? ` · ${t('تخفيض', 'Disc.')}: ${escHtml(summaryAmtOm(b.discountAmount))}` : ''}</small>`
                    : escHtml(summaryAmtOm(maintenanceRequestTotal(r)));
                const receiptBtn = r.linkedToAccounting
                    ? `<button type="button" class="btn-outline mini-btn" onclick="event.stopPropagation();printMaintenanceReceipt('${rid}')">${t('طباعة الإيصال', 'Print receipt')}</button>`
                    : '—';
                return `<tr onclick="openMaintenanceDetailModal('${rid}')" style="cursor:pointer">
                <td>${escHtml(r.requestNo)}</td><td>${escHtml(toStr(r.createdAt).slice(0, 10))}</td>
                <td>${escHtml(r.tenant || '—')}</td><td>${amountCell}</td>
                <td>${maintenanceStatusChip(r.status, r.linkedToAccounting)}</td>
                <td onclick="event.stopPropagation()">${receiptBtn}</td>
            </tr>`;
            }).join('')
            : `<tr><td colspan="6" style="text-align:center;color:#666">${t('لا توجد طلبات صيانة', 'No maintenance requests')}</td></tr>`;
        return `
            <div class="details-section">
                <h5>${t('الصيانة', 'Maintenance')}</h5>
                <table class="data-table" style="width:100%;font-size:11px">
                    <thead><tr><th>${t('رقم الطلب', 'Request')}</th><th>${t('التاريخ', 'Date')}</th><th>${t('المستأجر', 'Tenant')}</th><th>${t('المبلغ', 'Amount')}</th><th>${t('الحالة', 'Status')}</th><th>${t('إجراء', 'Action')}</th></tr></thead>
                    <tbody>${rows}</tbody>
                </table>
                <div style="margin-top:10px;display:flex;gap:8px;flex-wrap:wrap">
                    <button type="button" class="btn-outline mini-btn" onclick="openMaintenanceRequestModal({building:'${bEsc}',unit:'${uEsc}'})">${t('طلب صيانة جديد', 'New maintenance')}</button>
                    <button type="button" class="btn-outline mini-btn" onclick="openMaintenanceWorkspaceForUnit('${bEsc}','${uEsc}')">${t('فتح نظام الصيانة', 'Open maintenance')}</button>
                </div>
            </div>`;
    }

    function renderUnitDetailsAllOperationsSection(unit) {
        if (!unit) return '';
        const ops = [];
        getMaintenanceRequestsForUnit(unit.building, unit.unit).forEach((r) => {
            ops.push({
                sort: toStr(r.completedAt || r.createdAt),
                typeAr: 'صيانة',
                typeEn: 'Maintenance',
                ref: r.requestNo,
                amount: summaryAmtOm(maintenanceRequestTotal(r)),
                status: maintenanceStatusLabel(r.status),
                staff: r.completedBy || r.createdBy || '—',
                tenant: r.tenant || '—'
            });
        });
        try {
            getAccountingChequesForUnit(unit.building, unit.unit).filter((c) => isAccountingChequePaidStatus(c.status)).slice(0, 5).forEach((c) => {
                ops.push({
                    sort: toStr(c.lastActionDate || c.dueDate),
                    typeAr: 'محاسبة — شيك',
                    typeEn: 'Accounting — cheque',
                    ref: c.chequeNo || '—',
                    amount: summaryAmtOm(c.paidAmount || c.amount),
                    status: accountingChequeStatusLabel(c.status),
                    staff: '—',
                    tenant: c.tenant || '—'
                });
            });
        } catch (_eAcctOps) {}
        ops.sort((a, b) => toStr(b.sort).localeCompare(toStr(a.sort)));
        const rows = ops.length
            ? ops.map((o) => `<tr><td>${escHtml(o.typeAr)} / ${escHtml(o.typeEn)}</td><td>${escHtml(o.ref)}</td><td>${escHtml(o.tenant)}</td><td>${escHtml(o.amount)}</td><td>${escHtml(o.status)}</td><td>${escHtml(o.staff)}</td><td>${escHtml(o.sort || '—')}</td></tr>`).join('')
            : `<tr><td colspan="7" style="text-align:center;color:#666">${t('لا توجد عمليات مسجلة', 'No recorded operations')}</td></tr>`;
        return `
            <div class="details-section">
                <h5>${t('سجل العمليات على العقار / Property operations log', 'Property operations log / سجل العمليات')}</h5>
                <p style="margin:0 0 8px;font-size:11px;color:#666">${t('محاسبة وصيانة وغيرها — مرتبطة بالمستأجر والوحدة', 'Accounting, maintenance, and more — linked to tenant and unit')}</p>
                <table class="data-table" style="width:100%;font-size:11px">
                    <thead><tr><th>${t('النوع', 'Type')}</th><th>${t('المرجع', 'Ref')}</th><th>${t('المستأجر', 'Tenant')}</th><th>${t('المبلغ', 'Amount')}</th><th>${t('الحالة', 'Status')}</th><th>${t('الموظف', 'Staff')}</th><th>${t('التاريخ', 'Date')}</th></tr></thead>
                    <tbody>${rows}</tbody>
                </table>
            </div>`;
    }

    function openNotificationsWorkspace() {
        if (isViewerMode) return;
        if (!usersRegistryHasRows()) {
            setWorkspaceMode('notifications');
            return;
        }
        const u = getLoggedInUser();
        if (!u) {
            openAuthLoginModal();
            return;
        }
        if (!canAccessNotificationsPage()) {
            alert(
                t(
                    'لا تملك صلاحية عرض صفحة التنبيهات.',
                    'You do not have permission to view the notifications page.'
                )
            );
            return;
        }
        setWorkspaceMode('notifications');
    }

    function renderUserPermissionChecksHtml(userObj) {
        return renderUserModuleAccessGridHtml(userObj);
    }

    function renderUserModuleAccessGridHtml(userObj) {
        const nu = userObj ? normalizeUserRecord({ ...userObj }) : { moduleAccess: defaultModuleAccessAllApprove() };
        const ma = getUserModuleAccess(nu);
        const levelHdr = BHD_ACCESS_LEVELS.map(
            (lv) => `<th>${t(lv.labelAr, lv.labelEn)}</th>`
        ).join('');
        const rows = BHD_MODULE_GROUPS.map((g) => {
            const mods = BHD_MODULE_DEFS.filter((m) => m.group === g.key);
            if (!mods.length) return '';
            const modRows = mods
                .map((m) => {
                    const cur = normalizeModuleAccessLevel(ma[m.key]);
                    const cells = BHD_ACCESS_LEVELS.map((lv) => {
                        const checked = cur === lv.key ? 'checked' : '';
                        return `<td><input type="radio" name="mod_${escAttr(m.key)}" data-module-key="${escAttr(m.key)}" data-access-level="${escAttr(lv.key)}" ${checked}></td>`;
                    }).join('');
                    return `<tr><td>${t(m.labelAr, m.labelEn)}</td>${cells}</tr>`;
                })
                .join('');
            return `<tr class="users-module-group-row"><td colspan="${BHD_ACCESS_LEVELS.length + 1}">${t(g.labelAr, g.labelEn)}</td></tr>${modRows}`;
        }).join('');
        return `<div class="users-module-access-wrap">
            <table class="users-module-access-table">
                <thead><tr><th>${t('النافذة / الوحدة', 'Module')}</th>${levelHdr}</tr></thead>
                <tbody>${rows}</tbody>
            </table>
        </div>`;
    }

    function renderApprovalWorkflowSettingsHtml() {
        const wf = { ...getDefaultApprovalWorkflows(), ...loadApprovalWorkflows() };
        const mkSelect = (fieldKey, labelAr, labelEn) => {
            const opts = BHD_APPROVAL_WORKFLOW_PRESETS.map((p) => {
                const sel = wf[fieldKey] === p.key ? 'selected' : '';
                return `<option value="${escAttr(p.key)}" ${sel}>${t(p.labelAr, p.labelEn)}</option>`;
            }).join('');
            return `<div style="display:flex;flex-direction:column;gap:4px">
                <label style="font-size:12px;font-weight:700">${t(labelAr, labelEn)}</label>
                <select data-workflow-key="${escAttr(fieldKey)}" onchange="saveApprovalWorkflowsFromForm()">${opts}</select>
            </div>`;
        };
        return `<div class="users-workflow-settings">
            <div style="font-size:13px;font-weight:700;margin-bottom:4px">${t('سير اعتماد المحاسبة', 'Accounting approval workflow')}</div>
            <p style="font-size:11px;color:#666;margin:0 0 8px;line-height:1.5">${t('يُطبَّق بالترتيب على المعاملات الجديدة وطلبات التعديل والحذف.', 'Applied in order to new transactions and edit/delete requests.')}</p>
            <div class="users-workflow-grid">
                ${mkSelect('accounting_entry', 'معاملة جديدة', 'New transaction')}
                ${mkSelect('accounting_edit', 'طلب تعديل', 'Edit request')}
                ${mkSelect('accounting_delete', 'طلب حذف', 'Delete request')}
            </div>
        </div>`;
    }

    function saveApprovalWorkflowsFromForm() {
        const next = { ...getDefaultApprovalWorkflows(), ...loadApprovalWorkflows() };
        document.querySelectorAll('[data-workflow-key]').forEach((sel) => {
            const k = sel.getAttribute('data-workflow-key');
            if (k) next[k] = toStr(sel.value) || next[k];
        });
        saveApprovalWorkflows(next);
    }

    function collectModuleAccessFromForm() {
        const ma = defaultModuleAccessNone();
        const grid = document.getElementById('userPermGrid');
        if (!grid) return ma;
        grid.querySelectorAll('input[data-module-key]:checked').forEach((inp) => {
            const k = inp.getAttribute('data-module-key');
            if (k) ma[k] = normalizeModuleAccessLevel(inp.getAttribute('data-access-level'));
        });
        return ma;
    }

    function renderUserPermissionBadges(userObj) {
        const nu = normalizeUserRecord(userObj);
        const ma = getUserModuleAccess(nu);
        const active = BHD_MODULE_DEFS.filter((m) => moduleAccessOrder(ma[m.key]) > 0);
        if (!active.length) return '—';
        return active
            .slice(0, 5)
            .map((m) => {
                const lvl = normalizeModuleAccessLevel(ma[m.key]);
                const lv = BHD_ACCESS_LEVELS.find((x) => x.key === lvl);
                const lvLbl = lv ? t(lv.labelAr, lv.labelEn) : lvl;
                return `<span class="users-badge" title="${escHtml(lvLbl)}">${escHtml(t(m.labelAr, m.labelEn))}</span>`;
            })
            .join('') + (active.length > 5 ? `<span class="users-badge">+${active.length - 5}</span>` : '');
    }

    function getUsersListFiltered() {
        const q = toStr(usersEditorState.listSearch).toLowerCase();
        return usersRegistry
            .map((u) => normalizeUserRecord(u))
            .filter((nu) => {
                if (!q) return true;
                const hay = [
                    nu.userNo,
                    nu.username,
                    nu.displayName,
                    nu.email,
                    nu.phone,
                    nu.contactType,
                    getUserRoleLabel(nu.role),
                    addressBookTypeLabel(nu.contactType)
                ]
                    .join(' ')
                    .toLowerCase();
                return hay.includes(q);
            });
    }

    function importUsersFromAddressBook() {
        if (!canAccessUserManagementPage()) return;
        reloadUsersRegistryFromStorageForAuth();
        let created = 0;
        let skipped = 0;
        (addressBookEntries || []).forEach((entry, idx) => {
            const key = addressBookEntryKey(entry);
            if (findUserByAddressBookKey(key)) {
                skipped += 1;
                return;
            }
            const u = provisionUserFromAddressBookEntry(entry, { entryIndex: idx });
            if (u) created += 1;
        });
        localStorage.setItem('bhd_address_book', JSON.stringify(addressBookEntries));
        persistAuthOnly();
        renderUsersManagementPage();
        alert(
            t(
                `تم استيراد ${created} مستخدماً جديداً، وتخطي ${skipped} مرتبط مسبقاً.`,
                `Imported ${created} new users; skipped ${skipped} already linked.`
            )
        );
    }

    function onUserContactTypePresetChange(applyPreset) {
        const ctEl = document.getElementById('userContactTypeSelect');
        if (!ctEl || applyPreset !== true) return;
        const perms = presetPermissionsForContactType(toStr(ctEl.value) || 'tenant');
        const roleEl = document.getElementById('userRoleSelect');
        if (roleEl) roleEl.value = contactTypeToRole(ctEl.value);
        applyUserModuleAccessToGrid(deriveModuleAccessFromLegacyPermissions(perms));
    }

