    function onOrganizationLogoFileSelected(ev) {
        const file = ev?.target?.files?.[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = () => {
            const dataUrl = toStr(reader.result);
            const img = document.querySelector('#orgLogoPreview img');
            if (img) img.src = dataUrl;
            const host = document.getElementById('organizationPanelHost');
            if (host) host.dataset.pendingLogoDataUrl = dataUrl;
            if (host) host.dataset.pendingLogoFileName = file.name || 'logo.png';
        };
        reader.readAsDataURL(file);
    }

    function clearOrganizationLogo() {
        const host = document.getElementById('organizationPanelHost');
        if (host) {
            host.dataset.pendingLogoDataUrl = '';
            host.dataset.pendingLogoFileName = '';
            host.dataset.clearLogo = '1';
        }
        const img = document.querySelector('#orgLogoPreview img');
        if (img) img.src = getPrintLogoSrc();
        const fileInp = document.getElementById('orgLogoFileInput');
        if (fileInp) fileInp.value = '';
    }

    function saveOrganizationSettingsFromForm() {
        const host = document.getElementById('organizationPanelHost');
        const pendingLogo = host ? toStr(host.dataset.pendingLogoDataUrl) : '';
        const pendingLogoName = host ? toStr(host.dataset.pendingLogoFileName) : '';
        const clearLogo = host && host.dataset.clearLogo === '1';
        const prev = loadOrganizationSettings();
        const next = saveOrganizationSettings({
            nameAr: toStr(document.getElementById('orgNameArInput')?.value),
            nameEn: toStr(document.getElementById('orgNameEnInput')?.value),
            email: toStr(document.getElementById('orgEmailInput')?.value),
            website: toStr(document.getElementById('orgWebsiteInput')?.value),
            crNumber: toStr(document.getElementById('orgCrInput')?.value),
            linesAr: toStr(document.getElementById('orgLinesArInput')?.value),
            linesEn: toStr(document.getElementById('orgLinesEnInput')?.value),
            addressAr: toStr(document.getElementById('orgAddressArInput')?.value),
            addressEn: toStr(document.getElementById('orgAddressEnInput')?.value),
            logoDataUrl: clearLogo ? '' : pendingLogo !== '' ? pendingLogo : prev.logoDataUrl,
            logoFileName: clearLogo ? 'BHD_Logo_04.png' : pendingLogoName || prev.logoFileName
        });
        if (host) {
            delete host.dataset.pendingLogoDataUrl;
            delete host.dataset.pendingLogoFileName;
            delete host.dataset.clearLogo;
        }
        renderOrganizationSettingsPage();
        alert(t('تم حفظ إعدادات المنشأة.', 'Organization settings saved.'));
        return next;
    }

