    function selectBusinessDocTemplate(key) {
        _activeBusinessDocTemplateKey = toStr(key) || 'invoice';
        renderDocumentTemplatesPage();
    }

    function saveBusinessDocTemplateFromEditor() {
        const key = _activeBusinessDocTemplateKey || 'invoice';
        const html = toStr(document.getElementById('businessDocTemplateEditor')?.value);
        if (!html.trim()) {
            alert(t('محتوى القالب فارغ.', 'Template content is empty.'));
            return;
        }
        setBusinessDocTemplateHtml(key, html, { isCustom: true });
        renderDocumentTemplatesPage();
        alert(t('تم حفظ القالب.', 'Template saved.'));
    }

    function triggerBusinessDocTemplateImport() {
        document.getElementById('businessDocTemplateImportInput')?.click();
    }

    function onBusinessDocTemplateImportSelected(ev) {
        const file = ev?.target?.files?.[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = () => {
            let raw = toStr(reader.result);
            const bodyMatch = raw.match(/<body[^>]*>([\s\S]*)<\/body>/i);
            if (bodyMatch) raw = bodyMatch[1];
            const key = _activeBusinessDocTemplateKey || 'invoice';
            setBusinessDocTemplateHtml(key, raw, { isCustom: true, importedFrom: file.name || 'import.html' });
            renderDocumentTemplatesPage();
            alert(t('تم استيراد القالب.', 'Template imported.'));
        };
        reader.readAsText(file, 'UTF-8');
        ev.target.value = '';
    }

    function resetActiveBusinessDocTemplate() {
        const key = _activeBusinessDocTemplateKey || 'invoice';
        if (!confirm(t('استعادة القالب الافتراضي لهذا النوع؟', 'Reset this template to default?'))) return;
        resetBusinessDocTemplate(key);
        renderDocumentTemplatesPage();
    }

    function printActiveBusinessDocTemplate() {
        const key = _activeBusinessDocTemplateKey || 'invoice';
        const html = getBusinessDocTemplateHtml(key);
        const def = BHD_BUSINESS_DOC_TEMPLATE_DEFS.find((x) => x.key === key);
        printWithSiteStandard(
            def ? { ar: def.labelAr, en: def.labelEn } : { ar: key, en: key },
            documentShellPrint(html)
        );
    }

