    function refreshDashboardIfVisible() {
        if (isViewerMode) return;
        try {
            if (document.body.classList.contains('mode-dashboard')) {
                renderOperationsTable();
                renderRegistryTable();
                try { renderDashboardCalendar(); } catch (_eCal) {}
            }
        } catch (_eDashRefresh) {
            console.warn('refreshDashboardIfVisible', _eDashRefresh);
        }
    }

    function loadDashboardAux(force) {
        const now = Date.now();
        if (!force && _loadDashboardAuxLastAt && now - _loadDashboardAuxLastAt < 2500) return;
        _loadDashboardAuxLastAt = now;
        try {
            const rawBuildings = localStorage.getItem('bhd_buildings_list');
            const savedBuildings = JSON.parse(rawBuildings || '[]');
            if (Array.isArray(savedBuildings) && rawBuildings !== null) {
                buildingsList.splice(0, buildingsList.length, ...savedBuildings.map((x) => toStr(x)).filter(Boolean));
            }
        } catch (e) {}
        try {
            const rawOwners = localStorage.getItem('bhd_owners_list');
            const savedOwners = JSON.parse(rawOwners || '[]');
            if (Array.isArray(savedOwners) && rawOwners !== null) {
                ownersList.splice(0, ownersList.length, ...savedOwners.map((x) => toStr(x)).filter(Boolean));
            }
        } catch (e) {}
        try {
            unitReservations = JSON.parse(localStorage.getItem('bhd_unit_reservations') || '[]');
            if (!Array.isArray(unitReservations)) unitReservations = [];
            try {
                migrateUnitReservationsMultiUnit();
            } catch (_eMigRes) {}
            try {
                if (repairReservationMultiUnitRows()) {
                    localStorage.setItem('bhd_unit_reservations', JSON.stringify(unitReservations));
                }
            } catch (_eRepResMu) {}
        } catch (e) {
            unitReservations = [];
        }
        try {
            reservationCancellationLog = JSON.parse(localStorage.getItem('bhd_reservation_cancellations') || '[]');
            if (!Array.isArray(reservationCancellationLog)) reservationCancellationLog = [];
        } catch (e) {
            reservationCancellationLog = [];
        }
        try {
            evictionRequests = JSON.parse(localStorage.getItem('bhd_eviction_requests') || '[]');
            if (!Array.isArray(evictionRequests)) evictionRequests = [];
        } catch (e) {
            evictionRequests = [];
        }
        try {
            ownerBuildingMap = JSON.parse(localStorage.getItem('bhd_owner_building_map') || '{}');
            if (!ownerBuildingMap || typeof ownerBuildingMap !== 'object') ownerBuildingMap = {};
        } catch (e) {
            ownerBuildingMap = {};
        }
        try {
            buildingProfiles = JSON.parse(localStorage.getItem('bhd_building_profiles') || '{}');
            if (!buildingProfiles || typeof buildingProfiles !== 'object') buildingProfiles = {};
            Object.keys(buildingProfiles).forEach((k) => {
                if (buildingProfiles[k] && typeof buildingProfiles[k] === 'object') {
                    buildingProfiles[k].buildingStatus = normalizeBuildingStatus(buildingProfiles[k].buildingStatus);
                }
            });
            buildingProfilesShadow = { ...buildingProfiles };
            try {
                if (repairOversizedBuildingProfilesInMemory()) {
                    localStorage.setItem('bhd_building_profiles', JSON.stringify(buildingProfiles));
                }
            } catch (_eRepairBp) {}
        } catch (e) {
            buildingProfiles = {};
        }
        try {
            ownerProfiles = JSON.parse(localStorage.getItem('bhd_owner_profiles') || '{}');
            if (!ownerProfiles || typeof ownerProfiles !== 'object') ownerProfiles = {};
        } catch (e) {
            ownerProfiles = {};
        }
        try {
            addressBookEntries = JSON.parse(localStorage.getItem('bhd_address_book') || '[]');
            if (!Array.isArray(addressBookEntries)) addressBookEntries = [];
        } catch (e) {
            addressBookEntries = [];
        }
        try {
            seedLearnedNamePairsFromExistingData();
        } catch (_eSeedNames) {}
        try {
            managedUnitsData = JSON.parse(localStorage.getItem('bhd_managed_units') || '[]');
            if (!Array.isArray(managedUnitsData)) managedUnitsData = [];
        } catch (e) {
            managedUnitsData = [];
        }
        if (buildingProfiles && typeof buildingProfiles === 'object') {
            try {
                syncManagedUnitsFromProfiles();
                localStorage.setItem('bhd_managed_units', JSON.stringify(managedUnitsData));
            } catch (e) {}
        }
        try {
            usersRegistry = JSON.parse(localStorage.getItem('bhd_users_registry') || '[]');
            if (!Array.isArray(usersRegistry)) usersRegistry = [];
        } catch (e) {
            usersRegistry = [];
        }
        try {
            ensureDefaultBhdAdminAccount();
        } catch (eEnsAdmin) {}
        try {
            authSession = JSON.parse(localStorage.getItem('bhd_auth_session') || 'null');
            if (!authSession || typeof authSession !== 'object') authSession = null;
        } catch (e) {
            authSession = null;
        }
        validateAuthSession();
        scheduleAutomaticDataSync(false);
    }

    function scheduleAppBackgroundMaintenance() {
        scheduleAutomaticDataSync(true);
    }

    function saveDashboardAux() {
        sanitizeAllUnitReservationRowsForStorage();
        bumpUnitsDataCache();
        localStorage.setItem('bhd_buildings_list', JSON.stringify(buildingsList));
        localStorage.setItem('bhd_unit_reservations', JSON.stringify(unitReservations));
        localStorage.setItem('bhd_reservation_cancellations', JSON.stringify(reservationCancellationLog));
        localStorage.setItem('bhd_eviction_requests', JSON.stringify(evictionRequests));
        localStorage.setItem('bhd_owner_building_map', JSON.stringify(ownerBuildingMap));
        localStorage.setItem('bhd_building_profiles', JSON.stringify(buildingProfiles));
        localStorage.setItem('bhd_owner_profiles', JSON.stringify(ownerProfiles));
        localStorage.setItem('bhd_address_book', JSON.stringify(addressBookEntries));
        localStorage.setItem('bhd_managed_units', JSON.stringify(managedUnitsData));
        localStorage.setItem('bhd_users_registry', JSON.stringify(usersRegistry));
        localStorage.setItem('bhd_auth_session', JSON.stringify(authSession));
        syncBhdKvToServer();
        scheduleBhdCloudSyncAll(300);
    }

    async function flushBhdPropertyPersistenceNow() {
        syncManagedUnitsFromProfiles();
        localStorage.setItem('bhd_building_profiles', JSON.stringify(buildingProfiles));
        localStorage.setItem('bhd_buildings_list', JSON.stringify(buildingsList));
        localStorage.setItem('bhd_owner_building_map', JSON.stringify(ownerBuildingMap));
        localStorage.setItem('bhd_managed_units', JSON.stringify(managedUnitsData));
        await mirrorKvFromLocalStorageToIndexedDb();
        await syncBhdKvToServer();
        if (window.__bhdCloudApiActive) {
            try {
                await bhdCloudPushPropertiesNow();
            } catch (_eCloudPush) {}
        }
    }

