        localStorage.setItem('bhd_buildings_list', JSON.stringify([]));
        localStorage.setItem('bhd_unit_reservations', JSON.stringify([]));
        localStorage.setItem('bhd_reservation_cancellations', JSON.stringify([]));
        localStorage.setItem('bhd_eviction_requests', JSON.stringify([]));
        localStorage.setItem('bhd_owner_building_map', JSON.stringify({}));
        localStorage.setItem('bhd_building_profiles', JSON.stringify({}));
        localStorage.setItem('bhd_managed_units', JSON.stringify([]));
        localStorage.setItem('bhd_file_registry', JSON.stringify([]));
