    async function confirmCleanupPassword() {
        syncAuthStateFromStorage();
        const u = getLoggedInUser();
        if (!u) {
            openAuthLoginModal();
            return false;
        }
        if (!effectivePermission('import_export')) {
            alert(
                t('لا تملك صلاحية تصفية البيانات.', 'You do not have permission to run data cleanup.')
            );
            return false;
        }
        const who = toStr(u.displayName) || toStr(u.email) || toStr(u.username) || '—';
        const loginHint = [toStr(u.username), toStr(u.email)].filter(Boolean).join(' / ') || '—';

        if (toStr(u.role) === 'system_admin') {
            const dlg = await showAppConfirmDialog(
                t(
                    `أنت مسجّل دخولك كمسؤول نظام:\n${who}\n(${loginHint})\n\nتأكيد متابعة تصفية البيانات؟`,
                    `You are signed in as system admin:\n${who}\n(${loginHint})\n\nContinue with data cleanup?`
                ),
                t('تأكيد تصفية البيانات', 'Confirm data cleanup')
            );
            return !!dlg.confirmed;
        }

        await reloadUsersRegistryFromAllStoresForAuth();
        const dlg = await showAppPasswordConfirmDialog({
            title: t('تأكيد تصفية البيانات', 'Confirm data cleanup'),
            message: t(
                `أدخل كلمة مرور تسجيل الدخول لحسابك (${who}).\nاسم المستخدم / البريد: ${loginHint}`,
                `Enter your sign-in password for (${who}).\nUsername / email: ${loginHint}`
            ),
            passwordLabel: t('كلمة مرور الدخول', 'Sign-in password')
        });
        if (!dlg.confirmed) return false;
        const pw = toStr(dlg.note);
        if (!pw) {
            alert(t('كلمة المرور مطلوبة.', 'Password is required.'));
            return false;
        }
        if (!verifyPasswordForUserId(u.id, pw)) {
            alert(
                t(
                    `❌ كلمة المرور غير صحيحة لحساب: ${who}\n\n• استخدم نفس كلمة مرور تسجيل الدخول.\n• اسم المستخدم / البريد: ${loginHint}`,
                    `❌ Incorrect password for account: ${who}\n\n• Use the same password as sign-in.\n• Username / email: ${loginHint}`
                )
            );
            return false;
        }
        return true;
    }

    async function runDataCleanup(scope) {
        if (!(await confirmCleanupPassword())) {
            return;
        }
        const scopeConfirm = scope === 'all'
            ? t(
                'سيتم حذف كل بيانات العقود والحجوزات والملاك والمباني ودفتر العناوين من المتصفح وقاعدة SQLite.\n\nيُحتفظ فقط بحسابات المستخدمين والمظهر.\n\nهل أنت متأكد؟',
                'All contracts, reservations, owners, buildings, and address book data will be removed from browser storage and SQLite.\n\nOnly user accounts and theme are kept.\n\nAre you sure?'
            )
            : scope === 'accounting'
              ? t(
                    'سيتم تصفير كل بيانات المحاسبة (الإيرادات، المصروفات، الشيكات، الفواتير، السندات).\n\nهل أنت متأكد؟',
                    'All accounting data will be reset (income, expenses, cheques, invoices, vouchers).\n\nAre you sure?'
                )
              : scope === 'maintenance'
                ? t(
                      'سيتم تصفير كل بيانات الصيانة وطلباتها.\n\nهل أنت متأكد؟',
                      'All maintenance data and requests will be reset.\n\nAre you sure?'
                  )
                : scope === 'tasks'
                  ? t(
                        'سيتم تصفير كل بيانات المهام.\n\nهل أنت متأكد؟',
                        'All tasks data will be reset.\n\nAre you sure?'
                    )
                  : t('تأكيد تنفيذ التصفية؟', 'Confirm cleanup?');
        if (!confirm(scopeConfirm)) return;

        if (scope === 'all') {
            clearDemoContractFormFields();
            buildingsList.length = 0;
            ownersList.length = 0;
            importedUnitsData = [];
            managedUnitsData = [];
            unitReservations = [];
            evictionRequests = [];
            reservationCancellationLog = [];
            ownerBuildingMap = {};
            buildingProfiles = {};
            buildingProfilesShadow = {};
            ownerProfiles = {};
            addressBookEntries = [];
            fileRegistry = [];
            contractEntryContext = { mode: 'contract', unit: null };
            localStorage.setItem('bhd_use_empty_base_units', '1');
        } else if (scope === 'contracts') {
            fileRegistry = [];
        } else if (scope === 'buildings') {
            buildingsList.length = 0;
            importedUnitsData = [];
            managedUnitsData = [];
            ownerBuildingMap = {};
            buildingProfiles = {};
            buildingProfilesShadow = {};
            localStorage.setItem('bhd_use_empty_base_units', '1');
        } else if (scope === 'tenants') {
            addressBookEntries = addressBookEntries.filter((x) => toStr(x.type) === 'owner');
        } else if (scope === 'reservations') {
            unitReservations = [];
            evictionRequests = [];
            reservationCancellationLog = [];
        } else if (scope === 'owners') {
            ownersList.length = 0;
            ownerProfiles = {};
            ownerBuildingMap = {};
            addressBookEntries = addressBookEntries.filter((x) => toStr(x.type) !== 'owner');
        } else if (scope === 'addressbook') {
            addressBookEntries = [];
        } else if (scope === 'accounting') {
            _accountingRegistryCache = null;
            _accountingRegistryCacheRaw = null;
            const emptyAcct = emptyAccountingRegistry();
            try {
                const emptyJson = JSON.stringify(emptyAcct);
                localStorage.setItem(ACCOUNTING_REGISTRY_KEY, emptyJson);
                _accountingRegistryCache = emptyAcct;
                _accountingRegistryCacheRaw = emptyJson;
            } catch (_eAcctEmpty) {}
        } else if (scope === 'maintenance') {
            try {
                localStorage.setItem(MAINTENANCE_REGISTRY_KEY, JSON.stringify(emptyMaintenanceRegistry()));
            } catch (_eMaint) {}
        } else if (scope === 'tasks') {
            try {
                localStorage.setItem(TASKS_REGISTRY_KEY, JSON.stringify(defaultTasksRegistry()));
            } catch (_eTasks) {}
        }

        persistCleanupScopeToLocalStorage(scope);
        const keysToPurge = getBhdKeysForCleanupScope(scope);
        const purgeOpts = scope === 'all'
            ? { wipeAllExcept: BHD_KEYS_KEEP_ON_FULL_WIPE }
            : {};
        try {
            await purgeBhdKeysFromAllStores(keysToPurge, purgeOpts);
            applyEmptyStorageDefaultsForScope(scope);
            persistCleanupScopeToLocalStorage(scope);
            if (scope === 'accounting') {
                const emptyJson = JSON.stringify(emptyAccountingRegistry());
                try {
                    localStorage.setItem(ACCOUNTING_REGISTRY_KEY, emptyJson);
                    _accountingRegistryCache = emptyAccountingRegistry();
                    _accountingRegistryCacheRaw = emptyJson;
                } catch (_eAcctPersist) {}
                if (window.bhdDesktop && window.bhdDesktop.kvPutBulk) {
                    await window.bhdDesktop.kvPutBulk({ [ACCOUNTING_REGISTRY_KEY]: emptyJson });
                } else if (bhdApiAvailable) {
                    await fetch('/api/kv/bulk', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ [ACCOUNTING_REGISTRY_KEY]: emptyJson })
                    });
                }
            }
            if (window.bhdDesktop && !window.bhdDesktop.kvClearKeys && !window.bhdDesktop.kvWipeAllExcept) {
                console.warn('Desktop wipe API missing — restart desktop app');
            }
        } catch (ePurge) {
            console.error('purge failed', ePurge);
            alert(t(
                'تعذّر حذف بعض البيانات من قاعدة التخزين. أعد تشغيل التطبيق وحاول مرة أخرى.',
                'Could not purge all storage layers. Restart the app and try again.'
            ));
            return;
        }

        try {
            await mirrorKvFromLocalStorageToIndexedDb();
            await syncBhdKvToServer();
        } catch (eSync) {}
        try {
            localStorage.setItem('bhd_last_data_wipe', String(Date.now()));
            if (scope === 'all') {
                localStorage.setItem('bhd_hide_demo_units', '1');
                localStorage.setItem('bhd_use_empty_base_units', '1');
            }
        } catch (eW) {}

        closeDataCleanupModal();
        const doneMsg =
            scope === 'accounting'
                ? t(
                      '✅ تم تصفير بيانات المحاسبة. سيتم تحديث الصفحة الآن.',
                      '✅ Accounting data has been reset. The page will refresh now.'
                  )
                : t(
                      '✅ تم حذف البيانات (بما فيها الوحدات التجريبية المضمّنة في البرنامج). سيتم تحديث الصفحة الآن.',
                      '✅ Data wiped (including built-in demo units). The page will refresh now.'
                  );
        alert(doneMsg);
        location.reload();
    }

    function escHtml(s) {
        return String(s ?? '')
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;');
    }

    function escAttr(s) {
        return String(s ?? '')
            .replace(/&/g, '&amp;')
            .replace(/"/g, '&quot;')
            .replace(/</g, '&lt;')
            .replace(/'/g, '&#39;');
    }

    function formatDateTimeDisplay(iso) {
        if (!iso) return '— / —';
        const d = new Date(iso);
        if (Number.isNaN(d.getTime())) return escHtml(String(iso));
        const ar = d.toLocaleString('ar-OM', { dateStyle: 'medium', timeStyle: 'short' });
        const en = d.toLocaleString('en-GB', { dateStyle: 'medium', timeStyle: 'short' });
        return `${escHtml(ar)} · ${escHtml(en)}`;
    }

    /** سجل الحجز لهذه الوحدة / Reservation ledger row for unit */
    function findUnitReservationRecordFromRow(u) {
        if (!u) return null;
        const b = normalizeReservationBuildingKey(u.building);
        const un = normalizeUnit(u.unit);
        if (!b || !un) return null;
        return (
            (unitReservations || []).find(
                (r) => normalizeReservationBuildingKey(r.building) === b && normalizeUnit(r.unit) === un
            ) || null
        );
    }

    function unitHasActiveReservation(building, unit) {
        return !!findUnitReservationRecordFromRow({ building: toStr(building), unit: toStr(unit) });
    }

    function unitHasTenancyDraftForUnit(building, unit) {
        const m = loadTenancyContractDraftsMap();
        return !!getTenancyDraftMapEntry(m, building, unit);
    }

    function unitHasSavedContractForUnit(building, unit) {
        if (getSavedContractMapEntry(loadSavedContractsByUnitMap(), building, unit)) return true;
        try {
            const saved = JSON.parse(localStorage.getItem('bhd_contract_full') || 'null');
            if (!saved || typeof saved !== 'object') return false;
            const match =
                normalizeReservationBuildingKey(saved.buildingNo) === normalizeReservationBuildingKey(building) &&
                normalizeUnit(saved.flatNo) === normalizeUnit(unit);
            return match && (!!saved.contractSavedAt || /^TC-/i.test(toStr(saved.agreementNo)));
        } catch (e) {
            return false;
        }
    }

    function unitIsRentedWithActiveLease(building, unit) {
        const row = getUnitRecordByBuildingUnit(building, unit);
        return !!(row && toStr(row.status).toLowerCase() === 'rented' && unitRowHasActiveTenantLikeBinding(row));
    }

    /** مسار عقد مسموح: حجز نشط، أو مسودة بعد التحويل، أو عقد محفوظ لوحدة مؤجرة فعلياً / Eligible contract workflow only */
    function unitHasEligibleContractWorkflow(building, unit, options = {}) {
        const isRenewal = options.isRenewal === true;
        const b = toStr(building);
        const u = toStr(unit);
        if (!b || !u) return false;
        if (isRenewal) {
            return (
                unitIsRentedWithActiveLease(b, u) ||
                unitHasTenancyDraftForUnit(b, u) ||
                (unitHasSavedContractForUnit(b, u) && unitIsRentedWithActiveLease(b, u))
            );
        }
        if (unitHasTenancyDraftForUnit(b, u)) return true;
        if (unitHasSavedContractForUnit(b, u)) return true;
        return false;
    }

    function isContractsWorkspaceScreenActive() {
        try {
            return !isViewerMode && !!document.body && document.body.classList.contains('mode-contracts');
        } catch (_eCws) {
            return false;
        }
    }

    function isContractWorkspaceUnlockedForCurrentUnit(options = {}) {
        if (isViewerMode) return true;
        const d = getFormData();
        const b = toStr(d.buildingNo);
        const u = toStr(d.flatNo);
        if (!b || !u) return false;
        return unitHasEligibleContractWorkflow(b, u, options);
    }

    function renderContractsWorkspaceLockedPlaceholder() {
        const container = document.getElementById('currentDocument');
        if (!container) return;
        container.innerHTML = `<div class="contracts-locked-placeholder" style="padding:24px;text-align:center;color:#5a3d00;background:#fff8e6;border:1px dashed #e6d08a;border-radius:10px;margin:12px">
            <p style="margin:0 0 12px;font-weight:700">${t('شاشة العقود مقفولة — مطلوب حجز أولاً / Contracts workspace locked — reservation required first', 'شاشة العقود مقفولة — مطلوب حجز أولاً / Contracts workspace locked — reservation required first')}</p>
            <button type="button" class="btn-primary" onclick="openReservationsWorkspace()">${t('📌 الانتقال إلى صفحة الحجوزات / Go to reservations page', '📌 الانتقال إلى صفحة الحجوزات / Go to reservations page')}</button>
        </div>`;
        const tabsContainer = document.getElementById('tabsContainer');
        if (tabsContainer) tabsContainer.innerHTML = '';
    }

    function applyContractsWorkspaceLockState() {
        if (isViewerMode || !isContractsWorkspaceScreenActive()) return;
        const root = document.getElementById('contractsWorkspace');
        const wasLocked = !!(root && root.classList.contains('contracts-workspace--reservation-locked'));
        const unlocked = isContractWorkspaceUnlockedForCurrentUnit();
        if (root) root.classList.toggle('contracts-workspace--reservation-locked', !unlocked);
        const note = document.getElementById('contractsReservationRequiredLockNote');
        if (note) {
            note.hidden = unlocked;
            note.style.display = unlocked ? 'none' : 'block';
            if (!unlocked) {
                note.textContent = t(
                    note.getAttribute('data-ar') || '',
                    note.getAttribute('data-en') || ''
                );
            }
        }
        if (root) {
            root.querySelectorAll('button[onclick*="saveAllData"], button[onclick*="openDocumentsWindow"]').forEach((btn) => {
                btn.disabled = !unlocked;
            });
        }
        if (!unlocked) {
            renderContractsWorkspaceLockedPlaceholder();
        } else {
            try { refreshContractFinancialCalculations(); } catch (_eFinUnlock) {}
            try { refreshContractDocumentsForPreview(); } catch (_eDocUnlock) {}
            if (wasLocked) {
                try { renderDocument(currentDoc); } catch (eRelock) {}
            }
            try {
                refreshContractsAccountingReceiptPrintUi();
            } catch (_eCwAcctPr) {}
        }
    }

    function alertContractWorkspaceLockedOrMissingUnit() {
        const d = getFormData();
        if (!toStr(d.buildingNo) || !toStr(d.flatNo)) {
            alert(t('⚠️ حدّد المبنى والوحدة أولاً.', '⚠️ Select building and unit first.'));
            return;
        }
        alert(
            t(
                '⚠️ لا يمكن استخدام شاشة العقود لهذه الوحدة بدون حجز.\n\nالخطوة المطلوبة:\n1) احجز الوحدة من «وحدات شاغرة»\n2) أكمل بيانات المستأجر في دفتر العناوين\n3) من «وحدات محجوزة» استخدم «تحويل عقد الإيجار»\n4) ثم أكمل العقد من شاشة العقود',
                '⚠️ Contracts workspace cannot be used for this unit without a reservation.\n\nRequired steps:\n1) Reserve from Vacant units\n2) Complete tenant in the address book\n3) From Reserved units use «Convert tenancy contract»\n4) Then complete the contract in Contracts workspace'
            )
        );
    }

    /** لا عقد مباشر إلا بحجز أو مسودة تعاقد أو عقد محفوظ لوحدة مؤجرة / No direct contract without reservation, draft, or active saved lease */
    function assertContractRequiresReservationOrDraftOrActiveLease(building, unit, options = {}) {
        const isRenewal = options.isRenewal === true;
        const b = toStr(building);
        const u = toStr(unit);
        if (!b || !u) {
            alert(
                t(
                    '⚠️ حدّد المبنى والوحدة أولاً.',
                    '⚠️ Select building and unit first.'
                )
            );
            return false;
        }
        if (isRenewal) {
            if (unitHasEligibleContractWorkflow(b, u, { isRenewal: true })) {
                return true;
            }
            alert(
                t(
                    '⚠️ التجديد متاح فقط للوحدات المؤجرة بعقد نشط.',
                    '⚠️ Renewal is only available for units with an active rented lease.'
                )
            );
            return false;
        }
        if (unitHasEligibleContractWorkflow(b, u)) {
            return true;
        }
        alert(
            t(
                '⚠️ لا يمكن إنشاء عقد مباشرة لهذه الوحدة.\n\nالخطوة المطلوبة:\n1) احجز الوحدة من «وحدات شاغرة»\n2) أكمل بيانات المستأجر في دفتر العناوين\n3) من «وحدات محجوزة» استخدم «تحويل عقد الإيجار»\n4) ثم أكمل العقد من شاشة العقود',
                '⚠️ You cannot create a contract directly for this unit.\n\nRequired steps:\n1) Reserve the unit from Vacant units\n2) Complete tenant data in the address book\n3) From Reserved units use «Convert tenancy contract»\n4) Then complete the contract in Contracts workspace'
            )
        );
        return false;
    }

    function validateReservationTenantAddressBookCompleteOrAlert(formData) {
        const d = formData || getReservationFormData();
        const entry = findTenantAddressBookEntryForReservation(null, d);
        if (!entry) {
            alert(
                t(
                    '⚠️ لا يمكن حفظ الحجز: المستأجر غير موجود في دفتر العناوين.\n\nأضف الجهة في الدفتر أو استوردها من القائمة المنسدلة ثم أعد المحاولة.',
                    '⚠️ Cannot save reservation: tenant is not in the address book.\n\nAdd the party in the address book or import from the dropdown, then try again.'
                )
            );
            return false;
        }
        const issues = getAddressBookIssues(entry, { forReservation: true });
        if (issues.length) {
            alert(
                t(
                    '⚠️ لا يمكن حفظ الحجز: بيانات المستأجر في دفتر العناوين غير مكتملة:\n\n• ',
                    '⚠️ Cannot save reservation: tenant address book data is incomplete:\n\n• '
                ) + issues.join('\n• ')
            );
            return false;
        }
        return true;
    }

    function isReservedUnitRow(u) {
        const st = toStr(u.status).toLowerCase();
        if (st === 'reserved' || st.includes('محجوز') || st.includes('حجز')) return true;
        return unitReservations.some((r) => reservationCoversUnit(r, u.building, u.unit));
    }

    function makeReservationGroupId() {
        return `rgrp_${Date.now()}_${Math.random().toString(16).slice(2, 8)}`;
    }

    function normalizeReservationUnitEntry(entry) {
        const u = entry && typeof entry === 'object' ? entry : {};
        return {
            unit: toStr(u.unit),
            floor: toStr(u.floor || u.floorDetails || ''),
            unitType: toStr(u.unitType || 'Flat'),
            monthlyRent: toStr(u.monthlyRent || ''),
            electricity: toStr(u.electricity || u.electricityMeter || ''),
            water: toStr(u.water || u.waterMeter || '')
        };
    }

    function unitSnapshotFromUnitRow(u) {
        if (!u) return null;
        return normalizeReservationUnitEntry({
            unit: u.unit,
            floor: u.floor,
            unitType: u.unitType,
            monthlyRent: resolveUnitMonthlyRentForReservation(u),
            electricity: u.electricity,
            water: u.water
        });
    }

    function getReservationUnitsList(r) {
        if (!r) return [];
        if (Array.isArray(r.units) && r.units.length) {
            return r.units.map(normalizeReservationUnitEntry).filter((x) => x.unit);
        }
        const fd = r.formData && typeof r.formData === 'object' ? r.formData : {};
        try {
            if (fd.linkedUnitsJson) {
                const parsed = JSON.parse(toStr(fd.linkedUnitsJson) || '[]');
                if (Array.isArray(parsed) && parsed.length) {
                    return parsed.map(normalizeReservationUnitEntry).filter((x) => x.unit);
                }
            }
        } catch (_eLinkedJson) {}
        const legacy = toStr(r.unit);
        if (!legacy) return [];
        return [
            normalizeReservationUnitEntry({
                unit: r.unit,
                floor: fd.floorDetails,
                unitType: fd.unitType,
                monthlyRent: fd.monthlyRent,
                electricity: fd.electricityMeter,
                water: fd.waterMeter
            })
        ];
    }

    /** مزامنة صف الحجز مع linkedUnitsJson و units[] / Keep reservation row multi-unit fields consistent */
    function repairReservationMultiUnitRows() {
        if (!Array.isArray(unitReservations)) return false;
        let touched = false;
        unitReservations = unitReservations.map((r) => {
            if (!r || typeof r !== 'object') return r;
            const units = getReservationUnitsList(r);
            const primary = units[0] || { unit: toStr(r.unit) };
            const fd = r.formData && typeof r.formData === 'object' ? { ...r.formData } : {};
            const linkedJson = units.length ? JSON.stringify(units) : toStr(fd.linkedUnitsJson);
            if (units.length > 1) {
                fd.linkedUnitsJson = linkedJson;
                fd.flatNo = toStr(primary.unit);
                fd.monthlyRent = sumReservationUnitsMonthlyRent(units).toFixed(3);
            }
            const next = {
                ...r,
                building: toStr(r.building),
                unit: toStr(primary.unit) || toStr(r.unit),
                units,
                reservationGroupId: toStr(r.reservationGroupId) || makeReservationGroupId(),
                formData: fd
            };
            if (
                !Array.isArray(r.units) ||
                r.units.length !== units.length ||
                toStr(r.unit) !== next.unit ||
                (units.length > 1 && toStr(fd.linkedUnitsJson) !== toStr(r.formData?.linkedUnitsJson))
            ) {
                touched = true;
            }
            return next;
        });
        return touched;
    }

    function reservationCoversUnit(r, building, unit) {
        const bK = normalizeReservationBuildingKey(r?.building);
        const uN = normalizeUnit(unit);
        if (!bK || !uN) return false;
        if (normalizeReservationBuildingKey(building) !== bK) return false;
        return getReservationUnitsList(r).some((x) => normalizeUnit(x.unit) === uN);
    }

    function findReservationIndexForUnit(building, unit) {
        return unitReservations.findIndex((r) => reservationCoversUnit(r, building, unit));
    }

    function findReservationIndexByGroupId(groupId) {
        const g = toStr(groupId);
        if (!g) return -1;
        return unitReservations.findIndex((r) => toStr(r.reservationGroupId) === g);
    }

    function formatReservationUnitsLabel(r) {
        const list = getReservationUnitsList(r);
        if (list.length <= 1) return escHtml(list[0]?.unit || toStr(r.unit) || '—');
        const unitsStr = list.map((x) => x.unit).join(', ');
        return `${escHtml(unitsStr)} <span class="chip" style="font-size:10px;margin-inline-start:4px">${list.length} ${t('وحدات', 'units')}</span>`;
    }

    function sumReservationUnitsMonthlyRent(units) {
        return (units || []).reduce((s, u) => s + (parseFloat(u.monthlyRent) || 0), 0);
    }

    function migrateUnitReservationsMultiUnit() {
        if (!Array.isArray(unitReservations)) return;
        repairReservationMultiUnitRows();
        unitReservations = unitReservations.map((r) => {
            if (!r || typeof r !== 'object') return r;
            const units = getReservationUnitsList(r);
            const primary = units[0] || { unit: toStr(r.unit) };
            return {
                ...r,
                building: toStr(r.building),
                unit: toStr(primary.unit) || toStr(r.unit),
                units,
                reservationGroupId: toStr(r.reservationGroupId) || makeReservationGroupId()
            };
        });
    }

    function vacantPickKey(building, unit) {
        return normalizeReservationBuildingKey(building) + '\t' + normalizeUnit(unit);
    }

    function getActiveReservationLinkedUnits() {
        const ctx = contractEntryContext;
        if (ctx && Array.isArray(ctx.linkedUnits) && ctx.linkedUnits.length) {
            return ctx.linkedUnits.map(normalizeReservationUnitEntry).filter((x) => x.unit);
        }
        const unit = resFormVal('flatNo');
        if (!unit) return [];
        return [
            normalizeReservationUnitEntry({
                unit,
                floor: resFormVal('floorDetails'),
                unitType: resFormVal('unitType'),
                monthlyRent: resFormVal('monthlyRent'),
                electricity: resFormVal('electricityMeter'),
                water: resFormVal('waterMeter')
            })
        ];
    }

    function setActiveReservationLinkedUnits(units, building) {
        const list = (units || []).map(normalizeReservationUnitEntry).filter((x) => x.unit);
        if (!contractEntryContext || contractEntryContext.mode !== 'reservation') {
            contractEntryContext = { mode: 'reservation', unit: null, linkedUnits: list };
        } else {
            contractEntryContext.linkedUnits = list;
        }
        if (building) contractEntryContext.building = building;
        refreshReservationLinkedUnitsPanel();
    }

    function syncReservationPrimaryUnitToForm(unitEntry) {
        const u = normalizeReservationUnitEntry(unitEntry);
        if (!u.unit) return;
        resFormSet('flatNo', u.unit);
        resFormSet('floorDetails', u.floor);
        resFormSet('unitType', u.unitType);
        resFormSet('electricityMeter', u.electricity);
        resFormSet('waterMeter', u.water);
        if (u.monthlyRent) resFormSet('monthlyRent', u.monthlyRent);
        if (contractEntryContext?.mode === 'reservation') {
            contractEntryContext.unit = {
                building: resFormVal('buildingNo'),
                unit: u.unit,
                floor: u.floor,
                unitType: u.unitType,
                electricity: u.electricity,
                water: u.water,
                monthlyRent: u.monthlyRent
            };
        }
        try {
            updateReservationFormCalculations();
        } catch (_e) {}
    }

    function syncReservationMonthlyRentFieldFromLinkedUnits() {
        const units = getActiveReservationLinkedUnits();
        const monthlyEl = document.getElementById('resMonthlyRent');
        const wrap = document.getElementById('resMonthlyRentWrap');
        const hint = document.getElementById('resMonthlyRentHint');
        if (!monthlyEl) return;
        const multi = units.length > 1;
        const total = sumReservationUnitsMonthlyRent(units);
        const lbl = wrap?.querySelector('label');
        if (lbl) {
            if (multi) {
                lbl.setAttribute('data-ar', 'إجمالي الإيجار الشهري / Total monthly rent (OMR)');
                lbl.setAttribute('data-en', 'Total monthly rent (OMR) / إجمالي الإيجار الشهري');
                lbl.textContent = t('إجمالي الإيجار الشهري / Total monthly rent (OMR)', 'Total monthly rent (OMR) / إجمالي الإيجار الشهري');
            } else {
                lbl.setAttribute('data-ar', 'الإيجار الشهري / Monthly rent (OMR)');
                lbl.setAttribute('data-en', 'Monthly rent (OMR) / الإيجار الشهري');
                lbl.textContent = t('الإيجار الشهري / Monthly rent (OMR)', 'Monthly rent (OMR) / الإيجار الشهري');
            }
        }
        if (hint) hint.style.display = multi ? 'block' : 'none';
        if (multi) {
            monthlyEl.readOnly = true;
            monthlyEl.value = total.toFixed(3);
        } else if (units.length === 1) {
            monthlyEl.readOnly = false;
            const r = toStr(units[0].monthlyRent);
            if (r && document.activeElement !== monthlyEl) monthlyEl.value = r;
        } else {
            monthlyEl.readOnly = false;
        }
    }

    function updateReservationTotalRentLabelInPanel() {
        const el = document.getElementById('resLinkedUnitsTotalRent');
        if (!el) return;
        el.textContent = formatOMR(sumReservationUnitsMonthlyRent(getActiveReservationLinkedUnits()));
    }

    function updateReservationLinkedUnitRent(idx, rawValue) {
        const units = getActiveReservationLinkedUnits();
        if (idx < 0 || idx >= units.length) return;
        const rentNum = parseFloat(toStr(rawValue));
        units[idx] = {
            ...units[idx],
            monthlyRent: Number.isFinite(rentNum) ? rentNum.toFixed(3) : toStr(rawValue)
        };
        if (!contractEntryContext || contractEntryContext.mode !== 'reservation') {
            contractEntryContext = { mode: 'reservation', unit: null, linkedUnits: units };
        } else {
            contractEntryContext.linkedUnits = units;
            if (idx === 0 && contractEntryContext.unit && typeof contractEntryContext.unit === 'object') {
                contractEntryContext.unit = { ...contractEntryContext.unit, monthlyRent: units[0].monthlyRent };
            }
        }
        if (units.length === 1 && idx === 0) {
            const monthlyEl = document.getElementById('resMonthlyRent');
            if (monthlyEl && document.activeElement !== monthlyEl) monthlyEl.value = units[0].monthlyRent;
        }
        syncReservationMonthlyRentFieldFromLinkedUnits();
        updateReservationTotalRentLabelInPanel();
        updateReservationFormCalculations();
    }

    function refreshReservationLinkedUnitsPanel() {
        const wrap = document.getElementById('resLinkedUnitsPanel');
        if (!wrap) return;
        const units = getActiveReservationLinkedUnits();
        if (!units.length) {
            wrap.innerHTML = '';
            syncReservationMonthlyRentFieldFromLinkedUnits();
            return;
        }
        const rows = units
            .map((u, idx) => {
                const isPrimary = idx === 0;
                const rentVal = (parseFloat(u.monthlyRent) || 0).toFixed(3);
                return `<tr>
            <td>${escHtml(u.unit)}</td>
            <td>${escHtml(u.floor || '—')}</td>
            <td style="min-width:110px">
                <input type="number" class="res-linked-unit-rent" data-idx="${idx}" value="${escAttr(rentVal)}" step="0.001" min="0"
                    style="width:100%;max-width:120px;padding:4px 6px;border:1px solid #ccd6df;border-radius:6px"
                    oninput="updateReservationLinkedUnitRent(${idx}, this.value)"
                    title="${t('إيجار هذه الوحدة', 'Rent for this unit')}">
            </td>
            <td style="white-space:nowrap">
                ${isPrimary ? `<span class="chip">${t('رئيسية', 'Primary')}</span>` : `<button type="button" class="mini-btn" onclick="setReservationPrimaryUnitIndex(${idx})">${t('تعيين رئيسية', 'Set primary')}</button>`}
                ${units.length > 1 ? `<button type="button" class="mini-btn" onclick="removeReservationLinkedUnit(${idx})">${t('إزالة', 'Remove')}</button>` : ''}
            </td>
        </tr>`;
            })
            .join('');
        const total = sumReservationUnitsMonthlyRent(units);
        const panelTitle =
            units.length > 1
                ? t('الوحدات المرتبطة بالحجز', 'Units in this reservation')
                : t('بيانات الوحدة والإيجار', 'Unit details & rent');
        wrap.innerHTML = `
        <div style="margin:12px 0;padding:12px;border:1px solid #dfe7ee;border-radius:8px;background:#f8fbfd">
            <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px;margin-bottom:8px">
                <strong>${panelTitle} (${units.length})</strong>
                ${units.length > 1 ? `<button type="button" class="mini-btn btn-primary" onclick="openAddUnitsToReservationModal()">➕ ${t('إضافة وحدة من نفس المبنى', 'Add unit (same building)')}</button>` : `<button type="button" class="mini-btn btn-primary" onclick="openAddUnitsToReservationModal()">➕ ${t('إضافة وحدة أخرى', 'Add another unit')}</button>`}
            </div>
            <table class="ops-table" style="margin:0"><thead><tr>
                <th>${t('الوحدة', 'Unit')}</th><th>${t('الطابق', 'Floor')}</th><th>${t('الإيجار الشهري (OMR)', 'Monthly rent (OMR)')}</th><th></th>
            </tr></thead><tbody>${rows}</tbody></table>
            <div style="margin-top:8px;font-size:12px"><b>${t('إجمالي الإيجار الشهري:', 'Total monthly rent:')}</b> <span id="resLinkedUnitsTotalRent">${formatOMR(total)}</span></div>
            <small style="display:block;margin-top:6px;color:#555">${t('يمكن تعديل قيمة الإيجار لكل وحدة على حدة.', 'You can edit the rent amount for each unit separately.')}</small>
        </div>`;
        syncReservationMonthlyRentFieldFromLinkedUnits();
        try {
            updateReservationFormCalculations();
        } catch (_e2) {}
    }

    function setReservationPrimaryUnitIndex(idx) {
        const units = getActiveReservationLinkedUnits();
        if (idx < 0 || idx >= units.length) return;
        const picked = units[idx];
        const rest = units.filter((_, i) => i !== idx);
        setActiveReservationLinkedUnits([picked, ...rest], resFormVal('buildingNo'));
        syncReservationPrimaryUnitToForm(picked);
        updateReservationSummaryPanel();
    }

    function removeReservationLinkedUnit(idx) {
        const units = getActiveReservationLinkedUnits();
        if (units.length <= 1) return;
        const removed = units[idx];
        if (!confirm(t(`إزالة الوحدة ${removed.unit} من الحجز؟`, `Remove unit ${removed.unit} from this reservation?`))) return;
        const next = units.filter((_, i) => i !== idx);
        setActiveReservationLinkedUnits(next, resFormVal('buildingNo'));
        syncReservationPrimaryUnitToForm(next[0]);
        updateReservationSummaryPanel();
    }

    function openAddUnitsToReservationModal() {
        const building = resFormVal('buildingNo');
        if (!building) {
            alert(t('حدّد المبنى أولاً.', 'Select a building first.'));
            return;
        }
        loadDashboardAux();
        const linked = getActiveReservationLinkedUnits();
        const linkedSet = new Set(linked.map((x) => normalizeUnit(x.unit)));
        const candidates = getUnitsData().filter((u) => {
            if (u.status !== 'Vacant' || isReservedUnitRow(u)) return false;
            if (normalizeReservationBuildingKey(u.building) !== normalizeReservationBuildingKey(building)) return false;
            return !linkedSet.has(normalizeUnit(u.unit));
        });
        const body = document.getElementById('resAddUnitsModalBody');
        if (!body) return;
        if (!candidates.length) {
            body.innerHTML = `<p>${t('لا توجد وحدات شاغرة إضافية في هذا المبنى.', 'No additional vacant units in this building.')}</p>`;
        } else {
            body.innerHTML = `<table class="ops-table"><thead><tr>
            <th><input type="checkbox" id="resAddUnitsSelectAll" onchange="toggleResAddUnitsSelectAll(this.checked)"></th>
            <th>${t('الوحدة', 'Unit')}</th><th>${t('الطابق', 'Floor')}</th><th>${t('إيجار', 'Rent')}</th>
        </tr></thead><tbody>${candidates
                .map(
                    (u, i) => `<tr>
            <td><input type="checkbox" class="res-add-unit-cb" data-idx="${i}"></td>
            <td>${escHtml(u.unit)}</td><td>${escHtml(u.floor || '—')}</td><td>${formatOMR(u.monthlyRent)}</td>
        </tr>`
                )
                .join('')}</tbody></table>`;
            window._resAddUnitsCandidates = candidates;
        }
        document.getElementById('resAddUnitsModal')?.classList.add('open');
        localizeBilingualUi();
    }

    function toggleResAddUnitsSelectAll(checked) {
        document.querySelectorAll('.res-add-unit-cb').forEach((cb) => {
            cb.checked = checked;
        });
    }

    function confirmAddUnitsToReservation() {
        const candidates = window._resAddUnitsCandidates || [];
        const picked = [];
        document.querySelectorAll('.res-add-unit-cb:checked').forEach((cb) => {
            const i = parseInt(cb.dataset.idx, 10);
            if (!Number.isNaN(i) && candidates[i]) picked.push(unitSnapshotFromUnitRow(candidates[i]));
        });
        if (!picked.length) {
            alert(t('اختر وحدة واحدة على الأقل.', 'Select at least one unit.'));
            return;
        }
        const merged = [...getActiveReservationLinkedUnits(), ...picked];
        setActiveReservationLinkedUnits(merged, resFormVal('buildingNo'));
        closeResAddUnitsModal();
        updateReservationSummaryPanel();
    }

    function closeResAddUnitsModal() {
        document.getElementById('resAddUnitsModal')?.classList.remove('open');
        window._resAddUnitsCandidates = null;
    }

    function toggleVacantUnitPick(index) {
        const u = window._insightUnitRows?.[index];
        if (!u) return;
        const key = vacantPickKey(u.building, u.unit);
        const st = window._vacantUnitPickState || { building: '', keys: [] };
        if (!st.keys.includes(key)) {
            if (st.building && normalizeReservationBuildingKey(st.building) !== normalizeReservationBuildingKey(u.building)) {
                alert(t('يمكن اختيار وحدات من مبنى واحد فقط في كل حجز.', 'You can only pick units from one building per reservation.'));
                return;
            }
            st.building = u.building;
            st.keys.push(key);
        } else {
            st.keys = st.keys.filter((k) => k !== key);
            if (!st.keys.length) st.building = '';
        }
        window._vacantUnitPickState = st;
        const topVac = insightNavStack[insightNavStack.length - 1];
        if (topVac && topVac.mode === 'vacant') {
            refreshInsightVacantView();
            return;
        }
        renderInsightContent();
    }

    function startMultiUnitReservationFromVacant() {
        const st = window._vacantUnitPickState || { keys: [] };
        if (!st.keys || st.keys.length < 1) {
            alert(t('اختر وحدة واحدة على الأقل.', 'Select at least one unit.'));
            return;
        }
        const rows = (window._insightUnitRows || []).filter((u) => st.keys.includes(vacantPickKey(u.building, u.unit)));
        if (!rows.length) return;
        closeDashboardInsight();
        const units = rows.map(unitSnapshotFromUnitRow).filter(Boolean);
        const primary = rows[0];
        contractEntryContext = {
            mode: 'reservation',
            unit: { ...primary },
            linkedUnits: units,
            reservationGroupId: null
        };
        enterReservationModeForUnit(primary);
        setActiveReservationLinkedUnits(units, primary.building);
        setWorkspaceMode('reservations');
        showReservationsWorkspaceView('form');
        window._vacantUnitPickState = { building: '', keys: [] };
    }

    function buildLinkedContractUnitsPayload(units, building) {
        const b = toStr(building);
        return (units || []).map((u) => ({
            building: b,
            unit: toStr(u.unit),
            floorDetails: toStr(u.floor),
            unitType: toStr(u.unitType || 'Flat'),
            monthlyRent: toStr(u.monthlyRent),
            electricityMeter: toStr(u.electricity),
            waterMeter: toStr(u.water)
        }));
    }

    function getLinkedContractUnitsFromForm() {
        try {
            const raw = document.getElementById('linkedContractUnitsJson')?.value;
            const arr = JSON.parse(toStr(raw) || '[]');
            return Array.isArray(arr) ? arr : [];
        } catch (_e) {
            return [];
        }
    }

    /** جمع وحدات العقد المرتبطة من كل المصادر (مسودة، محفوظ، حجز) / Collect linked units from drafts, saved map, reservations */
    function collectLinkedContractUnitsFromAgreementSiblings(building, agreementNo, payloadOpt) {
        const bNorm = normalizeReservationBuildingKey(building);
        const ag = toStr(agreementNo).trim();
        if (!bNorm || !ag || ag === '_draft') return [];
        const seen = new Set();
        const siblings = [];
        const pushUnit = (lu, sourcePayload) => {
            const u = normalizeUnit(lu?.unit || lu?.flatNo || sourcePayload?.flatNo);
            if (!u || seen.has(u)) return;
            seen.add(u);
            const slice = getLinkedContractUnitSlice(sourcePayload || {}, u);
            siblings.push({
                building: bNorm,
                unit: u,
                floorDetails: toStr(lu?.floorDetails || lu?.floor || slice.floorDetails),
                unitType: toStr(lu?.unitType || slice.unitType || 'Flat'),
                monthlyRent: toStr(lu?.monthlyRent ?? slice.monthlyRent),
                electricityMeter: toStr(lu?.electricityMeter || lu?.electricity || slice.electricityMeter),
                waterMeter: toStr(lu?.waterMeter || lu?.water || slice.waterMeter)
            });
        };
        const ingestPayload = (p) => {
            if (!p || typeof p !== 'object') return;
            if (normalizeReservationBuildingKey(p.buildingNo) !== bNorm) return;
            if (toStr(p.agreementNo).trim() !== ag) return;
            const linked = getLinkedContractUnitsFromPayload(p);
            if (linked.length > 1) {
                linked.forEach((lu) => pushUnit(lu, p));
                return;
            }
            pushUnit({ unit: p.flatNo }, p);
        };
        if (payloadOpt && typeof payloadOpt === 'object') ingestPayload(payloadOpt);
        try {
            Object.values(loadSavedContractsByUnitMap()).forEach((entry) => ingestPayload(entry?.payload));
        } catch (_eSavSib) {}
        try {
            Object.values(loadTenancyContractDraftsMap()).forEach((entry) => ingestPayload(entry?.payload));
        } catch (_eDrSib) {}
        try {
            (unitReservations || []).forEach((r) => {
                if (normalizeReservationBuildingKey(r?.building) !== bNorm) return;
                if (toStr(r?.agreementNo).trim() !== ag) return;
                getReservationUnitsList(r).forEach((lu) => pushUnit(lu, r.formData || {}));
            });
        } catch (_eResSib) {}
        if (siblings.length <= 1) return [];
        siblings.sort((a, b) => compareSmart(a.unit, b.unit));
        return siblings;
    }

    function enrichPayloadWithResolvedLinkedContractUnits(payload) {
        if (!payload || typeof payload !== 'object') return payload;
        const linked = resolveLinkedContractUnitsForWorkspace(payload, { skipForm: true });
        if (linked.length <= 1) return payload;
        return {
            ...payload,
            linkedContractUnits: linked,
            linkedContractUnitsJson: JSON.stringify(linked)
        };
    }

    function resolveLinkedContractUnitsForWorkspace(payloadOpt, opt = {}) {
        const skipForm = opt.skipForm === true;
        let fromForm = [];
        if (!skipForm) {
            try {
                fromForm = getLinkedContractUnitsFromForm();
            } catch (_eFormLinked) {}
            if (fromForm.length > 1) return fromForm;
        }
        const payload =
            payloadOpt && typeof payloadOpt === 'object'
                ? payloadOpt
                : !skipForm && isContractsWorkspaceScreenActive()
                  ? collectStorableContractFullFromDom()
                  : {};
        let linked = getLinkedContractUnitsFromPayload(payload);
        if (linked.length > 1) return linked;
        const b = toStr(payload.buildingNo);
        const u = toStr(payload.flatNo);
        if (b && u) {
            const full = getContractPayloadForUnit({ building: b, unit: u });
            linked = getLinkedContractUnitsFromPayload(full);
            if (linked.length > 1) return linked;
            const prim = findLinkedContractPrimaryForUnitInSavedMap({ building: b, unit: u });
            if (prim) {
                const primPayload = getContractPayloadForUnit(prim);
                linked = getLinkedContractUnitsFromPayload(primPayload);
                if (linked.length > 1) return linked;
            }
            const draftPayload = getTenancyDraftPayloadForUnit({ building: b, unit: u });
            linked = getLinkedContractUnitsFromPayload(draftPayload);
            if (linked.length > 1) return linked;
        }
        const ag = toStr(payload.agreementNo).trim();
        if (ag && b) {
            const siblings = collectLinkedContractUnitsFromAgreementSiblings(b, ag, payload);
            if (siblings.length > 1) return siblings;
        }
        if (!skipForm) {
            const bDom = toStr(document.getElementById('buildingNo')?.value);
            const agDom = toStr(document.getElementById('agreementNo')?.value).trim();
            if (agDom && bDom && (agDom !== ag || bDom !== b)) {
                const siblingsDom = collectLinkedContractUnitsFromAgreementSiblings(bDom, agDom, payload);
                if (siblingsDom.length > 1) return siblingsDom;
            }
        }
        return fromForm.length ? fromForm : linked;
    }

    function ensureLinkedContractUnitsOnForm(payloadOpt) {
        const units = resolveLinkedContractUnitsForWorkspace(payloadOpt);
        const tx = document.getElementById('linkedContractUnitsJson');
        if (tx && units.length > 1) {
            tx.value = JSON.stringify(units);
        }
        return units;
    }

    function refreshLinkedContractUnitsPanel(payloadOpt) {
        const host = document.getElementById('linkedContractUnitsPanel');
        if (!host) return;
        const units = ensureLinkedContractUnitsOnForm(payloadOpt);
        if (units.length <= 1) {
            host.innerHTML = '';
            host.style.display = 'none';
            return;
        }
        host.style.display = 'block';
        const primaryUnit = normalizeUnit(document.getElementById('flatNo')?.value);
        const rows = units
            .map((u, idx) => {
                const isPrimary = normalizeUnit(u.unit) === primaryUnit || (idx === 0 && !primaryUnit);
                return `<tr>
            <td>${escHtml(u.unit)}</td>
            <td>${escHtml(u.floorDetails || '—')}</td>
            <td>${escHtml(u.unitType || 'Flat')}</td>
            <td>${formatOMR(u.monthlyRent)}</td>
            <td style="white-space:nowrap">${isPrimary ? `<span class="chip">${t('رئيسية', 'Primary')}</span>` : ''}</td>
        </tr>`;
            })
            .join('');
        const total = units.reduce((s, u) => s + (parseFloat(u.monthlyRent) || 0), 0);
        host.innerHTML = `
        <div style="margin:8px 0 14px;padding:12px;border:1px solid #dfe7ee;border-radius:8px;background:#f8fbfd">
            <strong>${t('وحدات مرتبطة بهذا العقد', 'Units linked to this contract')} (${units.length})</strong>
            <table class="ops-table" style="margin-top:8px"><thead><tr>
                <th>${t('الوحدة', 'Unit')}</th><th>${t('الطابق', 'Floor')}</th><th>${t('النوع', 'Type')}</th><th>${t('إيجار شهري (OMR)', 'Monthly rent (OMR)')}</th><th></th>
            </tr></thead><tbody>${rows}</tbody></table>
            <div style="margin-top:8px;font-size:12px"><b>${t('إجمالي الإيجار الشهري:', 'Total monthly rent:')}</b> ${formatOMR(total)}</div>
            <small style="display:block;margin-top:6px;color:#555">${t('تُعرض إيجارات الوحدات كما في الحجز. الإيجار الإجمالي في حقل «الإيجار الشهري» أعلاه.', 'Unit rents are shown as in the reservation. Total rent appears in the monthly rent field above.')}</small>
        </div>`;
    }

    function getLinkedContractUnitsFromPayload(payload) {
        if (!payload || typeof payload !== 'object') return [];
        if (Array.isArray(payload.linkedContractUnits) && payload.linkedContractUnits.length) {
            return payload.linkedContractUnits;
        }
        try {
            const arr = JSON.parse(toStr(payload.linkedContractUnitsJson) || '[]');
            return Array.isArray(arr) ? arr : [];
        } catch (_e) {
            return [];
        }
    }

    /** الوحدة الأساسية لعقد مرتبط بعدة وحدات / Primary unit for a multi-unit linked contract */
    function resolveContractWorkflowPrimaryUnit(building, unit, payloadOpt) {
        const payload =
            payloadOpt ||
            getContractPayloadForUnit({ building, unit }) ||
            getSavedContractPayloadForUnit({ building, unit });
        const linked = getLinkedContractUnitsFromPayload(payload);
        const b = toStr(payload?.buildingNo || building);
        if (linked.length > 1) {
            return { building: b, unit: normalizeUnit(linked[0]?.unit || payload?.flatNo || unit), payload };
        }
        return { building: b || toStr(building), unit: normalizeUnit(unit || payload?.flatNo), payload };
    }

    function isLinkedContractSecondaryUnit(building, unit, payloadOpt) {
        const payload =
            payloadOpt ||
            getContractPayloadForUnit({ building, unit }) ||
            getSavedContractPayloadForUnit({ building, unit });
        const linked = getLinkedContractUnitsFromPayload(payload);
        if (linked.length <= 1) return false;
        const primary = normalizeUnit(linked[0]?.unit || payload?.flatNo);
        return normalizeUnit(unit) !== primary;
    }

    /** الوحدة الأساسية لعرض عقد مزدوج — للوحدة الثانوية / Primary unit for dual-contract display */
    function getLinkedContractDisplayPrimaryUnit(unit) {
        if (!unit || !toStr(unit.building) || !toStr(unit.unit)) return null;
        const primSaved = findLinkedContractPrimaryForUnitInSavedMap(unit);
        if (primSaved && normalizeUnit(primSaved.unit) !== normalizeUnit(unit.unit)) return primSaved;
        const payload = getSavedContractPayloadForUnit(unit) || getTenancyDraftPayloadForUnit(unit);
        const linked = getLinkedContractUnitsFromPayload(payload);
        if (linked.length <= 1) return null;
        const primary = resolveContractWorkflowPrimaryUnit(unit.building, unit.unit, payload);
        if (normalizeUnit(primary.unit) === normalizeUnit(unit.unit)) return null;
        return { building: primary.building, unit: primary.unit };
    }

    function isLinkedContractSecondaryUnitForDisplay(unit) {
        return !!getLinkedContractDisplayPrimaryUnit(unit);
    }

    function openPrimaryLinkedContractFromUnitDetails() {
        const unit = selectedUnitDetailsRecord;
        const prim = getLinkedContractDisplayPrimaryUnit(unit);
        if (!prim) return;
        const primaryRow = getUnitsData().find(
            (x) =>
                normalizeReservationBuildingKey(x.building) === normalizeReservationBuildingKey(prim.building) &&
                normalizeUnit(x.unit) === normalizeUnit(prim.unit)
        );
        closeUnitDetailsModal();
        if (primaryRow) {
            openUnitDetailsForUnit(primaryRow);
            return;
        }
        openContractFullViewModal({ building: prim.building, unit: prim.unit });
    }

    function buildLinkedContractSecondaryNoticeHtml(unit) {
        const prim = getLinkedContractDisplayPrimaryUnit(unit);
        if (!prim) return '';
        return `<div class="details-section" style="margin:0 0 12px;padding:14px;border:1px solid #c5d9e8;border-radius:10px;background:#f0f7fc">
            <h5 style="margin:0 0 8px;font-size:14px;color:#1a4d6e">${t('وحدة مرتبطة بعقد مزدوج', 'Unit linked to a dual contract')}</h5>
            <p style="font-size:12px;color:#444;margin:0 0 10px;line-height:1.6">${t(
                `هذه الوحدة (${toStr(unit.unit)}) مؤجرة ضمن عقد واحد يشمل عدة وحدات. بيانات العقد الكاملة والطباعة والإيصالات تُدار من الوحدة الأساسية`,
                `This unit (${toStr(unit.unit)}) is rented under one contract covering multiple units. Full contract data, printing, and receipts are managed from the primary unit`
            )} <strong>${escHtml(prim.unit)}</strong> ${t('في', 'in')} <strong>${escHtml(prim.building)}</strong>.</p>
            <button type="button" class="btn-primary mini-btn" onclick="openPrimaryLinkedContractFromUnitDetails()">${t('متابعة إلى العقد الأساسي', 'Open primary contract')}</button>
        </div>`;
    }

    function getMultiUnitContractGroupKey(building, unit, payloadOpt) {
        const payload =
            payloadOpt ||
            getContractPayloadForUnit({ building, unit }) ||
            getSavedContractPayloadForUnit({ building, unit });
        const linked = getLinkedContractUnitsFromPayload(payload);
        const b = normalizeReservationBuildingKey(payload?.buildingNo || building);
        const ag = toStr(payload?.agreementNo).trim();
        if (linked.length > 1 && ag) {
            const units = linked
                .map((lu) => normalizeUnit(lu.unit))
                .filter(Boolean)
                .sort()
                .join(',');
            return `multi:${b}:${ag}:${units}`;
        }
        return _tenancyDraftStorageKey(building, unit);
    }

    function formatLinkedContractUnitsLabel(payload) {
        const linked = getLinkedContractUnitsFromPayload(payload);
        if (linked.length <= 1) return toStr(payload?.flatNo || linked[0]?.unit);
        return linked
            .map((lu) => toStr(lu.unit))
            .filter(Boolean)
            .join(t('، ', ', '));
    }

    function getLinkedContractUnitSlice(payload, unit) {
        const u = normalizeUnit(unit || payload?.flatNo);
        const linked = getLinkedContractUnitsFromPayload(payload);
        if (linked.length > 1) {
            const hit = linked.find((lu) => normalizeUnit(lu.unit) === u);
            if (hit) {
                return {
                    unit: u,
                    floorDetails: toStr(hit.floorDetails || hit.floor),
                    unitType: toStr(hit.unitType),
                    monthlyRent: parseFloat(hit.monthlyRent) || 0,
                    electricityMeter: toStr(hit.electricityMeter),
                    waterMeter: toStr(hit.waterMeter)
                };
            }
        }
        return {
            unit: u,
            floorDetails: toStr(payload?.floorDetails),
            unitType: toStr(payload?.unitType),
            monthlyRent: parseFloat(payload?.monthlyRent) || 0,
            electricityMeter: toStr(payload?.electricityMeter),
            waterMeter: toStr(payload?.waterMeter)
        };
    }

    function resolveContractDisplayFieldsForUnit(unit) {
        if (!unit) return null;
        const prim = getLinkedContractPrimaryLifecycleUnit(unit);
        const saved = getSavedContractPayloadForUnit(unit);
        const draft = getTenancyDraftPayloadForUnit(unit);
        const primaryPayload =
            (prim && getSavedContractPayloadForUnit(prim)) || saved || draft || getContractPayloadForUnit(unit);
        const slice = getLinkedContractUnitSlice(primaryPayload, unit.unit);
        const linked = getLinkedContractUnitsFromPayload(primaryPayload);
        const agreementNo = toStr(saved?.agreementNo || primaryPayload?.agreementNo || unit.agreementNo);
        return {
            payload: primaryPayload,
            slice,
            linked,
            isMultiUnit: linked.length > 1,
            agreementNo,
            monthlyRent: slice.monthlyRent || parseFloat(unit.monthlyRent) || 0,
            agreementRent: parseFloat(unit.agreementRent) || slice.monthlyRent || parseFloat(unit.monthlyRent) || 0,
            floor: slice.floorDetails || unit.floor,
            unitType: slice.unitType || unit.unitType,
            electricity: slice.electricityMeter || unit.electricity,
            water: slice.waterMeter || unit.water
        };
    }

    function buildLinkedContractUnitsDetailsSectionHtml(unit) {
        if (isLinkedContractSecondaryUnitForDisplay(unit)) return '';
        const fields = resolveContractDisplayFieldsForUnit(unit);
        if (!fields || !fields.isMultiUnit) return '';
        const rows = fields.linked
            .map((lu) => {
                const luUnit = toStr(lu.unit);
                const isCurrent = normalizeUnit(luUnit) === normalizeUnit(unit.unit);
                return `<tr${isCurrent ? ' style="background:#f3f8fc;font-weight:700"' : ''}>
                    <td>${escHtml(luUnit)}${isCurrent ? ` <span class="chip" style="font-size:10px">${t('هذه الوحدة', 'This unit')}</span>` : ''}</td>
                    <td>${escHtml(lu.floorDetails || lu.floor || '—')}</td>
                    <td>${escHtml(lu.unitType || '—')}</td>
                    <td>${escHtml(formatOMR(lu.monthlyRent))}</td>
                    <td>${escHtml(lu.electricityMeter || '—')}</td>
                    <td>${escHtml(lu.waterMeter || '—')}</td>
                </tr>`;
            })
            .join('');
        const total = fields.linked.reduce((s, lu) => s + (parseFloat(lu.monthlyRent) || 0), 0);
        return `<div class="details-section">
            <h5>${t('وحدات العقد المرتبطة', 'Linked contract units')}</h5>
            <p style="font-size:11px;color:#555;margin:0 0 8px;line-height:1.5">${t('عقد واحد يشمل الوحدات التالية — الإيجار المعروض أعلاه خاص بهذه الوحدة فقط.', 'One contract covers the units below — rent shown above is for this unit only.')}</p>
            <div class="table-wrap"><table class="data-table" style="width:100%;font-size:11px">
                <thead><tr>
                    <th>${t('الوحدة', 'Unit')}</th><th>${t('الطابق', 'Floor')}</th><th>${t('النوع', 'Type')}</th>
                    <th>${t('الإيجار الشهري', 'Monthly rent')}</th><th>${t('كهرباء', 'Electricity')}</th><th>${t('ماء', 'Water')}</th>
                </tr></thead>
                <tbody>${rows}</tbody>
            </table></div>
            <p style="font-size:11px;color:#666;margin:8px 0 0"><b>${t('إجمالي إيجار العقد:', 'Contract total rent:')}</b> ${escHtml(formatOMR(total))}</p>
        </div>`;
    }

    function repairSavedContractsByUnitMapStorageKeys() {
        const map = loadSavedContractsByUnitMap();
        const merged = {};
        let touched = false;
        Object.keys(map).forEach((k) => {
            const tab = k.indexOf('\t');
            if (tab < 0) return;
            const entry = map[k];
            if (!entry) return;
            const nk = _tenancyDraftStorageKey(k.slice(0, tab), k.slice(tab + 1));
            const prev = merged[nk];
            if (!prev || toStr(entry.updatedAt || entry.savedAt) >= toStr(prev.updatedAt || prev.savedAt)) {
                merged[nk] = entry;
            }
            if (nk !== k) touched = true;
        });
        if (touched || Object.keys(merged).length !== Object.keys(map).length) {
            saveSavedContractsByUnitMap(merged);
        }
        return touched;
    }

    function purgeDuplicateLinkedUnitAccountingEntries(reg, building, agreementNo, linkedUnits) {
        const b = toStr(building);
        const ag = toStr(agreementNo);
        const linked = Array.isArray(linkedUnits) ? linkedUnits : [];
        if (!b || linked.length <= 1) return false;
        let touched = false;
        linked.slice(1).forEach((lu) => {
            const secUk = accountingUnitKey(b, lu.unit);
            const beforeDep = (reg.deposits || []).length;
            const beforeChq = (reg.cheques || []).length;
            reg.deposits = (reg.deposits || []).filter((d) => {
                if (d.unitKey !== secUk) return true;
                if (ag && toStr(d.agreementNo) === ag) return false;
                return d.type !== 'security' && d.type !== 'insurance';
            });
            reg.cheques = (reg.cheques || []).filter((c) => !(c.unitKey === secUk && (!ag || toStr(c.agreementNo) === ag)));
            reg.entries = (reg.entries || []).filter((e) => !(e.unitKey === secUk && (!ag || toStr(e.agreementNo) === ag)));
            if ((reg.deposits || []).length !== beforeDep || (reg.cheques || []).length !== beforeChq) touched = true;
        });
        return touched;
    }

    function repairDuplicateMultiUnitAccountingEntries() {
        const processed = new Set();
        const reg = loadAccountingRegistry();
        let touched = false;
        const scanPayload = (p) => {
            if (!p || typeof p !== 'object') return;
            const linked = getLinkedContractUnitsFromPayload(p);
            if (linked.length <= 1) return;
            const gk = getMultiUnitContractGroupKey(p.buildingNo, p.flatNo, p);
            if (processed.has(gk)) return;
            processed.add(gk);
            if (purgeDuplicateLinkedUnitAccountingEntries(reg, p.buildingNo, toStr(p.agreementNo), linked)) touched = true;
        };
        try {
            Object.values(loadTenancyContractDraftsMap()).forEach((e) => scanPayload(e?.payload));
        } catch (_eRepDraft) {}
        try {
            Object.values(loadSavedContractsByUnitMap()).forEach((e) => scanPayload(e?.payload));
        } catch (_eRepSaved) {}
        if (touched) {
            try {
                saveAccountingRegistry(reg);
            } catch (_eRepSave) {}
        }
        return touched;
    }

    function repairAccountingChequesPendingWithoutContractData(regOpt) {
        const reg = regOpt || loadAccountingRegistry();
        let touched = false;
        const payloadCache = new Map();
        (reg.cheques || []).forEach((ch) => {
            const pk = normalizeReservationBuildingKey(ch.building) + '\t' + normalizeUnit(ch.unit);
            if (!payloadCache.has(pk)) {
                payloadCache.set(pk, getContractPayloadForUnit({ building: ch.building, unit: ch.unit }));
            }
            const payload = payloadCache.get(pk);
            if (!payload) return;
            const idx =
                ch.sourceType === 'vat'
                    ? parseInt(ch.chequeIndex, 10) || 0
                    : parseInt(ch.monthIndex, 10) || 0;
            let row = null;
            let ready = false;
            if (ch.sourceType === 'vat') {
                const rows = parsePayloadJsonArrayField(payload, 'vatChequeScheduleJson', 'vatChequeSchedule');
                row = rows.find((r, i) => (parseInt(r.chequeIndex || r.monthIndex, 10) || i + 1) === idx) || rows[idx - 1];
                ready = contractVatChequeRowReadyForAccounting(row, payload);
            } else {
                const rows = parsePayloadJsonArrayField(payload, 'paymentScheduleJson', 'paymentSchedule');
                row = rows.find((r) => (parseInt(r.monthIndex, 10) || 0) === idx) || rows[idx - 1];
                ready = contractRentChequeRowReadyForAccounting(row, payload);
            }
            if (isAccountingChequePendingReceipt(ch.status) && !ready) {
                ch.status = 'awaiting_contract_data';
                ch.updatedAt = new Date().toISOString();
                touched = true;
            } else if (isAccountingChequeAwaitingContractData(ch.status) && ready) {
                ch.status = 'pending_receipt';
                if (row) {
                    ch.chequeNo = toStr(row.checkNo || row.chequeNo).trim() || ch.chequeNo;
                    ch.dueDate = toStr(row.dueDate || row.paymentDate) || ch.dueDate;
                    ch.amount = parseFloat(row.amount) || ch.amount;
                }
                ch.updatedAt = new Date().toISOString();
                touched = true;
            }
        });
        return touched;
    }

    function mirrorTenancyPayloadToLinkedUnits(basePayload, perUnitFn) {
        const linked = getLinkedContractUnitsFromPayload(basePayload);
        const b = toStr(basePayload?.buildingNo);
        if (!b || linked.length <= 1) {
            perUnitFn(basePayload, b, toStr(basePayload?.flatNo));
            return;
        }
        linked.forEach((lu) => {
            const unitPayload = {
                ...basePayload,
                flatNo: toStr(lu.unit),
                floorDetails: toStr(lu.floorDetails),
                unitType: toStr(lu.unitType),
                monthlyRent: toStr(lu.monthlyRent),
                electricityMeter: toStr(lu.electricityMeter),
                waterMeter: toStr(lu.waterMeter)
            };
            perUnitFn(unitPayload, b, lu.unit);
        });
    }

    function repairInferLinkedContractGroupsFromSavedMap(savedMap, draftMap) {
        const groups = new Map();
        Object.keys(savedMap).forEach((sk) => {
            const entry = savedMap[sk];
            const p = entry?.payload;
            if (!p) return;
            const ag = toStr(p.agreementNo).trim();
            const b = normalizeReservationBuildingKey(p.buildingNo);
            if (!ag || ag === '_draft' || !b) return;
            const gk = `${b}\t${ag}`;
            if (!groups.has(gk)) groups.set(gk, []);
            groups.get(gk).push({ sk, entry, p });
        });
        let touched = false;
        groups.forEach((items) => {
            const byUnit = new Map();
            items.forEach((it) => {
                const u = normalizeUnit(it.p.flatNo);
                if (!u) return;
                const prev = byUnit.get(u);
                if (!prev || toStr(it.entry.updatedAt || it.entry.savedAt) >= toStr(prev.entry.updatedAt || prev.entry.savedAt)) {
                    byUnit.set(u, it);
                } else {
                    delete savedMap[it.sk];
                    touched = true;
                }
            });
            const uniqueItems = [...byUnit.values()];
            if (uniqueItems.length <= 1) return;
            const sortedUnits = [...byUnit.keys()].sort((a, b) => compareSmart(a, b));
            const baseItem = uniqueItems.find((it) => normalizeUnit(it.p.flatNo) === sortedUnits[0]) || uniqueItems[0];
            const p0 = baseItem.p;
            const linked = sortedUnits.map((u) => {
                const hit = byUnit.get(u);
                const slice = getLinkedContractUnitSlice(hit?.p || p0, u);
                return {
                    building: toStr(p0.buildingNo),
                    unit: u,
                    floorDetails: slice.floorDetails,
                    unitType: slice.unitType,
                    monthlyRent: toStr(slice.monthlyRent),
                    electricityMeter: slice.electricityMeter,
                    waterMeter: slice.waterMeter
                };
            });
            const status = baseItem.entry.lifecycleStatus || resolveContractLifecycleStatus(p0);
            const shared = {
                ...p0,
                linkedContractUnits: linked,
                linkedContractUnitsJson: JSON.stringify(linked)
            };
            mirrorTenancyPayloadToLinkedUnits(shared, (unitPayload, bKey, uKey) => {
                const merged = {
                    ...shared,
                    ...unitPayload,
                    flatNo: toStr(uKey),
                    linkedContractUnits: linked,
                    linkedContractUnitsJson: JSON.stringify(linked),
                    contractSavedAt: toStr(p0.contractSavedAt) || baseItem.entry.savedAt,
                    contractSavedStatus: status
                };
                const dk = _tenancyDraftStorageKey(bKey, uKey);
                savedMap[dk] = {
                    payload: merged,
                    lifecycleStatus: status,
                    savedAt: merged.contractSavedAt,
                    updatedAt: new Date().toISOString(),
                    lastActorUserId: baseItem.entry.lastActorUserId,
                    lastActorName: baseItem.entry.lastActorName
                };
                if (draftMap[dk]) {
                    delete draftMap[dk];
                    touched = true;
                }
                touched = true;
            });
        });
        return touched;
    }

    function repairInferLinkedContractGroupsFromDraftMap(draftMap) {
        const groups = new Map();
        Object.keys(draftMap || {}).forEach((dk) => {
            const entry = draftMap[dk];
            const p = entry?.payload;
            if (!p) return;
            const ag = toStr(p.agreementNo).trim();
            const b = normalizeReservationBuildingKey(p.buildingNo);
            if (!ag || ag === '_draft' || !b) return;
            const gk = `${b}\t${ag}`;
            if (!groups.has(gk)) groups.set(gk, []);
            groups.get(gk).push({ dk, entry, p });
        });
        let touched = false;
        groups.forEach((items) => {
            const byUnit = new Map();
            items.forEach((it) => {
                const u = normalizeUnit(it.p.flatNo);
                if (!u) return;
                const prev = byUnit.get(u);
                if (!prev || toStr(it.entry.updatedAt) >= toStr(prev.entry.updatedAt)) {
                    byUnit.set(u, it);
                }
            });
            const uniqueItems = [...byUnit.values()];
            if (uniqueItems.length <= 1) return;
            const sortedUnits = [...byUnit.keys()].sort((a, b) => compareSmart(a, b));
            const baseItem = uniqueItems.find((it) => normalizeUnit(it.p.flatNo) === sortedUnits[0]) || uniqueItems[0];
            const p0 = baseItem.p;
            const linked = sortedUnits.map((u) => {
                const hit = byUnit.get(u);
                const slice = getLinkedContractUnitSlice(hit?.p || p0, u);
                return {
                    building: toStr(p0.buildingNo),
                    unit: u,
                    floorDetails: slice.floorDetails,
                    unitType: slice.unitType,
                    monthlyRent: toStr(slice.monthlyRent),
                    electricityMeter: slice.electricityMeter,
                    waterMeter: slice.waterMeter
                };
            });
            uniqueItems.forEach((it) => {
                const u = normalizeUnit(it.p.flatNo);
                const slice = getLinkedContractUnitSlice(it.p, u);
                const merged = {
                    ...p0,
                    ...it.p,
                    flatNo: toStr(u),
                    floorDetails: slice.floorDetails,
                    unitType: slice.unitType,
                    monthlyRent: toStr(slice.monthlyRent),
                    electricityMeter: slice.electricityMeter,
                    waterMeter: slice.waterMeter,
                    linkedContractUnits: linked,
                    linkedContractUnitsJson: JSON.stringify(linked)
                };
                draftMap[it.dk] = {
                    ...it.entry,
                    payload: merged,
                    updatedAt: new Date().toISOString()
                };
                touched = true;
            });
        });
        return touched;
    }

    function repairLinkedContractUnitsLifecycleConsistency() {
        try {
            repairSavedContractsByUnitMapStorageKeys();
        } catch (_eRepKeys) {}
        const savedMap = loadSavedContractsByUnitMap();
        const draftMap = loadTenancyContractDraftsMap();
        let touched = false;
        try {
            if (repairInferLinkedContractGroupsFromSavedMap(savedMap, draftMap)) touched = true;
        } catch (_eInferLinked) {}
        try {
            if (repairInferLinkedContractGroupsFromDraftMap(draftMap)) touched = true;
        } catch (_eInferDrLinked) {}
        const processed = new Set();
        Object.keys(savedMap).forEach((sk) => {
            const entry = savedMap[sk];
            const p = entry?.payload;
            if (!p) return;
            const linked = getLinkedContractUnitsFromPayload(p);
            if (linked.length <= 1) return;
            const b = toStr(p.buildingNo);
            const groupKey = getMultiUnitContractGroupKey(b, p.flatNo, p);
            if (processed.has(groupKey)) return;
            processed.add(groupKey);
            const status = entry.lifecycleStatus || resolveContractLifecycleStatus(p);
            mirrorTenancyPayloadToLinkedUnits(p, (unitPayload, bKey, uKey) => {
                const merged = {
                    ...p,
                    ...unitPayload,
                    flatNo: toStr(uKey),
                    linkedContractUnits: linked,
                    linkedContractUnitsJson: JSON.stringify(linked),
                    contractSavedAt: toStr(p.contractSavedAt) || entry.savedAt,
                    contractSavedStatus: status
                };
                const dk = _tenancyDraftStorageKey(bKey, uKey);
                const prevSaved = savedMap[dk];
                const needsSavedSync =
                    !prevSaved ||
                    draftMap[dk] ||
                    toStr(prevSaved.lifecycleStatus) !== status ||
                    toStr(prevSaved.payload?.contractSavedStatus) !== status ||
                    toStr(prevSaved.payload?.agreementNo) !== toStr(merged.agreementNo);
                if (needsSavedSync) {
                    savedMap[dk] = {
                        payload: merged,
                        lifecycleStatus: status,
                        savedAt: merged.contractSavedAt,
                        updatedAt: new Date().toISOString(),
                        lastActorUserId: entry.lastActorUserId,
                        lastActorName: entry.lastActorName
                    };
                    touched = true;
                }
                if (draftMap[dk]) {
                    delete draftMap[dk];
                    touched = true;
                }
            });
        });
        Object.keys(draftMap).forEach((dk) => {
            const tab = dk.indexOf('\t');
            if (tab < 0) return;
            const uRef = { building: dk.slice(0, tab), unit: dk.slice(tab + 1) };
            const prim = findLinkedContractPrimaryForUnitInSavedMap(uRef);
            if (!prim) return;
            const primaryEntry = getSavedContractMapEntry(savedMap, prim.building, prim.unit);
            const p = primaryEntry?.payload;
            if (!p) return;
            const linked = getLinkedContractUnitsFromPayload(p);
            if (linked.length <= 1) return;
            const status = primaryEntry.lifecycleStatus || resolveContractLifecycleStatus(p);
            const slice = getLinkedContractUnitSlice(p, uRef.unit);
            const merged = {
                ...p,
                flatNo: toStr(uRef.unit),
                floorDetails: slice.floorDetails,
                unitType: slice.unitType,
                monthlyRent: toStr(slice.monthlyRent),
                electricityMeter: slice.electricityMeter,
                waterMeter: slice.waterMeter,
                linkedContractUnits: linked,
                linkedContractUnitsJson: JSON.stringify(linked),
                contractSavedAt: toStr(p.contractSavedAt) || primaryEntry.savedAt,
                contractSavedStatus: status
            };
            const nk = _tenancyDraftStorageKey(uRef.building, uRef.unit);
            savedMap[nk] = {
                payload: merged,
                lifecycleStatus: status,
                savedAt: merged.contractSavedAt,
                updatedAt: new Date().toISOString(),
                lastActorUserId: primaryEntry.lastActorUserId,
                lastActorName: primaryEntry.lastActorName
            };
            delete draftMap[dk];
            touched = true;
        });
        if (touched) {
            saveSavedContractsByUnitMap(savedMap);
            saveTenancyContractDraftsMap(draftMap);
            bumpUnitsDataCache();
        }
        return touched;
    }

    function ensureOwnerLinksPlaceholder() {
        if (Object.keys(ownerBuildingMap).length > 0) return;
        const buildings = [...new Set(getUnitsData().map((x) => x.building).filter(Boolean))];
        if (!buildings.length || !ownersList.length) return;
        buildings.forEach((b, i) => {
            const o = ownersList[i % ownersList.length];
            if (!ownerBuildingMap[o]) ownerBuildingMap[o] = [];
            ownerBuildingMap[o].push(b);
        });
        saveDashboardAux();
    }

    function parseBulkNames(text) {
        return [...new Set(String(text || '').split(/[\r\n,;]+/).map((x) => toStr(x)).filter(Boolean))];
    }

    function makeBuildingLabel(profile) {
        if (!profile) return '';
        const explicit = toStr(profile.name);
        if (explicit) return explicit;
        const parts = [];
        if (toStr(profile.area)) parts.push(toStr(profile.area));
        if (toStr(profile.plotNo)) parts.push(`Plot ${toStr(profile.plotNo)}`);
        if (toStr(profile.buildingNo)) parts.push(`Building ${toStr(profile.buildingNo)}`);
        return parts.join(', ');
    }

    function extractPlotBuildingKey(label) {
        const s = toStr(label).toLowerCase();
        const p = (s.match(/plot\s*([\w/-]+)/i) || [])[1] || '';
        const b = (s.match(/building\s*([\w/-]+)/i) || [])[1] || '';
        if (!p && !b) return '';
        return `${p}|${b}`;
    }

    function createEmptyFloor(index = 0) {
        return {
            name: index === 0 ? 'الطابق الأرضي' : `الطابق ${index + 1}`,
            selectedTypes: ['Flat'],
            unitCount: 0,
            units: [],
            unitsDetailed: []
        };
    }

    function getBuildingTypeOptions() {
        return ['فيلا', 'متعدد الطوابق'];
    }

    const BUILDING_STATUS_ACTIVE = 'نشط';

    /** حدود أمان لمنع تعطّل الواجهة عند أعداد طوابق/وحدات خاطئة */
    const BHD_MAX_BUILDING_FLOORS = 120;
    const BHD_MAX_UNITS_PER_FLOOR = 200;
    const BHD_MAX_FLOOR_DESIGNER_RENDER = 30;
    const BHD_MAX_TOTAL_UNITS_PER_BUILDING = 2500;

    function clampBuildingFloorCount(n) {
        const x = Math.max(0, parseInt(n, 10) || 0);
        return Math.min(x, BHD_MAX_BUILDING_FLOORS);
    }

    function clampFloorUnitCount(n) {
        const x = Math.max(0, parseInt(n, 10) || 0);
        return Math.min(x, BHD_MAX_UNITS_PER_FLOOR);
    }

    function sanitizeBuildingProfileFloors(profile) {
        if (!profile || typeof profile !== 'object') return profile;
        const p = profile;
        let floors = Array.isArray(p.floors) ? p.floors.map((f, i) => normalizeFloorData(f, i)) : [];
        const targetFloors = clampBuildingFloorCount(p.floorCount || floors.length);
        if (floors.length > targetFloors) floors = floors.slice(0, targetFloors);
        while (floors.length < targetFloors) floors.push(normalizeFloorData(createEmptyFloor(floors.length), floors.length));
        floors = floors.map((floor, idx) => {
            const f = normalizeFloorData(floor, idx);
            const uc = clampFloorUnitCount(f.unitCount || (f.unitsDetailed || []).length);
            let unitsDetailed = Array.isArray(f.unitsDetailed) ? f.unitsDetailed.slice() : [];
            if (unitsDetailed.length > uc) unitsDetailed = unitsDetailed.slice(0, uc);
            while (unitsDetailed.length < uc) {
                unitsDetailed.push({
                    number: '',
                    type: (f.selectedTypes && f.selectedTypes[0]) || 'Flat',
                    electricity: '',
                    water: '',
                    monthlyRent: ''
                });
            }
            return {
                ...f,
                unitCount: uc,
                unitsDetailed,
                units: unitsDetailed.map((u) => toStr(u.number)).filter(Boolean)
            };
        });
        p.floors = floors;
        p.floorCount = floors.length;
        return p;
    }

    function repairOversizedBuildingProfilesInMemory() {
        if (!buildingProfiles || typeof buildingProfiles !== 'object') return false;
        let changed = false;
        Object.keys(buildingProfiles).forEach((k) => {
            const raw = buildingProfiles[k];
            if (!raw || typeof raw !== 'object') return;
            const beforeFloors = Number(raw.floorCount || (raw.floors || []).length || 0);
            const beforeUnits = (raw.floors || []).reduce(
                (s, f) => s + (Array.isArray(f?.unitsDetailed) ? f.unitsDetailed.length : Number(f?.unitCount) || 0),
                0
            );
            const sanitized = sanitizeBuildingProfileFloors({ ...raw });
            const afterFloors = Number(sanitized.floorCount || 0);
            const afterUnits = (sanitized.floors || []).reduce(
                (s, f) => s + (Array.isArray(f.unitsDetailed) ? f.unitsDetailed.length : 0),
                0
            );
            if (beforeFloors !== afterFloors || beforeUnits !== afterUnits) {
                sanitized._structureTrimmedAt = new Date().toISOString();
                sanitized._structureTrimNote = `floors ${beforeFloors}→${afterFloors}, units ${beforeUnits}→${afterUnits}`;
                buildingProfiles[k] = sanitized;
                changed = true;
            }
        });
        return changed;
    }

    function getBuildingStatusOptions() {
        return [
            { value: 'نشط', label: 'نشط / Active' },
            { value: 'مباع', label: 'مباع / Sold' },
            { value: 'موقوف', label: 'موقوف / Suspended' },
            { value: 'منتهي التعاقد', label: 'منتهي التعاقد / Contract ended' }
        ];
    }

    function normalizeBuildingStatus(v) {
        const s = toStr(v);
        const valid = getBuildingStatusOptions().map((o) => o.value);
        return valid.includes(s) ? s : BUILDING_STATUS_ACTIVE;
    }

    function isBuildingProfileActive(profile) {
        return normalizeBuildingStatus(profile?.buildingStatus) === BUILDING_STATUS_ACTIVE;
    }

    function formatBuildingStatusLabel(status) {
        const s = normalizeBuildingStatus(status);
        const hit = getBuildingStatusOptions().find((o) => o.value === s);
        return hit ? hit.label : s;
    }

    function buildingStatusChipHtml(status) {
        const s = normalizeBuildingStatus(status);
        const cls =
            s === BUILDING_STATUS_ACTIVE
                ? 'building-status-active'
                : s === 'مباع'
                  ? 'building-status-sold'
                  : s === 'موقوف'
                    ? 'building-status-suspended'
                    : 'building-status-ended';
        return `<span class="chip ${cls}" style="font-size:11px">${escHtml(formatBuildingStatusLabel(s))}</span>`;
    }

    /** شارة حالة الوحدة (شاغر/مؤجر/محجوز…) — نفس ألوان الجدول الرئيسي / Unit status chip — same colors as main table */
    function unitOccupancyStatusChipHtml(u) {
        if (!u) return '';
        if (isReservedUnitRow(u)) {
            return `<span class="chip contract-state-reservation_confirmed">${escHtml(t('محجوز', 'Reserved'))}</span>`;
        }
        const days = daysUntil(u.endDate);
        const token = getStatusToken(u, days);
        const statusText =
            token === 'Expiring'
                ? t('قريب الانتهاء', 'Expiring soon')
                : token === 'Overdue'
                  ? t('منتهي', 'Overdue')
                  : token === 'NoEndDate'
                    ? t('بدون تاريخ', 'No end date')
                    : u.status === 'Vacant'
                      ? t('شاغر', 'Vacant')
                      : t('مؤجر', 'Rented');
        const statusClass =
            token === 'Expiring' || token === 'Overdue' ? 'expiring' : u.status === 'Vacant' ? 'vacant' : 'rented';
        return `<span class="chip ${statusClass}">${escHtml(statusText)}</span>`;
    }

    /** هل تُعرض وحدات هذا المبنى في الجداول والحجز؟ / Should this building's units appear in operations? */
    function isBuildingNameActive(buildingName) {
        const b = toStr(buildingName);
        if (!b) return true;
        const profile = getBuildingProfile(b);
        if (!profile) return true;
        return isBuildingProfileActive(profile);
    }

    function getActiveBuildingNames() {
        const set = new Set();
        Object.values(buildingProfiles || {}).forEach((raw) => {
            const profile = raw || {};
            const name = makeBuildingLabel(profile);
            if (name && isBuildingProfileActive(profile)) set.add(name);
        });
        return [...set].sort((a, b) => a.localeCompare(b, 'ar'));
    }

    function filterUnitsToActiveBuildingsOnly(rows) {
        return (rows || []).filter((u) => isBuildingNameActive(u.building));
    }

    function getUnitTypeChoices() {
        return [
            { value: 'Flat', label: 'شقة' },
            { value: 'Shop', label: 'محل' },
            { value: 'Office', label: 'مكتب' },
            { value: 'Room', label: 'غرفة' }
        ];
    }

    function parseRentAmountInput(v) {
        const raw = toStr(v).replace(/,/g, '.').replace(/[^\d.]/g, '');
        if (!raw) return '';
        const n = parseFloat(raw);
        return Number.isFinite(n) && n >= 0 ? n : '';
    }

    function formatRentAmountForInput(v) {
        const n = parseRentAmountInput(v);
        return n === '' ? '' : String(n);
    }

    /** إيجار الوحدة من ملف المبنى — للحجز والعقود / Default unit rent from building profile */
    function lookupBuildingUnitDefaultRent(buildingName, unitNo, floorName) {
        const label = toStr(buildingName);
        if (!label) return '';
        const key = resolveBuildingProfileKey(label) || label;
        const profile = buildingProfiles[key];
        if (!profile) return '';
        if (toStr(profile.buildingType) === 'فيلا') {
            return formatRentAmountForInput(profile.villaMonthlyRent);
        }
        const floors = Array.isArray(profile.floors) ? profile.floors : [];
        for (let fi = 0; fi < floors.length; fi++) {
            const floor = normalizeFloorData(floors[fi], fi);
            if (floorName && toStr(floor.name) && toStr(floor.name) !== toStr(floorName)) continue;
            const u = (floor.unitsDetailed || []).find(
                (ud) => normalizeUnit(ud.number) === normalizeUnit(unitNo)
            );
            if (u) return formatRentAmountForInput(u.monthlyRent);
        }
        return '';
    }

    function resolveUnitMonthlyRentForReservation(unit) {
        const fromRow = formatRentAmountForInput(unit?.monthlyRent);
        if (fromRow !== '') return fromRow;
        return lookupBuildingUnitDefaultRent(unit?.building, unit?.unit, unit?.floor);
    }

    function normalizeFloorData(floor, index = 0) {
        const base = createEmptyFloor(index);
        const selectedTypes = Array.isArray(floor?.selectedTypes) && floor.selectedTypes.length
            ? floor.selectedTypes.map((x) => toStr(x)).filter(Boolean)
            : (toStr(floor?.unitType) ? [toStr(floor.unitType)] : base.selectedTypes);
        const unitsDetailed = Array.isArray(floor?.unitsDetailed) && floor.unitsDetailed.length
            ? floor.unitsDetailed.map((u) => ({
                number: toStr(u.number),
                type: toStr(u.type) || selectedTypes[0] || 'Flat',
                electricity: toStr(u.electricity),
                water: toStr(u.water),
                monthlyRent: formatRentAmountForInput(u.monthlyRent)
            }))
            : (Array.isArray(floor?.units) ? floor.units : []).map((u) => ({
                number: toStr(u),
                type: selectedTypes[0] || 'Flat',
                electricity: '',
                water: '',
                monthlyRent: ''
            }));
        return {
            name: toStr(floor?.name) || base.name,
            selectedTypes,
            unitCount: Number(floor?.unitCount || unitsDetailed.length || 0),
            units: unitsDetailed.map((u) => u.number),
            unitsDetailed
        };
    }

    function createUnitRowsFromProfile(profile) {
        const buildingName = makeBuildingLabel(profile);
        if (!buildingName) return [];
        const safeProfile = sanitizeBuildingProfileFloors({ ...(profile || {}) });
        const rows = [];
        const floors = Array.isArray(safeProfile.floors) ? safeProfile.floors : [];
        let unitBudget = BHD_MAX_TOTAL_UNITS_PER_BUILDING;
        floors.forEach((rawFloor, floorIdx) => {
            const floor = normalizeFloorData(rawFloor, floorIdx);
            const floorName = toStr(floor.name);
            const unitsDetailed = Array.isArray(floor.unitsDetailed) ? floor.unitsDetailed : [];
            unitsDetailed.forEach((unitRow) => {
                if (unitBudget <= 0) return;
                const unit = toStr(unitRow.number);
                const unitType = toStr(unitRow.type) || 'Flat';
                if (!unit) return;
                unitBudget -= 1;
                rows.push({
                    serialNo: '',
                    building: buildingName,
                    unit,
                    floor: floorName,
                    unitType,
                    status: 'Vacant',
                    tenant: '',
                    tenantEn: '',
                    civilCard: '',
                    contactNo: '',
                    mobile: '',
                    agreementNo: '',
                    monthlyRent: parseRentAmountInput(unitRow.monthlyRent) || 0,
                    agreementRent: parseRentAmountInput(unitRow.monthlyRent) || 0,
                    startDate: '',
                    endDate: '',
                    remainingDays: '',
                    monthsLeft: '',
                    evacuationDate: '',
                    electricity: toStr(unitRow.electricity),
                    electricityReading: '',
                    water: toStr(unitRow.water),
                    waterReading: '',
                    remarks: '',
                    ownerNames: formatOwnerNamesForBuilding(buildingName)
                });
            });
        });
        if (!rows.length && toStr(safeProfile.buildingType) === 'فيلا') {
            const fallbackUnit = toStr(safeProfile.buildingNo) || 'VILLA-1';
            rows.push({
                serialNo: '',
                building: buildingName,
                unit: fallbackUnit,
                floor: t('فيلا', 'Villa'),
                unitType: 'Flat',
                status: 'Vacant',
                tenant: '',
                tenantEn: '',
                civilCard: '',
                contactNo: '',
                mobile: '',
                agreementNo: '',
                monthlyRent: parseRentAmountInput(safeProfile.villaMonthlyRent) || 0,
                agreementRent: parseRentAmountInput(safeProfile.villaMonthlyRent) || 0,
                startDate: '',
                endDate: '',
                remainingDays: '',
                monthsLeft: '',
                evacuationDate: '',
                electricity: toStr(safeProfile.electricityMeter),
                electricityReading: '',
                water: toStr(safeProfile.waterMeter),
                waterReading: '',
                remarks: '',
                ownerNames: formatOwnerNamesForBuilding(buildingName)
            });
        }
        return rows;
    }

    function syncManagedUnitsFromProfiles() {
        const grouped = {};
        Object.values(buildingProfiles || {}).forEach((raw) => {
            const profile = raw || {};
            const name = makeBuildingLabel(profile);
            if (!name) return;
            const prev = grouped[name];
            if (!prev) {
                grouped[name] = profile;
                return;
            }
            const prevTs = new Date(toStr(prev.updatedAt) || 0).getTime() || 0;
            const curTs = new Date(toStr(profile.updatedAt) || 0).getTime() || 0;
            if (curTs >= prevTs) grouped[name] = profile;
        });
        managedUnitsData = Object.values(grouped)
            .filter((profile) => isBuildingProfileActive(profile))
            .flatMap((profile) => createUnitRowsFromProfile(profile));
        try {
            const reg = loadAccountingRegistry();
            let coaChanged = false;
            managedUnitsData.forEach((mu) => {
                if (mu && ensureCoaForPropertyUnit(mu.building, mu.unit, reg)) coaChanged = true;
            });
            if (coaChanged) saveAccountingRegistry(reg);
        } catch (_eCoaMu) {}
    }

    function getAllKnownBuildings() {
        const set = new Set(buildingsList.map((b) => toStr(b)).filter(Boolean));
        Object.values(buildingProfiles).forEach((profile) => {
            const name = makeBuildingLabel(profile);
            if (name) set.add(name);
        });
        getUnitsData().forEach((u) => {
            const b = toStr(u.building);
            if (b) set.add(b);
        });
        return [...set].sort((a, b) => a.localeCompare(b, 'ar'));
    }

    /** المباني المسجّلة فعلياً (قائمة + ملفات) — بدون أسماء واردة من وحدات فقط / Registered buildings only */
    function getRegisteredBuildings() {
        const set = new Set();
        (buildingsList || []).forEach((b) => {
            const s = toStr(b);
            if (s) set.add(s);
        });
        Object.keys(buildingProfiles || {}).forEach((k) => {
            const key = toStr(k);
            if (key) set.add(key);
            const label = makeBuildingLabel(buildingProfiles[k]);
            if (label) set.add(label);
        });
        return [...set].sort((a, b) => a.localeCompare(b, 'ar'));
    }

    function isBuildingLinkedToOwner(owner, building) {
        return (ownerBuildingMap[owner] || []).includes(building);
    }

    /** أسماء الملاك المرتبطين بمبنى معيّن (من خريطة الربط) / Owner names linked to a building */
    function getOwnerNamesForBuilding(buildingName) {
        const b = toStr(buildingName);
        if (!b) return [];
        return Object.keys(ownerBuildingMap)
            .filter((owner) => (ownerBuildingMap[owner] || []).includes(b))
            .sort((a, c) => a.localeCompare(c, 'ar'));
    }

    function formatOwnerNamesForBuilding(buildingName) {
        const names = getOwnerNamesForBuilding(buildingName);
        return names.length ? names.join('، ') : '';
    }

    function collectBuildingLinkedOwnersFromForm() {
        return Array.from(document.querySelectorAll('#buildingOwnerLinkChips .building-owner-link-chip'))
            .map((el) => toStr(el.getAttribute('data-building-owner-link')))
            .filter(Boolean);
    }

    function renderBuildingOwnerLinkChip(owner) {
        const o = toStr(owner);
        if (!o) return '';
        return `<span class="tag building-owner-link-chip" data-building-owner-link="${escAttr(o)}" style="display:inline-flex;align-items:center;gap:6px;margin:4px 6px 4px 0">
            ${escHtml(o)}
            <button type="button" class="mini-btn building-owner-link-remove" data-remove-building-owner="${escAttr(o)}" title="${escAttr(t('إزالة', 'Remove'))}" onclick="removeBuildingOwnerLink(this.getAttribute('data-remove-building-owner'))">×</button>
        </span>`;
    }

    function refreshBuildingOwnerPickSelectOptions() {
        const select = document.getElementById('buildingOwnerPickSelect');
        if (!select) return;
        const linked = new Set(collectBuildingLinkedOwnersFromForm());
        const available = ownersList.filter((o) => !linked.has(o));
        const current = toStr(select.value);
        select.innerHTML =
            `<option value="">${t('— اختر مالكاً من القائمة —', '— Select owner from list —')}</option>` +
            available.map((o) => `<option value="${escAttr(o)}">${escHtml(o)}</option>`).join('');
        if (current && available.includes(current)) select.value = current;
    }

    function renderBuildingOwnerLinkChipsHtml(linkedOwners) {
        const list = Array.isArray(linkedOwners) ? linkedOwners : [];
        if (!list.length) {
            return `<span style="font-size:12px;color:#888">${t('لم يُربط أي مالك بعد.', 'No owners linked yet.')}</span>`;
        }
        return list.map((o) => renderBuildingOwnerLinkChip(o)).join('');
    }

    function addBuildingOwnerLinkFromPick() {
        const select = document.getElementById('buildingOwnerPickSelect');
        const owner = toStr(select?.value);
        if (!owner) {
            alert(t('اختر مالكاً من القائمة المنسدلة أولاً.', 'Select an owner from the dropdown first.'));
            return;
        }
        const linked = collectBuildingLinkedOwnersFromForm();
        if (linked.includes(owner)) return;
        const host = document.getElementById('buildingOwnerLinkChips');
        if (!host) return;
        if (!linked.length) host.innerHTML = '';
        host.insertAdjacentHTML('beforeend', renderBuildingOwnerLinkChip(owner));
        wireBuildingOwnerLinkRemoval();
        if (select) select.value = '';
        refreshBuildingOwnerPickSelectOptions();
        scheduleBuildingRequiredFieldRefresh();
    }

    function removeBuildingOwnerLink(owner) {
        const o = toStr(owner);
        document.querySelectorAll('#buildingOwnerLinkChips .building-owner-link-chip').forEach((chip) => {
            if (toStr(chip.getAttribute('data-building-owner-link')) === o) chip.remove();
        });
        const host = document.getElementById('buildingOwnerLinkChips');
        if (host && !host.querySelector('.building-owner-link-chip')) {
            host.innerHTML = `<span style="font-size:12px;color:#888">${t('لم يُربط أي مالك بعد.', 'No owners linked yet.')}</span>`;
        }
        refreshBuildingOwnerPickSelectOptions();
        scheduleBuildingRequiredFieldRefresh();
    }

    /** مزامنة ربط ملاك متعددين بمبنى واحد / Sync multiple owners linked to one building */
    function syncBuildingOwnerLinks(buildingName, selectedOwners) {
        const b = toStr(buildingName);
        if (!b) return;
        const selectedSet = new Set((selectedOwners || []).map((o) => toStr(o)).filter(Boolean));
        selectedSet.forEach((owner) => {
            if (!ownersList.includes(owner)) ownersList.push(owner);
        });
        ownersList.forEach((owner) => {
            const arr = ownerBuildingMap[owner] || [];
            const has = arr.includes(b);
            if (selectedSet.has(owner)) {
                if (!has) {
                    if (!ownerBuildingMap[owner]) ownerBuildingMap[owner] = [];
                    ownerBuildingMap[owner].push(b);
                }
            } else if (has) {
                ownerBuildingMap[owner] = arr.filter((x) => x !== b);
            }
        });
    }

    function renderBuildingOwnerLinkSelect(buildingName) {
        if (!ownersList.length) {
            return `<p style="font-size:12px;color:#777;margin:0">${t('أضف ملاكاً من قسم «أسماء الملاك» أولاً.', 'Add owners under Owners first.')}</p>`;
        }
        const linked = getOwnerNamesForBuilding(buildingName);
        const available = ownersList.filter((o) => !linked.includes(o));
        return `
            <div id="buildingOwnersLinkHost" class="building-owners-link-host">
                <div style="display:flex;flex-wrap:wrap;gap:8px;align-items:center;margin-bottom:8px">
                    <select id="buildingOwnerPickSelect" style="flex:1;min-width:220px;max-width:100%;padding:9px 10px;border-radius:8px;border:1px solid #ced8df;font-family:inherit;font-size:13px">
                        <option value="">${t('— اختر مالكاً من القائمة —', '— Select owner from list —')}</option>
                        ${available.map((o) => `<option value="${escAttr(o)}">${escHtml(o)}</option>`).join('')}
                    </select>
                    <button type="button" class="btn-outline mini-btn" onclick="addBuildingOwnerLinkFromPick()">${t('إضافة مالك', 'Add owner')}</button>
                </div>
                <div id="buildingOwnerLinkChips" style="min-height:32px;padding:6px 8px;border:1px solid #e0e6eb;border-radius:8px;background:#fafcfe;line-height:1.6">
                    ${renderBuildingOwnerLinkChipsHtml(linked)}
                </div>
            </div>`;
    }

    function persistReferenceData(refreshInsight = true) {
        localStorage.setItem('bhd_buildings_list', JSON.stringify(buildingsList));
        localStorage.setItem('bhd_owners_list', JSON.stringify(ownersList));
        localStorage.setItem('bhd_owner_building_map', JSON.stringify(ownerBuildingMap));
        localStorage.setItem('bhd_owner_profiles', JSON.stringify(ownerProfiles));
        refreshAddressBookFromSystem(false);
        saveDashboardAux();
        updateAuthHeaderBar();
        updateSummaryPanel();
        if (pageMode === 'dashboard') {
            renderOperationsTable();
            renderRegistryTable();
        } else {
            renderDocument(currentDoc);
        }
        if (refreshInsight && insightNavStack.length) renderInsightContent();
    }

    function getEmptyOwnerProfile() {
        return {
            fullName: '',
            fullNameEn: '',
            firstName: '',
            secondName: '',
            thirdName: '',
            tribe: '',
            civilId: '',
            idExpiryDate: '',
            phone: '',
            email: '',
            idCardAttachment: null
        };
    }

    function getEditableOwnerProfile(name = '') {
        if (name && ownerProfiles[name]) {
            return { ...getEmptyOwnerProfile(), ...ownerProfiles[name], fullName: toStr(ownerProfiles[name].fullName) || name };
        }
        if (name) {
            return { ...getEmptyOwnerProfile(), fullName: name };
        }
        return getEmptyOwnerProfile();
    }

    function buildOwnerFullName(parts) {
        return [parts.firstName, parts.secondName, parts.thirdName, parts.tribe].map((x) => toStr(x)).filter(Boolean).join(' ');
    }

    function normalizeOwnerAttachment(raw) {
        if (!raw) return null;
        if (typeof raw === 'string') {
            return { name: raw, type: '', dataUrl: '' };
        }
        if (typeof raw === 'object') {
            return {
                name: toStr(raw.name),
                type: toStr(raw.type),
                dataUrl: toStr(raw.dataUrl || raw.url || '')
            };
        }
        return null;
    }

    function normalizeBuildingAttachment(raw) {
        if (!raw) return null;
        if (typeof raw === 'string') {
            return { name: raw, type: '', dataUrl: '' };
        }
        if (typeof raw === 'object') {
            return {
                name: toStr(raw.name),
                type: toStr(raw.type),
                dataUrl: toStr(raw.dataUrl || raw.url || '')
            };
        }
        return null;
    }

    async function openStoredAttachment(att, fallbackTitle = 'Attachment') {
        const attachment = att && att.dataUrl !== undefined ? att : normalizeOwnerAttachment(att) || normalizeBuildingAttachment(att);
        if (!attachment) {
            alert('لا يوجد ملف محفوظ.');
            return;
        }
        if (!attachment.dataUrl) {
            attachment.dataUrl = await bhdResolveAttachmentUrl(attachment);
        }
        if (!attachment.dataUrl) {
            alert('لا يوجد ملف محفوظ.');
            return;
        }
        const title = escHtml(attachment.name || fallbackTitle);
        const isImage = attachment.type.startsWith('image/') || attachment.dataUrl.startsWith('data:image/');
        const isPdf = attachment.type === 'application/pdf' || attachment.dataUrl.startsWith('data:application/pdf');
        const w = window.open('', '_blank');
        if (!w) {
            alert('تعذر فتح الملف. يرجى السماح بالنوافذ المنبثقة.');
            return;
        }
        const body = isImage
            ? `<div style="padding:16px;text-align:center"><img src="${attachment.dataUrl}" alt="${title}" style="max-width:100%;max-height:90vh;object-fit:contain"></div>`
            : isPdf
                ? `<embed src="${attachment.dataUrl}" type="application/pdf" style="width:100%;height:100vh">`
                : `<div style="padding:16px"><a href="${attachment.dataUrl}" download="${title}">تنزيل الملف / Download File</a></div>`;
        w.document.write(`
            <html>
                <head>
                    <title>${title}</title>
                    <meta charset="utf-8">
                    <style>
                        body { margin: 0; font-family: Tahoma, Arial, sans-serif; background: #f8f8f8; }
                    </style>
                </head>
                <body>${body}</body>
            </html>
        `);
        w.document.close();
    }

    /** طباعة مرفق (صورة/PDF/غيره) في نافذة منفصلة ثم استدعاء onDone */
    async function openStoredAttachmentAndPrint(att, caption, onDone) {
        const attachment = att && att.dataUrl !== undefined ? att : normalizeOwnerAttachment(att) || normalizeBuildingAttachment(att);
        if (!attachment) {
            if (onDone) onDone();
            return;
        }
        if (!attachment.dataUrl) {
            attachment.dataUrl = await bhdResolveAttachmentUrl(attachment);
        }
        if (!attachment.dataUrl) {
            if (onDone) onDone();
            return;
        }
        const title = escHtml(attachment.name || caption || 'Attachment');
        const capHtml = escHtml(caption || attachment.name || 'Attachment');
        const isImage = (attachment.type && attachment.type.startsWith('image/')) || attachment.dataUrl.startsWith('data:image/');
        const isPdf = attachment.type === 'application/pdf' || attachment.dataUrl.startsWith('data:application/pdf');
        const w = window.open('', '_blank');
        if (!w) {
            alert('تعذر فتح الملف للطباعة — اسمح بالنوافذ المنبثقة.\nCould not open file for printing — allow pop-ups.');
            if (onDone) onDone();
            return;
        }
        const body = isImage
            ? `<div style="padding:16px;text-align:center"><p style="font-size:13px;font-weight:700;margin:0 0 12px">${capHtml}</p><img src="${attachment.dataUrl}" alt="${title}" style="max-width:100%;max-height:85vh;object-fit:contain"></div>`
            : isPdf
                ? `<div style="padding:8px"><p style="font-size:13px;font-weight:700;margin:0 0 8px">${capHtml}</p><embed src="${attachment.dataUrl}" type="application/pdf" style="width:100%;min-height:90vh;border:0"></div>`
                : `<div style="padding:16px"><p style="font-size:13px;font-weight:700">${capHtml}</p><p style="font-size:11px;color:#555">معاينة غير متاحة — استخدم التنزيل / Preview not available — use download.</p><a href="${attachment.dataUrl}" download="${title}">تنزيل / Download</a></div>`;
        w.document.write(`<!DOCTYPE html><html lang="ar"><head><meta charset="utf-8"><title>${title}</title><style>body{margin:0;font-family:Tajawal,Tahoma,sans-serif;background:#fff} @media print { body { -webkit-print-color-adjust: exact; print-color-adjust: exact; } }</style></head><body>${body}</body></html>`);
        w.document.close();
        const finish = () => {
            try { w.close(); } catch (e) {}
            if (onDone) setTimeout(onDone, 150);
        };
        const doPrint = () => {
            try { w.focus(); w.print(); } catch (e) {}
            w.addEventListener('afterprint', finish, { once: true });
            setTimeout(finish, 3200);
        };
        if (isPdf) setTimeout(doPrint, 800);
        else setTimeout(doPrint, 350);
    }

    function queuePrintAttachments(items, index = 0) {
        if (!items || !items.length || index >= items.length) return;
        const cur = items[index];
        openStoredAttachmentAndPrint(cur.att, cur.caption, () => {
            setTimeout(() => queuePrintAttachments(items, index + 1), 450);
        });
    }

    function collectBuildingProfileAttachments(profile, buildingLabel) {
        if (!profile) return [];
        const prefix = `${buildingLabel} — `;
        const out = [];
        const t = normalizeBuildingAttachment(profile.titleDeedAttachment);
        if (t && t.dataUrl) out.push({ att: t, caption: `${prefix}سند الملكية / Title deed` });
        const s = normalizeBuildingAttachment(profile.surveySketchAttachment);
        if (s && s.dataUrl) out.push({ att: s, caption: `${prefix}الرسم المساحي / Survey sketch` });
        return out;
    }

