    function openBuildingEditor(name = '') {
        if (!assertPermissionOrAlert('manage_properties', 'لا تملك صلاحية تعديل العقارات.', 'No permission to edit properties.')) return;
        window._pendingBuildingTitleDeedAttachment = null;
        window._pendingBuildingSurveySketchAttachment = null;
        clearBuildingRequiredFieldStates();
        closeDataGapsModal();
        initBuildingRequiredFieldWatchers();
        const resolved = resolveBuildingProfileKey(name) || name || '';
        buildingEditorState = { open: true, originalName: resolved };
        document.getElementById('dashboardInsightModal')?.classList.add('open');
        insightNavStack = [{ mode: 'buildings' }];
        renderInsightContent();
        wireBuildingOwnerLinkRemoval();
        scheduleBuildingRequiredFieldRefresh();
        setTimeout(() => {
            const statusEl = document.getElementById('buildingStatusInput');
            if (statusEl) {
                try {
                    statusEl.scrollIntoView({ behavior: 'smooth', block: 'center' });
                } catch (e) {}
            }
        }, 120);
    }

    function closeBuildingEditor() {
        window._pendingBuildingTitleDeedAttachment = null;
        window._pendingBuildingSurveySketchAttachment = null;
        buildingEditorState = { open: false, originalName: '' };
        clearBuildingRequiredFieldStates();
        renderInsightContent();
    }

    function renderFloorDesignerRows(floors = []) {
        const typeChoices = getUnitTypeChoices();
        return floors.map((rawFloor, idx) => {
            const floor = normalizeFloorData(rawFloor, idx);
            const allowedTypes = floor.selectedTypes || [];
            const sourceRows = (floor.unitsDetailed && floor.unitsDetailed.length)
                ? floor.unitsDetailed
                : Array.from({ length: Number(floor.unitCount || 0) }, () => ({ number: '', type: allowedTypes[0] || 'Flat', electricity: '', water: '' }));
            const detailRows = sourceRows.map((u, unitIdx) => renderUnitDetailRow(u, unitIdx, allowedTypes)).join('');
            return `
                <div class="floor-editor-row insight-nested" data-floor-index="${idx}" style="margin-top:8px;padding:10px;border:1px solid #ddd;border-radius:10px">
                    <div style="font-weight:700;margin-bottom:8px">الطابق ${idx + 1}</div>
                    <div class="registry-form" style="display:grid;grid-template-columns:1.2fr .8fr;gap:8px">
                        <div style="display:flex;flex-direction:column;gap:4px">
                            <label style="font-size:12px;font-weight:700;color:#444">اسم الطابق</label>
                            <input data-floor-field="name" value="${escHtml(floor.name || '')}">
                        </div>
                        <div style="display:flex;flex-direction:column;gap:4px">
                            <label style="font-size:12px;font-weight:700;color:#444">عدد الوحدات</label>
                            <input type="number" min="0" data-floor-field="count" value="${Number(floor.unitCount || (floor.unitsDetailed || []).length || 0)}" oninput="onFloorUnitCountChange(this)">
                        </div>
                    </div>
                    <div class="building-floor-types-cell" style="margin-top:10px">
                        <div style="font-size:12px;font-weight:700;color:#444;margin-bottom:6px">أنواع الوحدات المتاحة في هذا الطابق</div>
                        <div style="display:flex;gap:10px;flex-wrap:wrap">
                            ${typeChoices.map((choice) => `
                                <label style="display:flex;align-items:center;gap:4px;font-size:12px">
                                    <input type="checkbox" data-floor-field="type-check" value="${choice.value}" ${floor.selectedTypes.includes(choice.value) ? 'checked' : ''} onchange="onFloorTypeChecksChange(this)">
                                    <span>${choice.label}</span>
                                </label>
                            `).join('')}
                        </div>
                    </div>
                    <div class="building-floor-units-cell" style="margin-top:10px">
                        <div style="font-size:12px;font-weight:700;color:#444;margin-bottom:6px">الوحدات التفصيلية</div>
                        <div class="units-detail-host">${detailRows}</div>
                    </div>
                </div>
            `;
        }).join('');
    }

    function openBuildingFloorsDesigner() {
        const type = toStr(document.getElementById('buildingTypeInput')?.value) || 'متعدد الطوابق';
        const countInput = document.getElementById('buildingFloorCountInput');
        const host = document.getElementById('buildingFloorsDesigner');
        if (!host) return;
        if (type === 'فيلا') {
            host.innerHTML = '';
            return;
        }
        const rawCount = Math.max(0, Number(countInput?.value || 0));
        const count = clampBuildingFloorCount(rawCount);
        if (countInput && rawCount !== count) countInput.value = String(count);
        const current = collectBuildingProfileForm().floors;
        const floors = [];
        for (let i = 0; i < count; i++) floors.push(normalizeFloorData(current[i] || createEmptyFloor(i), i));
        const renderCount = Math.min(count, BHD_MAX_FLOOR_DESIGNER_RENDER);
        const renderFloors = floors.slice(0, renderCount);
        const limitNote =
            count > BHD_MAX_FLOOR_DESIGNER_RENDER
                ? `<p style="font-size:12px;color:#b71c1c;margin:0 0 8px;line-height:1.45">${t(
                      `يُعرض أول ${BHD_MAX_FLOOR_DESIGNER_RENDER} طوابق فقط في المحرّر لسلامة الأداء (الإجمالي المسجّل: ${count}). احفظ العقار ثم عدّل الطوابق على دفعات.`,
                      `Only the first ${BHD_MAX_FLOOR_DESIGNER_RENDER} floors are shown in the editor for performance (total registered: ${count}). Save the property, then edit floors in batches.`
                  )}</p>`
                : count >= BHD_MAX_BUILDING_FLOORS
                  ? `<p style="font-size:12px;color:#8a5a00;margin:0 0 8px">${t(
                        `الحد الأقصى للطوابق: ${BHD_MAX_BUILDING_FLOORS}`,
                        `Maximum floors: ${BHD_MAX_BUILDING_FLOORS}`
                    )}</p>`
                  : '';
        host.innerHTML = count
            ? `<div style="font-size:12px;color:#555;margin-bottom:6px">${t('إعداد الطوابق والوحدات', 'Floors and units setup')}</div>${limitNote}${renderFloorDesignerRows(renderFloors)}`
            : `<p style="font-size:12px;color:#777">${t('أدخل عدد الطوابق لتظهر لك الحقول تلقائياً.', 'Enter number of floors to show fields automatically.')}</p>`;
        scheduleBuildingRequiredFieldRefresh();
    }

    function findDuplicateBuildingSketchNo(sketchNo, excludeBuildingKey) {
        const sn = toStr(sketchNo).trim().toLowerCase();
        if (!sn) return null;
        const exclude = toStr(excludeBuildingKey);
        for (const key of Object.keys(buildingProfiles || {})) {
            if (exclude && (key === exclude || resolveBuildingProfileKey(key) === exclude)) continue;
            const p = buildingProfiles[key];
            if (p && toStr(p.sketchNo).trim().toLowerCase() === sn) return makeBuildingLabel(p) || key;
        }
        return null;
    }

    function clearBuildingRequiredFieldStates() {
        const cls = [
            'bhd-field-required-empty',
            'bhd-field-required-filled',
            'bhd-field-required-empty-block',
            'bhd-field-required-filled-block'
        ];
        cls.forEach((c) => document.querySelectorAll('.' + c).forEach((el) => el.classList.remove(c)));
    }

    function clearBuildingProfileGapHighlights() {
        clearBuildingRequiredFieldStates();
    }

    function findBuildingUnitFieldEl(floorIndex, unitNumber, unitField, unitIndex) {
        const floorRow = document.querySelector(`#buildingFloorsDesigner [data-floor-index="${floorIndex}"]`);
        if (!floorRow || !unitField) return null;
        const rows = Array.from(floorRow.querySelectorAll('.unit-detail-row'));
        if (unitNumber) {
            const hit = rows.find(
                (r) => normalizeUnit(toStr(r.querySelector('[data-unit-field="number"]')?.value)) === normalizeUnit(unitNumber)
            );
            if (hit) return hit.querySelector(`[data-unit-field="${unitField}"]`);
        }
        if (unitIndex != null && unitIndex >= 0 && rows[unitIndex]) {
            return rows[unitIndex].querySelector(`[data-unit-field="${unitField}"]`);
        }
        return null;
    }

    function resolveBuildingRequiredFieldElement(check) {
        if (!check) return null;
        if (check.fieldId) return document.getElementById(check.fieldId);
        const row =
            check.floorIndex != null
                ? document.querySelector(`#buildingFloorsDesigner [data-floor-index="${check.floorIndex}"]`)
                : null;
        if (check.kind === 'floorName') return row?.querySelector('[data-floor-field="name"]') || null;
        if (check.kind === 'floorTypes') return row?.querySelector('.building-floor-types-cell') || row;
        if (check.kind === 'floorUnits') return row?.querySelector('.building-floor-units-cell') || row?.querySelector('[data-floor-field="count"]') || row;
        if (check.kind === 'buildingOwners') return document.getElementById('buildingOwnersLinkHost');
        if (check.unitField && check.floorIndex != null) {
            return findBuildingUnitFieldEl(check.floorIndex, check.unitNumber, check.unitField, check.unitIndex);
        }
        return row;
    }

    function applyBuildingRequiredFieldState(el, filled) {
        if (!el) return;
        const emptyCls = 'bhd-field-required-empty';
        const filledCls = 'bhd-field-required-filled';
        const emptyBlock = 'bhd-field-required-empty-block';
        const filledBlock = 'bhd-field-required-filled-block';
        const isControl = el.matches('input, select, textarea');
        const isFile = el.type === 'file';
        const cell = el.closest('.building-field-cell');
        if (isFile) {
            const block = cell || el;
            block.classList.remove(emptyBlock, filledBlock, emptyCls, filledCls);
            block.classList.add(filled ? filledBlock : emptyBlock);
            return;
        }
        if (isControl) {
            el.classList.remove(emptyCls, filledCls, emptyBlock, filledBlock);
            el.classList.add(filled ? filledCls : emptyCls);
            if (cell) {
                cell.classList.remove(emptyBlock, filledBlock);
                cell.classList.add(filled ? filledBlock : emptyBlock);
            }
            return;
        }
        el.classList.remove(emptyCls, filledCls, emptyBlock, filledBlock);
        el.classList.add(filled ? filledBlock : emptyBlock);
    }

    function scheduleBuildingRequiredFieldRefresh() {
        clearTimeout(buildingRequiredRefreshTimer);
        buildingRequiredRefreshTimer = setTimeout(refreshBuildingRequiredFieldStates, 60);
    }

    function refreshBuildingRequiredFieldStates() {
        if (!buildingEditorState.open) return;
        const root = document.getElementById('buildingEditorRoot');
        if (!root) return;
        clearBuildingRequiredFieldStates();
        const profile = collectBuildingProfileForm();
        const { checks } = validateBuildingProfileComplete(profile);
        (checks || []).forEach((check) => {
            applyBuildingRequiredFieldState(resolveBuildingRequiredFieldElement(check), !!check.filled);
        });
    }

    function scrollToFirstBuildingRequiredGap(missing) {
        const first = (missing || []).find((m) => !m.filled) || (missing || [])[0];
        if (!first) return;
        const el = resolveBuildingRequiredFieldElement(first);
        if (!el) return;
        try {
            (el.closest('.building-field-cell') || el.closest('.floor-editor-row') || el).scrollIntoView({
                behavior: 'smooth',
                block: 'center'
            });
        } catch (e) {}
    }

    function highlightBuildingProfileGaps(missing) {
        refreshBuildingRequiredFieldStates();
        scrollToFirstBuildingRequiredGap(missing);
    }

    function showBuildingProfileGapsModal(missing) {
        const host = document.getElementById('dataGapsBody');
        if (!host) return;
        const items = (missing || []).filter((m) => m && m.ar);
        host.innerHTML = `
            <p style="font-size:13px;margin:0 0 10px;line-height:1.55">${t(
                'الحقول الإلزامية: فارغة بإطار أحمر، ومكتملة بإطار أخضر في النموذج. النواقص:',
                'Required fields: empty = red outline, completed = green outline in the form. Still missing:'
            )}</p>
            <ol style="margin:0;padding-right:20px;font-size:13px;line-height:1.65;color:#333">
                ${items.map((m) => `<li><strong>${escHtml(m.ar)}</strong> / ${escHtml(m.en)}</li>`).join('')}
            </ol>
        `;
        document.getElementById('dataGapsModal')?.classList.add('open');
        try {
            localizeBilingualUi();
        } catch (e) {}
    }

    function isBuildingRentMissing(v) {
        return formatRentAmountForInput(v) === '';
    }

    function collectBuildingProfileRequiredChecks(profile) {
        const checks = [];
        const push = (ar, en, fieldId, floorIndex, unitIndex, unitField, unitNumber, kind, filled) => {
            checks.push({
                ar,
                en,
                fieldId: fieldId || '',
                floorIndex: floorIndex == null ? null : floorIndex,
                unitIndex: unitIndex == null ? null : unitIndex,
                unitField: unitField || '',
                unitNumber: unitNumber || '',
                kind: kind || '',
                filled: !!filled
            });
        };
        const tv = (v) => toStr(v);
        push('اسم العقار', 'Building name', 'buildingNameInput', null, null, null, null, '', !!tv(profile.name));
        push('نوع المبنى', 'Building type', 'buildingTypeInput', null, null, null, null, '', !!tv(profile.buildingType));
        push('حالة المبنى', 'Building status', 'buildingStatusInput', null, null, null, null, '', !!normalizeBuildingStatus(profile.buildingStatus));
        push('رقم المبنى', 'Building number', 'buildingNoInput', null, null, null, null, '', !!tv(profile.buildingNo));
        push('رقم القطعة', 'Plot number', 'buildingPlotNoInput', null, null, null, null, '', !!tv(profile.plotNo));
        push('رقم المجمع', 'Complex number', 'buildingComplexNoInput', null, null, null, null, '', !!tv(profile.complexNo));
        push('نوع استعمال الأرض', 'Land use', 'buildingLandUseInput', null, null, null, null, '', !!tv(profile.landUse));
        const td = normalizeBuildingAttachment(profile.titleDeedAttachment);
        const ss = normalizeBuildingAttachment(profile.surveySketchAttachment);
        push('نسخة سند الملكية', 'Title deed attachment', 'buildingTitleDeedAttachmentInput', null, null, null, null, '', !!(td && td.dataUrl));
        push('نسخة الرسم المساحي', 'Survey sketch attachment', 'buildingSurveySketchAttachmentInput', null, null, null, null, '', !!(ss && ss.dataUrl));
        push('رابط الموقع (Google Maps)', 'Google Maps URL', 'buildingGoogleMapsUrlInput', null, null, null, null, '', !!tv(profile.googleMapsUrl));
        push('رقم عداد الكهرباء العام', 'Main electricity meter', 'buildingElectricityMeterInput', null, null, null, null, '', !!tv(profile.electricityMeter));
        push('رقم عداد الماء العام', 'Main water meter', 'buildingWaterMeterInput', null, null, null, null, '', !!tv(profile.waterMeter));
        push('رقم الانترنت', 'Internet number', 'buildingInternetNoInput', null, null, null, null, '', !!tv(profile.internetNo));
        push('رقم عداد ماء الحريق', 'Fire water meter', 'buildingFireWaterMeterInput', null, null, null, null, '', !!tv(profile.fireWaterMeter));
        push('رقم عداد كهرباء الحريق', 'Fire electricity meter', 'buildingFireElectricityMeterInput', null, null, null, null, '', !!tv(profile.fireElectricityMeter));
        push('رقم السكة/الزقاق', 'Way/lane number', 'buildingWayNoInput', null, null, null, null, '', !!tv(profile.wayNo));
        push('رقم الرسم المساحي (الكروكي)', 'Survey sketch number', 'buildingSketchNoInput', null, null, null, null, '', !!tv(profile.sketchNo));
        push('المحافظة', 'Governorate', 'buildingGovernorateInput', null, null, null, null, '', !!tv(profile.governorate));
        push('الولاية', 'Wilayat', 'buildingWilayatInput', null, null, null, null, '', !!tv(profile.wilayat));
        push('المنطقة', 'Area', 'buildingAreaInput', null, null, null, null, '', !!tv(profile.area));
        const ownerLinkKey = makeBuildingLabel(profile) || profile.name || buildingEditorState.originalName;
        const ownerCount = buildingEditorState.open
            ? collectBuildingLinkedOwnersFromForm().length
            : getOwnerNamesForBuilding(ownerLinkKey).length;
        push(
            'ملاك مرتبطون (واحد على الأقل)',
            'Linked owners (at least one)',
            '',
            null,
            null,
            null,
            null,
            'buildingOwners',
            ownerCount > 0
        );
        const floors = Array.isArray(profile.floors) ? profile.floors.map((f, i) => normalizeFloorData(f, i)) : [];
        if (tv(profile.buildingType) === 'فيلا') {
            push(
                'قيمة الإيجار الشهري (ر.ع)',
                'Monthly rent (OMR)',
                'buildingVillaMonthlyRentInput',
                null,
                null,
                null,
                null,
                '',
                !isBuildingRentMissing(profile.villaMonthlyRent)
            );
        } else {
            push('الطوابق والوحدات', 'Floors & units', 'buildingFloorCountInput', null, null, null, null, '', floors.length > 0);
            floors.forEach((floor, fi) => {
                push(`اسم الطابق ${fi + 1}`, `Floor ${fi + 1} name`, '', fi, null, null, null, 'floorName', !!tv(floor.name));
                push(
                    `أنواع الوحدات — طابق ${fi + 1}`,
                    `Unit types — floor ${fi + 1}`,
                    '',
                    fi,
                    null,
                    null,
                    null,
                    'floorTypes',
                    !!(floor.selectedTypes && floor.selectedTypes.length)
                );
                const ud = (floor.unitsDetailed || []).filter((x) => tv(x.number));
                push(`وحدات الطابق ${fi + 1}`, `Units on floor ${fi + 1}`, '', fi, null, null, null, 'floorUnits', ud.length > 0);
                ud.forEach((unit, ui) => {
                    const un = tv(unit.number);
                    push(
                        `إيجار الوحدة ${un} (ر.ع)`,
                        `Unit ${un} monthly rent (OMR)`,
                        '',
                        fi,
                        ui,
                        'monthlyRent',
                        un,
                        '',
                        !isBuildingRentMissing(unit.monthlyRent)
                    );
                    push(
                        `رقم كهرباء الوحدة ${un}`,
                        `Unit ${un} electricity`,
                        '',
                        fi,
                        ui,
                        'electricity',
                        un,
                        '',
                        !!tv(unit.electricity)
                    );
                    push(
                        `رقم ماء الوحدة ${un}`,
                        `Unit ${un} water`,
                        '',
                        fi,
                        ui,
                        'water',
                        un,
                        '',
                        !!tv(unit.water)
                    );
                });
            });
        }
        return checks;
    }

    function validateBuildingProfileComplete(profile) {
        const checks = collectBuildingProfileRequiredChecks(profile);
        const missing = checks.filter((c) => !c.filled).map(({ ar, en, fieldId, floorIndex, unitIndex, unitField, unitNumber, kind }) => ({
            ar,
            en,
            fieldId,
            floorIndex,
            unitIndex,
            unitField,
            unitNumber,
            kind
        }));
        if (missing.length) {
            const msg =
                t('يرجى إكمال الحقول الإلزامية التالية:', 'Please complete the required fields:') +
                '\n\n• ' +
                missing.map((m) => `${m.ar} / ${m.en}`).join('\n• ');
            return { ok: false, missing, checks, message: msg };
        }
        return { ok: true, missing: [], checks, message: '' };
    }

    function wireBuildingOwnerLinkRemoval() {
        const host = document.getElementById('buildingOwnerLinkChips');
        if (!host) return;
        if (host.dataset.removeWired === '1') return;
        host.dataset.removeWired = '1';
        host.addEventListener('click', (e) => {
            const btn = e.target.closest('.building-owner-link-remove[data-remove-building-owner]');
            if (!btn) return;
            e.preventDefault();
            e.stopPropagation();
            removeBuildingOwnerLink(btn.getAttribute('data-remove-building-owner'));
        });
    }

    function initBuildingOwnerLinkHandlers() {
        if (window._buildingOwnerLinkHandlersInit) return;
        window._buildingOwnerLinkHandlersInit = true;
        document.addEventListener('click', (e) => {
            const btn = e.target.closest('.building-owner-link-remove[data-remove-building-owner]');
            if (!btn || !btn.closest('#buildingOwnersLinkHost')) return;
            e.preventDefault();
            e.stopPropagation();
            removeBuildingOwnerLink(btn.getAttribute('data-remove-building-owner'));
        }, true);
    }

    function initBuildingRequiredFieldWatchers() {
        if (window._buildingRequiredWatchInit) return;
        window._buildingRequiredWatchInit = true;
        initBuildingOwnerLinkHandlers();
        const handler = (e) => {
            if (!buildingEditorState.open) return;
            if (!e.target.closest('[data-building-editor-root]')) return;
            scheduleBuildingRequiredFieldRefresh();
        };
        document.addEventListener('input', handler, true);
        document.addEventListener('change', handler, true);
    }

    function validateBuildingProfileForReservation(profile) {
        const missing = [];
        const add = (ar, en) => missing.push(`${ar} / ${en}`);
        const t = (v) => toStr(v);
        if (!t(profile.name)) add('اسم العقار', 'Building name');
        if (!t(profile.buildingNo)) add('رقم المبنى', 'Building number');
        if (!t(profile.plotNo)) add('رقم القطعة', 'Plot number');
        if (!t(profile.landUse)) add('نوع استعمال الأرض', 'Land use');
        const floors = Array.isArray(profile.floors) ? profile.floors.map((f, i) => normalizeFloorData(f, i)) : [];
        if (!floors.length) add('الطوابق والوحدات', 'Floors & units');
        return { ok: missing.length === 0, missing };
    }

    function validateOwnerProfileComplete(profile) {
        const missing = [];
        const add = (ar, en) => missing.push(`${ar} / ${en}`);
        const t = (v) => toStr(v);
        if (!t(profile.fullName) && !t(profile.fullNameEn)) add('اسم المالك (عربي/English)', 'Owner name (Arabic/English)');
        if (!t(profile.civilId)) add('الرقم المدني', 'Civil ID');
        if (!t(profile.phone)) add('رقم الهاتف', 'Phone');
        if (!t(profile.email)) add('البريد الإلكتروني', 'Email');
        if (!t(profile.idExpiryDate)) add('تاريخ انتهاء البطاقة', 'ID expiry date');
        const idc = normalizeOwnerAttachment(profile.idCardAttachment);
        if (!idc || !idc.dataUrl) add('نسخة من البطاقة الشخصية', 'ID card copy');
        if (missing.length) {
            const msg = 'يرجى إكمال الحقول الإلزامية للمالك:\nPlease complete required owner fields:\n\n• ' + missing.join('\n• ');
            return { ok: false, message: msg };
        }
        return { ok: true, message: '' };
    }

    function upsertBuildingProfile(profile) {
        const name = makeBuildingLabel(profile);
        if (!name) {
            alert('يرجى إدخال اسم العقار أو رقم المبنى مع بيانات كافية.');
            return false;
        }
        const originalName = buildingEditorState.originalName || '';
        const dupSketch = findDuplicateBuildingSketchNo(profile.sketchNo, originalName);
        if (dupSketch) {
            alert(
                t(
                    `رقم الرسم المساحي (الكروكي) مستخدم في مبنى: ${dupSketch}`,
                    `Survey sketch number is already used by building: ${dupSketch}`
                )
            );
            return false;
        }
        profile.name = name;
        profile = sanitizeBuildingProfileFloors(profile);
        const now = new Date().toISOString();
        const actor = getCurrentActorLabel();

        let prev = null;
        if (originalName && buildingProfiles[originalName]) {
            prev = buildingProfiles[originalName];
        } else if (!originalName && buildingProfiles[name]) {
            prev = buildingProfiles[name];
        }

        if (originalName && originalName !== name) {
            delete buildingProfiles[originalName];
            const oldIdx = buildingsList.indexOf(originalName);
            if (oldIdx >= 0) buildingsList.splice(oldIdx, 1);
            Object.keys(ownerBuildingMap).forEach((owner) => {
                ownerBuildingMap[owner] = (ownerBuildingMap[owner] || []).map((b) => (b === originalName ? name : b));
            });
            unitReservations = unitReservations.map((r) => {
                if (toStr(r.building) !== originalName) return r;
                const next = { ...r, building: name };
                if (next.formData && typeof next.formData === 'object') {
                    next.formData = { ...next.formData, buildingNo: name };
                }
                return next;
            });
            try {
                const saved = JSON.parse(localStorage.getItem('bhd_contract_full') || '{}');
                if (toStr(saved.buildingNo) === originalName) {
                    saved.buildingNo = name;
                    localStorage.setItem('bhd_contract_full', JSON.stringify(saved));
                }
            } catch (e) {}
            const formBuilding = document.getElementById('buildingNo');
            if (formBuilding && toStr(formBuilding.value) === originalName) formBuilding.value = name;
        }

        if (prev) {
            profile.createdAt = prev.createdAt || prev.updatedAt || now;
            profile.createdBy = prev.createdBy || prev.updatedBy || actor;
        } else {
            profile.createdAt = now;
            profile.createdBy = actor;
        }
        profile.updatedAt = now;
        profile.updatedBy = actor;

        buildingProfiles[name] = profile;
        buildingProfilesShadow[name] = { ...profile };
        if (originalName && originalName !== name) {
            buildingProfiles[originalName] = { ...profile, name };
            buildingProfilesShadow[originalName] = { ...profile, name };
        }
        const pbKey = extractPlotBuildingKey(name) || extractPlotBuildingKey(originalName);
        if (pbKey) {
            const allKeys = [...new Set([...Object.keys(buildingProfiles), ...getAllKnownBuildings()])];
            allKeys.forEach((label) => {
                if (extractPlotBuildingKey(label) === pbKey || extractPlotBuildingKey(buildingProfiles[label]?.name) === pbKey) {
                    buildingProfiles[label] = { ...profile, name };
                    buildingProfilesShadow[label] = { ...profile, name };
                }
            });
        }
        if (!buildingsList.includes(name)) buildingsList.push(name);
        syncManagedUnitsFromProfiles();
        return name;
    }

    function collectBuildingAliasSet(buildingName) {
        const set = new Set();
        const seed = resolveBuildingProfileKey(buildingName) || toStr(buildingName);
        if (seed) set.add(seed);
        const prof = buildingProfiles[seed];
        const label = makeBuildingLabel(prof) || seed;
        if (label) set.add(label);

        let changed = true;
        while (changed) {
            changed = false;
            const pbKeys = new Set();
            set.forEach((a) => {
                const pb = extractPlotBuildingKey(a);
                if (pb) pbKeys.add(pb);
            });
            const tryAdd = (candidate) => {
                const c = toStr(candidate);
                if (!c) return;
                if (set.has(c)) return;
                for (const a of set) {
                    if (normalizeReservationBuildingKey(a) === normalizeReservationBuildingKey(c)) {
                        set.add(c);
                        changed = true;
                        return;
                    }
                }
                const cp = extractPlotBuildingKey(c);
                if (cp && pbKeys.has(cp)) {
                    set.add(c);
                    changed = true;
                }
            };
            Object.keys(buildingProfiles || {}).forEach((k) => {
                tryAdd(k);
                tryAdd(makeBuildingLabel(buildingProfiles[k]));
            });
            (buildingsList || []).forEach(tryAdd);
        }
        return set;
    }

    function purgeBuildingRecordsForAliases(aliases) {
        const matchKey = (k) => {
            const key = toStr(k);
            if (!key) return false;
            if (buildingNameInAliasSet(key, aliases)) return true;
            const fromProfile = makeBuildingLabel(buildingProfiles[key]) || makeBuildingLabel(buildingProfilesShadow[key]);
            return fromProfile && buildingNameInAliasSet(fromProfile, aliases);
        };
        Object.keys(buildingProfiles || {}).forEach((k) => {
            if (matchKey(k)) delete buildingProfiles[k];
        });
        Object.keys(buildingProfilesShadow || {}).forEach((k) => {
            if (matchKey(k)) delete buildingProfilesShadow[k];
        });
        buildingsList = (buildingsList || []).filter((b) => !buildingNameInAliasSet(b, aliases));
        managedUnitsData = (managedUnitsData || []).filter((u) => !buildingNameInAliasSet(u.building, aliases));
        importedUnitsData = (importedUnitsData || []).filter((u) => !buildingNameInAliasSet(u.building, aliases));
        Object.keys(ownerBuildingMap || {}).forEach((owner) => {
            ownerBuildingMap[owner] = (ownerBuildingMap[owner] || []).filter((b) => !buildingNameInAliasSet(b, aliases));
        });
        insightNavStack = (insightNavStack || []).filter((frame) => {
            if (frame.mode === 'building' && frame.building && buildingNameInAliasSet(frame.building, aliases)) return false;
            return true;
        });
    }

    function forcePersistBuildingDeleteState() {
        try {
            localStorage.setItem('bhd_building_profiles', JSON.stringify(buildingProfiles));
            localStorage.setItem('bhd_buildings_list', JSON.stringify(buildingsList));
            localStorage.setItem('bhd_owner_building_map', JSON.stringify(ownerBuildingMap));
            localStorage.setItem('bhd_managed_units', JSON.stringify(managedUnitsData));
            mirrorKvFromLocalStorageToIndexedDb();
        } catch (e) {
            console.error('Building delete persist failed:', e);
            throw e;
        }
    }

    function buildingNameInAliasSet(buildingName, aliasSet) {
        const b = toStr(buildingName);
        if (!b || !aliasSet || !aliasSet.size) return false;
        for (const a of aliasSet) {
            if (normalizeReservationBuildingKey(a) === normalizeReservationBuildingKey(b)) return true;
        }
        const pb = extractPlotBuildingKey(b);
        if (pb) {
            for (const a of aliasSet) {
                if (extractPlotBuildingKey(a) === pb) return true;
            }
        }
        return false;
    }

    function getBuildingDeleteBlockers(buildingName) {
        const aliases = collectBuildingAliasSet(buildingName);
        if (!aliases.size) return [t('المبنى غير موجود.', 'Building not found.')];
        const blockers = [];
        const matchB = (b) => buildingNameInAliasSet(b, aliases);
        (unitReservations || []).forEach((r) => {
            if (matchB(r.building) && toStr(r.unit)) {
                blockers.push(t(`حجز للوحدة ${r.unit}`, `Reservation for unit ${r.unit}`));
            }
        });
        getUnitsData().forEach((u) => {
            if (!matchB(u.building) || !toStr(u.unit)) return;
            if (unitHasSavedContractForUnit(u.building, u.unit)) {
                blockers.push(t(`عقد محفوظ — وحدة ${u.unit}`, `Saved contract — unit ${u.unit}`));
            } else if (unitHasTenancyDraftForUnit(u.building, u.unit)) {
                blockers.push(t(`مسودة عقد — وحدة ${u.unit}`, `Contract draft — unit ${u.unit}`));
            } else if (unitIsRentedWithActiveLease(u.building, u.unit)) {
                blockers.push(t(`وحدة مؤجرة — ${u.unit}`, `Rented unit — ${u.unit}`));
            }
        });
        return [...new Set(blockers)];
    }

    function deleteBuildingProfile(buildingName) {
        if (!assertPermissionOrAlert('manage_properties', 'لا تملك صلاحية حذف العقارات.', 'No permission to delete properties.')) return;
        const aliases = collectBuildingAliasSet(buildingName);
        if (!aliases.size) {
            alert(t('المبنى غير موجود أو سبق حذفه.', 'Building not found or already deleted.'));
            return;
        }
        const blockers = getBuildingDeleteBlockers(buildingName).filter((x) => x !== t('المبنى غير موجود.', 'Building not found.'));
        if (blockers.length) {
            const head = t(
                'لا يمكن حذف هذا العقار لوجود بيانات مرتبطة به:\n\n',
                'Cannot delete this property — linked data exists:\n\n'
            );
            const tail = blockers.length > 10 ? `\n… +${blockers.length - 10}` : '';
            alert(head + blockers.slice(0, 10).join('\n') + tail);
            return;
        }
        const label = [...aliases].sort((a, b) => b.length - a.length)[0] || toStr(buildingName);
        if (
            !confirm(
                t(
                    `حذف العقار «${label}» نهائياً من النظام؟\n\nسيتم إزالة المبنى ووحداته من القائمة. لا يمكن التراجع.`,
                    `Permanently delete property «${label}»?\n\nThe building and its units will be removed. This cannot be undone.`
                )
            )
        ) {
            return;
        }
        aliases.forEach((key) => {
            delete buildingProfiles[key];
            delete buildingProfilesShadow[key];
        });
        purgeBuildingRecordsForAliases(aliases);
        bumpUnitsDataCache();
        syncManagedUnitsFromProfiles();
        if (buildingEditorState.open && buildingNameInAliasSet(buildingEditorState.originalName, aliases)) {
            closeBuildingEditor();
        }
        try {
            forcePersistBuildingDeleteState();
        } catch (e) {
            alert(t('❌ فشل حفظ الحذف. أعد تشغيل التطبيق وحاول مرة أخرى.', '❌ Failed to save deletion. Restart the app and try again.'));
            return;
        }
        persistReferenceData(true);
        try {
            renderInsightContent();
        } catch (_eRe) {}
        alert(t('✅ تم حذف العقار.', '✅ Property deleted.'));
    }

    function confirmDeleteBuilding(buildingName) {
        deleteBuildingProfile(buildingName);
    }

    function addOwnerFromDashboard() {
        if (!assertPermissionOrAlert('manage_owners', 'لا تملك صلاحية إدارة الملاك.', 'No permission to manage owners.')) return;
        const input = document.getElementById('ownerNameInput');
        const name = toStr(input?.value);
        if (!name) {
            alert('يرجى إدخال اسم المالك.');
            return;
        }
        if (!ownersList.includes(name)) ownersList.push(name);
        if (!ownerBuildingMap[name]) ownerBuildingMap[name] = [];
        if (!ownerProfiles[name]) ownerProfiles[name] = { ...getEmptyOwnerProfile(), fullName: name };
        if (input) input.value = '';
        persistReferenceData();
    }

    function exportOwnersToExcel() {
        exportOwnersExcel();
    }

    function triggerOwnersExcelImport() {
        const input = document.getElementById('bhdOwnersExcelInput');
        if (input) {
            input.value = '';
            input.click();
            return;
        }
        const fallback = document.createElement('input');
        fallback.type = 'file';
        fallback.accept = '.xlsx,.xls';
        fallback.onchange = (e) => {
            const file = e.target.files && e.target.files[0];
            if (file) importOwnersFromExcel(file);
        };
        fallback.click();
    }

    function importOwnersFromExcel(file) {
        if (!assertPermissionOrAlert('import_export', 'لا تملك صلاحية إدارة الملاك.', 'No permission to manage owners.')) return;
        if (!bhdEnsureXlsxForBulkExchange()) return;
        readWorkbook(file).then((wb) => {
            const ws = wb.Sheets['Owners'] || wb.Sheets[wb.SheetNames[0]];
            if (!ws) {
                alert(t('❌ لم يتم العثور على ورقة Owners داخل ملف Excel.', '❌ Owners sheet not found in Excel file.'));
                return;
            }
            const rows = XLSX.utils.sheet_to_json(ws, { defval: '' });
            if (!rows.length) {
                alert(t('⚠️ ملف الملاك فارغ.', '⚠️ Owners file is empty.'));
                return;
            }
            let added = 0;
            rows.forEach((row) => {
                const fullName =
                    toStr(row.FullName || row.OwnerName) ||
                    toStr(excelPickRowField(row, ['اسم المالك الكامل', 'Full name'])) ||
                    toStr(excelPickRowField(row, ['اسم المالك']));
                if (!fullName) return;
                const original = ownerProfiles[fullName] || getEmptyOwnerProfile();
                ownerProfiles[fullName] = {
                    ...original,
                    fullName,
                    firstName: toStr(row.FirstName || excelPickRowField(row, ['الاسم الأول', 'First name'])),
                    secondName: toStr(row.SecondName || excelPickRowField(row, ['الاسم الثاني', 'Second name'])),
                    thirdName: toStr(row.ThirdName || excelPickRowField(row, ['الاسم الثالث', 'Third name'])),
                    tribe: toStr(row.Tribe || excelPickRowField(row, ['القبيلة', 'Tribe'])),
                    civilId: toStr(row.CivilId || excelPickRowField(row, ['الرقم المدني', 'Civil ID'])),
                    idExpiryDate: normalizeDate(row.IdExpiryDate || excelPickRowField(row, ['انتهاء البطاقة', 'ID expiry'])),
                    phone: toStr(row.Phone || excelPickRowField(row, ['الهاتف', 'Phone'])),
                    email: toStr(row.Email || excelPickRowField(row, ['البريد', 'Email'])),
                    idCardAttachment: normalizeOwnerAttachment(
                        row.IdCardAttachment || excelPickRowField(row, ['نسخة البطاقة', 'ID card'])
                    )
                };
                if (!ownersList.includes(fullName)) {
                    ownersList.push(fullName);
                    added++;
                }
                if (!ownerBuildingMap[fullName]) ownerBuildingMap[fullName] = [];
                const linkedRaw =
                    row.LinkedBuildings ||
                    excelPickRowField(row, ['المباني المرتبطة', 'Linked buildings']) ||
                    row['المباني المرتبطة'];
                const linkedBuildings = parseBulkNames(String(linkedRaw || '').replace(/\|/g, '\n'));
                linkedBuildings.forEach((b) => {
                    if (!ownerBuildingMap[fullName].includes(b)) ownerBuildingMap[fullName].push(b);
                });
            });
            persistReferenceData();
            closeBulkDataExchangeModal();
            alert(t(`✅ تم استيراد/تحديث الملاك (${added} جديد).`, `✅ Owners imported/updated (${added} new).`));
        }).catch(() => {
            alert('❌ تعذر قراءة ملف Excel الخاص بالملاك.');
        });
    }

    async function addBuildingFromDashboard() {
        if (!assertPermissionOrAlert('manage_properties', 'لا تملك صلاحية تعديل العقارات.', 'No permission to edit properties.')) return;
        if (!ownersList.length) {
            alert('أضف مالكاً من قسم «أسماء الملاك» أولاً، ثم اربطه بالعقار.\nAdd an owner under Owners first, then link the property.');
            return;
        }
        const profile = collectBuildingProfileForm();
        const selectedOwners = collectBuildingLinkedOwnersFromForm();
        const isEditingExisting = !!buildingEditorState.originalName;
        const buildingType = toStr(profile.buildingType) || 'متعدد الطوابق';
        const rawFloorCount = buildingType === 'فيلا' ? 1 : Number(profile.floorCount || 0);
        if (rawFloorCount > BHD_MAX_BUILDING_FLOORS) {
            alert(
                t(
                    `عدد الطوابق (${rawFloorCount}) أكبر من الحد المسموح (${BHD_MAX_BUILDING_FLOORS}). صحّح العدد ثم أعد الحفظ.`,
                    `Floor count (${rawFloorCount}) exceeds the limit (${BHD_MAX_BUILDING_FLOORS}). Correct it and save again.`
                )
            );
            return;
        }
        const dupSketch = findDuplicateBuildingSketchNo(profile.sketchNo, buildingEditorState.originalName);
        if (dupSketch) {
            highlightBuildingProfileGaps([
                {
                    ar: 'رقم الرسم المساحي (الكروكي) مكرر',
                    en: 'Survey sketch number is duplicate',
                    fieldId: 'buildingSketchNoInput',
                    filled: false
                }
            ]);
            alert(
                t(
                    `رقم الرسم المساحي (الكروكي) مستخدم مسبقاً في مبنى: ${dupSketch}\nلا يمكن تكراره في مبنى آخر.`,
                    `Survey sketch number is already used by building: ${dupSketch}\nIt cannot be duplicated on another building.`
                )
            );
            return;
        }
        const ve = validateBuildingProfileComplete(profile);
        if (!ve.ok) {
            highlightBuildingProfileGaps(ve.missing);
            showBuildingProfileGapsModal(ve.missing);
            const okDraft = confirm(
                t(
                    'لا تزال هناك نواقص في بيانات العقار (الحقول الفارغة بالأحمر والمكتملة بالأخضر).\nهل تريد الحفظ كمسودة الآن؟',
                    'Property data is still incomplete (empty fields in red, completed in green).\nDo you want to save as draft now?'
                )
            );
            if (!okDraft) return;
        }
        if (!selectedOwners.length) {
            alert(
                t(
                    'اختر مالكاً واحداً على الأقل لهذا العقار (يمكن اختيار أكثر من مالك).',
                    'Select at least one owner for this property (you may select multiple owners).'
                )
            );
            return;
        }
        const name = upsertBuildingProfile(profile);
        if (!name) {
            return;
        }
        syncBuildingOwnerLinks(name, selectedOwners);
        try {
            await flushBhdPropertyPersistenceNow();
        } catch (e) {
            alert(t('❌ فشل حفظ بيانات المبنى محلياً. تحقق من مساحة التخزين في المتصفح.', '❌ Failed to save building data locally. Check browser storage space.'));
            console.error('Building force-persist failed:', e);
            return;
        }
        buildingEditorState = { open: true, originalName: name };
        persistReferenceData();
        // Verify saved data can be read back immediately.
        try {
            const verify = JSON.parse(localStorage.getItem('bhd_building_profiles') || '{}');
            if (!verify || typeof verify !== 'object' || !verify[name]) {
                alert(t('⚠️ تم الحفظ لكن تعذّر التحقق من تخزين بيانات المبنى. حاول مرة أخرى.', '⚠️ Saved, but verification failed for building storage. Please try again.'));
            }
        } catch (e) {}
        if (!ve.ok) {
            alert(
                t(
                    '💾 تم حفظ بيانات العقار كمسودة. أكمل الحقول الناقصة (الإطار الأحمر) ثم احفظ مرة أخرى.',
                    '💾 Property saved as draft. Complete the missing fields (red outline) then save again.'
                )
            );
        } else {
            clearBuildingProfileGapHighlights();
            closeDataGapsModal();
            alert(t('✅ تم حفظ بيانات العقار بنجاح.', '✅ Property data saved successfully.'));
        }
        renderInsightContent();
    }

    function getBuildingProfile(buildingName) {
        const key = resolveBuildingProfileKey(buildingName) || buildingName;
        return buildingProfiles[key] || buildingProfiles[buildingName] || null;
    }

