    function printReservationForm(i) {
        const r = unitReservations[i];
        if (!r) return;
        const template = DOCUMENT_SYSTEM_TEMPLATES.reservation_form;
        const html = template && typeof template.buildHtml === 'function' ? template.buildHtml(r) : '';
        if (!html) return;
        const win = window.open('', '_blank');
        if (!win) return;
        win.document.write(html);
        win.document.close();
    }

    function resumeReservationDraft(i) {
        const r = unitReservations[i];
        if (!r) return;
        const units = getReservationUnitsList(r);
        const primary = units[0] || { unit: r.unit };
        const d = r.formData && typeof r.formData === 'object'
            ? r.formData
            : {
                agreementNo: toStr(r.agreementNo) || nextReservationNumber(),
                type: 'جديد New',
                buildingNo: toStr(r.building),
                flatNo: toStr(primary.unit),
                tenantNameAr: toStr(r.reservedBy),
                tenantMobile: toStr(r.phone)
            };
        contractEntryContext = {
            mode: 'reservation',
            unit: { building: r.building, unit: primary.unit },
            linkedUnits: units,
            reservationGroupId: toStr(r.reservationGroupId)
        };
        try { setReservationFormFlowActive(true); } catch (_eRes) {}
        closeDashboardInsight();
        setWorkspaceMode('reservations');
        showReservationsWorkspaceView('form');
        applyObjectToReservationFormFields(d);
        if (!resFormVal('buildingNo')) resFormSet('buildingNo', toStr(r.building));
        if (!resFormVal('flatNo')) resFormSet('flatNo', toStr(primary.unit));
        if (!resFormVal('tenantNameAr') && toStr(r.reservedBy)) resFormSet('tenantNameAr', toStr(r.reservedBy));
        if (!resFormVal('tenantMobile') && toStr(r.phone)) resFormSet('tenantMobile', toStr(r.phone));
        setActiveReservationLinkedUnits(units, r.building);
        syncReservationPrimaryUnitToForm(primary);
        updateReservationsWorkspaceUi();
        alert(t('✅ تم فتح مسودة الحجز لاستكمالها.', '✅ Reservation draft opened for completion.'));
    }

    function insightAddEvictionPrompt() {
        const building = prompt('المبنى:');
        if (!building) return;
        const unit = prompt('رقم الوحدة:');
        if (!unit) return;
        const tenant = prompt('اسم المستأجر:') || '';
        const requestDate = prompt('تاريخ الطلب (YYYY-MM-DD):') || new Date().toISOString().slice(0, 10);
        const plannedDate = prompt('تاريخ الإخلاء المتوقع (YYYY-MM-DD):') || '';
        const evictionActor = getCurrentActorLedgerRecord();
        evictionRequests.push({
            building,
            unit,
            tenant,
            requestDate,
            plannedDate,
            notes: '',
            staffUserId: evictionActor.staffUserId,
            staffName: evictionActor.staffName
        });
        saveDashboardAux();
        insightNavStack = [{ mode: 'evictions' }];
        renderInsightContent();
    }

    function removeEviction(i) {
        evictionRequests.splice(i, 1);
        saveDashboardAux();
        renderInsightContent();
    }

    function updateOperationsStats(data) {
        const total = data.length;
        const rented = data.filter((x) => x.status === 'Rented').length;
        const vacant = data.filter((x) => x.status === 'Vacant' && !isReservedUnitRow(x)).length;
        const reserved = data.filter((u) => isReservedUnitRow(u)).length;
        const buildingsCount = Object.values(buildingProfiles || {}).filter((p) => {
            const name = makeBuildingLabel(p);
            return name && isBuildingProfileActive(p);
        }).length;
        const ownersCount = ownersList.length;

        const exp30 = data.filter((x) => {
            const days = daysUntil(x.endDate);
            return days !== null && days >= 0 && days <= 30;
        }).length;
        const exp60 = data.filter((x) => {
            const days = daysUntil(x.endDate);
            return days !== null && days >= 0 && days <= 60;
        }).length;
        const exp90 = data.filter((x) => {
            const days = daysUntil(x.endDate);
            return days !== null && days >= 0 && days <= 90;
        }).length;

        const monthlyTotal = data
            .filter((x) => x.status === 'Rented')
            .reduce((s, u) => s + (parseFloat(u.monthlyRent) || 0), 0);
        const yearlyEstimate = monthlyTotal * 12;

        const set = (id, value) => {
            const el = document.getElementById(id);
            if (el) el.textContent = String(value);
        };
        set('statBuildings', buildingsCount);
        set('statOwnersCount', ownersCount);
        set('statTotalUnits', total);
        set('statRentedUnits', rented);
        set('statVacantUnits', vacant);
        set('statReservedUnits', reserved);
        set('statMonthlyTotal', formatOMR(monthlyTotal));
        set('statYearlyTotal', formatOMR(yearlyEstimate));
        set('statExpiring30', exp30);
        set('statExpiring60', exp60);
        set('statExpiring90', exp90);
        set('statEvictionQueue', evictionRequests.length);
        try {
            renderDashboardModuleHub();
        } catch (_eDashHub) {}
    }

    function updateBuildingsFilter(data) {
        const select = document.getElementById('unitsBuildingFilter');
        if (!select) return;
        const current = select.value || "all";
        const opts = ["all", ...new Set(data.map((x) => x.building).filter(Boolean))];
        select.innerHTML = opts.map((b) => `<option value="${b}">${b === "all" ? t('كل المباني', 'All buildings') : b}</option>`).join('');
        if (opts.includes(current)) select.value = current;
    }

    function updateBatchBuildingFilter(data) {
        const select = document.getElementById('batchBuildingFilter');
        if (!select) return;
        const current = select.value || "all";
        const opts = ["all", ...new Set(data.map((x) => x.building).filter(Boolean))];
        select.innerHTML = opts.map((b) => `<option value="${b}">${b === "all" ? t('كل المباني (للطباعة المرنة)', 'All buildings (flex print)') : b}</option>`).join('');
        if (opts.includes(current)) select.value = current;
    }

    function prefillContractFromUnit(unit, isRenewal = false, options = {}) {
        if (!unit) return;
        if (!options.skipReservationGate && !assertContractRequiresReservationOrDraftOrActiveLease(unit.building, unit.unit, { isRenewal })) return;
        setTenancyDraftCompletionFieldLocks(false);
        try { setTenantIdentityLockedFromAddressBook(false); } catch (_eAbClr2) {}
        if (!isRenewal) {
            const fullPayload = enrichPayloadWithResolvedLinkedContractUnits(
                enrichPayloadDepositFromAccounting(getContractPayloadForUnit(unit))
            );
            if (fullPayload) {
                applyObjectToContractFormFields(fullPayload, { hydratingFromSaved: true });
                try {
                    updateSummaryPanel();
                } catch (_eSum) {}
                const needsAdditional =
                    options.additionalDataOnly === true ||
                    (options.fullEdit !== true && payloadNeedsAdditionalDataForLifecycle(fullPayload));
                if (needsAdditional) {
                    enterContractAdditionalDataMode(fullPayload);
                } else if (!contractActivationRequirementsComplete(fullPayload)) {
                    exitContractAdditionalDataMode();
                    enterContractActivationDataMode(fullPayload);
                } else {
                    exitContractAdditionalDataMode();
                    exitContractActivationDataMode();
                }
                try {
                    applyContractsWorkspaceLockState();
                } catch (_eCwsPf) {}
                try {
                    applyTenancyAndTenantFieldLocks();
                } catch (_eSavLockPf) {}
                return;
            }
        }
        const fallback = new Date();
        const startDate = isRenewal
            ? new Date(new Date(unit.endDate || fallback).getTime() + 86400000).toISOString().slice(0, 10)
            : (unit.startDate || '');
        const endDate = isRenewal
            ? (() => {
                const s = new Date(startDate);
                s.setFullYear(s.getFullYear() + 1);
                s.setDate(s.getDate() - 1);
                return s.toISOString().slice(0, 10);
            })()
            : (unit.endDate || '');

        document.getElementById('agreementNo').value = isRenewal
            ? proposeContractRenewalAgreementNumber()
            : (unit.agreementNo || '');
        document.getElementById('contractTypeSelect').value = (unit.unitType === 'Shop' || unit.unitType === 'Office')
            ? 'تجاري Commercial'
            : 'سكني Residential';
        ensureTypeSelectAlwaysNew();
        document.getElementById('tenantNameAr').value = unit.tenant || '';
        document.getElementById('tenantNameEn').value = unit.tenant || '';
        document.getElementById('tenantMobile').value = unit.mobile || '';
        document.getElementById('buildingNo').value = unit.building || '';
        document.getElementById('flatNo').value = unit.unit || '';
        document.getElementById('floorDetails').value = unit.floor || '';
        document.getElementById('unitType').value = unit.unitType || 'Flat';
        document.getElementById('electricityMeter').value = unit.electricity || '';
        document.getElementById('waterMeter').value = unit.water || '';
        const rentPrefill = resolveUnitMonthlyRentForReservation(unit) || (unit.monthlyRent != null && unit.monthlyRent !== '' ? String(unit.monthlyRent) : '');
        document.getElementById('monthlyRent').value = rentPrefill;
        document.getElementById('startDate').value = startDate;
        document.getElementById('endDate').value = endDate;
        document.getElementById('contractMonths').value = 12;
        document.getElementById('depositAmount').value = rentPrefill;
        try { renderInsuranceDepositItemsRows([]); } catch (e) {}
        try { renderCustomRentItemsRows([]); } catch (e) {}
        try {
            rebuildPaymentScheduleFromContractDefaults();
        } catch (e) {}
        updateSummaryPanel();
        try {
            persistContractWorkspaceDraftSilent();
        } catch (_ePfSav) {}
        try { applyContractsWorkspaceLockState(); } catch (_eCwsPf) {}
    }

    function openUnitContract(unit, isRenewal = false) {
        if (isRenewal) {
            selectedUnitDetailsRecord = unit;
            openContractRenewalModal(unit);
            return;
        }
        prefillContractFromUnit(unit, false);
        try {
            mergeMandatoryDocsFromAddressBookAfterLoadIfMatch();
        } catch (_eAbOpen) {}
        try {
            syncContractPrintAttachmentsFromPayload(getFormData());
            syncContractPrintAttachmentsToStore();
        } catch (_eAttOpen) {}
        openDocumentsWindow();
    }

    function buildPayloadFromUnit(unit, isRenewal = false) {
        const fallback = new Date();
        const startDate = isRenewal
            ? new Date(new Date(unit.endDate || fallback).getTime() + 86400000).toISOString().slice(0, 10)
            : (unit.startDate || '');
        const endDate = isRenewal
            ? (() => {
                const s = new Date(startDate);
                s.setFullYear(s.getFullYear() + 1);
                s.setDate(s.getDate() - 1);
                return s.toISOString().slice(0, 10);
            })()
            : (unit.endDate || '');

        const contract = {
            agreementNo: isRenewal ? proposeContractRenewalAgreementNumber() : (unit.agreementNo || ''),
            contractType: (unit.unitType === 'Shop' || unit.unitType === 'Office') ? 'تجاري Commercial' : 'سكني Residential',
            type: 'جديد New',
            municipalFormNo: '',
            municipalContractNo: '',
            tenantNameAr: unit.tenant || '',
            tenantNameEn: unit.tenant || '',
            tenantId: '',
            tenantMobile: unit.mobile || '',
            tenantPassport: '',
            tenantEmail: '',
            buildingNo: unit.building || '',
            flatNo: unit.unit || '',
            floorDetails: unit.floor || '',
            unitType: unit.unitType || 'Flat',
            electricityMeter: unit.electricity || '',
            waterMeter: unit.water || '',
            monthlyRent: String(unit.monthlyRent || ''),
            contractMonths: '12',
            startDate,
            endDate,
            unitHandoverDate: '',
            agreedRentPaymentDay: '5',
            paymentMethod: 'شيك CHQ',
            depositAmount: String(unit.monthlyRent || ''),
            insuranceDepositItemsJson: '[]',
            customRentItemsJson: '[]',
            paymentSchedule: [],
            paymentScheduleJson: '[]'
        };
        return {
            contract,
            buildings: [...buildingsList],
            owners: [...ownersList],
            buildingProfiles,
            ownerProfiles,
            managedUnitsData,
            currentDoc: isRenewal ? 1 : 0
        };
    }

    function renderOperationsTable() {
        if (isViewerMode) return;
        try {
            repairLinkedContractUnitsLifecycleConsistency();
        } catch (_eRepOpsLinked) {}
        const allData = getUnitsData();
        const portalUser = getLoggedInUser();
        const portalScoped = isPortalScopedUser(portalUser);
        updateOperationsStats(portalScoped ? allData.filter((u) => unitPassesPortalScope(u.building, u.unit)) : allData);
        updateBuildingsFilter(allData);
        updateBatchBuildingFilter(allData);
        const filters = getFiltersState();

        const rows = allData.filter((u) => {
            if (portalScoped) {
                const scope = getPortalScopedBuildingUnit();
                if (scope.building || scope.unit) {
                    if (!unitPassesPortalScope(u.building, u.unit)) return false;
                }
            }
            const days = daysUntil(u.endDate);
            const normalizedStatus = getStatusToken(u, days);
            const hasUtilities = !!toStr(u.electricity) && !!toStr(u.water);

            const fullText = `${u.tenant || ''} ${u.unit || ''} ${u.building || ''} ${u.ownerNames || ''} ${u.electricity || ''} ${u.water || ''}`.toLowerCase();
            const matchSearch = !filters.search || fullText.includes(filters.search);
            const matchBuilding = filters.building === 'all' || u.building === filters.building;
            const matchStatus = filters.status === 'all' || normalizedStatus === filters.status;
            const matchExpire = filters.expire === 'all' || (days !== null && days >= 0 && days <= Number(filters.expire));
            const matchUtilities = filters.utilities === 'all'
                || (filters.utilities === 'complete' && hasUtilities)
                || (filters.utilities === 'missing' && !hasUtilities);
            return matchSearch && matchBuilding && matchStatus && matchExpire && matchUtilities;
        });

        rows.sort((a, b) => {
            const dir = operationsSortState.dir === 'asc' ? 1 : -1;
            const da = daysUntil(a.endDate);
            const db = daysUntil(b.endDate);
            let va = '';
            let vb = '';
            switch (operationsSortState.key) {
                case 'building': va = a.building; vb = b.building; break;
                case 'owner': va = a.ownerNames || formatOwnerNamesForBuilding(a.building); vb = b.ownerNames || formatOwnerNamesForBuilding(b.building); break;
                case 'unit': va = a.unit; vb = b.unit; break;
                case 'tenant': va = a.tenant; vb = b.tenant; break;
                case 'status': va = getStatusToken(a, da); vb = getStatusToken(b, db); break;
                case 'contractState': va = getContractLifecycleStateRank(getContractLifecycleStateKey(a)); vb = getContractLifecycleStateRank(getContractLifecycleStateKey(b)); break;
                case 'endDate': va = a.endDate || '9999-12-31'; vb = b.endDate || '9999-12-31'; break;
                case 'days': va = da === null ? 99999 : da; vb = db === null ? 99999 : db; break;
                case 'electricity': va = a.electricity; vb = b.electricity; break;
                case 'water': va = a.water; vb = b.water; break;
                default: va = da === null ? 99999 : da; vb = db === null ? 99999 : db;
            }
            return compareSmart(va, vb) * dir;
        });

        const tbody = document.getElementById('unitsTableBody');
        if (!tbody) return;
        window._unitsViewRows = rows;
        updateSortIndicators();
        renderOperationsTablePageSlice();
        renderRegistryTable();
    }

    function selectUnitFromTable(index, isRenewal, openViewer) {
        const unit = (window._unitsViewRows || [])[index];
        if (!unit) return;
        if (isRenewal && !ensureUnitActionAllowed(unit, 'renew')) return;
        if (isRenewal) {
            selectedUnitDetailsRecord = unit;
            openContractRenewalModal(unit);
            return;
        }
        if (openViewer) {
            openUnitContract(unit, false);
        } else {
            prefillContractFromUnit(unit, false);
            renderOperationsTable();
        }
    }

    function openContractForActivation(rowIndex) {
        const unit = (window._unitsViewRows || [])[rowIndex];
        if (!unit) return;
        if (
            !assertPermissionOrAlert(
                'manage_contracts',
                'لا تملك صلاحية العقود والمستندات.',
                'No permission to access contracts.'
            )
        ) {
            return;
        }
        prefillContractFromUnit(unit, false, { skipReservationGate: true });
        try {
            setWorkspaceMode('contracts');
            showContractsWorkspaceView('form');
            try {
                applyContractsWorkspaceLockState();
            } catch (_eCwsAct) {}
            try {
                document.getElementById('contractsFormPanel')?.scrollIntoView({ block: 'start', behavior: 'smooth' });
            } catch (_eScrollAct) {}
        } catch (_eWsAct) {}
    }

    function openContractForAdditionalData(rowIndex) {
        const unit = (window._unitsViewRows || [])[rowIndex];
        if (!unit) return;
        if (
            !assertPermissionOrAlert(
                'manage_contracts',
                'لا تملك صلاحية العقود والمستندات.',
                'No permission to access contracts.'
            )
        ) {
            return;
        }
        prefillContractFromUnit(unit, false, { skipReservationGate: true, additionalDataOnly: true });
        try {
            setWorkspaceMode('contracts');
            showContractsWorkspaceView('form');
            try {
                applyContractsWorkspaceLockState();
            } catch (_eCwsAdd) {}
            try {
                document.getElementById('contractsFormPanel')?.scrollIntoView({ block: 'start', behavior: 'smooth' });
            } catch (_eScrollAdd) {}
        } catch (_eWs) {}
    }

    function unitDetailsIsIncompleteTenancyDraft(unit) {
        if (!unit) return false;
        if (toStr(unit.status).toLowerCase() === 'vacant') return false;
        if (getSavedContractPayloadForUnit(unit)) return false;
        const prim = getLinkedContractPrimaryLifecycleUnit(unit);
        if (prim && getSavedContractPayloadForUnit(prim)) return false;
        return isUnitInTenancyContractDraftMap(unit);
    }

    function unitDetailsNeedsAdditionalContractData(unit) {
        if (!unit) return false;
        const k = getContractLifecycleStateKey(unit);
        return k === 'active_pending' || k === 'renewal_pending';
    }

    function unitDetailsHasRenewalDraft(unit) {
        return !!getContractRenewalDraftEntryForUnit(unit);
    }

    function unitDetailsShowsCompletionToolbar(unit) {
        return unitDetailsIsIncompleteTenancyDraft(unit) || unitDetailsNeedsAdditionalContractData(unit);
    }

    /** عقد جديد / طباعة الاستمارات — بعد الحجز أو للوحدة المؤجرة فقط / Contract & print actions after reservation or when rented */
    function unitDetailsAllowsContractPrintActions(unit) {
        if (!unit) return false;
        if (toStr(unit.status).toLowerCase() === 'rented') return true;
        return isReservedUnitRow(unit);
    }

    function updateUnitDetailsToolbarForDraft() {
        const std = document.getElementById('unitDetailsToolbarStandard');
        const draft = document.getElementById('unitDetailsToolbarDraftMode');
        const linkedBar = document.getElementById('unitDetailsLinkedSecondaryToolbar');
        if (!std || !draft) return;
        const unit = selectedUnitDetailsRecord;
        const isLinkedSecondary = !!(unit && isLinkedContractSecondaryUnitForDisplay(unit));
        const isDraftOnly = !isViewerMode && unit && !isLinkedSecondary && unitDetailsIsIncompleteTenancyDraft(unit);
        const isPending = !isViewerMode && unit && !isLinkedSecondary && unitDetailsNeedsAdditionalContractData(unit);
        const showCompletionToolbar = isDraftOnly || isPending;
        const contractPrintBar = document.getElementById('unitDetailsContractPrintToolbar');
        const contractWrap = document.getElementById('unitDetailsContractWrap');
        const vacantHint = document.getElementById('unitDetailsVacantNoContractHint');
        const showContractPrint = unit && !isLinkedSecondary && unitDetailsAllowsContractPrintActions(unit);
        if (linkedBar) {
            linkedBar.style.display = isLinkedSecondary ? 'flex' : 'none';
            if (isLinkedSecondary) {
                const prim = getLinkedContractDisplayPrimaryUnit(unit);
                const btn = document.getElementById('unitDetailsOpenPrimaryContractBtn');
                if (btn && prim) {
                    btn.textContent = t(
                        `📋 متابعة إلى العقد الأساسي (${prim.unit})`,
                        `📋 Open primary contract (${prim.unit})`
                    );
                }
            }
        }
        if (std) std.style.display = isLinkedSecondary || showCompletionToolbar ? 'none' : '';
        if (contractPrintBar) {
            contractPrintBar.style.display = showContractPrint ? '' : 'none';
        }
        if (contractWrap) {
            contractWrap.style.display = 'none';
        }
        if (vacantHint) {
            const showHint = unit && !showContractPrint && toStr(unit.status).toLowerCase() === 'vacant' && !showCompletionToolbar;
            vacantHint.style.display = showHint ? 'block' : 'none';
        }
        if (!showContractPrint) {
            closeUnitDetailsIeMenus();
        }
        try {
            refreshUnitDetailsAccountingReceiptPrintUi(unit);
        } catch (_eUdAcctPr) {}
        if (showCompletionToolbar) {
            std.style.display = 'none';
            draft.style.display = 'flex';
            const cancelBtn = draft.querySelector('button[onclick*="openUnitDetailsCancelContractModal"]');
            const completeBtn = draft.querySelector('button[onclick*="completeUnitDetailsFromToolbar"]');
            const isRenewalPending = !!(unit && getContractLifecycleStateKey(unit) === 'renewal_pending');
            if (cancelBtn) cancelBtn.style.display = isDraftOnly ? '' : 'none';
            if (completeBtn) {
                completeBtn.textContent = isRenewalPending
                    ? t('📋 متابعة تجديد العقد / Continue renewal', '📋 Continue renewal / متابعة تجديد العقد')
                    : isPending
                      ? t('📋 إكمال البيانات الإضافية / Complete additional data', '📋 Complete additional data / إكمال البيانات الإضافية')
                      : t('📋 استكمال بيانات التعاقد / Complete contract data', '📋 Complete contract data / استكمال بيانات التعاقد');
            }
        } else {
            std.style.display = '';
            draft.style.display = 'none';
        }
        const editBtn = document.getElementById('unitDetailsEditBtn');
        const viewBtn = document.getElementById('unitDetailsViewBtn');
        const requestBtn = document.getElementById('unitDetailsRequestEditBtn');
        const requestStatus = document.getElementById('unitDetailsEditRequestStatus');
        const canEdit = unit && unitDetailsAllowsContractEdit(unit);
        const showRequest = unit && unitDetailsShouldShowRequestEditButton(unit);
        const u = getLoggedInUser();
        const b = unit ? toStr(unit.building) : '';
        const f = unit ? toStr(unit.unit) : '';
        const pendingReq =
            u && b && f && hasPendingContractEditRequest(b, f, u.id);
        const oneTimeGrant = u && b && f && getActiveOneTimeEditGrant(b, f, u.id);
        if (editBtn) {
            editBtn.style.display = 'none';
            editBtn.hidden = true;
            editBtn.disabled = true;
        }
        if (viewBtn) {
            const showView = !!(unit && !isLinkedSecondary && unitDetailsAllowsContractPrintActions(unit));
            viewBtn.style.display = showView ? '' : 'none';
            viewBtn.hidden = !showView;
        }
        const renewBtn = document.getElementById('unitDetailsRenewBtn');
        if (renewBtn) {
            const hasRenewalDraft = !!(unit && unitDetailsHasRenewalDraft(unit));
            const showRenew = !!(unit && !isLinkedSecondary && (unitDetailsAllowsContractRenewal(unit) || hasRenewalDraft));
            renewBtn.style.display = showRenew ? '' : 'none';
            renewBtn.hidden = !showRenew;
            if (showRenew) {
                renewBtn.textContent = hasRenewalDraft
                    ? t('📋 متابعة تجديد العقد', '📋 Continue renewal')
                    : t('🔁 تجديد العقد', '🔁 Renew contract');
                renewBtn.onclick = hasRenewalDraft
                    ? () => openContractRenewalFinancialByKey(b, f)
                    : () => openContractRenewalModal();
            }
        }
        const cancelContractBtn = document.getElementById('unitDetailsCancelContractBtn');
        if (cancelContractBtn) {
            const hasPending = !!(unit && unitDetailsHasCancellationRequest(unit));
            const showCancel = !!(unit && !isLinkedSecondary && unitDetailsAllowsContractCancellation(unit));
            cancelContractBtn.style.display = showCancel ? '' : 'none';
            cancelContractBtn.hidden = !showCancel;
            if (showCancel) {
                cancelContractBtn.textContent = hasPending
                    ? t('📋 متابعة إلغاء العقد / Continue cancellation', '📋 Continue cancellation / متابعة إلغاء العقد')
                    : t('🛑 إلغاء العقد / Cancel contract', '🛑 Cancel contract / إلغاء العقد');
            }
        }
        const editRenewalBtn = document.getElementById('unitDetailsEditRenewalBtn');
        if (editRenewalBtn) {
            editRenewalBtn.style.display = 'none';
            editRenewalBtn.hidden = true;
        }
        const propDocsBtn = document.getElementById('unitDetailsPropertyDocsBtn');
        const propDocsViewBtn = document.getElementById('unitDetailsPropertyDocsViewBtn');
        const savedPayload = unit ? getSavedContractPayloadForUnit(unit) : null;
        const finOk = savedPayload && contractFinancialDataComplete(savedPayload);
        const docsOk = savedPayload && contractPropertyDocumentsComplete(savedPayload);
        const docCount = savedPayload ? parsePropertyDocumentsBundle(savedPayload).filter((d) => contractAttachmentPresent(d)).length : 0;
        const coreCount = unit && savedPayload ? collectPropertyDocumentCoreAttachments(unit, savedPayload).length : 0;
        if (propDocsBtn) {
            const showUpload = !!(unit && finOk && !docsOk && effectivePermission('manage_contracts'));
            propDocsBtn.style.display = showUpload ? '' : 'none';
            propDocsBtn.hidden = !showUpload;
        }
        if (propDocsViewBtn) {
            const showView = !!(unit && (docCount > 0 || coreCount > 0));
            propDocsViewBtn.style.display = showView ? '' : 'none';
            propDocsViewBtn.hidden = !showView;
        }
        if (requestBtn) {
            requestBtn.style.display = showRequest && !pendingReq ? '' : 'none';
            requestBtn.hidden = !(showRequest && !pendingReq);
            requestBtn.disabled = !!pendingReq;
        }
        if (requestStatus) {
            let msg = '';
            if (oneTimeGrant && canEdit) {
                msg = t(
                    '✓ تمت الموافقة — يمكنك التعديل مرة واحدة ثم الحفظ.',
                    '✓ Approved — you may edit once, then save.'
                );
            } else if (pendingReq) {
                const agr = getAgreementNoForSavedUnit(b, f);
                msg = t(
                    `طلب التعديل قيد المراجعة لدى المسؤول (عقد ${agr}).`,
                    `Edit request pending administrator review (contract ${agr}).`
                );
            } else if (showRequest) {
                msg = t(
                    'لا تملك صلاحية تعديل العقد المحفوظ — اضغط «طلب تعديل».',
                    'You cannot edit this saved contract — press «Request edit».'
                );
            }
            if (msg) {
                requestStatus.textContent = msg;
                requestStatus.style.display = 'block';
                requestStatus.removeAttribute('hidden');
            } else {
                requestStatus.style.display = 'none';
                requestStatus.setAttribute('hidden', 'hidden');
            }
        }
    }

    function getTenancyDraftPayloadForUnit(unit) {
        if (!unit) return null;
        const m = loadTenancyContractDraftsMap();
        const e = getTenancyDraftMapEntry(m, unit.building, unit.unit);
        return e && e.payload && typeof e.payload === 'object' ? e.payload : null;
    }

    const CONTRACT_RENEWAL_DRAFTS_KEY = 'bhd_contract_renewal_drafts';

    function loadContractRenewalDraftsMap() {
        try {
            const raw = localStorage.getItem(CONTRACT_RENEWAL_DRAFTS_KEY);
            const o = raw ? JSON.parse(raw) : null;
            return o && typeof o === 'object' && !Array.isArray(o) ? o : {};
        } catch (_eRenLoad) {
            return {};
        }
    }

    function saveContractRenewalDraftsMap(map) {
        try {
            localStorage.setItem(CONTRACT_RENEWAL_DRAFTS_KEY, JSON.stringify(map || {}));
        } catch (_eRenSave) {}
    }

    function getContractRenewalDraftMapEntry(map, building, unit) {
        const k = _tenancyDraftStorageKey(building, unit);
        return map && map[k] ? map[k] : null;
    }

    function getContractRenewalDraftEntryForUnit(unit) {
        if (!unit) return null;
        return getContractRenewalDraftMapEntry(loadContractRenewalDraftsMap(), unit.building, unit.unit);
    }

    function upsertContractRenewalDraft(building, unit, entry) {
        const b = toStr(building);
        const u = toStr(unit);
        if (!b || !u || !entry || typeof entry !== 'object') return;
        const map = loadContractRenewalDraftsMap();
        const actor = getCurrentActorLedgerRecord();
        map[_tenancyDraftStorageKey(b, u)] = {
            ...entry,
            updatedAt: new Date().toISOString(),
            lastActorUserId: actor.staffUserId,
            lastActorName: actor.staffName
        };
        saveContractRenewalDraftsMap(map);
    }

    function removeContractRenewalDraft(building, unit) {
        const b = toStr(building);
        const u = toStr(unit);
        if (!b || !u) return;
        const map = loadContractRenewalDraftsMap();
        const k = _tenancyDraftStorageKey(b, u);
        if (!map[k]) return;
        delete map[k];
        saveContractRenewalDraftsMap(map);
    }

    const CONTRACT_RENEWAL_LOG_KEY = 'bhd_contract_renewal_log';

    function generateContractRenewalLogId() {
        return `crl_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 7)}`;
    }

    function loadContractRenewalLog() {
        try {
            const raw = localStorage.getItem(CONTRACT_RENEWAL_LOG_KEY);
            const arr = raw ? JSON.parse(raw) : [];
            return Array.isArray(arr) ? arr : [];
        } catch (_eCrlLoad) {
            return [];
        }
    }

    function saveContractRenewalLog(list) {
        try {
            localStorage.setItem(CONTRACT_RENEWAL_LOG_KEY, JSON.stringify(Array.isArray(list) ? list.slice(-500) : []));
        } catch (_eCrlSave) {}
        try {
            syncBhdKvToServer();
        } catch (_eCrlKv) {}
    }

    function renewalLogDetailsFromCtx(ctx, payload) {
        const prev = ctx?.previousSnapshot || getSavedContractPayloadForUnit(ctx?.unit) || {};
        const r = ctx?.renewal || {};
        const p = payload && typeof payload === 'object' ? payload : {};
        return {
            building: toStr(ctx?.unit?.building),
            unit: toStr(ctx?.unit?.unit),
            party: toStr(prev.tenantNameAr || prev.tenantNameEn),
            agreementNo: toStr(r.agreementNo || p.agreementNo),
            prevAgreementNo: toStr(prev.agreementNo || ctx?.unit?.agreementNo),
            prevFrom: toStr(ctx?.prevStart || prev.startDate),
            prevTo: toStr(ctx?.prevEnd || prev.endDate),
            from: toStr(r.newStart || p.startDate),
            to: toStr(r.newEnd || p.endDate),
            rent: formatOMR(p.monthlyRent || prev.monthlyRent)
        };
    }

    function logContractRenewalEvent(eventType, unit, details) {
        const d = details && typeof details === 'object' ? details : {};
        const b = toStr(unit?.building || d.building);
        const u = toStr(unit?.unit || d.unit);
        if (!b || !u) return null;
        const actor = getCurrentActorLedgerRecord();
        const entry = {
            id: generateContractRenewalLogId(),
            eventType: toStr(eventType),
            building: b,
            unit: u,
            party: toStr(d.party),
            agreementNo: toStr(d.agreementNo),
            prevAgreementNo: toStr(d.prevAgreementNo),
            from: toStr(d.from),
            to: toStr(d.to),
            prevFrom: toStr(d.prevFrom),
            prevTo: toStr(d.prevTo),
            rent: toStr(d.rent),
            note: toStr(d.note),
            at: new Date().toISOString(),
            staffUserId: actor.staffUserId,
            staffName: actor.staffName
        };
        const list = loadContractRenewalLog();
        list.push(entry);
        saveContractRenewalLog(list);
        return entry;
    }

    /** استعادة العقد النشط من لقطة ما قبل التجديد إذا تلوّث بمسودة التجديد / Restore active contract if renewal draft overwrote it */
    function repairSavedContractCorruptedByRenewalDraft(unit) {
        const draft = getContractRenewalDraftEntryForUnit(unit);
        if (!draft?.previousSnapshot) return false;
        const saved = getSavedContractEntryForUnit(unit);
        if (!saved?.payload) return false;
        const prev = draft.previousSnapshot;
        if (contractPayloadNeedsAdditionalData(prev)) return false;
        const savedPayload = saved.payload;
        const renewalStart = toStr(draft.renewal?.newStart || draft.payload?.startDate);
        const savedStart = toStr(savedPayload.startDate);
        const prevStart = toStr(prev.startDate);
        const prevAg = toStr(prev.agreementNo);
        const savedAg = toStr(savedPayload.agreementNo);
        const looksCorrupted =
            toStr(saved.lifecycleStatus) === 'active_pending' &&
            contractPayloadNeedsAdditionalData(savedPayload) &&
            (savedStart === renewalStart || savedAg !== prevAg);
        if (!looksCorrupted) return false;
        const restored = cloneContractPayloadForArchive(prev);
        if (!restored) return false;
        restored.contractSavedStatus = 'active';
        upsertSavedContractForUnit(unit.building, unit.unit, restored, 'active');
        clearBhdContractFullIfMatchesUnit(unit.building, unit.unit);
        return true;
    }

    function repairAllRenewalDraftSavedContracts() {
        let repaired = 0;
        try {
            const map = loadContractRenewalDraftsMap();
            Object.keys(map).forEach((k) => {
                const entry = map[k];
                const p = entry?.payload;
                if (!p || !toStr(p.buildingNo) || !toStr(p.flatNo)) return;
                const unit = { building: p.buildingNo, unit: p.flatNo };
                if (repairSavedContractCorruptedByRenewalDraft(unit)) repaired += 1;
            });
        } catch (_eRenRepair) {}
        return repaired;
    }

    /** هل مسودة التجديد تفتقد شيكات الفترة الجديدة فقط؟ / Renewal draft missing new-period cheque data only */
    function contractRenewalFinancialNeedsAdditionalData(payload) {
        if (!payload || typeof payload !== 'object') return true;
        const byChq = isPaymentMethodCheque(payload.paymentMethod);
        const schedule = parsePayloadJsonArrayField(payload, 'paymentScheduleJson', 'paymentSchedule');
        if (!schedule.length) return true;
        if (schedule.some((r) => paymentScheduleRowHasGap(r, byChq))) return true;
        if (toStr(payload.contractSubjectToVat) === 'yes' && toStr(payload.vatPaymentMode) === 'separate') {
            const vatSchedule = parsePayloadJsonArrayField(payload, 'vatChequeScheduleJson', 'vatChequeSchedule');
            const count = Math.max(1, parseInt(toStr(payload.vatChequeCount), 10) || 1);
            if (vatSchedule.length < count) return true;
            if (vatSchedule.some((r) => vatChequeRowHasGap(r))) return true;
        }
        return false;
    }

    /** نواقص التجديد — بدون تأمين/إيصال (محفوظة في العقد السابق) / Renewal gaps — exclude deposit (prior contract) */
    function analyzeRenewalAdditionalDataGaps(payload) {
        const gaps = analyzeContractAdditionalDataGaps(payload);
        gaps.depositReceiptRef = false;
        gaps.depositAttachment = false;
        gaps.insuranceDepositRowIds = [];
        return gaps;
    }

    /** هل التجديد يحتاج بيانات مالية إضافية (شيكات فقط)؟ / Renewal missing new-period cheques only */
    function contractRenewalPayloadNeedsAdditionalData(payload) {
        return contractRenewalFinancialNeedsAdditionalData(payload);
    }

    /** هل التجديد غير مكتمل (شيكات أو بيانات بلدية)؟ / Renewal incomplete for final save */
    function renewalPayloadNeedsDraftSave(payload) {
        return contractRenewalPayloadNeedsAdditionalData(payload);
    }

    let _renewalGapContinueCallback = null;

    function formatRenewalAdditionalDataGapMessages(gaps) {
        const msgs = [];
        if (!gaps) return msgs;
        if (gaps.municipalFormNo) {
            msgs.push(t('رقم استمارة العقد البلدي / Municipal contract form no.', 'Municipal contract form no. / رقم استمارة العقد البلدي'));
        }
        if (gaps.municipalContractNo) {
            msgs.push(t('رقم العقد البلدي / Municipal contract no.', 'Municipal contract no. / رقم العقد البلدي'));
        }
        if (gaps.depositReceiptRef) {
            msgs.push(t('مرجع إيصال التأمين / Deposit receipt ref.', 'Deposit receipt ref. / مرجع إيصال التأمين'));
        }
        if (gaps.depositAttachment) {
            msgs.push(t('مرفق إيصال التأمين / Deposit receipt attachment', 'Deposit receipt attachment / مرفق إيصال التأمين'));
        }
        if (gaps.paymentScheduleIncomplete) {
            msgs.push(t('جدول الدفع / الشيكات / Payment schedule / cheques', 'Payment schedule / cheques / جدول الدفع / الشيكات'));
        }
        (gaps.paymentScheduleMonthIndices || []).forEach((m) => {
            msgs.push(t(`شيك إيجار — شهر ${m} / Rent cheque — month ${m}`, `Rent cheque — month ${m} / شيك إيجار — شهر ${m}`));
        });
        (gaps.vatChequeIndices || []).forEach((i) => {
            msgs.push(t(`شيك ضريبة — ${i} / VAT cheque — ${i}`, `VAT cheque — ${i} / شيك ضريبة — ${i}`));
        });
        (gaps.insuranceDepositRowIds || []).forEach((id) => {
            msgs.push(t(`بند تأمين (${id}) / Insurance line (${id})`, `Insurance line (${id}) / بند تأمين (${id})`));
        });
        return msgs;
    }

    function collectRenewalWizardHardGapMessages(renewal) {
        const msgs = [];
        if (!renewal?.newStart || !renewal?.newEnd) {
            msgs.push(
                t(
                    'فترة العقد الجديدة (تاريخ البداية والنهاية) / New contract period (start & end dates)',
                    'New contract period (start & end dates) / فترة العقد الجديدة'
                )
            );
        } else if (parseYmdToLocalDate(renewal.newEnd) < parseYmdToLocalDate(renewal.newStart)) {
            msgs.push(
                t(
                    'تاريخ النهاية يجب أن يكون بعد البداية / End date must be after start date',
                    'End date must be after start date / تاريخ النهاية بعد البداية'
                )
            );
        }
        const rent = parseRentAmountInput(renewal?.monthlyRent);
        if (rent === '' || rent <= 0) {
            msgs.push(
                t(
                    'القيمة الإيجارية الشهرية (أكبر من صفر) / Monthly rent (greater than zero)',
                    'Monthly rent (greater than zero) / القيمة الإيجارية الشهرية'
                )
            );
        }
        return msgs;
    }

    function collectRenewalWizardSoftGapMessages(renewal) {
        const msgs = [];
        if (!toStr(renewal?.agreementNo).trim()) {
            msgs.push(t('رقم العقد الجديد / New agreement no.', 'New agreement no. / رقم العقد الجديد'));
        }
        if (!toStr(renewal?.municipalFormNo).trim()) {
            msgs.push(t('رقم استمارة العقد البلدي / Municipal contract form no.', 'Municipal contract form no. / رقم استمارة العقد البلدي'));
        }
        if (!toStr(renewal?.municipalContractNo).trim()) {
            msgs.push(t('رقم العقد البلدي / Municipal contract no.', 'Municipal contract no. / رقم العقد البلدي'));
        }
        return msgs;
    }

    function collectRenewalMandatoryDocGapMessages(payload) {
        const msgs = [];
        if (!payload) return msgs;
        let store = {};
        try {
            const raw = JSON.parse(toStr(payload.contractMandatoryDocsJson) || '{}');
            if (raw && typeof raw === 'object' && !Array.isArray(raw)) store = raw;
        } catch (_eMandG) {}
        const slots = getContractMandatoryDocSlotsFromData(payload);
        const ixAb = findAddressBookTenantIndexForData(payload);
        slots.forEach((sl) => {
            if (contractAttachmentPresent(store[sl.key])) return;
            if (ixAb >= 0) {
                const abAtt = lookupMandatoryAttachmentFromAddressBook(sl.key, addressBookEntries[ixAb]);
                if (contractAttachmentPresent(cloneContractDocMeta(abAtt))) return;
            }
            msgs.push(String(sl.label).replace(/<[^>]+>/g, ''));
        });
        return msgs;
    }

    function collectRenewalFinancialGapMessages(payload, unit, mode) {
        const msgs = [];
        if (!payload) return msgs;
        const gaps = analyzeRenewalAdditionalDataGaps(payload);
        msgs.push(...formatRenewalAdditionalDataGapMessages(gaps));
        if (contractRenewalFinancialNeedsAdditionalData(payload) && !gaps.paymentScheduleIncomplete) {
            const byChq = isPaymentMethodCheque(payload.paymentMethod);
            const schedule = parsePayloadJsonArrayField(payload, 'paymentScheduleJson', 'paymentSchedule');
            if (!schedule.length && toStr(payload.paymentMethod).trim()) {
                msgs.push(
                    t('جدول شيكات فترة التجديد / Renewal period cheque schedule', 'Renewal period cheque schedule / جدول شيكات فترة التجديد')
                );
            }
        }
        if (mode === 'finalize') {
            const entry = findAddressBookEntryForRenewalPayload(payload, unit);
            if (!entry) {
                msgs.push(
                    t(
                        'المستأجر غير موجود في دفتر العناوين / Tenant not in address book',
                        'Tenant not in address book / المستأجر في دفتر العناوين'
                    )
                );
            } else {
                getAddressBookIssues(entry).forEach((issue) => msgs.push(issue));
            }
            msgs.push(...collectRenewalMandatoryDocGapMessages(payload));
        }
        const seen = new Set();
        return msgs.filter((m) => {
            const k = toStr(m);
            if (!k || seen.has(k)) return false;
            seen.add(k);
            return true;
        });
    }

    function getCurrentRenewalStep() {
        if (document.getElementById('contractRenewalFinancialModal')?.classList.contains('open')) return 2;
        if (document.getElementById('contractRenewalModal')?.classList.contains('open')) return 1;
        return 0;
    }

    function syncRenewalStepPills(step) {
        const mark = (el, on) => {
            if (el) el.classList.toggle('active', !!on);
        };
        mark(document.getElementById('contractRenewalStepPill1'), step === 1);
        mark(document.getElementById('contractRenewalStepPill2'), step === 2);
        const finModal = document.getElementById('contractRenewalFinancialModal');
        if (finModal) {
            const pills = finModal.querySelectorAll('.crn-steps .crn-step-pill');
            if (pills[0]) mark(pills[0], step === 1);
            if (pills[1]) mark(pills[1], step === 2);
        }
    }

    function refreshRenewalGapsBanner() {
        const step = getCurrentRenewalStep();
        const bannerId = step === 1 ? 'crnGapsBanner' : step === 2 ? 'crnfGapsBanner' : '';
        const el = bannerId ? document.getElementById(bannerId) : null;
        if (!el) return;
        let msgs = [];
        if (step === 1) {
            msgs = [
                ...collectRenewalWizardHardGapMessages(collectContractRenewalWizardData()),
                ...collectRenewalWizardSoftGapMessages(collectContractRenewalWizardData())
            ];
        } else if (step === 2) {
            msgs = collectRenewalFinancialGapMessages(
                collectContractRenewalFinancialFromModal(),
                _contractRenewalCtx?.unit,
                'draft'
            );
        }
        const seen = new Set();
        msgs = msgs.filter((m) => {
            const k = toStr(m);
            if (!k || seen.has(k)) return false;
            seen.add(k);
            return true;
        });
        if (!msgs.length) {
            el.style.display = 'none';
            el.innerHTML = '';
            return;
        }
        el.style.display = '';
        el.innerHTML = `<strong>${t('ملاحظات نواقص / Missing data notes', 'Missing data notes / ملاحظات نواقص')}:</strong><ul>${msgs
            .map((m) => `<li>${escHtml(m)}</li>`)
            .join('')}</ul>`;
    }

    function openContractRenewalGapsModal(messages, onContinue, opt = {}) {
        const list = Array.isArray(messages) ? messages.filter((m) => toStr(m)) : [];
        const host = document.getElementById('contractRenewalGapsList');
        const titleEl = document.getElementById('contractRenewalGapsTitle');
        const introEl = document.getElementById('contractRenewalGapsIntro');
        const continueBtn = document.getElementById('contractRenewalGapsContinueBtn');
        const completeBtn = document.getElementById('contractRenewalGapsCompleteBtn');
        if (!host) {
            if (onContinue && opt.allowContinue !== false) onContinue();
            return;
        }
        _renewalGapContinueCallback = typeof onContinue === 'function' ? onContinue : null;
        const allowContinue = opt.allowContinue !== false && !!_renewalGapContinueCallback;
        if (titleEl) {
            titleEl.textContent =
                opt.title ||
                (allowContinue
                    ? t('ملاحظات نواقص التجديد / Renewal gaps notice', 'Renewal gaps notice / ملاحظات نواقص التجديد')
                    : t('لا يمكن المتابعة / Cannot continue', 'Cannot continue / لا يمكن المتابعة'));
        }
        if (introEl) {
            introEl.textContent =
                opt.intro ||
                (allowContinue
                    ? t(
                          'توجد بيانات ناقصة. يمكنك إكمالها الآن أو المتابعة على أي حال.',
                          'Some data is missing. Complete it now or continue anyway.'
                      )
                    : t(
                          'أكمل البيانات التالية قبل المتابعة:',
                          'Complete the following before continuing:'
                      ));
        }
        host.innerHTML = list.map((m) => `<li>${escHtml(m)}</li>`).join('');
        if (continueBtn) {
            continueBtn.textContent =
                opt.continueLabel || t('المتابعة على أي حال / Continue anyway', 'Continue anyway / المتابعة على أي حال');
            continueBtn.style.display = allowContinue ? '' : 'none';
        }
        if (completeBtn) {
            completeBtn.textContent =
                opt.completeLabel || t('إكمال النواقص / Complete gaps', 'Complete gaps / إكمال النواقص');
        }
        document.getElementById('contractRenewalGapsModal')?.classList.add('open');
        try {
            localizeBilingualUi();
        } catch (_eLocGaps) {}
    }

    function closeContractRenewalGapsModal() {
        document.getElementById('contractRenewalGapsModal')?.classList.remove('open');
        _renewalGapContinueCallback = null;
        refreshRenewalGapsBanner();
    }

    function confirmContractRenewalGapsContinue() {
        const fn = _renewalGapContinueCallback;
        closeContractRenewalGapsModal();
        if (fn) fn();
    }

    function goRenewalStepBack() {
        if (getCurrentRenewalStep() !== 2) return;
        reopenContractRenewalWizardFromFinancial();
    }

    function goRenewalStepForward() {
        const step = getCurrentRenewalStep();
        if (step === 1) {
            requestContinueContractRenewalToFinancials();
        } else if (step === 2) {
            requestRenewalSave({ forceDraft: false });
        }
    }

    function requestContinueContractRenewalToFinancials() {
        const renewal = collectContractRenewalWizardData();
        const hard = collectRenewalWizardHardGapMessages(renewal);
        if (hard.length) {
            openContractRenewalGapsModal(hard, null, {
                allowContinue: false,
                title: t('لا يمكن المتابعة / Cannot continue', 'Cannot continue / لا يمكن المتابعة'),
                intro: t('أكمل البيانات التالية قبل الانتقال للخطوة التالية:', 'Complete the following before the next step:')
            });
            return;
        }
        const soft = collectRenewalWizardSoftGapMessages(renewal);
        if (soft.length) {
            openContractRenewalGapsModal(soft, () => continueContractRenewalToFinancials(), {
                continueLabel: t(
                    'متابعة إلى الشيكات والمبالغ / Continue to cheques & amounts',
                    'Continue to cheques & amounts / متابعة إلى الشيكات والمبالغ'
                ),
                completeLabel: t('إكمال النواقص / Complete gaps', 'Complete gaps / إكمال النواقص')
            });
            return;
        }
        continueContractRenewalToFinancials();
    }

    function requestRenewalSave(opt = {}) {
        const forceDraft = opt.forceDraft === true;
        const payload = collectContractRenewalFinancialFromModal();
        const unit = _contractRenewalCtx?.unit;
        const mode = forceDraft ? 'draft' : 'finalize';
        const msgs = collectRenewalFinancialGapMessages(payload, unit, mode);
        if (msgs.length) {
            openContractRenewalGapsModal(msgs, () => saveContractRenewalFromModal({ forceDraft }), {
                continueLabel: forceDraft
                    ? t('حفظ مسودة على أي حال / Save draft anyway', 'Save draft anyway / حفظ مسودة على أي حال')
                    : t(
                          'حفظ على أي حال (مسودة إن لزم) / Save anyway (draft if needed)',
                          'Save anyway (draft if needed) / حفظ على أي حال'
                      ),
                completeLabel: t('إكمال النواقص / Complete gaps', 'Complete gaps / إكمال النواقص'),
                intro: forceDraft
                    ? t(
                          'توجد نواقص. يمكن إكمالها أو حفظ مسودة التجديد على أي حال.',
                          'Gaps found. Complete them or save the renewal draft anyway.'
                      )
                    : t(
                          'توجد نواقص. يمكن إكمالها أو المتابعة (يُحفظ كمسودة إن لم تكتمل البيانات).',
                          'Gaps found. Complete them or continue (saved as draft if data is incomplete).'
                      )
            });
            return;
        }
        saveContractRenewalFromModal({ forceDraft });
    }

    function findAddressBookEntryForRenewalPayload(payload, unit) {
        refreshAddressBookFromSystem(false);
        const u = {
            building: toStr(payload?.buildingNo) || toStr(unit?.building),
            unit: toStr(payload?.flatNo) || toStr(unit?.unit),
            tenant: toStr(payload?.tenantNameAr),
            mobile: toStr(payload?.tenantMobile),
            civilCard: toStr(payload?.tenantId) || toStr(payload?.tenantCommercialRegNo)
        };
        const byUnit = findAddressBookEntryForUnit(u);
        if (byUnit) return byUnit;
        const ix = findAddressBookTenantIndexForData(payload || {});
        return ix >= 0 ? addressBookEntries[ix] : null;
    }

    function validateRenewalTenantDocumentsOrAlert(payload, unit) {
        const entry = findAddressBookEntryForRenewalPayload(payload, unit);
        if (!entry) {
            alert(
                t(
                    '⚠️ لا يمكن إتمام التجديد: المستأجر غير موجود في دفتر العناوين أو لا يمكن مطابقته.\n\nحدّث بيانات المستأجر في الدفتر ثم أعد المحاولة.',
                    '⚠️ Cannot complete renewal: tenant not found in the address book or could not be matched.\n\nUpdate tenant data in the address book, then try again.'
                )
            );
            return false;
        }
        const issues = getAddressBookIssues(entry);
        if (issues.length) {
            alert(
                t(
                    '⚠️ لا يمكن إتمام التجديد: مستندات المستأجر منتهية أو ناقصة أو قريبة الانتهاء:\n\n• ',
                    '⚠️ Cannot complete renewal: tenant documents are expired, missing, or near expiry:\n\n• '
                ) + issues.join('\n• ')
            );
            return false;
        }
        return true;
    }

    function validateRenewalMandatoryDocumentsOrAlert(payload) {
        if (!payload) return false;
        let store = {};
        try {
            const raw = JSON.parse(toStr(payload.contractMandatoryDocsJson) || '{}');
            if (raw && typeof raw === 'object' && !Array.isArray(raw)) store = { ...raw };
        } catch (_eMand) {}
        const slots = getContractMandatoryDocSlotsFromData(payload);
        const ixAb = findAddressBookTenantIndexForData(payload);
        const miss = [];
        slots.forEach((sl) => {
            if (contractAttachmentPresent(store[sl.key])) return;
            if (ixAb >= 0) {
                const abAtt = lookupMandatoryAttachmentFromAddressBook(sl.key, addressBookEntries[ixAb]);
                const c = cloneContractDocMeta(abAtt);
                if (contractAttachmentPresent(c)) return;
            }
            miss.push(sl.label);
        });
        if (miss.length) {
            const plain = miss.map((x) => String(x).replace(/<[^>]+>/g, ''));
            alert(
                `${t('مستندات إلزامية ناقصة للتجديد:', 'Missing required documents for renewal:')}\n\n• ${plain.join('\n• ')}`
            );
            return false;
        }
        return true;
    }

    async function resolveRenewalPrintableAttachments(payload, unit) {
        const u = {
            building: toStr(payload?.buildingNo) || toStr(unit?.building),
            unit: toStr(payload?.flatNo) || toStr(unit?.unit)
        };
        const allowedKeys = buildRenewalPrintAttachmentKeySet(payload);
        let fromPayload = [];
        let fromAb = [];
        let diskItems = [];
        try {
            fromPayload = collectRenewalPrintableAttachmentsFromPayload(payload);
        } catch (_ePl) {}
        try {
            fromAb = collectRenewalTenantAttachmentsFromAddressBook(u, payload);
        } catch (_eAb) {}
        try {
            diskItems = await collectRenewalAttachmentsFromDiskDirect(payload, allowedKeys);
        } catch (_eDisk) {}
        return mergeContractPrintableAttachmentLists(fromPayload, diskItems, fromAb);
    }

    function sanitizePathSegmentForFile(s) {
        const raw = toStr(s).trim();
        if (!raw) return '_';
        return (
            raw
                .replace(/[<>:"|?*\x00-\x1f]/g, '_')
                .replace(/[/\\]+/g, '_')
                .replace(/\s+/g, '_')
                .replace(/_+/g, '_')
                .replace(/^\.+/, '')
                .slice(0, 120) || '_'
        );
    }

    function renewalAttachmentPathAllowed(relPath, payload) {
        const rel = toStr(relPath).replace(/\\/g, '/');
        if (!rel) return true;
        const prevAg = sanitizePathSegmentForFile(payload?.previousAgreementNo);
        if (prevAg && prevAg !== '_' && prevAg !== '_draft' && rel.includes(`/contracts/${prevAg}/`)) {
            return false;
        }
        return true;
    }

    function renewalFilePathMatchesAgreement(filePath, agreementNo) {
        const ag = sanitizePathSegmentForFile(agreementNo);
        if (!ag || ag === '_draft') return false;
        const rel = toStr(filePath).replace(/\\/g, '/');
        return rel.includes(`/contracts/${ag}/`);
    }

    function renewalFilePathIsDraft(filePath) {
        const rel = toStr(filePath).replace(/\\/g, '/');
        return /\/contracts\/_draft\//i.test(rel);
    }

    function contractFileEntryMatchesRenewalCtx(f, ctx) {
        if (!contractFileEntryMatchesCtx(f, ctx)) return false;
        const rel = toStr(f.file_path).replace(/\\/g, '/');
        const prevAg = sanitizePathSegmentForFile(ctx?.previousAgreementNo);
        if (prevAg && prevAg !== '_' && prevAg !== '_draft' && rel.includes(`/contracts/${prevAg}/`)) {
            return false;
        }
        const newAg = sanitizePathSegmentForFile(ctx?.agreementNo);
        if (newAg && newAg !== '_' && newAg !== '_draft' && rel.includes(`/contracts/${newAg}/`)) return true;
        if (renewalFilePathIsDraft(rel)) return true;
        return false;
    }

    function isRenewalTenantMandatoryDocKey(key) {
        const k = toStr(key);
        if (!k) return false;
        if (k === 'tenant_person_id' || k === 'tenant_person_passport' || k === 'tenant_company_cr') return true;
        return /^co_sig_/.test(k);
    }

    function buildRenewalPrintAttachmentKeySet(payload) {
        const keys = new Set();
        if (!payload) return keys;
        parsePayloadJsonArrayField(payload, 'paymentScheduleJson', 'paymentSchedule').forEach((r) => {
            keys.add(`pay_chq_${r.monthIndex || 0}`);
        });
        parsePayloadJsonArrayField(payload, 'vatChequeScheduleJson', 'vatChequeSchedule').forEach((r) => {
            keys.add(`vat_chq_${r.chequeIndex || 0}`);
        });
        try {
            const mand = JSON.parse(toStr(payload.contractMandatoryDocsJson) || '{}');
            if (mand && typeof mand === 'object' && !Array.isArray(mand)) {
                Object.keys(mand).forEach((key) => {
                    if (isRenewalTenantMandatoryDocKey(key)) keys.add(key);
                });
            }
        } catch (_eMk) {}
        return keys;
    }

    /** مرفقات طباعة التجديد: شيكات الفترة الجديدة + مستندات المستأجر فقط / Renewal print: new-period cheques + tenant docs only */
    function collectRenewalPrintableAttachmentsFromPayload(payload) {
        if (!payload || typeof payload !== 'object') return [];
        const items = [];
        const seen = new Set();
        const pushUnique = (entry) => {
            const url = toStr(entry.dataUrl).trim();
            const rel = toStr(entry.relativePath).trim();
            const dedupe = url || rel;
            if (!dedupe || seen.has(dedupe)) return;
            seen.add(dedupe);
            items.push(entry);
        };
        try {
            const mand = JSON.parse(toStr(payload.contractMandatoryDocsJson) || '{}');
            if (mand && typeof mand === 'object' && !Array.isArray(mand)) {
                Object.keys(mand).forEach((key) => {
                    if (!isRenewalTenantMandatoryDocKey(key)) return;
                    const att = mand[key];
                    const url = pickEmbeddedDataUrl(att, att?.dataUrl);
                    const rel = toStr(att?.relativePath);
                    if (!url && !rel) return;
                    if (rel && !renewalAttachmentPathAllowed(rel, payload)) return;
                    pushUnique({
                        key,
                        label: mandatoryDocKeyFallbackLabel(key),
                        name: toStr(att?.name),
                        type: toStr(att?.type),
                        dataUrl: url,
                        relativePath: rel,
                        storedOnDisk: !!att?.storedOnDisk
                    });
                });
            }
        } catch (_eMandRen) {}
        parsePayloadJsonArrayField(payload, 'paymentScheduleJson', 'paymentSchedule').forEach((r) => {
            const url = pickEmbeddedDataUrl(r.checkAttachmentDataUrl, r.attachmentDataUrl, r.dataUrl);
            const rel = toStr(r.checkAttachmentRelativePath || r.attachmentRelativePath);
            if (!url && !rel) return;
            if (rel && !renewalAttachmentPathAllowed(rel, payload)) return;
            const chk = toStr(r.checkNo).trim();
            const m = r.monthIndex || 0;
            pushUnique({
                key: `pay_chq_${m}`,
                label: t(`شيك إيجار — شهر ${m}`, `Rent cheque — month ${m}`) + (chk ? ` (${chk})` : ''),
                name: toStr(r.checkAttachmentName || r.attachmentName),
                type: '',
                dataUrl: url,
                relativePath: rel,
                storedOnDisk: !!(r.storedOnDisk || rel),
                monthIndex: m,
                checkNo: chk,
                amount: toStr(r.amount)
            });
        });
        parsePayloadJsonArrayField(payload, 'vatChequeScheduleJson', 'vatChequeSchedule').forEach((r) => {
            const url = pickEmbeddedDataUrl(r.checkAttachmentDataUrl, r.attachmentDataUrl, r.dataUrl);
            const rel = toStr(r.checkAttachmentRelativePath || r.attachmentRelativePath);
            if (!url && !rel) return;
            if (rel && !renewalAttachmentPathAllowed(rel, payload)) return;
            const chk = toStr(r.checkNo).trim();
            const idx = r.chequeIndex || 0;
            pushUnique({
                key: `vat_chq_${idx}`,
                label: t(`شيك ضريبة — ${idx}`, `VAT cheque — ${idx}`) + (chk ? ` (${chk})` : ''),
                name: toStr(r.checkAttachmentName || r.attachmentName),
                type: '',
                dataUrl: url,
                relativePath: rel,
                storedOnDisk: !!(r.storedOnDisk || rel),
                chequeIndex: idx,
                checkNo: chk,
                amount: toStr(r.amount)
            });
        });
        return items;
    }

    function collectRenewalTenantAttachmentsFromAddressBook(unit, payload) {
        const all = collectAddressBookPrintableAttachments(unit, payload);
        return all.filter((it) => isRenewalTenantMandatoryDocKey(it?.key));
    }

    async function collectRenewalAttachmentsFromDiskDirect(ctx, allowedKeys) {
        if (!window.bhdDesktop?.fileListEntries) return [];
        const allowed = allowedKeys instanceof Set ? allowedKeys : buildRenewalPrintAttachmentKeySet(ctx);
        let files = [];
        try {
            files = await listContractFileEntriesForCtx(ctx);
        } catch (_eList) {
            files = [];
        }
        const items = [];
        files.forEach((f) => {
            if (!contractFileEntryMatchesRenewalCtx(f, ctx)) return;
            const it = fileEntryToPrintAttachmentItem(f);
            if (!it) return;
            const rel = toStr(f.file_path).replace(/\\/g, '/');
            const isMandatoryOnDisk =
                /\/attachments\/mandatory\//i.test(rel) || /mandatory/i.test(toStr(f.doc_type));
            if (isMandatoryOnDisk) {
                items.push(it);
                return;
            }
            const canon = canonicalPrintAttachmentKey(it.key) || toStr(it.key);
            if (isRenewalTenantMandatoryDocKey(canon)) {
                items.push(it);
                return;
            }
            if (allowed.has(canon) || allowed.has(toStr(it.key))) items.push(it);
        });
        return items;
    }

    async function printContractRenewalSaveBundle(payload, unit, opt = {}) {
        const printPrefix =
            toStr(payload?.buildingNo) && toStr(payload?.flatNo)
                ? `${toStr(payload.buildingNo)}-${toStr(payload.flatNo)}`
                : toStr(opt.unitPrefix);
        const attachmentItems =
            Array.isArray(opt.attachmentItems) && opt.attachmentItems.length
                ? opt.attachmentItems
                : await resolveRenewalPrintableAttachments(payload, unit);
        const printPayload = {
            ...payload,
            scopeDiskRepairToAgreement: true
        };
        return printContractDocumentsByIndices(CONTRACT_RENEWAL_SAVE_PRINT_INDICES, {
            targetWindow: opt.targetWindow,
            printToken: opt.printToken,
            suppressAlerts: opt.suppressAlerts === true,
            closeOnFail: opt.closeOnFail === true,
            formDataOverride: printPayload,
            skipValidation: true,
            skipDiskAttachmentMerge: true,
            attachmentItems,
            unitPrefix: printPrefix,
            includeFinancialReceipt: true
        });
    }

    function clearBhdContractFullIfMatchesUnit(buildingNo, flatNo) {
        const b = toStr(buildingNo);
        const f = normalizeUnit(flatNo);
        if (!b || !f) return;
        try {
            const raw = localStorage.getItem('bhd_contract_full');
            if (!raw) return;
            const o = JSON.parse(raw);
            if (!o || typeof o !== 'object') return;
            if (
                normalizeReservationBuildingKey(o.buildingNo) === normalizeReservationBuildingKey(b) &&
                normalizeUnit(o.flatNo) === f
            ) {
                localStorage.removeItem('bhd_contract_full');
            }
        } catch (e) {}
    }

    function clearContractWorkspaceUnitPointers() {
        try {
            sessionStorage.removeItem('bhd_contract_workspace_building');
            sessionStorage.removeItem('bhd_contract_workspace_unit');
            localStorage.removeItem('bhd_contract_workspace_last_building');
            localStorage.removeItem('bhd_contract_workspace_last_unit');
        } catch (_ePtr) {}
    }

    function cancelPendingContractWorkspaceDraftSave() {
        if (_contractDraftSaveTimer) {
            clearTimeout(_contractDraftSaveTimer);
            _contractDraftSaveTimer = null;
        }
    }

    /** إعادة نموذج العقد إلى فارغ بعد إبطال مسودة — دون إعادة حفظ مسودة من DOM / Clear contract workspace after draft cancel without re-saving */
    function revertContractWorkspaceDomAfterTenancyDraftCancelled(buildingNo, flatNo) {
        const bd = toStr(document.getElementById('buildingNo')?.value);
        const fdRaw = normalizeUnit(document.getElementById('flatNo')?.value);
        if (!toStr(buildingNo) || !toStr(flatNo)) return;
        if (toStr(bd) !== toStr(buildingNo) || fdRaw !== normalizeUnit(toStr(flatNo))) return;
        cancelPendingContractWorkspaceDraftSave();
        try {
            clearBhdContractFullIfMatchesUnit(buildingNo, flatNo);
            clearContractWorkspaceUnitPointers();
            exitContractAdditionalDataMode();
        } catch (_eClrMode) {}
        try {
            clearDemoContractFormFields();
            const depRow = document.getElementById('depositAttachmentRow');
            if (depRow) {
                depRow.dataset.attachmentName = '';
                depRow.dataset.attachmentDataUrl = '';
                depRow.dataset.attachmentRelativePath = '';
                depRow.dataset.attachmentFileId = '';
                depRow.dataset.storedOnDisk = '0';
                const dsp = depRow.querySelector('[data-deposit-att-name]');
                if (dsp) dsp.textContent = '—';
            }
            const depInp = document.getElementById('depositAttachmentInput');
            if (depInp) depInp.value = '';
            const depAmt = document.getElementById('depositAmount');
            if (depAmt) depAmt.value = '';
            const depRef = document.getElementById('depositReceiptRef');
            if (depRef) depRef.value = '';
            const linked = document.getElementById('linkedContractUnitsJson');
            if (linked) linked.value = '[]';
            try { renderInsuranceDepositItemsRows([]); } catch (e) {}
            try { renderCustomRentItemsRows([]); } catch (e) {}
            try { renderPaymentScheduleFromRows([]); } catch (e) {}
            try { refreshLinkedContractUnitsPanel(); } catch (e) {}
            try { updateSummaryPanel(); } catch (e) {}
        } catch (eClr) {}
        try {
            setTenancyDraftCompletionFieldLocks(false);
            try {
                setTenantIdentityLockedFromAddressBook(false);
            } catch (_eAbClrRv) {}
        } catch (eL) {}
        try { applyContractsWorkspaceLockState(); } catch (_eRvLock) {}
    }
    function removeSavedContractsForTargets(targets) {
        (Array.isArray(targets) ? targets : []).forEach(({ building, unit }) => {
            removeSavedContractForKeys(building, unit);
        });
    }

    function collectLinkedContractGroupTargets(unit, payloadOpt) {
        const b = toStr(unit?.building);
        const u = toStr(unit?.unit);
        const seen = new Set();
        const out = [];
        const addTarget = (building, unitNo) => {
            const bb = toStr(building);
            const uu = toStr(unitNo);
            if (!bb || !uu) return;
            const k = normalizeReservationBuildingKey(bb) + '\t' + normalizeUnit(uu);
            if (seen.has(k)) return;
            seen.add(k);
            out.push({ building: bb, unit: uu });
        };
        let payload =
            payloadOpt && typeof payloadOpt === 'object'
                ? payloadOpt
                : getTenancyDraftPayloadForUnit(unit) || getSavedContractPayloadForUnit(unit);
        const primRef = findLinkedContractPrimaryForUnitInSavedMap(unit);
        if (primRef) {
            const primPayload =
                getContractPayloadForUnit(primRef) ||
                getTenancyDraftPayloadForUnit(primRef) ||
                getSavedContractPayloadForUnit(primRef);
            if (primPayload) payload = primPayload;
            addTarget(primRef.building, primRef.unit);
        }
        addTarget(b, u);
        getLinkedContractUnitsFromPayload(payload).forEach((lu) => {
            addTarget(lu.building || payload?.buildingNo || b, lu.unit);
        });
        const ag = toStr(payload?.agreementNo).trim();
        const bNorm = normalizeReservationBuildingKey(payload?.buildingNo || b);
        if (ag && bNorm) {
            const savedMap = loadSavedContractsByUnitMap();
            const draftMap = loadTenancyContractDraftsMap();
            Object.values(savedMap).forEach((entry) => {
                const p = entry?.payload;
                if (!p || normalizeReservationBuildingKey(p.buildingNo) !== bNorm) return;
                if (toStr(p.agreementNo).trim() !== ag) return;
                addTarget(p.buildingNo, p.flatNo);
            });
            Object.values(draftMap).forEach((entry) => {
                const p = entry?.payload;
                if (!p || normalizeReservationBuildingKey(p.buildingNo) !== bNorm) return;
                if (toStr(p.agreementNo).trim() !== ag) return;
                addTarget(p.buildingNo, p.flatNo);
            });
        }
        return out.length ? out : [{ building: b, unit: u }];
    }

    function collectTenancyDraftCancelTargets(unit, payload) {
        return collectLinkedContractGroupTargets(unit, payload);
    }

    /** إعادة الحجز كمسودة بعد إلغاء مسودة العقد — لا يُنشأ حجزاً مكتملاً / Restore reservation draft after cancelling tenancy draft */
    function restoreReservationDraftAfterCancelledTenancyDraft(unit, payload) {
        if (!unit || !payload || typeof payload !== 'object') return false;
        const b = toStr(unit.building);
        const uN = toStr(unit.unit);
        if (!b || !uN) return false;
        const linkedRaw = getLinkedContractUnitsFromPayload(payload);
        const unitsList = linkedRaw.length
            ? linkedRaw.map((lu) =>
                  normalizeReservationUnitEntry({
                      unit: lu.unit,
                      floor: lu.floorDetails,
                      unitType: lu.unitType,
                      monthlyRent: lu.monthlyRent,
                      electricity: lu.electricityMeter,
                      water: lu.waterMeter
                  })
              )
            : [
                  normalizeReservationUnitEntry({
                      unit: uN,
                      floor: unit.floor,
                      unitType: unit.unitType,
                      monthlyRent: payload.monthlyRent
                  })
              ];
        const primary = unitsList[0] || { unit: uN };
        const groupTargets = collectLinkedContractGroupTargets({ building: b, unit: uN }, payload);
        if (groupTargets.some((t) => findReservationIndexForUnit(t.building, t.unit) >= 0)) return false;
        const formData = sanitizeFormDataForReservationStorage({
            ...payload,
            buildingNo: b,
            flatNo: toStr(primary.unit),
            linkedUnitsJson: JSON.stringify(unitsList),
            monthlyRent:
                linkedRaw.length > 1
                    ? sumReservationUnitsMonthlyRent(unitsList).toFixed(3)
                    : toStr(payload.monthlyRent),
            type: 'جديد New'
        });
        const actor = getCurrentActorLedgerRecord();
        unitReservations.push({
            building: b,
            unit: toStr(primary.unit),
            units: unitsList,
            reservationGroupId: makeReservationGroupId(),
            reservedBy:
                toStr(payload.tenantNameAr || payload.tenantNameEn || unit.tenant) ||
                t('مسودة بدون اسم مستأجر', 'Draft without tenant name'),
            phone: toStr(payload.tenantMobile || unit.mobile),
            agreementNo: toStr(payload.agreementNo),
            since: new Date().toISOString().slice(0, 10),
            state: 'draft',
            formData,
            staffUserId: actor.staffUserId,
            staffName: actor.staffName
        });
        collectTenancyDraftCancelTargets(unit, payload).forEach(({ building, unit: u }) => {
            if (building && u) removeForcedVacantUnitForKeys(building, u);
        });
        try {
            syncAccountingDepositFromReservationPayload(b, toStr(primary.unit), formData);
        } catch (_eResAcctRestore) {}
        return true;
    }

    function logTenancyDraftCancellation(building, unit, dateStr, reason) {
        const key = 'bhd_tenancy_draft_cancellations';
        let list = [];
        try {
            list = JSON.parse(localStorage.getItem(key) || '[]');
            if (!Array.isArray(list)) list = [];
        } catch (e) {
            list = [];
        }
        const dcActor = getCurrentActorLedgerRecord();
        list.push({
            building: toStr(building),
            unit: toStr(unit),
            date: toStr(dateStr),
            reason: toStr(reason),
            at: new Date().toISOString(),
            staffUserId: dcActor.staffUserId,
            staffName: dcActor.staffName
        });
        try {
            localStorage.setItem(key, JSON.stringify(list));
        } catch (e) {}
    }

    const CONTRACT_CANCELLATION_REQUESTS_KEY = 'bhd_contract_cancellation_requests';
    const CONTRACT_CANCELLATION_FORM_07_INDEX = 6;

    function isContractCancellationFormOnlyPrint(indices) {
        const list = [
            ...new Set(
                (Array.isArray(indices) ? indices : [])
                    .map((n) => parseInt(n, 10))
                    .filter((n) => !Number.isNaN(n))
            )
        ];
        return list.length === 1 && list[0] === CONTRACT_CANCELLATION_FORM_07_INDEX;
    }

    let _unitDetailsCancelModalMode = 'draft';
    let _unitDetailsCancellationDocsCtx = null;

    function loadContractCancellationRequestsMap() {
        try {
            const raw = localStorage.getItem(CONTRACT_CANCELLATION_REQUESTS_KEY);
            const o = raw ? JSON.parse(raw) : null;
            return o && typeof o === 'object' && !Array.isArray(o) ? o : {};
        } catch (_eCcrLoad) {
            return {};
        }
    }

    function saveContractCancellationRequestsMap(map) {
        try {
            localStorage.setItem(CONTRACT_CANCELLATION_REQUESTS_KEY, JSON.stringify(map || {}));
        } catch (_eCcrSave) {}
    }

    function getContractCancellationRequestForUnit(unit) {
        if (!unit) return null;
        const map = loadContractCancellationRequestsMap();
        const e = map[_tenancyDraftStorageKey(unit.building, unit.unit)];
        return e && typeof e === 'object' ? e : null;
    }

    function upsertContractCancellationRequestForUnit(building, unit, entry) {
        const b = toStr(building);
        const u = toStr(unit);
        if (!b || !u || !entry || typeof entry !== 'object') return;
        const map = loadContractCancellationRequestsMap();
        map[_tenancyDraftStorageKey(b, u)] = entry;
        saveContractCancellationRequestsMap(map);
    }

    function removeContractCancellationRequestForUnit(building, unit) {
        const b = toStr(building);
        const u = toStr(unit);
        if (!b || !u) return;
        const map = loadContractCancellationRequestsMap();
        const k = _tenancyDraftStorageKey(b, u);
        if (!map[k]) return;
        delete map[k];
        saveContractCancellationRequestsMap(map);
    }

    function fileRefFromPersistResult(ref) {
        if (!ref || typeof ref !== 'object') return null;
        return {
            name: toStr(ref.name),
            type: toStr(ref.type),
            dataUrl: ref.storedOnDisk ? '' : toStr(ref.dataUrl),
            relativePath: toStr(ref.relativePath),
            fileId: toStr(ref.fileId),
            storedOnDisk: !!ref.storedOnDisk || !!toStr(ref.relativePath)
        };
    }

    function appendCancellationRequestEvent(req, eventType, note, extra) {
        const r = req && typeof req === 'object' ? req : {};
        const actor = getCurrentActorLedgerRecord();
        const events = Array.isArray(r.events) ? r.events.slice() : [];
        events.push({
            type: toStr(eventType),
            at: new Date().toISOString(),
            note: toStr(note),
            staffUserId: actor.staffUserId,
            staffName: actor.staffName,
            ...(extra && typeof extra === 'object' ? extra : {})
        });
        r.events = events;
        r.updatedAt = new Date().toISOString();
        return r;
    }

    function isCancellationDateReached(cancelDateYmd) {
        const cd = parseYmdToLocalDate(cancelDateYmd);
        if (!cd) return false;
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        cd.setHours(0, 0, 0, 0);
        return cd.getTime() <= today.getTime();
    }

    function cancellationRequestHasSignedForm07(req) {
        return contractAttachmentPresent(req?.signedForm07);
    }

    function unitDetailsHasCancellationRequest(unit) {
        const req = getContractCancellationRequestForUnit(unit);
        return !!(req && toStr(req.status) === 'pending');
    }

    function unitDetailsAllowsContractCancellation(unit) {
        if (!unit || !effectivePermission('manage_contracts')) return false;
        if (unitDetailsIsIncompleteTenancyDraft(unit)) return false;
        if (getContractRenewalDraftEntryForUnit(unit)) return false;
        if (unitDetailsHasCancellationRequest(unit)) return true;
        if (unitDetailsNeedsAdditionalContractData(unit)) return false;
        if (getContractLifecycleStateKey(unit) !== 'active') return false;
        return !!getSavedContractPayloadForUnit(unit);
    }

    function computeContractCancellationFinancials(payload, cancelDateYmd) {
        const p = payload && typeof payload === 'object' ? payload : {};
        const start = toStr(p.startDate);
        const end = toStr(p.endDate);
        const cancel = toStr(cancelDateYmd);
        const monthlyRent = parseFloat(p.monthlyRent) || 0;
        const contractMonths = Math.max(1, parseInt(p.contractMonths, 10) || 0);
        const fullPeriod = computeContractPeriodMonthsAndExtraDays(start, end, contractMonths);
        const totalMunicipal = parseFloat(calcMunicipalFeesFromPayload(p)) || 0;
        const monthsBase = Math.max(1, fullPeriod.months || contractMonths);
        const municipalPerMonth = totalMunicipal / monthsBase;
        const depositAmount = parseFloat(p.depositAmount) || 0;
        const insRows = parsePayloadJsonArrayField(p, 'insuranceDepositItemsJson', 'insuranceDepositItems');
        const insuranceTotal = insRows.reduce((s, x) => s + (parseFloat(x.amount) || 0), 0);
        const totalDeposit = depositAmount + insuranceTotal;
        const attachAccountingCancellationFields = (res) => {
            try {
                const acct = getAccountingSummaryForUnit(toStr(p.buildingNo), toStr(p.flatNo));
                res.accountingPaid = parseFloat(acct.paid) || 0;
                res.accountingRemaining = parseFloat(acct.remaining) || 0;
                res.accountingOverdue = parseFloat(acct.overdue) || 0;
                res.accountingDepositsHeld = parseFloat(acct.depositsHeld) || 0;
                res.accountingClaims = parseFloat(acct.claims) || 0;
            } catch (_eAcctCan) {
                res.accountingPaid = 0;
                res.accountingRemaining = 0;
                res.accountingOverdue = 0;
                res.accountingDepositsHeld = 0;
                res.accountingClaims = 0;
            }
            return res;
        };
        const result = {
            start,
            end,
            cancel,
            monthlyRent,
            contractMonths: monthsBase,
            contractExtraDays: fullPeriod.extraDays || 0,
            totalMunicipal,
            municipalPerMonth,
            totalDeposit,
            depositAmount,
            insuranceTotal,
            isEarlyTermination: false,
            remainingMonths: 0,
            remainingExtraDays: 0,
            remainingMunicipal: 0,
            remainingDays: null,
            cancelOnOrAfterEnd: false,
            cancelBeforeStart: false
        };
        if (!start || !end || !cancel) return attachAccountingCancellationFields(result);
        const cancelDt = parseYmdToLocalDate(cancel);
        const endDt = parseYmdToLocalDate(end);
        const startDt = parseYmdToLocalDate(start);
        if (!cancelDt) return attachAccountingCancellationFields(result);
        if (startDt && cancelDt < startDt) {
            result.cancelBeforeStart = true;
            return attachAccountingCancellationFields(result);
        }
        if (endDt && cancelDt >= endDt) {
            result.cancelOnOrAfterEnd = true;
            return attachAccountingCancellationFields(result);
        }
        if (endDt && cancelDt < endDt) {
            result.isEarlyTermination = true;
            const remaining = computeContractPeriodMonthsAndExtraDays(cancel, end, 0);
            result.remainingMonths = remaining.months || 0;
            result.remainingExtraDays = remaining.extraDays || 0;
            result.remainingDays = diffCalendarDaysBetweenYmd(cancel, end);
            const remainingMunicipal =
                municipalPerMonth * result.remainingMonths + (municipalPerMonth / 30) * result.remainingExtraDays;
            result.remainingMunicipal = parseFloat(remainingMunicipal.toFixed(3));
        }
        return attachAccountingCancellationFields(result);
    }

    function formatContractCancellationRemainingPeriod(fin) {
        if (!fin) return '—';
        const parts = [];
        if (fin.remainingMonths) {
            parts.push(
                t(`${fin.remainingMonths} شهر`, `${fin.remainingMonths} month${fin.remainingMonths === 1 ? '' : 's'}`)
            );
        }
        if (fin.remainingExtraDays) {
            parts.push(
                t(`${fin.remainingExtraDays} يوم`, `${fin.remainingExtraDays} day${fin.remainingExtraDays === 1 ? '' : 's'}`)
            );
        }
        if (!parts.length && fin.remainingDays !== null) {
            return t(`${fin.remainingDays} يوم`, `${fin.remainingDays} day${fin.remainingDays === 1 ? '' : 's'}`);
        }
        return parts.length ? parts.join(t(' و ', ' and ')) : '—';
    }

    function renderUnitDetailsCancelContractSummary() {
        const summaryEl = document.getElementById('unitDetailsCancelFinSummary');
        const depositEl = document.getElementById('unitDetailsCancelDepositNotice');
        if (!summaryEl || !depositEl) return;
        if (_unitDetailsCancelModalMode !== 'active_new' && _unitDetailsCancelModalMode !== 'active_manage') {
            summaryEl.style.display = 'none';
            summaryEl.innerHTML = '';
            depositEl.style.display = 'none';
            depositEl.innerHTML = '';
            return;
        }
        const unit = selectedUnitDetailsRecord;
        const payload = unit ? getSavedContractPayloadForUnit(unit) : null;
        const cancelDate = toStr(document.getElementById('unitDetailsCancelDraftDate')?.value);
        const fin = computeContractCancellationFinancials(payload, cancelDate);
        if (!payload || !cancelDate) {
            summaryEl.style.display = 'none';
            depositEl.style.display = 'none';
            return;
        }
        if (fin.cancelBeforeStart) {
            summaryEl.style.display = 'block';
            summaryEl.innerHTML = `<p style="margin:0;font-size:12px;color:#b71c1c;line-height:1.55">${t(
                'تاريخ الإلغاء قبل بداية العقد — راجع التاريخ المختار.',
                'Cancellation date is before contract start — please review the selected date.'
            )}</p>`;
            depositEl.style.display = 'none';
            return;
        }
        const periodLabel = formatContractPeriodBilingual(fin.start, fin.end, fin.contractMonths);
        const remainingLabel = fin.cancelOnOrAfterEnd
            ? t('لا فترة متبقية (الإلغاء في أو بعد نهاية العقد)', 'No remaining period (cancellation on or after contract end)')
            : formatContractCancellationRemainingPeriod(fin);
        const finItem = (label, value, highlight) =>
            `<div class="ud-cancel-fin-item${highlight ? ' ud-cancel-fin-item--highlight' : ''}"><small>${escHtml(label)}</small><strong>${escHtml(value)}</strong></div>`;
        const finItemClick = (kind, label, value) =>
            `<div class="ud-cancel-fin-item ud-acct-fin-card" onclick="openUnitAccountingDetailModal('${kind}', '${escHtml(unit.building).replace(/'/g, "\\'")}', '${escHtml(unit.unit).replace(/'/g, "\\'")}')" role="button" tabindex="0"><small>${escHtml(label)}</small><strong>${escHtml(value)}</strong></div>`;
        summaryEl.style.display = 'block';
        summaryEl.innerHTML = `
            <h6>${t('حسابات الإلغاء / Cancellation accounts', 'Cancellation accounts / حسابات الإلغاء')}</h6>
            <div class="ud-cancel-fin-grid">
                ${finItem(t('مدة العقد / Contract period', 'Contract period / مدة العقد'), periodLabel)}
                ${finItem(t('إجمالي رسوم البلدية للعقد / Total municipal fees', 'Total municipal fees / إجمالي رسوم البلدية'), summaryAmtOm(fin.totalMunicipal))}
                ${finItem(
                    t('رسوم البلدية الشهرية (محسوبة) / Municipal fee per month', 'Municipal fee per month (calculated) / رسوم البلدية الشهرية'),
                    summaryAmtOm(fin.municipalPerMonth)
                )}
                ${finItem(t('الفترة المتبقية / Remaining period', 'Remaining period / الفترة المتبقية'), remainingLabel, true)}
                ${finItem(
                    t('رسوم البلدية للفترة المتبقية / Remaining municipal fees', 'Remaining municipal fees / رسوم البلدية المتبقية'),
                    fin.isEarlyTermination ? summaryAmtOm(fin.remainingMunicipal) : summaryAmtOm(0),
                    fin.isEarlyTermination
                )}
            </div>
            <h6 style="margin-top:14px">${t('بيانات المحاسبة / Accounting data', 'Accounting data / بيانات المحاسبة')}</h6>
            <div class="ud-cancel-fin-grid">
                ${finItemClick('paid', t('المدفوع / Paid', 'Paid / المدفوع'), summaryAmtOm(fin.accountingPaid))}
                ${finItemClick('remaining', t('المتبقي / Remaining', 'Remaining / المتبقي'), summaryAmtOm(fin.accountingRemaining))}
                ${finItemClick('overdue', t('المتأخرات / Overdue', 'Overdue / المتأخرات'), summaryAmtOm(fin.accountingOverdue))}
                ${finItemClick('deposits', t('الضمان / Deposits', 'Deposits / الضمان'), summaryAmtOm(fin.accountingDepositsHeld))}
            </div>
            ${
                fin.isEarlyTermination
                    ? `<p style="margin:10px 0 0;font-size:11px;color:#555;line-height:1.5">${t(
                          'يُحسب تقسيم رسوم البلدية على عدد أشهر العقد ثم تُطبَّق على الفترة من تاريخ الإلغاء حتى نهاية العقد.',
                          'Municipal fees are split across contract months, then applied to the period from cancellation date to contract end.'
                      )}</p>`
                    : ''
            }`;
        if (fin.isEarlyTermination && fin.totalDeposit > 0) {
            depositEl.style.display = 'block';
            depositEl.innerHTML = `⚠️ ${t(
                `يوجد مبلغ ضمان بقيمة ${summaryAmtOm(fin.totalDeposit)} — المبلغ لا يُسترد (إلغاء قبل نهاية العقد).`,
                `There is a deposit of ${summaryAmtOm(fin.totalDeposit)} — non-refundable (cancellation before contract end).`
            )}`;
        } else {
            depositEl.style.display = 'none';
            depositEl.innerHTML = '';
        }
    }

    function renderCancellationRequestEventLog(req) {
        const host = document.getElementById('unitDetailsCancelEventLog');
        if (!host) return;
        const events = Array.isArray(req?.events) ? req.events.slice().reverse() : [];
        if (!events.length) {
            host.style.display = 'none';
            host.innerHTML = '';
            return;
        }
        host.style.display = 'block';
        host.innerHTML = `<strong style="display:block;margin-bottom:6px;color:#4a1525">${t('سجل الحركات / Activity log', 'Activity log / سجل الحركات')}</strong>${events
            .map((ev) => {
                const when = escHtml(toStr(ev.at).slice(0, 16).replace('T', ' '));
                const who = escHtml(toStr(ev.staffName) || '—');
                const type = escHtml(cancellationEventTypeLabel(ev.type));
                const note = escHtml(toStr(ev.note));
                const extra =
                    ev.cancelDate && toStr(ev.cancelDate) !== toStr(req.cancelDate)
                        ? ` · ${t('تاريخ', 'Date')}: ${escHtml(toStr(ev.cancelDate))}`
                        : '';
                return `<div style="margin-bottom:5px"><strong>${type}</strong> — ${when} — ${who}${extra}${note ? `<br><span style="color:#666">${note}</span>` : ''}</div>`;
            })
            .join('')}`;
    }

    function cancellationEventTypeLabel(type) {
        const map = {
            requested: t('طلب إلغاء / Cancellation requested', 'Cancellation requested / طلب إلغاء'),
            rescheduled: t('تعديل التاريخ / Date rescheduled', 'Date rescheduled / تعديل التاريخ'),
            signed_form_uploaded: t('رفع استمارة 07 / Form 07 uploaded', 'Form 07 uploaded / رفع استمارة 07'),
            confirmed: t('تأكيد الإلغاء / Cancellation confirmed', 'Cancellation confirmed / تأكيد الإلغاء'),
            withdrawn: t('إلغاء الطلب / Request withdrawn', 'Request withdrawn / إلغاء الطلب'),
            final_docs_saved: t('حفظ مستندات الإلغاء / Final docs saved', 'Final docs saved / حفظ مستندات الإلغاء')
        };
        return map[toStr(type)] || toStr(type) || '—';
    }

    function renderUnitDetailsCancelSigned07Label(req) {
        const lbl = document.getElementById('unitDetailsCancelSigned07Label');
        if (!lbl) return;
        if (cancellationRequestHasSignedForm07(req)) {
            lbl.textContent = `✓ ${toStr(req.signedForm07.name)}`;
            lbl.style.color = '#2e7d32';
        } else {
            lbl.textContent = t('لم تُرفع بعد / Not uploaded yet', 'Not uploaded yet / لم تُرفع بعد');
            lbl.style.color = '#888';
        }
    }

    function renderUnitDetailsCancelModalActions(mode, req) {
        const host = document.getElementById('unitDetailsCancelActions');
        if (!host) return;
        const backBtn = `<button type="button" class="btn-outline" onclick="closeUnitDetailsCancelContractModal()" data-ar="رجوع" data-en="Back">رجوع / Back</button>`;
        if (mode === 'draft') {
            host.innerHTML =
                backBtn +
                `<button type="button" class="btn-primary" style="background:#b71c1c;border-color:#b71c1c" onclick="confirmUnitDetailsCancelDraft()" data-ar="تأكيد إلغاء المسودة" data-en="Confirm draft cancellation">تأكيد إلغاء المسودة / Confirm draft cancellation</button>`;
            return;
        }
        if (mode === 'active_new') {
            host.innerHTML =
                backBtn +
                `<button type="button" class="btn-primary" style="background:#b71c1c;border-color:#b71c1c" onclick="saveUnitDetailsCancellationRequest()" data-ar="حفظ الطلب" data-en="Save request">حفظ الطلب / Save request</button>`;
            return;
        }
        const dateReached = isCancellationDateReached(req?.cancelDate);
        const hasSigned = cancellationRequestHasSignedForm07(req);
        const canConfirm = dateReached && hasSigned;
        host.innerHTML =
            backBtn +
            `<button type="button" class="btn-outline" style="border-color:#b71c1c;color:#b71c1c" onclick="withdrawUnitDetailsCancellationRequest()" data-ar="إلغاء الطلب" data-en="Withdraw request">إلغاء الطلب / Withdraw request</button>` +
            `<button type="button" class="btn-outline" onclick="rescheduleUnitDetailsCancellationRequest()" data-ar="حفظ التاريخ الجديد" data-en="Save new date">📅 حفظ التاريخ الجديد / Save new date</button>` +
            (canConfirm
                ? `<button type="button" class="btn-primary" style="background:#b71c1c;border-color:#b71c1c" onclick="confirmUnitDetailsCancellationRequest()" data-ar="تأكيد الإلغاء" data-en="Confirm cancellation">✓ تأكيد الإلغاء / Confirm cancellation</button>`
                : `<button type="button" class="btn-primary" style="background:#999;border-color:#999;opacity:0.85" disabled title="${escAttr(
                      !dateReached
                          ? t('ينتظر تاريخ الإلغاء', 'Awaiting cancellation date')
                          : t('ارفع استمارة 07 الموقّعة أولاً', 'Upload signed form 07 first')
                  )}">${t('تأكيد الإلغاء', 'Confirm cancellation')} / Confirm</button>`);
    }

    function configureUnitDetailsCancelContractModal(mode, req) {
        _unitDetailsCancelModalMode = mode;
        const titleEl = document.getElementById('unitDetailsCancelModalTitle');
        const introEl = document.getElementById('unitDetailsCancelModalIntro');
        const notesLabel = document.getElementById('unitDetailsCancelNotesLabel');
        const notesEl = document.getElementById('unitDetailsCancelDraftReason');
        const uploadSec = document.getElementById('unitDetailsCancelUploadSection');
        const banner = document.getElementById('unitDetailsCancelStatusBanner');
        const isDraft = mode === 'draft';
        const isManage = mode === 'active_manage';
        const isActive = mode === 'active_new' || isManage;
        if (titleEl) {
            titleEl.textContent = isDraft
                ? t('إلغاء مسودة العقد / Cancel draft contract', 'Cancel draft contract / إلغاء مسودة العقد')
                : isManage
                  ? t('متابعة إلغاء العقد / Continue cancellation', 'Continue cancellation / متابعة إلغاء العقد')
                  : t('طلب إلغاء العقد / Request contract cancellation', 'Request contract cancellation / طلب إلغاء العقد');
        }
        if (introEl) {
            introEl.textContent = isDraft
                ? t('أدخل تاريخ الإلغاء وأسباب إلغاء المسودة.', 'Enter cancellation date and reasons for cancelling the draft.')
                : isManage
                  ? t(
                        'العقار في انتظار الإلغاء — يمكنك تأكيد الطلب عند تاريخ الإلغاء (بعد رفع استمارة 07)، أو تعديل التاريخ، أو إلغاء الطلب.',
                        'Property awaiting cancellation — confirm on the cancellation date (after uploading signed form 07), reschedule, or withdraw the request.'
                    )
                  : t(
                        'حدّد تاريخ الإلغاء — عند الحفظ يصبح العقار «في انتظار الإلغاء».',
                        'Select cancellation date — on save the property becomes «awaiting cancellation».'
                    );
        }
        if (notesLabel) {
            notesLabel.textContent = isDraft
                ? t('أسباب الإلغاء / Reasons', 'Reasons / أسباب الإلغاء')
                : t('ملاحظات وتعليقات / Notes & comments', 'Notes & comments / ملاحظات وتعليقات');
        }
        if (notesEl) {
            notesEl.placeholder = isDraft
                ? t('أسباب الإلغاء / Reasons for cancellation', 'Reasons for cancellation / أسباب الإلغاء')
                : t('ملاحظات وتعليقات (اختياري) / Notes & comments (optional)', 'Notes & comments (optional) / ملاحظات (اختياري)');
        }
        if (uploadSec) uploadSec.style.display = isManage ? '' : 'none';
        if (banner) {
            if (isManage && req) {
                const reached = isCancellationDateReached(req.cancelDate);
                banner.style.display = 'block';
                banner.innerHTML = `📌 ${t(
                    `في انتظار إلغاء العقد — التاريخ المطلوب: ${toStr(req.cancelDate)}${reached ? ' (وصل التاريخ)' : ''}`,
                    `Awaiting contract cancellation — requested date: ${toStr(req.cancelDate)}${reached ? ' (date reached)' : ''}`
                )}`;
            } else {
                banner.style.display = 'none';
                banner.innerHTML = '';
            }
        }
        if (isManage && req) {
            renderCancellationRequestEventLog(req);
            renderUnitDetailsCancelSigned07Label(req);
        } else {
            const logEl = document.getElementById('unitDetailsCancelEventLog');
            if (logEl) {
                logEl.style.display = 'none';
                logEl.innerHTML = '';
            }
            const signedLbl = document.getElementById('unitDetailsCancelSigned07Label');
            if (signedLbl) signedLbl.textContent = '—';
        }
        renderUnitDetailsCancelModalActions(mode, req);
    }

    function openUnitDetailsCancelContractModal() {
        const unit = selectedUnitDetailsRecord;
        if (!unit) return;
        const isDraft = unitDetailsIsIncompleteTenancyDraft(unit);
        const pendingReq = unitDetailsHasCancellationRequest(unit) ? getContractCancellationRequestForUnit(unit) : null;
        const canNew = !isDraft && !pendingReq && unitDetailsAllowsContractCancellation(unit);
        if (!isDraft && !pendingReq && !canNew) {
            alert(
                t(
                    'لا يمكن إلغاء العقد لهذه الوحدة في حالتها الحالية.',
                    'Contract cannot be cancelled for this unit in its current state.'
                )
            );
            return;
        }
        const el = document.getElementById('unitDetailsCancelDraftModal');
        if (!el) return;
        const mode = isDraft ? 'draft' : pendingReq ? 'active_manage' : 'active_new';
        const payload = getSavedContractPayloadForUnit(unit) || getContractPayloadForUnit(unit);
        configureUnitDetailsCancelContractModal(mode, pendingReq);
        const startEl = document.getElementById('unitDetailsCancelContractStart');
        const endEl = document.getElementById('unitDetailsCancelContractEnd');
        const de = document.getElementById('unitDetailsCancelDraftDate');
        const re = document.getElementById('unitDetailsCancelDraftReason');
        const signedInp = document.getElementById('unitDetailsCancelSigned07Input');
        const start = toStr(pendingReq?.startDate || payload?.startDate || unit.startDate);
        const end = toStr(pendingReq?.endDate || payload?.endDate || unit.endDate);
        if (startEl) startEl.textContent = start || '—';
        if (endEl) endEl.textContent = end || '—';
        const todayIso = new Date().toISOString().slice(0, 10);
        if (de) {
            de.value = toStr(pendingReq?.cancelDate) || todayIso;
            de.min = start || '';
            de.max = '';
            de.disabled = false;
        }
        if (re) re.value = toStr(pendingReq?.notes) || '';
        if (signedInp) signedInp.value = '';
        _unitDetailsCancelModalMode = mode;
        renderUnitDetailsCancelContractSummary();
        el.classList.add('open');
    }

    async function printCancellationForm07ForUnit(unit) {
        if (!unit) return;
        prefillContractFromUnit(unit, false, { skipReservationGate: true });
        try {
            mergeMandatoryDocsFromAddressBookAfterLoadIfMatch();
        } catch (_eAb) {}
        await printContractDocumentsByIndices([CONTRACT_CANCELLATION_FORM_07_INDEX], {
            includeFinancialReceipt: false,
            skipValidation: true,
            hydrateAttachments: false,
            attachmentItems: [],
            unitPrefix: `${toStr(unit.building)}-${toStr(unit.unit)}`
        });
    }

    async function saveUnitDetailsCancellationRequest() {
        if (!assertPermissionOrAlert('manage_contracts', 'لا تملك صلاحية طلب إلغاء العقد.', 'No permission to request contract cancellation.')) return;
        const unit = selectedUnitDetailsRecord;
        if (!unit || unitDetailsHasCancellationRequest(unit)) return;
        const payload = getSavedContractPayloadForUnit(unit);
        if (!payload) return;
        const dateStr = toStr(document.getElementById('unitDetailsCancelDraftDate')?.value);
        const notes = toStr(document.getElementById('unitDetailsCancelDraftReason')?.value).trim();
        if (!dateStr) {
            alert(t('يرجى اختيار تاريخ الإلغاء.', 'Please select a cancellation date.'));
            return;
        }
        const fin = computeContractCancellationFinancials(payload, dateStr);
        if (fin.cancelBeforeStart) {
            alert(t('تاريخ الإلغاء لا يمكن أن يكون قبل بداية العقد.', 'Cancellation date cannot be before contract start.'));
            return;
        }
        const actor = getCurrentActorLedgerRecord();
        let req = {
            status: 'pending',
            cancelDate: dateStr,
            notes,
            financials: fin,
            agreementNo: toStr(payload.agreementNo),
            tenant: toStr(payload.tenantNameAr || unit.tenant),
            startDate: fin.start,
            endDate: fin.end,
            signedForm07: null,
            municipalityLetter: null,
            supportingDocs: [],
            events: [],
            requestedAt: new Date().toISOString(),
            updatedAt: new Date().toISOString(),
            staffUserId: actor.staffUserId,
            staffName: actor.staffName
        };
        req = appendCancellationRequestEvent(req, 'requested', notes || t('طلب إلغاء عقد جديد', 'New contract cancellation request'), {
            cancelDate: dateStr
        });
        upsertContractCancellationRequestForUnit(unit.building, unit.unit, req);
        syncBhdKvToServer();
        closeUnitDetailsCancelContractModal();
        refreshUnitDetailsAfterCancellationChange();
        try {
            renderOperationsTable();
        } catch (_eTbl) {}
        alert(
            t(
                '✅ تم حفظ طلب الإلغاء — العقار الآن «في انتظار إلغاء العقد».',
                '✅ Cancellation request saved — property is now «awaiting contract cancellation».'
            )
        );
    }

    async function rescheduleUnitDetailsCancellationRequest() {
        const unit = selectedUnitDetailsRecord;
        if (!unit) return;
        const req = getContractCancellationRequestForUnit(unit);
        if (!req || toStr(req.status) !== 'pending') return;
        const payload = getSavedContractPayloadForUnit(unit);
        const dateStr = toStr(document.getElementById('unitDetailsCancelDraftDate')?.value);
        const notes = toStr(document.getElementById('unitDetailsCancelDraftReason')?.value).trim();
        if (!dateStr) {
            alert(t('يرجى اختيار تاريخ الإلغاء.', 'Please select a cancellation date.'));
            return;
        }
        const fin = computeContractCancellationFinancials(payload, dateStr);
        if (fin.cancelBeforeStart) {
            alert(t('تاريخ الإلغاء لا يمكن أن يكون قبل بداية العقد.', 'Cancellation date cannot be before contract start.'));
            return;
        }
        const prevDate = toStr(req.cancelDate);
        let updated = { ...req, cancelDate: dateStr, notes, financials: fin };
        updated = appendCancellationRequestEvent(
            updated,
            'rescheduled',
            notes || t(`تعديل التاريخ من ${prevDate} إلى ${dateStr}`, `Date changed from ${prevDate} to ${dateStr}`),
            { cancelDate: dateStr, previousDate: prevDate }
        );
        upsertContractCancellationRequestForUnit(unit.building, unit.unit, updated);
        syncBhdKvToServer();
        configureUnitDetailsCancelContractModal('active_manage', updated);
        renderUnitDetailsCancelContractSummary();
        alert(t('تم تحديث تاريخ الإلغاء وتسجيل الحركة.', 'Cancellation date updated and activity logged.'));
    }

    function withdrawUnitDetailsCancellationRequest() {
        const unit = selectedUnitDetailsRecord;
        if (!unit) return;
        const req = getContractCancellationRequestForUnit(unit);
        if (!req) return;
        const notes = toStr(document.getElementById('unitDetailsCancelDraftReason')?.value).trim();
        if (
            !confirm(
                t(
                    'إلغاء طلب الإلغاء بالكامل؟ يمكنك بعدها تجديد العقد.',
                    'Withdraw the cancellation request entirely? You may then renew the contract.'
                )
            )
        ) {
            return;
        }
        let withdrawn = appendCancellationRequestEvent(req, 'withdrawn', notes || t('تم إلغاء طلب الإلغاء', 'Cancellation request withdrawn'));
        logActiveContractCancellation(unit.building, unit.unit, {
            agreementNo: req.agreementNo,
            tenant: req.tenant,
            startDate: req.startDate,
            endDate: req.endDate,
            cancelDate: req.cancelDate,
            notes: `${t('طلب ملغى', 'Request withdrawn')}${notes ? ` — ${notes}` : ''}`,
            totalMunicipal: req.financials?.totalMunicipal,
            municipalPerMonth: req.financials?.municipalPerMonth,
            remainingMunicipal: req.financials?.remainingMunicipal,
            remainingMonths: req.financials?.remainingMonths,
            remainingExtraDays: req.financials?.remainingExtraDays,
            totalDeposit: req.financials?.totalDeposit,
            status: 'withdrawn'
        });
        removeContractCancellationRequestForUnit(unit.building, unit.unit);
        syncBhdKvToServer();
        closeUnitDetailsCancelContractModal();
        refreshUnitDetailsAfterCancellationChange();
        try {
            renderOperationsTable();
        } catch (_eTbl) {}
        alert(t('تم إلغاء طلب الإلغاء — العقد ما زال نشطاً.', 'Cancellation request withdrawn — contract remains active.'));
    }

