    function confirmUnitDetailsCancellationRequest() {
        if (!assertPermissionOrAlert('manage_contracts', 'لا تملك صلاحية تأكيد الإلغاء.', 'No permission to confirm cancellation.')) return;
        const unit = selectedUnitDetailsRecord;
        if (!unit) return;
        const req = getContractCancellationRequestForUnit(unit);
        if (!req || toStr(req.status) !== 'pending') {
            alert(t('لا يوجد طلب إلغاء معلّق.', 'No pending cancellation request.'));
            return;
        }
        if (!isCancellationDateReached(req.cancelDate)) {
            alert(t('لم يصل تاريخ الإلغاء بعد.', 'Cancellation date has not been reached yet.'));
            return;
        }
        if (!cancellationRequestHasSignedForm07(req)) {
            alert(t('ارفع استمارة 07 الموقّعة من الطرفين قبل التأكيد.', 'Upload the signed form 07 from both parties before confirming.'));
            return;
        }
        const payload = getSavedContractPayloadForUnit(unit);
        if (!payload) return;
        const notes = toStr(document.getElementById('unitDetailsCancelDraftReason')?.value).trim();
        if (
            !confirm(
                t(
                    'تأكيد إلغاء العقد؟ سيتم أرشفة العقد وإفراغ الوحدة.',
                    'Confirm contract cancellation? The contract will be archived and the unit marked vacant.'
                )
            )
        ) {
            return;
        }
        const fin = req.financials || computeContractCancellationFinancials(payload, req.cancelDate);
        const b = toStr(unit.building);
        const uN = toStr(unit.unit);
        const primary = resolveContractWorkflowPrimaryUnit(b, uN, payload);
        const primaryPayload =
            getSavedContractPayloadForUnit({ building: primary.building, unit: primary.unit }) || payload;
        const cancelTargets = collectLinkedContractGroupTargets(unit, primaryPayload);
        cancelTargets.forEach(({ building, unit: uKey }) => {
            const p =
                getSavedContractPayloadForUnit({ building, unit: uKey }) ||
                (normalizeUnit(uKey) === normalizeUnit(primary.unit) ? primaryPayload : null);
            if (!p) return;
            const snap = cloneContractPayloadForArchive(p);
            if (snap) archiveSupersededContractPayload(snap, { reason: 'cancelled', supersededBy: '' });
            removeSavedContractForKeys(building, uKey);
            removeTenancyContractDraftForKeys(building, uKey);
            removeContractRenewalDraft(building, uKey);
            clearBhdContractFullIfMatchesUnit(building, uKey);
            try {
                upsertForcedVacantUnit(building, uKey);
            } catch (_eFv) {}
        });
        try {
            repairLinkedContractUnitsLifecycleConsistency();
        } catch (_eCanActLinked) {}
        let finalReq = appendCancellationRequestEvent({ ...req, notes }, 'confirmed', notes || t('تم تأكيد الإلغاء', 'Cancellation confirmed'));
        logActiveContractCancellation(b, uN, {
            agreementNo: req.agreementNo,
            tenant: req.tenant,
            startDate: req.startDate,
            endDate: req.endDate,
            cancelDate: req.cancelDate,
            notes,
            totalMunicipal: fin.totalMunicipal,
            municipalPerMonth: fin.municipalPerMonth,
            remainingMunicipal: fin.remainingMunicipal,
            remainingMonths: fin.remainingMonths,
            remainingExtraDays: fin.remainingExtraDays,
            totalDeposit: fin.totalDeposit,
            signedForm07: req.signedForm07,
            status: 'completed_docs_pending',
            requestEvents: finalReq.events
        });
        removeContractCancellationRequestForUnit(b, uN);
        try {
            loadDashboardAux();
        } catch (_eLd) {}
        if (buildingProfiles && typeof buildingProfiles === 'object') {
            try {
                syncManagedUnitsFromProfiles();
            } catch (_eMu) {}
        }
        syncBhdKvToServer();
        closeUnitDetailsCancelContractModal();
        closeUnitDetailsModal();
        try {
            renderOperationsTable();
        } catch (_eTbl) {}
        _unitDetailsCancellationDocsCtx = { building: b, unit: uN, agreementNo: req.agreementNo };
        setTimeout(() => {
            try {
                openUnitDetailsCancellationDocsModal();
            } catch (_eDocs) {}
        }, 300);
        const finNote =
            fin.isEarlyTermination && fin.remainingMunicipal > 0
                ? `\n${t('رسوم البلدية للفترة المتبقية', 'Remaining municipal fees')}: ${summaryAmtOm(fin.remainingMunicipal)}`
                : '';
        const depNote =
            fin.isEarlyTermination && fin.totalDeposit > 0
                ? `\n${t('ملاحظة: مبلغ الضمان لا يُسترد (إلغاء قبل نهاية العقد).', 'Note: deposit is non-refundable (cancellation before contract end).')}`
                : '';
        alert(
            t(
                `تم تأكيد الإلغاء — العقار شاغر الآن.${finNote}${depNote}\n\nالخطوة التالية: رفع مستندات الإلغاء ورسالة البلدية.`,
                `Cancellation confirmed — unit is now vacant.${finNote}${depNote}\n\nNext: upload cancellation documents and the municipality letter.`
            )
        );
    }

