    async function onCancellationSupportingDocsFileChange(inp) {
        const ctx = _unitDetailsCancellationDocsCtx;
        const files = inp?.files ? [...inp.files] : [];
        if (!ctx || !files.length) return;
        ctx.supportingDocs = ctx.supportingDocs || [];
        const host = document.getElementById('unitDetailsCancelSupportingList');
        for (const f of files) {
            try {
                const ref = await bhdPersistUploadedFile(f, {
                    category: 'cancellation',
                    docType: 'cancellation_supporting',
                    buildingNo: ctx.building,
                    flatNo: ctx.unit,
                    agreementNo: ctx.agreementNo || '_cancelled'
                });
                ctx.supportingDocs.push(fileRefFromPersistResult(ref));
            } catch (_eS) {}
        }
        if (host) {
            host.innerHTML = (ctx.supportingDocs || [])
                .map((d) => `<div>✓ ${escHtml(toStr(d.name))}</div>`)
                .join('');
        }
    }

    function saveUnitDetailsCancellationFinalDocs() {
        const ctx = _unitDetailsCancellationDocsCtx;
        if (!ctx) return;
        if (!contractAttachmentPresent(ctx.municipalityLetter)) {
            alert(t('يرجى رفع أصل رسالة البلدية للإلغاء.', 'Please upload the original municipality cancellation letter.'));
            return;
        }
        const key = 'bhd_contract_cancellations';
        let list = [];
        try {
            list = JSON.parse(localStorage.getItem(key) || '[]');
            if (!Array.isArray(list)) list = [];
        } catch (_e) {
            list = [];
        }
        const idx = list.findIndex(
            (row) =>
                normalizeReservationBuildingKey(row.building) === normalizeReservationBuildingKey(ctx.building) &&
                normalizeUnit(String(row.unit)) === normalizeUnit(String(ctx.unit)) &&
                toStr(row.status) === 'completed_docs_pending'
        );
        const actor = getCurrentActorLedgerRecord();
        const patch = {
            municipalityLetter: ctx.municipalityLetter,
            supportingDocs: ctx.supportingDocs || [],
            status: 'completed',
            docsCompletedAt: new Date().toISOString(),
            docsStaffName: actor.staffName
        };
        if (idx >= 0) {
            list[idx] = { ...list[idx], ...patch };
        } else {
            list.push({
                building: ctx.building,
                unit: ctx.unit,
                agreementNo: ctx.agreementNo,
                ...patch,
                at: new Date().toISOString()
            });
        }
        try {
            localStorage.setItem(key, JSON.stringify(list));
        } catch (_eSave) {}
        syncBhdKvToServer();
        closeUnitDetailsCancellationDocsModal();
        _unitDetailsCancellationDocsCtx = null;
        alert(t('تم حفظ مستندات الإلغاء.', 'Cancellation documents saved.'));
    }

    function refreshUnitDetailsAfterCancellationChange() {
        const unit = selectedUnitDetailsRecord;
        if (!unit) return;
        try {
            const fresh = getUnitsData().find(
                (u) =>
                    normalizeReservationBuildingKey(u.building) === normalizeReservationBuildingKey(unit.building) &&
                    normalizeUnit(u.unit) === normalizeUnit(unit.unit)
            );
            if (fresh) selectedUnitDetailsRecord = fresh;
        } catch (_eFresh) {}
        const idx = (window._unitsViewRows || []).findIndex(
            (u) =>
                normalizeReservationBuildingKey(u.building) === normalizeReservationBuildingKey(unit.building) &&
                normalizeUnit(u.unit) === normalizeUnit(unit.unit)
        );
        if (idx >= 0) {
            try {
                openUnitDetailsModal(idx);
            } catch (_eReopen) {}
        } else {
            try {
                updateUnitDetailsToolbarForDraft();
            } catch (_eTb) {}
        }
    }

