    async function bhdTriggerPrintPreview(printToken) {
        if (bhdIsDesktopApp() && window.bhdDesktop?.printChildByToken) {
            try {
                const r = await window.bhdDesktop.printChildByToken(toStr(printToken));
                if (r && r.ok) return;
            } catch (_eDeskPr) {}
            try {
                const r2 = await window.bhdDesktop.printChildByToken('');
                if (r2 && r2.ok) return;
            } catch (_eDeskPr2) {}
        }
        try {
            const w = window._bhdLastPrintPreviewWin;
            if (w && !w.closed) {
                w.focus();
                w.print();
                return;
            }
        } catch (_eWinPr) {}
        alert(
            t(
                'تعذرت الطباعة تلقائياً. استخدم Ctrl+P من نافذة المعاينة.',
                'Automatic print failed. Use Ctrl+P in the preview window.'
            )
        );
    }
